            rst_mh     = (start) ? 0 : 1;
            start_a    = (start) ? 1 : 0;
            start_c    = (start) ? 1 : 0;

            naddr1_sel_op[0] = 0; 
            naddr2_sel_op[0] = 0; 
            naddr3_sel_op[0] = 0;
            naddr1_sel_op[1] = 0; 
            naddr2_sel_op[1] = 0; 
            naddr3_sel_op[1] = 0;

            ctr_next   = 0;
            ctr0_next  = 0;
            ctr1_next  = 0;

            nstate0     = (start) ? FSM0_LOAD_RHO : FSM0_INIT; 
        end
        {2'd2,FSM0_LOAD_RHO}: begin


            din_a     = data_i;
            valid_i_a = valid_i;
            ready_i_mux = 2;
            nstate0    = (ctr == 3 && ready_i_a && valid_i_a) ? FSM0_LOAD_MU : FSM0_LOAD_RHO; 


            if (ready_i_a && valid_i == 1) begin
                if (ctr == 3) begin
                    ctr_next = 0;
                end else begin
                    ctr_next = ctr + 1;
                end
            end else begin
                ctr_next = ctr;
            end 
        end
        {2'd2,FSM0_LOAD_MU}: begin


            if (ctr1 > 0) begin
                ready_i_mux = 6;
                valid_i_geny = valid_i;
                di_geny      = data_i;         
                ctr1_next  = (valid_i && ready_i) ? ctr1 + 1 : ctr1;
            end else begin
                ready_i_mux = 7;
                start_geny = (valid_i && ready_i) ? 1 : 0;
                ctr1_next  = (valid_i && ready_i) ? ctr1 + 1 : ctr1;
            end


            wea_ram0   = valid_o_a[0];
            ready_o_a[0]  = 1;
            addra_ram0 = {sample_state, ctr_a1};
            dia_ram0   = {1'd0, samples_a[3*23+:23], 1'd0, samples_a[2*23+:23], 1'd0, samples_a[1*23+:23], 1'd0, samples_a[0*23+:23]};

            web_ram0   = valid_o_a[1];
            ready_o_a[1]  = 1;
            addrb_ram0 = {sample_state+1'b1, ctr_a2};
            dib_ram0   = {1'd0, samples_a[7*23+:23], 1'd0, samples_a[6*23+:23], 1'd0, samples_a[5*23+:23], 1'd0, samples_a[4*23+:23]};


            if ({ctr1,3'd0} > mlen_PLUS64) begin
                nstate0 = FSM0_DECODE_S1;
                ctr1_next = 0;
                nstart_fsm1 = 1;
            end

        end
        {2'd2,FSM0_DECODE_S1}: begin


            if (ctr < S1_LEN[12:3]) begin
                ready_i_mux =- 4;
                valid_i_dec = valid_i;
                di_dec      = {data_i[0*8+:8],data_i[1*8+:8],data_i[2*8+:8],data_i[3*8+:8],
                               data_i[4*8+:8],data_i[5*8+:8],data_i[6*8+:8],data_i[7*8+:8]};
            end
            mode_dec    = ENCODE_S1;
            ready_o_dec = 1;
            wea_ram3    = valid_o_dec;
            addra_ram3  = ctr_dec;
            dia_ram3    = {1'd0, do_dec[3*23+:23], 1'd0, do_dec[2*23+:23], 1'd0, do_dec[1*23+:23], 1'd0, do_dec[0*23+:23]};


            wea_ram0   = valid_o_a[0];
            ready_o_a[0]  = 1;
            addra_ram0 = {sample_state, ctr_a1};
            dia_ram0   = {1'd0, samples_a[3*23+:23], 1'd0, samples_a[2*23+:23], 1'd0, samples_a[1*23+:23], 1'd0, samples_a[0*23+:23]};

            web_ram0   = valid_o_a[1];
            ready_o_a[1]  = 1;
            addrb_ram0 = {sample_state+1'b1, ctr_a2};
            dib_ram0   = {1'd0, samples_a[7*23+:23], 1'd0, samples_a[6*23+:23], 1'd0, samples_a[5*23+:23], 1'd0, samples_a[4*23+:23]};


            ctr_next  = (ctr_dec == {L,6'd0}-1) ? 0 
                        : (valid_i_dec && ready_i_dec) ? ctr + 1 : ctr;


            nstate0 = (ctr_dec == {L,6'd0}-1) ? FSM0_NTT_S1 : FSM0_DECODE_S1;
            rst_dec = (ctr_dec == {L,6'd0}-1) ? 1 : 0;

        end
        {2'd2,FSM0_NTT_S1}: begin


            if (ctr < S2_LEN[12:3]) begin
                ready_i_mux = 4;
                valid_i_dec = valid_i;
                di_dec      = {data_i[0*8+:8],data_i[1*8+:8],data_i[2*8+:8],data_i[3*8+:8],
                               data_i[4*8+:8],data_i[5*8+:8],data_i[6*8+:8],data_i[7*8+:8]};
            end
            mode_dec    = ENCODE_S2;
            ready_o_dec = 1;
            wea_ram5    = valid_o_dec;
            addra_ram5  = ctr_dec;
            dia_ram5    = {1'd0, do_dec[3*23+:23], 1'd0, do_dec[2*23+:23], 1'd0, do_dec[1*23+:23], 1'd0, do_dec[0*23+:23]};


            wea_ram0   = valid_o_a[0];
            ready_o_a[0]  = 1;
            addra_ram0 = {sample_state, ctr_a1};
            dia_ram0   = {1'd0, samples_a[3*23+:23], 1'd0, samples_a[2*23+:23], 1'd0, samples_a[1*23+:23], 1'd0, samples_a[0*23+:23]};

            web_ram0   = valid_o_a[1];
            ready_o_a[1]  = 1;
            addrb_ram0 = {sample_state+1'b1, ctr_a2};
            dib_ram0   = {1'd0, samples_a[7*23+:23], 1'd0, samples_a[6*23+:23], 1'd0, samples_a[5*23+:23], 1'd0, samples_a[4*23+:23]};


            addra_ram3 = {addr1_sel_op[1], addra1_op[1]};
            addrb_ram3 = {addr1_sel_op[1], addrb1_op[1]};
            web_ram3   = web1_op[1];
            dib_ram3   = dib1_op[1];
            doa1_op[1]  = doa_ram3;
            dob1_op[1]  = dob_ram3;


            ctr_next  = (done_op[1] && addr1_sel_op[1] == L-1) ? 0 
                        : (valid_i_dec && ready_i_dec) ? ctr + 1 : ctr;

            nstate0    = (done_op[1] && addr1_sel_op[1] == L-1) ? FSM0_NTT_S2 : FSM0_NTT_S1;
            rst_dec   = (ctr_dec == {K, 6'd0}-1 && valid_o_dec && ready_o_dec) ? 1 : 0;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = FORWARD_NTT_MODE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == L-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];
        end
        {2'd2,FSM0_NTT_S2}: begin


            if (ctr < T0_LEN[12:3]) begin
                ready_i_mux = 4;
                valid_i_dec = valid_i;
                di_dec      = {data_i[0*8+:8],data_i[1*8+:8],data_i[2*8+:8],data_i[3*8+:8],
                               data_i[4*8+:8],data_i[5*8+:8],data_i[6*8+:8],data_i[7*8+:8]};
            end
            mode_dec    = ENCODE_T0;
            ready_o_dec = 1;
            wea_ram3    = valid_o_dec;
            addra_ram3  = 512 | ctr_dec;
            dia_ram3    = {1'd0, do_dec[3*23+:23], 1'd0, do_dec[2*23+:23], 1'd0, do_dec[1*23+:23], 1'd0, do_dec[0*23+:23]};


            wea_ram0   = valid_o_a[0];
            ready_o_a[0]  = 1;
            addra_ram0 = {sample_state, ctr_a1};
            dia_ram0   = {1'd0, samples_a[3*23+:23], 1'd0, samples_a[2*23+:23], 1'd0, samples_a[1*23+:23], 1'd0, samples_a[0*23+:23]};

            web_ram0   = valid_o_a[1];
            ready_o_a[1]  = 1;
            addrb_ram0 = {sample_state+1'b1, ctr_a2};
            dib_ram0   = {1'd0, samples_a[7*23+:23], 1'd0, samples_a[6*23+:23], 1'd0, samples_a[5*23+:23], 1'd0, samples_a[4*23+:23]};


            addra_ram5 = {addr1_sel_op[1], addra1_op[1]};
            addrb_ram5 = {addr1_sel_op[1], addrb1_op[1]};
            web_ram5   = web1_op[1];
            dib_ram5   = dib1_op[1];
            doa1_op[1]  = doa_ram5;
            dob1_op[1]  = dob_ram5;


            ctr_next  = (done_op[1] && addr1_sel_op[1] == K-1) ? 0 
                        : (valid_i_dec && ready_i_dec) ? ctr + 1 : ctr;

            nstate0    = (done_op[1] && addr1_sel_op[1] == K-1) ? FSM0_NTT_T0 : FSM0_NTT_S2;
            rst_dec   = (ctr_dec == {K, 6'd0}-1 && valid_o_dec && ready_o_dec) ? 1 : 0;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = FORWARD_NTT_MODE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == K-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];
        end
        {2'd2,FSM0_NTT_T0}: begin


            addra_ram3 = 512 | {addr1_sel_op[1], addra1_op[1]};
            addrb_ram3 = 512 | {addr1_sel_op[1], addrb1_op[1]};
            web_ram3   = web1_op[1];
            dib_ram3   = dib1_op[1];
            doa1_op[1]  = doa_ram3;
            dob1_op[1]  = dob_ram3;


            wea_ram0   = valid_o_a[0];
            ready_o_a[0]  = 1;
            addra_ram0 = {sample_state, ctr_a1};
            dia_ram0   = {1'd0, samples_a[3*23+:23], 1'd0, samples_a[2*23+:23], 1'd0, samples_a[1*23+:23], 1'd0, samples_a[0*23+:23]};

            web_ram0   = valid_o_a[1];
            ready_o_a[1]  = 1;
            addrb_ram0 = {sample_state+1'b1, ctr_a2};
            dib_ram0   = {1'd0, samples_a[7*23+:23], 1'd0, samples_a[6*23+:23], 1'd0, samples_a[5*23+:23], 1'd0, samples_a[4*23+:23]};


            nstate0    = (done_op[1] && addr1_sel_op[1] == K-1) ? FSM0_STALL : FSM0_NTT_T0;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = FORWARD_NTT_MODE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == K-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];
        end
        {2'd2,FSM0_STALL}: begin
            nstate0 = (cstart_fsm0) ? FSM0_UNLOAD_Z :  FSM0_STALL;
        end
        {2'd2,FSM0_UNLOAD_Z}: begin


            mode_enc    = ENCODE_Z;
            valid_i_enc = (ctr != 0 && ctr[0] == 0) ? 1 : 0;
            di_enc      = {doa_ram6[24*3+:23], doa_ram6[24*2+:23],doa_ram6[24*1+:23],doa_ram6[24*0+:23]};
            addra_ram6  = ctr >> 1;

            ready_o_enc = ready_o;
            valid_o     = valid_o_enc;
            data_o      = {do_enc[8*0+:8], do_enc[8*1+:8],do_enc[8*2+:8],do_enc[8*3+:8],do_enc[8*4+:8],do_enc[8*5+:8],do_enc[8*6+:8],do_enc[8*7+:8]};



            ctr_next = ctr + 1;

            if (ctr == L*64*2+4) begin
                nstate0  = FSM0_UNLOAD_H;
                ctr_next = 0;
                rst_enc  = 1;
            end
        end
        {2'd2,FSM0_UNLOAD_H}: begin


            readyo_mh = ready_o;
            valid_o   = valido_mh;
            data_o    = {hint_o[8*0+:8], hint_o[8*1+:8],hint_o[8*2+:8],hint_o[8*3+:8],hint_o[8*4+:8],hint_o[8*5+:8],hint_o[8*6+:8],hint_o[8*7+:8]};


            ctr_next = (ready_o && valid_o) ? ctr + 1 : ctr;
            if (((ctr == 10 && sec_lvl != 3) || (ctr == 7 && sec_lvl == 3)) && ready_o && valid_o) begin
                nstate0  = FSM0_UNLOAD_C;
                ctr_next = 0;
            end
        end
        {2'd2,FSM0_UNLOAD_C}: begin


            read_ch_c = ready_o;
            data_o    = ch_c;
            valid_o   = 1;

            ctr_next = (ready_o) ? ctr + 1 : ctr;

            if (ctr == 3 && ready_o) begin
                nstate0  = FSM0_INIT;
                ctr_next = 0;
            end
        end
        endcase

        case(cstate1) 
        FSM1_STALL: begin

            ctrfsm1_next = 0;
            nstate1 = (cstart_fsm1) ? FSM1_GENY : FSM1_STALL;
            start_geny = (cstart_fsm1 && cstate0 == FSM0_STALL) ? 1 : 0;
        end
        FSM1_GENY: begin
            addra_ram1   = {fsm1_even, 9'd0} | ctrfsm1;
            dia_ram1     = {1'b0,do_geny[23*3+:23],1'b0,do_geny[23*2+:23],1'b0,do_geny[23*1+:23],1'b0,do_geny[23*0+:23]};
            wea_ram1     = valid_o_geny;
            ready_o_geny = 1;

            if (valid_o_geny && ready_o_geny) begin
                if (ctrfsm1 == {L, 6'd0}-1) begin
                    ctrfsm1_next = 0;
                    nstate1      = FSM1_WAIT;
                end else begin
                    ctrfsm1_next = ctrfsm1 + 1;
                end
            end
        end
        FSM1_WAIT: begin
            nstate1 = FSM1_NTT_Y;
            mode_op[0]  = FORWARD_NTT_MODE;
            rst_op[0]   = 1;
        end
        FSM1_NTT_Y: begin


            addra_ram1 = {fsm1_even, 9'd0} | {addr1_sel_op[0], addra1_op[0]};
            addrb_ram1 = {fsm1_even, 9'd0} | {addr1_sel_op[0], addrb1_op[0]};
            web_ram1   = web1_op[0];
            dib_ram1   = dib1_op[0];
            doa1_op[0]  = doa_ram1;
            dob1_op[0]  = dob_ram1;


            if (sec_lvl == 2 || cstate0 == 7) begin
                nstate1    = (done_op[0] && addr1_sel_op[0] == L-1) ? FSM1_MULT_A_Y : FSM1_NTT_Y;
                rst_op[0]   = (done_op[0]) ? 1 : 0;
            end else begin

                nstate1    = (done_a) ? FSM1_MULT_A_Y : FSM1_NTT_Y;
                rst_op[0]   = ((done_op[0] && addr1_sel_op[0] != L-1) || done_a) ? 1 : 0;
            end


            mode_op[0]  = FORWARD_NTT_MODE;
            naddr1_sel_op[0] = (done_op[0] && addr1_sel_op[0] == L-1) ? 0 
                             : (done_op[0]) ? addr1_sel_op[0] + 1 : addr1_sel_op[0];
        end
        FSM1_MULT_A_Y: begin


            addra_ram1 = {fsm1_even, 9'd0} | {addr1_sel_op[0], addra1_op[0]};
            addra_ram0  = {addr2_sel_op[0], addra2_op[0]};
            addra_ram2  = {addr3_sel_op[0], addrb1_op[0]};

            addrb_ram2 = {addr3_sel_op[0], addrb2_op[0]};
            web_ram2   = web2_op[0];
            dib_ram2   = dib2_op[0];

            doa1_op[0]  = doa_ram1;
            doa2_op[0]  = doa_ram0;
            dob1_op[0]  = (addr1_sel_op[0] == 0) ? 0 : doa_ram2; 


            mode_op[0]  = MULT_MODE;
            encode_mode_op[0] = ENCODE_TRUE;

            if (done_op[0]) begin
                rst_op[0] = 1;
                naddr2_sel_op[0] = addr2_sel_op[0] + 1;
                if (naddr1_sel_op[0] == L - 1) begin
                    naddr1_sel_op[0] = 0;
                    if (naddr3_sel_op[0] == K - 1) begin
                        naddr3_sel_op[0] = 0;
                        naddr2_sel_op[0] = 0;


                        nstate1 = FSM1_NTTI_W;
                    end else begin
                        naddr3_sel_op[0] = addr3_sel_op[0] + 1;
                    end
                end else begin
                    naddr1_sel_op[0] = addr1_sel_op[0] + 1;
                end
            end

        end
        FSM1_NTTI_W: begin


            addra_ram2 = {addr1_sel_op[0], addra1_op[0]};
            addrb_ram2 = {addr1_sel_op[0], addrb1_op[0]};
            web_ram2   = web1_op[0];
            dib_ram2   = dib1_op[0];
            doa1_op[0]  = doa_ram2;
            dob1_op[0]  = dob_ram2;


            nstate1    = (done_op[0] && addr1_sel_op[0] == K-1) ? FSM1_STALL : FSM1_NTTI_W;
            nstart_fsm2 = (done_op[0] && addr1_sel_op[0] == K-1) ? 1 : 0;

            rst_op[0]   = (done_op[0]) ? 1 : 0;
            mode_op[0]  = INVERSE_NTT_MODE;
            encode_mode_op[0] = ENCODE_TRUE;
            naddr1_sel_op[0] = (done_op[0] && addr1_sel_op[0] == K-1) ? 0 
                             : (done_op[0]) ? addr1_sel_op[0] + 1 : addr1_sel_op[0];
        end
        endcase


        case(cstate2)
        FSM2_STALL: begin
            nstart_fsm1  = (cstate0 < 7 && mode == 2) ? 1 : 0;
            ctrfsm2_next = 0;
            ctr0fsm2_next = 0;

            nstate2 = (cstart_fsm2 && !cstart_fsm0) ? FSM2_DECOMP : FSM2_STALL;
            rst_mh  = (cstart_fsm2 && !cstart_fsm0) ? 1 : 0;
        end
        FSM2_DECOMP: begin

            di_decomp  = doa_ram2;
            addra_ram2 = ctrfsm2;
            valid_i_decomp =  (ctrfsm2 > 0 && ctrfsm2 <= K*64 && ready_i_decomp && ready_i_decomp_last) ? 1 : 0; 
            ready_o_decomp = ready_i_enc;


            mode_enc    = ENCODE_W1;
            valid_i_enc = valid_o_decomp;
            di_enc = {dob_decomp[24*3+:23], dob_decomp[24*2+:23], dob_decomp[24*1+:23], dob_decomp[24*0+:23]};


            din_c = {do_enc[8*0+:8], do_enc[8*1+:8],do_enc[8*2+:8],do_enc[8*3+:8],do_enc[8*4+:8],do_enc[8*5+:8],do_enc[8*6+:8],do_enc[8*7+:8]}; 
            valid_i_c = valid_o_enc;
            ready_o_enc = ready_i_c;

            wea_ram4 = (valid_o_decomp && ready_i_enc) ? 1 : 0;
            web_ram4 = (valid_o_decomp && ready_i_enc) ? 1 : 0;
            addra_ram4 = ctr0fsm2 | 512;
            addrb_ram4 = ctr0fsm2;
            dia_ram4 = doa_decomp;
            dib_ram4 = dob_decomp;

            ctr0fsm2_next = (valid_o_decomp && ready_i_enc || (ctr0fsm2 >= K*64-1)) ? ctr0fsm2 + 1 : ctr0fsm2;



            rst_decomp = (ctr0fsm2 >= K*64-1 + 6) ? 1 : 0;
            rst_enc    = (ctr0fsm2 >= K*64-1 + 6) ? 1 : 0;
            nstate2    = (ctr0fsm2 >= K*64-1 + 6) ? FSM2_GEN_C : FSM2_DECOMP;
            ctrfsm2_next   = (ctr0fsm2 >= K*64-1 + 6)  ? 0 
                       : (ready_i_decomp) ? ctrfsm2 + 1
                       : (ready_i_decomp == 0 && ready_i_decomp_last == 1) ? ctrfsm2 - 1: ctrfsm2;
        end
        FSM2_GEN_C: begin
            addra_ram0 = 3584 | ctrfsm2;
            dia_ram0 = {1'b0,samples_c[23*3+:23],1'b0,samples_c[23*2+:23],1'b0,samples_c[23*1+:23],1'b0,samples_c[23*0+:23]};
            wea_ram0 = valid_o_c;
            ready_o_c = 1;

            nstate2     = (done_c) ? FSM2_NTT_C : FSM2_GEN_C;
            nstart_fsm1  = (done_c) ? 1 : 0;
            rst_op[1]    = (done_c) ? 1 : 0;

            ctrfsm2_next = (done_c) ? 0 
                            : (valid_o_c) ? ctrfsm2 + 1 : ctrfsm2;
        end
        FSM2_NTT_C: begin


            addra_ram0 = 3584 | {addr1_sel_op[1], addra1_op[1]};
            addrb_ram0 = 3584 | {addr1_sel_op[1], addrb1_op[1]};
            web_ram0   = web1_op[1];
            dib_ram0   = dib1_op[1];
            doa1_op[1]  = doa_ram0;
            dob1_op[1]  = dob_ram0;


            nstate2     = (done_op[1]) ? FSM2_MULTACC : FSM2_NTT_C;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = FORWARD_NTT_MODE;
            naddr1_sel_op[1] = 0;
        end
        FSM2_MULTACC: begin


            addra_ram3 = {addr1_sel_op[1], addra1_op[1]};
            addra_ram0 = 3584 | addra2_op[1];
            addrb_ram1 = {!fsm1_even, 9'd0} | {addr1_sel_op[1], addrb1_op[1]};

            addrb_ram6 = {addr1_sel_op[1], addrb2_op[1]};
            web_ram6   = web2_op[1];
            dib_ram6   = dib2_op[1];

            doa1_op[1]  = doa_ram3;
            doa2_op[1]  = doa_ram0;
            dob1_op[1]  = dob_ram1;


            mode_op[1]  = MULT_MODE;

            if (done_op[1]) begin
                rst_op[1] = 1;
                naddr1_sel_op[1] = addr1_sel_op[1] + 1;
                if (addr1_sel_op[1] == L - 1) begin
                    naddr1_sel_op[1] = 0;
                    nstate2 = FSM2_MULT_CS2;
                end 
            end
        end
        FSM2_MULT_CS2: begin

            addra_ram5 = {addr1_sel_op[1], addra1_op[1]};
            addra_ram0 = 3584 | addra2_op[1];

            addrb_ram5 = 512 | {addr1_sel_op[1], addrb2_op[1]};
            web_ram5   = web2_op[1];
            dib_ram5   = dib2_op[1];

            doa1_op[1]  = doa_ram5;
            doa2_op[1]  = doa_ram0;
            dob1_op[1]  = 0; 


            mode_op[1]  = MULT_MODE;

            if (done_op[1]) begin
                rst_op[1] = 1;
                naddr1_sel_op[1] = addr1_sel_op[1] + 1;
                if (addr1_sel_op[1] == K - 1) begin
                    naddr1_sel_op[1] = 0;
                    nstate2 = FSM2_MULT_CT0;
                end 
            end
        end
        FSM2_MULT_CT0: begin

            addra_ram3 = 512 | {addr1_sel_op[1], addra1_op[1]};
            addrb_ram0 = 3584 | addra2_op[1];

            addrb_ram6 = 512 | {addr1_sel_op[1], addrb2_op[1]};
            web_ram6   = web2_op[1];
            dib_ram6   = dib2_op[1];

            doa1_op[1]  = doa_ram3;
            doa2_op[1]  = dob_ram0;
            dob1_op[1]  = 0; 


            mode_op[1]  = MULT_MODE;

            if (done_op[1]) begin
                rst_op[1] = 1;
                naddr1_sel_op[1] = addr1_sel_op[1] + 1;
                if (addr1_sel_op[1] == K - 1) begin
                    naddr1_sel_op[1] = 0;
                    nstate2 = FSM2_NTTI_Z;
                end 
            end
        end
        FSM2_NTTI_Z: begin


            addra_ram6 = {addr1_sel_op[1], addra1_op[1]};
            addrb_ram6 = {addr1_sel_op[1], addrb1_op[1]};
            web_ram6   = web1_op[1];
            dib_ram6   = dib1_op[1];
            doa1_op[1]  = doa_ram6;
            dob1_op[1]  = dob_ram6;


            mode_norm = G1_SUB_BETA ;
            validi_norm = (web1_op[1] && ctrfsm2 >= 192) ? 1 : 0;
            di_norm = dib1_op[1];
            ctrfsm2_next = (done_op[1]) ? 0 
                        : (web1_op[1]) ? ctrfsm2 + 1 : ctrfsm2;


            nstate2    = (done_op[1] && addr1_sel_op[1] == L-1) ? FSM2_NTTI_CS2 : FSM2_NTTI_Z;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = INVERSE_NTT_MODE;
            encode_mode_op[1] = ENCODE_TRUE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == L-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];
        end
        FSM2_NTTI_CS2: begin


            addra_ram5 = 512 | {addr1_sel_op[1], addra1_op[1]};
            addrb_ram5 = 512 | {addr1_sel_op[1], addrb1_op[1]};
            web_ram5   = web1_op[1];
            dib_ram5   = dib1_op[1];
            doa1_op[1]  = doa_ram5;
            dob1_op[1]  = dob_ram5;


            nstate2    = (done_op[1] && addr1_sel_op[1] == K-1) ? FSM2_NTTI_CT0 : FSM2_NTTI_CS2;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = INVERSE_NTT_MODE;
            encode_mode_op[1] = ENCODE_TRUE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == K-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];
        end
        FSM2_NTTI_CT0: begin


            addra_ram6 = 512 | {addr1_sel_op[1], addra1_op[1]};
            addrb_ram6 = 512 | {addr1_sel_op[1], addrb1_op[1]};
            web_ram6   = web1_op[1];
            dib_ram6   = dib1_op[1];
            doa1_op[1]  = doa_ram6;
            dob1_op[1]  = dob_ram6;



            mode_norm   = G2 ;
            validi_norm = (web1_op[1] && ctrfsm2 > 192) ? 1 : 0;
            di_norm = dib1_op[1];
            ctrfsm2_next = (done_op[1]) ? 0 
                        : (web1_op[1]) ? ctrfsm2 + 1 : ctrfsm2;



            nstate2    = (done_op[1] && addr1_sel_op[1] == K-1) ? FSM2_SUB_W0_CS2 : FSM2_NTTI_CT0;



            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = INVERSE_NTT_MODE;
            encode_mode_op[1] = ENCODE_TRUE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == K-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];
        end
        FSM2_SUB_W0_CS2: begin


            addra_ram4 = 512 | {addr1_sel_op[1], addra1_op[1]};
            addra_ram5 = 512 | {addr1_sel_op[1], addra2_op[1]};

            doa1_op[1]  = doa_ram4;
            doa2_op[1]  = doa_ram5;

            addrb_ram5 = 512 | {addr1_sel_op[1], addrb2_op[1]};
            web_ram5   = web2_op[1];
            dib_ram5   = dib2_op[1];


            mode_norm   = G2_SUB_BETA ;
            validi_norm = web2_op[1];
            di_norm     = dib2_op[1];


            nstate2    = (done_op[1] && addr1_sel_op[1] == K-1) ? FSM2_MAKEHINT : FSM2_SUB_W0_CS2;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = SUB_MODE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == K-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];
        end 
        FSM2_MAKEHINT: begin


            addra_ram6 = 512 | {addr1_sel_op[1], addra1_op[1]};
            addra_ram5 = 512 | {addr1_sel_op[1], addra2_op[1]};

            doa1_op[1]  = doa_ram6;
            doa2_op[1]  = doa_ram5;

            addrb_ram5 = 512 | {addr1_sel_op[1], addrb2_op[1]};
            web_ram5   = web2_op[1];
            dib_ram5   = dib2_op[1];


            addra_ram4 = (web2_op[1]) ? {addr1_sel_op[1], addrb2_op[1]} + 1 : {addr1_sel_op[1], addrb2_op[1]};

            validi_mh = web2_op[1];
            polyi0_mh = dib2_op[1];
            polyi1_mh = doa_ram4;


            nstate2 = FSM2_MAKEHINT;

            rst_op[1]   = (done_op[1]) ? 1 : 0;
            mode_op[1]  = ADD_MODE;
            naddr1_sel_op[1] = (done_op[1] && addr1_sel_op[1] == K-1) ? 0 
                             : (done_op[1]) ? addr1_sel_op[1] + 1 : addr1_sel_op[1];

            if ((done_op[1] && addr1_sel_op[1] == K-1 && sec_lvl != 5) || (sec_lvl == 5 && done_op[0] && addr1_sel_op[0] == K-1)) begin
                if (reject_mh || norm_rejected) begin
                    nstate2 = FSM2_DECOMP;
                    rst_mh  = 1;
                    start_c = 1;
                    ctr0fsm2_next = 0;
                    ctrfsm2_next  = 0;
                end else begin
                    nstart_fsm0 = 1;
                    nstate2     = FSM2_STALL;
                end                
            end
        end
        endcase

    end

    integer i;

    always @(posedge clk) begin
        mlen_PLUS48  <= mlen + 48;
        mlen_PLUS64  <= mlen + 64;
        mlen_PLUS112 <= mlen + 112;

        start_op[0] <= 0;
        start_op[1] <= 0;

        addr1_sel_op[0] <= naddr1_sel_op[0]; 
        addr2_sel_op[0] <= naddr2_sel_op[0]; 
        addr3_sel_op[0] <= naddr3_sel_op[0]; 

        addr1_sel_op[1] <= naddr1_sel_op[1]; 
        addr2_sel_op[1] <= naddr2_sel_op[1]; 
        addr3_sel_op[1] <= naddr3_sel_op[1]; 

        ready_i_decomp_last <= ready_i_decomp;

        norm_rejected <= (rej_norm) ? 1 : norm_rejected;

        if (rst) begin
            cstate0 <= FSM0_INIT;
            cstate1 <= FSM1_STALL;
            cstate1 <= FSM2_STALL;
            ctr    <= 0;
            ctr0   <= 0;
            ctr1   <= 0;

            ctrfsm2 <= 0;
            ctrfsm1 <= 0;
            ctr0fsm2 <= 0;

            mlen <= 0;
            norm_rejected <= 0;

            fsm1_even <= 0;

            cstart_fsm0 <= 0;
            cstart_fsm1 <= 0;
            cstart_fsm2 <= 0;
        end else begin
            cstate0 <= nstate0;
            cstate1 <= nstate1;
            cstate2 <= nstate2;
            ctr    <= ctr_next;
            ctr0   <= ctr0_next;
            ctr1   <= ctr1_next;

            ctrfsm2 <= ctrfsm2_next;
            ctrfsm1 <= ctrfsm1_next;
            ctr0fsm2 <= ctr0fsm2_next;

            cstart_fsm0 <= nstart_fsm0;
            cstart_fsm1 <= nstart_fsm1;
            cstart_fsm2 <= nstart_fsm2;
        end

        case({mode,cstate0})
            {2'd0,KG_INIT}: begin
                addr1_sel_op[0] <= 0; 
                addr2_sel_op[0] <= 0; 
                addr3_sel_op[0] <= 0; 

                ctr_a1 <= 0;
                ctr_a2 <= 0;
                ctr_s1 <= 0;
                ctr_s2 <= 0;
                keccak_valid <= 0;

                ctr_t <= 0;
            end
            {2'd0,KG_UNLOAD_HASH}: begin
                rho <= (valid_i_a && ready_i_a) ?  {rho[255-64:0], dout[2]} : rho;
            end
            {2'd0,KG_SAMPLE_S1}: begin
                ctr_s1 <= (valid_o_s && ready_o_s) ? ctr_s1 + 1 : ctr_s1;
                if (ctr == S1_LEN[10:3]-1 && valid_o && ready_o) begin
                    ctr_s1 <= 0;
                end

                addr1_sel_op[0] <= 0; 
                start_op[0] <= (ctr == S1_LEN[10:3]-1 && valid_o && ready_o) ? 1 : 0;
            end
            {2'd0,KG_SAMPLE_S2}: begin
                ctr_s2 <= (valid_o_s && ready_o_s) ? ctr_s2 + 1 : ctr_s2;
                if (done_s) begin
                    ctr_s2 <= 0;
                end

                ctr <= (done_a) ? 0 : ctr_next;
                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                start_op[0]     <= ((done_op[0] && ~(addr1_sel_op[0] == K - 1 && sec_lvl != 2)) || (done_a && sec_lvl != 2)) ? 1 : 0;
            end
            {2'd0,KG_MULT_AS1}: begin
                start_op[0]     <= (addr3_sel_op[0] != (K-1)*(L-1) && done_op[0]) ? 1 : 0;

                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                addr2_sel_op[0] <= naddr2_sel_op[0];
                addr3_sel_op[0] <= naddr3_sel_op[0];

            end
            {2'd0,KG_NTTI_T}: begin
                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                start_op[0]     <= (done_op[0]) ? 1 : 0;

                rho <= (src_read[2] && ~src_ready_fsm && ctr > 0) ?  {rho[255-64:0], 64'd0} : rho;
                ctr <= (done_op[0] && addr1_sel_op[0] == K-1) ? 0 : ctr_next;
            end
            {2'd0,KG_ADD_T_S2}: begin
                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                start_op[0]     <= (addr1_sel_op[0] != K-1 && done_op[0]) ? 1 : 0;
                ctr <= (ctr == T1_LEN[11:3]-1 && valid_o  && ready_o) ? 0 : ctr_next;


                if (valid_o  && ready_o) begin
                    keccak_valid <= {keccak_valid[318:0], 1'b1};
                    keccak_fifo[0] <= {do_enc[7:0],do_enc[15:8], do_enc[23:16], do_enc[31:24], do_enc[39:32], do_enc[47:40],do_enc[55:48], do_enc[63:56]};
                    for (i = 0; i < 319; i = i + 1)
                        keccak_fifo[i+1] <= keccak_fifo[i];
                end
            end
            {2'd0,KG_ENCODE_T0}: begin
                ctr <= (ctr == T0_LEN[11:3]-1 && valid_o  && ready_o) ? 0 : ctr_next;
                ctr_t <= ctr_t + 1;


                if (src_read[2]  && ~src_ready_fsm) begin
                    keccak_valid <= {keccak_valid[318:0], 1'b0};
                    keccak_fifo[0] <= 0;
                    for (i = 0; i < 319; i = i + 1)
                        keccak_fifo[i+1] <= keccak_fifo[i];
                end

            end
            {2'd0,KG_UNLOAD_TR}: begin

                if (src_read[2]  && ~src_ready_fsm) begin
                    keccak_valid <= {keccak_valid[318:0], 1'b0};
                    keccak_fifo[0] <= 0;
                    for (i = 0; i < 319; i = i + 1)
                        keccak_fifo[i+1] <= keccak_fifo[i];
                end
            end
            {2'd1,VY_INIT}: begin
                mlen <= 0;
                ctr  <= 0;
                fail <= 0;
                COMP_FAIL    <= 0;
                ctr_dec <= 0;
                ctr_c   <= 0;


                addr1_sel_op[0] <= 0; 
                addr2_sel_op[0] <= 0; 
                addr3_sel_op[0] <= 0; 
            end 
            {2'd1,VY_LOAD_RHO}: begin
                RHO <= (valid_i && ready_i) ?  {RHO[255-64:0], data_i} : RHO;
                ctr <= ctr_next;
            end
            {2'd1,VY_LOAD_C}: begin
                C <= (valid_i && ready_i) ?  {C[255-64:0], data_i} : C;
            end
            {2'd1,VY_DECODE_Z}: begin
                ctr_dec <= (ctr_dec == {L, 6'd0}-1 && valid_o_dec && ready_o_dec) ? 0 
                             : (valid_o_dec) ? ctr_dec + 1 : ctr_dec;
                ctr_c   <= (valid_o_c)   ? ctr_c   + 1 : ctr_c;

                start_op[0] <= (ctr_dec == {L, 6'd0}-1 && valid_o_dec && ready_o_dec)  ? 1 :0;

                RHO <= (src_read[2] && ctr0 > 1) ?  {RHO[255-64:0], 64'd0} : RHO;
            end
            {2'd1,VY_NTT_Z}: begin
                ctr_dec <= (valid_o_dec) ? ctr_dec + 1 : ctr_dec;
                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                start_op[0]     <= (done_op[0]) ? 1 : 0;

                TR <= (dst_write[2]) ? {TR[255-64:0], dout[2]} : TR;
            end
            {2'd1,VY_NTT_T1}: begin
                TR <= (src_read[2] && ctr0 > 1) ? {TR[255-64:0], 64'd0} : TR;
                MU <= (dst_write[2]) ? {MU[512-64:0], dout[2]} : MU;

                mlen <= (ready_i && valid_i && ctr0 == 1) ? data_i[31:0] : mlen;
                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                start_op[0]     <= (done_op[0]) ? 1 : 0;
            end
            {2'd1,VY_NTT_C}: begin
                start_op[0]     <= ((done_op[0] && sec_lvl != 5) || (done_a && sec_lvl == 5)) ? 1 : 0;
            end
            {2'd1,VY_MULT_AZ}: begin
                start_op[0]     <= (done_op[0]) ? 1 : 0; 

                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                addr2_sel_op[0] <= naddr2_sel_op[0];
                addr3_sel_op[0] <= naddr3_sel_op[0];
            end
            {2'd1,VY_MULT_CT1}: begin
                start_op[0]     <= (done_op[0]) ? 1 : 0;

                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                addr2_sel_op[0] <= naddr2_sel_op[0];
                addr3_sel_op[0] <= naddr3_sel_op[0];
            end
            {2'd1,VY_SUB_AZ_CT1}: begin
                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                start_op[0]     <= (done_op[0]) ? 1 : 0; 
            end
            {2'd1,VY_INTT}: begin
                addr1_sel_op[0] <= naddr1_sel_op[0]; 
                start_op[0]     <= (done_op[0] && addr1_sel_op[0] != K-1) ? 1 : 0;

                MU <= (src_read[2] && ctr0 > 1) ? {MU[512-64:0], 64'd0} : MU;
            end
            {2'd1,VY_COMPARE}: begin
                if (dst_write[2]) begin
                    C <= {C[255-64:0], 64'd0};
                    if (dout[2] != C[255:256-64]) begin
                        fail <= 1;
                    end
                end
            end
            {2'd2,FSM0_LOAD_MU}: begin
                mlen <= (ready_i && valid_i && ctr1 == 0) ? data_i[31:0] : mlen;
            end
            {2'd2,FSM0_DECODE_S1}: begin
                if (valid_o_dec && ready_o_dec) begin
                    if (ctr_dec == {L, 6'd0}-1) begin
                        ctr_dec     <= 0;
                        start_op[1] <= 1;  
                    end else begin
                        ctr_dec <= ctr_dec + 1;
                    end
                end              
            end
            {2'd2,FSM0_NTT_S1}: begin
                ctr_dec <= (ctr_dec == {K, 6'd0}-1 && valid_o_dec && ready_o_dec) ? 0 
                             : (valid_o_dec) ? ctr_dec + 1 : ctr_dec;

                start_op[1] <= (rst_op[1]) ? 1 : 0; 
            end
            {2'd2,FSM0_NTT_S2}: begin
                ctr_dec <= (ctr_dec == {K, 6'd0}-1 && valid_o_dec && ready_o_dec) ? 0 
                             : (valid_o_dec) ? ctr_dec + 1 : ctr_dec;

                start_op[1] <= (rst_op[1]) ? 1 : 0; 
            end
            {2'd2,FSM0_NTT_T0}: begin
                start_op[1] <= (rst_op[1] && addr1_sel_op[1] != K-1) ? 1 : 0; 
            end
        endcase

        case(cstate1) 
        FSM1_WAIT: begin
            start_op[0] <= 1;
        end
        FSM1_NTT_Y: begin
            start_op[0] <= (rst_op[0]) ? 1 : 0; 
        end
        FSM1_MULT_A_Y: begin
            start_op[0] <= (rst_op[0]) ? 1 : 0; 
        end
        FSM1_NTTI_W: begin
            start_op[0] <= (rst_op[0] && addr1_sel_op[0] != K-1) ? 1 : 0; 
            fsm1_even <= (rst_op[0] && addr1_sel_op[0] == K-1) ? ~fsm1_even : fsm1_even;
        end
        endcase


        case(cstate2)
        FSM2_GEN_C: begin
            start_op[1] <= (done_c) ? 1 : 0;
        end
        FSM2_NTT_C: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_MULTACC: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_MULT_CS2: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_MULT_CT0: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_NTTI_Z: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_NTTI_CS2: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_NTTI_CT0: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_SUB_W0_CS2: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;
        end
        FSM2_MAKEHINT: begin
            start_op[1] <= (rst_op[1]) ? 1 : 0;

            if ((done_op[1] && addr1_sel_op[1] == K-1 && sec_lvl != 5) || (sec_lvl == 5 && done_op[0] && addr1_sel_op[0] == K-1)) begin
                norm_rejected <= 0; 
            end
        end
        endcase



        ctr_a1 <= (valid_o_a[0]) ? ctr_a1 + 1 : ctr_a1;
        ctr_a2 <= (valid_o_a[1]) ? ctr_a2 + 1 : ctr_a2;

        if (done_a) begin
            ctr_a1 <= 0;
            ctr_a2 <= 0;
        end
    end

endmodule

timescale 1ns / 1ps

module norm_check(
    input [2:0] sec_lvl,
    input [1:0] mode,
    input validi,
    input [95:0] di,
    output reg rej
    );

    reg [3:0] rej_lane;
    integer i;

    localparam
        G2_SUB_BETA = 3'd0,
        G1_SUB_BETA = 3'd1,
        G2          = 3'd2;

    localparam
        Q            = 23'd8380417,
        GAMMA1_LVL2  = 23'd131072,
        GAMMA1_LVL35 = 23'd524288,
        GAMMA2_LVL2  = 23'd95232,
        GAMMA2_LVL35 = 23'd261888,
        BETA2        = 23'd78,
        BETA3        = 23'd196,
        BETA5        = 23'd120;

    reg [22:0] GAMMA1;
    reg [22:0] GAMMA2;
    reg [22:0] BETA;

    reg [22:0] COND_UPPER, COND_LOWER;

    always @(*) begin

        case(sec_lvl)
        2: begin
            GAMMA1 = GAMMA1_LVL2;
            GAMMA2 = GAMMA2_LVL2;
        end
        default: begin
            GAMMA1 = GAMMA1_LVL35;
            GAMMA2 = GAMMA2_LVL35;
        end
        endcase

        case(sec_lvl)
        2: begin
            BETA = BETA2;
        end
        3: begin
            BETA = BETA3;
        end
        default: begin
            BETA = BETA5;
        end
        endcase

        case(mode)
        G2_SUB_BETA: begin
            COND_UPPER = GAMMA2 - BETA;
            COND_LOWER = Q - (GAMMA2 - BETA);
        end
        G1_SUB_BETA: begin
            COND_UPPER = GAMMA1 - BETA;
            COND_LOWER = Q - (GAMMA1 - BETA);
        end
        default: begin 
            COND_UPPER = GAMMA2;
            COND_LOWER = Q - (GAMMA2);
        end
        endcase

        rej_lane = 0;
        for (i = 0; i < 4; i = i + 1) begin
            if (di[i*24+:24] >= COND_UPPER && di[i*24+:24] <= COND_LOWER)
                rej_lane[i] = validi;
        end

        rej = |rej_lane;

    end

endmodule

timescale 1ns / 1ps

module butterfly2x2(
    input             clk,
    input             rst,
    input [2:0]       mode,
    input             validi,
    input [24*4-1:0]  datai,
    input [24*4-1:0]  zetai,
    input [24*4-1:0]  acci,
    output reg [24*4-1:0] datao,
    output reg            valido
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg [23:0] z0, z1, z2, z3;
    reg [23:0] z2_sr [8:0];
    reg [23:0] z3_sr [8:0];


    reg  [23:0] a0, b0, c0, d0;
    wire [23:0] a1, b1, c1, d1;
    reg  [23:0] a2, b2, c2, d2;
    wire [23:0] a3, b3, c3, d3;

    wire valido_1_1, valido_1_2, valido_2_1, valido_2_2;
    reg validi_1_1, validi_1_2, validi_2_1, validi_2_2;

    always @(*) begin
        a0 = datai[24*0+:24];
        b0 = datai[24*1+:24];
        c0 = datai[24*2+:24];
        d0 = datai[24*3+:24];

        z0 = zetai[24*0+:24];
        z1 = zetai[24*1+:24];
        z2 = z2_sr[5];
        z3 = z3_sr[5];

        validi_1_1 = validi;
        validi_1_2 = validi;
        validi_2_1 = validi;
        validi_2_2 = validi;


        datao[24*0+:24] = a3;
        datao[24*1+:24] = b3;
        datao[24*2+:24] = c3;
        datao[24*3+:24] = d3;

        case(mode)
        MULT_MODE, ADD_MODE, SUB_MODE: begin
            datao[24*0+:24] = b3;
            datao[24*1+:24] = b1;
            datao[24*2+:24] = d3;
            datao[24*3+:24] = d1;

            z0 = zetai[24*0+:24];
            z1 = zetai[24*1+:24];
            z2 = zetai[24*2+:24];
            z3 = zetai[24*3+:24];
        end
        FORWARD_NTT_MODE: begin
            datao[24*0+:24] = a3;
            datao[24*1+:24] = b3;
            datao[24*2+:24] = c3;
            datao[24*3+:24] = d3;
            validi_1_1 = validi;
            validi_1_2 = validi;
            validi_2_1 = valido_1_1;
            validi_2_2 = valido_1_2;

            z0 = zetai[24*0+:24];
            z1 = zetai[24*1+:24];
            z2 = z2_sr[7];
            z3 = z3_sr[7];
        end
        INVERSE_NTT_MODE: begin
            datao[24*0+:24] = a3;
            datao[24*1+:24] = b3;
            datao[24*2+:24] = c3;
            datao[24*3+:24] = d3;
            validi_1_1 = validi;
            validi_1_2 = validi;
            validi_2_1 = valido_1_1;
            validi_2_2 = valido_1_2;

            z0 = zetai[24*0+:24];
            z1 = zetai[24*1+:24];
            z2 = z2_sr[8];
            z3 = z3_sr[8];
        end
        endcase

        a2 = a1;
        c2 = b1;

        case(mode)
        MULT_MODE, ADD_MODE, SUB_MODE: begin
            a2 = acci[0*24+:24];
            a0 = acci[1*24+:24];
            c2 = acci[2*24+:24];
            c0 = acci[3*24+:24];

            b2 = datai[24*0+:24];
            d2 = datai[24*2+:24];
        end
        default: begin
            b2 = c1;
            d2 = d1;
        end
        endcase

        valido = valido_2_1 & valido_2_2;

    end


    butterfly BF1_1(
        clk, rst, mode, validi_1_1,
        a0, b0, z0, a1, b1,
        valido_1_1
        );

    butterfly BF1_2(
        clk, rst, mode, validi_1_2,
        c0, d0, z1, c1, d1,
        valido_1_2
        );

    butterfly BF2_1(
        clk, rst, mode, validi_2_1,
        a2, b2, z2, a3, b3,
        valido_2_1
        );

    butterfly BF2_2(
        clk, rst, mode, validi_2_2,
        c2, d2, z3, c3, d3,
        valido_2_2
        );

    integer i;
    initial begin
        for (i = 0; i < 8; i = i + 1) begin
            z2_sr[i] = 0;
            z3_sr[i] = 0;
        end
    end

    always @(posedge clk) begin

        if (rst) begin
            for (i = 0; i < 9; i = i + 1) begin
                z2_sr[i] <= 0;
                z3_sr[i] <= 0;
            end
        end else begin
            z2_sr[0] <= zetai[24*2+:24];
            z3_sr[0] <= zetai[24*3+:24];

            for (i = 1; i < 9; i = i + 1)
                z2_sr[i] <= z2_sr[i-1];
            for (i = 1; i < 9; i = i + 1)
                z3_sr[i] <= z3_sr[i-1];

        end
    end

endmodule

timescale 1ns / 1ps


module rejection_y #(
    parameter W            = 64,
    parameter SAMPLE_W     = 23,
    parameter BUS_W        = 4
    )(
        input  rst,
        input  clk,
        input [2:0] sec_lvl,
        input  valid_i,
        output reg ready_i,
        input  [W-1:0] rdi,
        output reg [SAMPLE_W*BUS_W-1:0] samples = 0,
        output reg valid_o = 0,
        input  ready_o
    );

    wire [4:0] RDI_SAMPLE_W;
    assign RDI_SAMPLE_W = (sec_lvl == 2) ? 18 : 20;


    localparam
        DILITHIUM_Q = 23'd8380417,
        GAMMA2_LIMIT  = 20'd131072,
        GAMMA3_5_LIMIT   = 20'd524288;    

    wire [19:0] GAMMA_LIMIT;
    assign GAMMA_LIMIT = (sec_lvl == 2) ? GAMMA2_LIMIT : GAMMA3_5_LIMIT;

    reg [79:0]  SIPO_IN, SIPO_IN_SHIFT;
    reg [137:0] SIPO_OUT;
    reg [3*SAMPLE_W-1:0] sipo_out_in;

    reg [19:0] rej_lane0, rej_lane1, rej_lane2;

    reg [22:0] sample0, sample1, sample2;
    reg rej_lane0_valid, rej_lane1_valid, rej_lane2_valid;
    reg [1:0] num_valid;

    reg [6:0] sipo_in_len, sipo_in_len_next;
    reg [7:0] sipo_out_len, sipo_out_len_next;

    reg [10:0] SHIFT_IN_AMT;


    always @(*) begin
        ready_i = (sipo_in_len < 3*RDI_SAMPLE_W) ? 1 : 0;
        valid_o = (sipo_out_len >= SAMPLE_W*BUS_W) ? 1 : 0; 

        if (sec_lvl == 2) begin
            rej_lane0 = {2'd0, SIPO_IN[17:0]};
            rej_lane1 = {2'd0, SIPO_IN[35:18]};
            rej_lane2 = {2'd0, SIPO_IN[53:36]};
        end else begin
            rej_lane0 = {SIPO_IN[19:0]};
            rej_lane1 = {SIPO_IN[39:20]};
            rej_lane2 = {SIPO_IN[59:40]};
        end

        if (sipo_in_len >= 3*RDI_SAMPLE_W) begin
            SHIFT_IN_AMT = 3*RDI_SAMPLE_W;
        end else if (sipo_in_len >= 2*RDI_SAMPLE_W) begin
            SHIFT_IN_AMT = 2*RDI_SAMPLE_W;
        end else if (sipo_in_len >= RDI_SAMPLE_W) begin
            SHIFT_IN_AMT = RDI_SAMPLE_W;
        end else begin
            SHIFT_IN_AMT = 0;
        end


        sample0 = (rej_lane0 > GAMMA_LIMIT) ? GAMMA_LIMIT + DILITHIUM_Q - rej_lane0 : GAMMA_LIMIT - rej_lane0;
        sample1 = (rej_lane1 > GAMMA_LIMIT) ? GAMMA_LIMIT + DILITHIUM_Q - rej_lane1 : GAMMA_LIMIT - rej_lane1;
        sample2 = (rej_lane2 > GAMMA_LIMIT) ? GAMMA_LIMIT + DILITHIUM_Q - rej_lane2 : GAMMA_LIMIT - rej_lane2;


        rej_lane0_valid = (sipo_in_len >= RDI_SAMPLE_W) ? 1 : 0;
        rej_lane1_valid = (sipo_in_len >= 2*RDI_SAMPLE_W) ? 1 : 0;
        rej_lane2_valid = (sipo_in_len >= 3*RDI_SAMPLE_W) ? 1 : 0;
        num_valid       = rej_lane0_valid + rej_lane1_valid + rej_lane2_valid;

        if (rej_lane0_valid == 0)
            sample0 = 0;
        if (rej_lane1_valid == 0)
            sample1 = 0;
        if (rej_lane2_valid == 0)
            sample2 = 0;

        sipo_in_len_next  = (ready_i && valid_i) ? sipo_in_len + W : sipo_in_len;
        sipo_out_len_next = (valid_o && ready_o) ? sipo_out_len - SAMPLE_W*BUS_W: sipo_out_len;      

        SIPO_IN_SHIFT = (SIPO_IN >> SHIFT_IN_AMT);

        sipo_out_in = {sample2, sample1, sample0}; 
        samples = SIPO_OUT[SAMPLE_W*BUS_W-1:0];
    end

    initial begin
        SIPO_IN  = 0;
        SIPO_OUT = 0;

        sipo_in_len  = 0;
        sipo_out_len = 0;
    end

    always @(posedge clk) begin

        sipo_in_len <= sipo_in_len_next - SHIFT_IN_AMT;
        if (valid_i) begin
            SIPO_IN <= SIPO_IN_SHIFT | (rdi << sipo_in_len - SHIFT_IN_AMT);
        end else begin
            SIPO_IN <= SIPO_IN_SHIFT;
        end

        if (num_valid == 1) begin
            sipo_out_len <= sipo_out_len_next + SAMPLE_W;
        end else if (num_valid == 2) begin
            sipo_out_len <= sipo_out_len_next + 2*SAMPLE_W;
        end else if (num_valid == 3) begin
            sipo_out_len <= sipo_out_len_next + 3*SAMPLE_W;
        end else begin
            sipo_out_len <= sipo_out_len_next;
        end

        if (valid_o) begin   
            if (num_valid != 0) begin
                SIPO_OUT <= (SIPO_OUT >> SAMPLE_W*BUS_W) | sipo_out_in << sipo_out_len_next;
            end else begin
                SIPO_OUT <= SIPO_OUT >> SAMPLE_W*BUS_W;
            end
        end else if (num_valid >0) begin
            SIPO_OUT <= SIPO_OUT | sipo_out_in << sipo_out_len;
        end

        if (rst) begin
            SIPO_IN  <= 0;
            SIPO_OUT <= 0;

            sipo_in_len  <= 0;
            sipo_out_len <= 0;         
        end   
    end

endmodule

timescale 1ns / 1ps



module ntt_fifo(
    input clk,
    input rst,
    input en,
    input [2:0] mode,
    input [95:0] data_in,
    input [95:0] new_value,
    output reg [95:0] data_out
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg [1:0] count = 0;
    reg piso_ena, piso_enb, piso_enc, piso_end;
    wire [23:0] fifo_a, fifo_b, fifo_c, fifo_d;
    wire [95:0] fifo_outa, fifo_outb, fifo_outc, fifo_outd;

    ntt_fifo_piso #(.DEPTH(4))  PISO_A (
        clk, en, piso_ena, data_in, new_value[0*24+:24], fifo_outa, fifo_a
    );
    ntt_fifo_piso #(.DEPTH(6))  PISO_B (
        clk, en, piso_enb, data_in, new_value[1*24+:24], fifo_outb, fifo_b
    );
    ntt_fifo_piso #(.DEPTH(5))  PISO_C (
        clk, en, piso_enc, data_in, new_value[2*24+:24], fifo_outc, fifo_c
    );
    ntt_fifo_piso #(.DEPTH(7))  PISO_D (
        clk, en, piso_end, data_in, new_value[3*24+:24], fifo_outd, fifo_d
    );

    always @(*) begin
        piso_ena = 0;
        piso_enb = 0;
        piso_enc = 0;
        piso_end = 0;
        data_out = 0;

        if (en) begin
            case(mode)
            FORWARD_NTT_MODE: begin

                case(count)
                0: begin
                    piso_end = 1;
                end
                1: begin
                    piso_enb = 1;
                end
                2: begin
                    piso_enc = 1;
                end
                3: begin
                    piso_ena = 1;
                end
                endcase
                data_out = {fifo_a, fifo_b, fifo_c, fifo_d};
            end
            INVERSE_NTT_MODE: begin
                case(count)
                0: begin
                    data_out = fifo_outa;
                end
                2: begin
                    data_out = fifo_outb;
                end
                1: begin
                    data_out = fifo_outc;
                end
                3: begin
                    data_out = fifo_outd;
                end
                endcase
            end
            endcase
        end
    end

    always @(posedge clk) begin
        if (rst)
            count <= 0;
        else if (en)
            count <= count + 1;

    end


endmodule

timescale 1ns / 1ps
module dual_port_rom #(parameter WIDTH=96, LENGTH=1024, INIT_FILE="") (clk,en,addra,addrb,doa,dob);
    input clk,en;
    input [$clog2(LENGTH)-1:0] addra,addrb;
    output [WIDTH-1:0] doa,dob;
    (* rom_style = "distributed" *) reg[WIDTH-1:0] ram [LENGTH-1:0];
    reg[WIDTH-1:0] doa,dob;

    always @(posedge clk) begin 
        if (en) begin
            doa <= ram[addra];
            dob <= ram[addrb];
        end
    end


    integer i;
    initial begin
        if (INIT_FILE != "") begin
            $readmemh(INIT_FILE, ram);
        end else begin
            for (i = 0; i < LENGTH; i = i + 1)
                ram[i] = 0;
        end
    end

endmodule

timescale 1ns / 1ps

module gen_c # (
    parameter SAMPLER_W   = 4,
    parameter SAMPLE_W    = 23,
    parameter W           = 64
    ) (
    input  start,
    input  rst,
    input  clk,
    input  [2:0] sec_lvl,
    input  mode,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output reg [SAMPLER_W*SAMPLE_W-1:0] samples = 0,
    output reg valid_o,
    input      ready_o,
    input          ch_read,
    output reg [W-1:0] ch,
    output reg done_sampler = 0,

    output reg  rst_k,
    output reg  [63:0] din,
    input [63:0] dout,
    output reg         src_ready,
    input        src_read,
    input        dst_write,
    output reg         dst_ready
    );

    localparam
        S_HOLD          = 4'd0,
        S_STORE_MU      = 4'd1,
        S_STORE_CHAT    = 4'd11,
        S_INIT          = 4'd2,
        S_ABSORB_MU     = 4'd3,
        S_ABSORB_W1     = 4'd4,
        S_HASH_CHAT     = 4'd5,
        S_INIT2         = 4'd6,
        S_ABSORB_CHAT   = 4'd7,
        S_STORE_SIGN    = 4'd8,
        S_SAMPLEC       = 4'd9,
        S_UNLOAD_C      = 4'd10,
        S_STALL         = 4'd12;


    localparam NEG_ONE = 23'd8380416;  

    reg  [31:0] ctrl_len;

    reg [3:0]  cstate, nstate;
    reg [31:0] ctr, ctr_next;
    reg [8:0]  sample_no;

    reg [63:0] dout_buffer;
    reg [511:0] MU_SIPO;
    reg [255:0] C_SIPO;
    reg [63:0] SIGN;
    reg [1:0] C_POLY [255:0];

    integer i;
    initial begin
        cstate = S_HOLD;
        nstate = S_HOLD;
        ctr    = 0;

        MU_SIPO   = 0;
        C_SIPO    = 0;
        sample_no = 0;

        for (i = 0; i < 256; i = i + 1) begin
            C_POLY[i] = 0;
        end
    end
    reg [7:0] sample_addr;
    reg [10:0] W1_LEN;
    reg [7:0]  TAU;

    always @(*) begin
        ch = C_SIPO[255:256-64];

        case(sec_lvl)
        2: begin
             W1_LEN = 4*192/8;
             TAU = 39;
        end
        3: begin
            W1_LEN = 6*256/8/2; 
            TAU = 49;
        end
        5: begin
             W1_LEN = 8*256/8/2; 
             TAU = 60;
        end
        default: begin
            W1_LEN = 0;
            TAU    = 0;
        end
        endcase
    end

    always @(*) begin
        nstate  = cstate;
        ready_i = 0;
        valid_o = 0;
        rst_k   = 0;

        din       = 0;
        src_ready = 1;
        dst_ready = 1;
        ctrl_len  = W1_LEN*64 + 512;
        ctr_next  = ctr;
        done_sampler = 0;
        samples      = 0;

        sample_addr = 0;

        case(cstate)
        S_HOLD: begin
            nstate = (start && !mode) ? S_STORE_MU : 
                     (start &&  mode) ? S_STORE_CHAT :   S_HOLD;
            rst_k  = 1;
        end
        S_STORE_MU: begin
            ready_i = (valid_i) ? 1 : 0;
            ctr_next = ctr + 1;
            if (ctr == 7 && valid_i) begin
                nstate = S_INIT;
            end        
        end
        S_STORE_CHAT: begin
            ready_i  = valid_i;
            ctr_next = (valid_i && ready_i) ? ctr + 1 : ctr;
            if (ctr == 3 && valid_i) begin
                nstate = S_INIT2;
            end  
        end
        S_INIT: begin

            src_ready = 0;
            din = {32'hE0000100, ctrl_len}; 
            nstate = (src_read) ? S_ABSORB_MU : S_INIT;
        end
        S_ABSORB_MU: begin
            din = MU_SIPO[511:512-64];
            src_ready = 0;
            ctr_next = (src_read) ? ctr + 1 : ctr;
            if (ctr == 7 && src_read) begin
                nstate = S_ABSORB_W1;
            end
        end
        S_ABSORB_W1: begin
            din       = seed_i;
            src_ready = ~valid_i;
            ready_i   = src_read;

            ctr_next = (src_read) ? ctr + 1 : ctr;
            nstate = (ctr == W1_LEN-1 && src_read) ? S_HASH_CHAT : S_ABSORB_W1;
        end
        S_HASH_CHAT: begin
            ctr_next = (dst_write) ? ctr + 1 : ctr;
            dst_ready = 0;

            nstate = (ctr == 3 && dst_write) ? S_INIT2 : S_HASH_CHAT;
            rst_k  = (ctr == 3 && dst_write) ? 1 : 0;
        end
        S_INIT2: begin

            src_ready = 0;
            din = {32'hE0008000, 32'd256}; 
            nstate = (src_read) ? S_ABSORB_CHAT : S_INIT2;
        end
        S_ABSORB_CHAT: begin
            din = C_SIPO[255:256-64];
            src_ready = 0;
            ctr_next = (src_read) ? ctr + 1 : ctr;
            if (ctr == 3 && src_read) begin
                nstate = S_STORE_SIGN;
            end
        end
        S_STORE_SIGN: begin
            ctr_next = (dst_write) ? ctr + 1 : ctr;
            dst_ready = 0;

            nstate = (ctr == 0 && dst_write) ? S_STALL : S_STORE_SIGN;
        end
        S_STALL: begin
            nstate = S_SAMPLEC;
        end
        S_SAMPLEC: begin
            sample_addr = dout_buffer[{4'd7-ctr[2:0],3'd0}+:8];

            ctr_next = ctr + 1;
            nstate = (sample_no == 256) ? S_UNLOAD_C : S_SAMPLEC;
            rst_k  = (sample_no == 256) ? 1 : 0;
            dst_ready = (ctr[2:0] == 6) ? 0 : 1;
        end
        S_UNLOAD_C: begin
            valid_o      = (ctr < 64) ? 1 : 0;
            done_sampler = (ctr == 64) ? 1 : 0;

            ctr_next = (ready_o && valid_o) ? ctr + 1 : ctr;


            case(C_POLY[{ctr,2'd0}])
            1: samples[0*SAMPLE_W+:SAMPLE_W] = 1;
            2: samples[0*SAMPLE_W+:SAMPLE_W] = NEG_ONE;
            default: samples[0*SAMPLE_W+:SAMPLE_W] = 0;
            endcase 

            case(C_POLY[{ctr,2'd1}])
            1: samples[1*SAMPLE_W+:SAMPLE_W] = 1;
            2: samples[1*SAMPLE_W+:SAMPLE_W] = NEG_ONE;
            default: samples[1*SAMPLE_W+:SAMPLE_W] = 0;
            endcase 

            case(C_POLY[{ctr,2'd2}])
            1: samples[2*SAMPLE_W+:SAMPLE_W] = 1;
            2: samples[2*SAMPLE_W+:SAMPLE_W] = NEG_ONE;
            default: samples[2*SAMPLE_W+:SAMPLE_W] = 0;
            endcase 

            case(C_POLY[{ctr,2'd3}])
            1: samples[3*SAMPLE_W+:SAMPLE_W] = 1;
            2: samples[3*SAMPLE_W+:SAMPLE_W] = NEG_ONE;
            default: samples[3*SAMPLE_W+:SAMPLE_W] = 0;
            endcase 

            nstate = (ctr == 64) ? S_INIT : S_UNLOAD_C;
        end
        default: begin
            nstate = S_HOLD;
        end
        endcase

    end

    always @(posedge clk) begin
        if (rst) begin
            cstate <= S_HOLD;
        end else begin
            cstate <= nstate;
        end

        dout_buffer <= dout;

        if (ch_read) begin
             C_SIPO   <= {C_SIPO[255-64:0], C_SIPO[255:256-64]};
        end

        case(cstate)
        S_HOLD: begin
            ctr   <= 0;
        end 
        S_STORE_MU: begin
            if (valid_i & ready_i) begin
                ctr     <= ctr_next;
                MU_SIPO <= {MU_SIPO[511-64:0], seed_i};
            end
        end
        S_STORE_CHAT: begin
            ctr <= (ctr == 3 && valid_i & ready_i) ? 0 : ctr_next;
            if (valid_i & ready_i) begin
                C_SIPO <= {C_SIPO[255-64:0], seed_i};
            end
        end
        S_INIT: begin
            ctr <= 0;
        end
        S_ABSORB_MU: begin
            ctr <= (ctr == 7 && src_read) ? 0 : ctr_next;
            if (src_read) begin
                 MU_SIPO   <= {MU_SIPO[511-64:0], MU_SIPO[511:512-64]};
            end
        end
        S_ABSORB_W1: begin            
            ctr <= (ctr == W1_LEN-1 && src_read) ? 0 : ctr_next;
        end
        S_HASH_CHAT: begin
            ctr   <= (ctr == 3 && dst_write) ? 0 : ctr_next;

            if (dst_write) begin
                C_SIPO   <= {C_SIPO[255-64:0], dout};
            end
        end
        S_ABSORB_CHAT: begin
            ctr <= (ctr == 3 && src_read) ? 0 : ctr_next;
            if (src_read) begin
                 C_SIPO   <= {C_SIPO[255-64:0], C_SIPO[255:256-64]};
            end
        end
        S_STORE_SIGN: begin
            sample_no <= 256 - TAU;

            for (i = 0; i < 256; i = i + 1) begin
                C_POLY[i] <= 0;
            end

            ctr <= (dst_write) ? 0 : ctr_next;
            if (dst_write) begin
                SIGN   <= {dout[0*8+:8], dout[1*8+:8], dout[2*8+:8], dout[3*8+:8], dout[4*8+:8],
                                    dout[5*8+:8], dout[6*8+:8], dout[7*8+:8]};
            end
        end
        S_SAMPLEC: begin
            if (sample_no <= 255) begin
                ctr <= ctr_next;
                if (sample_addr <= sample_no) begin

                    sample_no <= sample_no + 1;
                    C_POLY[sample_no]   <= C_POLY[sample_addr];
                    C_POLY[sample_addr] <= (SIGN[0]) ? 2 : 1; 
                    SIGN                <= (SIGN >> 1);
                end
            end else begin
                ctr <= 0;
            end
        end
        S_UNLOAD_C: begin
            ctr <= ctr_next;
        end
        endcase 
    end
endmodule

timescale 1ns / 1ps


module rejection_a #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter RDI_SAMPLE_W = 24,
    parameter BUS_W    = 4
    )(
        input  rst,
        input  clk,
        input  valid_i,
        output reg ready_i,
        input  [W-1:0] rdi,
        output reg [SAMPLE_W*BUS_W-1:0] samples = 0,
        output reg valid_o = 0,
        input  ready_o
    );

    localparam
        DILITHIUM_Q = 23'd8380417;    

    reg [2*W-1:0] rdi_shift;
    reg [9:0] rdi_shift_amt;

    reg [79:0]  SIPO_IN;
    reg [137:0] SIPO_OUT;
    reg [3*SAMPLE_W-1:0] sipo_out_in;
    reg [6*SAMPLE_W-1:0] sipo_out_in_shft;
    reg [9:0] sipo_out_in_shft_amt;

    reg [22:0] rej_lane0, rej_lane1, rej_lane2;
    reg rej_lane0_valid, rej_lane1_valid, rej_lane2_valid;
    reg [1:0] num_valid;

    reg [6:0] sipo_in_len, sipo_in_len_next;
    reg [7:0] sipo_out_len, sipo_out_len_next;

    always @(*) begin
        ready_i = (sipo_in_len < 3*RDI_SAMPLE_W) ? 1 : 0;
        valid_o = (sipo_out_len >= SAMPLE_W*BUS_W) ? 1 : 0; 

        rej_lane0 = SIPO_IN[22:0];
        rej_lane1 = SIPO_IN[46:24];
        rej_lane2 = SIPO_IN[70:48];

        rej_lane0_valid = (rej_lane0 < DILITHIUM_Q && sipo_in_len >= RDI_SAMPLE_W) ? 1 : 0;
        rej_lane1_valid = (rej_lane1 < DILITHIUM_Q && sipo_in_len >= 2*RDI_SAMPLE_W) ? 1 : 0;
        rej_lane2_valid = (rej_lane2 < DILITHIUM_Q && sipo_in_len >= 3*RDI_SAMPLE_W) ? 1 : 0;
        num_valid       = rej_lane0_valid + rej_lane1_valid + rej_lane2_valid;

        if (rej_lane0_valid == 0)
            rej_lane0 = 0;
        if (rej_lane1_valid == 0)
            rej_lane1 = 0;
        if (rej_lane2_valid == 0)
            rej_lane2 = 0;

        sipo_in_len_next  = (ready_i && valid_i) ? sipo_in_len + W : sipo_in_len;
        sipo_out_len_next = (valid_o && ready_o) ? sipo_out_len - SAMPLE_W*BUS_W: sipo_out_len;      

        casex({rej_lane2_valid, rej_lane1_valid, rej_lane0_valid})
        3'bx11:  sipo_out_in = {rej_lane2, rej_lane1, rej_lane0}; 
        3'bx01:  sipo_out_in = {23'd0,     rej_lane2, rej_lane0}; 
        3'bx10:  sipo_out_in = {23'd0,     rej_lane2, rej_lane1};  
        3'b100:  sipo_out_in = {23'd0,     23'd0,     rej_lane0};  
        default: sipo_out_in = {23'd0,     23'd0,     23'd0    }; 
        endcase

        if (sipo_in_len >= 3*RDI_SAMPLE_W) begin
            rdi_shift_amt =  3*RDI_SAMPLE_W;
        end else if (sipo_in_len >= 2*RDI_SAMPLE_W) begin
            rdi_shift_amt =  2*RDI_SAMPLE_W;
        end else begin
            rdi_shift_amt = 0;
        end

        rdi_shift = (rdi << sipo_in_len - rdi_shift_amt);


        if (valid_o) begin   
            sipo_out_in_shft_amt = sipo_out_len_next;
        end else begin
            sipo_out_in_shft_amt = sipo_out_len;
        end
        sipo_out_in_shft = (sipo_out_in << sipo_out_in_shft_amt);

        samples = SIPO_OUT[SAMPLE_W*BUS_W-1:0];
    end

    initial begin
        SIPO_IN  = 0;
        SIPO_OUT = 0;

        sipo_in_len  = 0;
        sipo_out_len = 0;
    end

    always @(posedge clk) begin
        if (rst) begin
            sipo_in_len  <= 0;
            sipo_out_len <= 0;  

            SIPO_IN  <= 0;
            SIPO_OUT <= 0;      
        end else begin
            sipo_in_len <= sipo_in_len_next - rdi_shift_amt;
            if (sipo_in_len >= 3*RDI_SAMPLE_W) begin
                if (valid_i) begin
                    SIPO_IN <= (SIPO_IN >> 3*RDI_SAMPLE_W) | rdi_shift;
                end else begin
                    SIPO_IN <= (SIPO_IN >> 3*RDI_SAMPLE_W);
                end

            end else if (sipo_in_len >= 2*RDI_SAMPLE_W) begin
                if (valid_i) begin
                    SIPO_IN <= (SIPO_IN >> 2*RDI_SAMPLE_W) | rdi_shift;
                end else begin
                    SIPO_IN <= (SIPO_IN >> 2*RDI_SAMPLE_W);
                end
            end else begin
                if (valid_i) begin
                    SIPO_IN <= SIPO_IN | rdi_shift;
                end else begin
                    SIPO_IN <= SIPO_IN;
                end
            end

            if (num_valid == 1) begin
                sipo_out_len <= sipo_out_len_next + SAMPLE_W;
            end else if (num_valid == 2) begin
                sipo_out_len <= sipo_out_len_next + 2*SAMPLE_W;
            end else if (num_valid == 3) begin
                sipo_out_len <= sipo_out_len_next + 3*SAMPLE_W;
            end else begin
                sipo_out_len <= sipo_out_len_next;
            end

            if (valid_o) begin   
                if (num_valid != 0) begin
                    SIPO_OUT <= (SIPO_OUT >> SAMPLE_W*BUS_W) | sipo_out_in_shft;
                end else begin
                    SIPO_OUT <= SIPO_OUT >> SAMPLE_W*BUS_W;
                end
            end else if (num_valid >0) begin
                SIPO_OUT <= SIPO_OUT | sipo_out_in_shft;
            end
        end    
    end
endmodule

timescale 1ns / 1ps

module uncenter_coeff(
    input [2:0] sec_lvl,
    input [2:0] mode,
    input [22:0] di,
    output reg [22:0] dout
    );

    localparam
        Q = 23'd8380417;

    localparam
        M_NONE   = 3'd0,
        M_ETA    = 3'd1,
        M_T0     = 3'd2,
        M_T1     = 3'd3,
        M_GAMMA1 = 3'd4;

    reg signed [23:0] t0, t1;

    reg [3:0] ETA;
    reg [12:0] T;
    reg [19:0] GAMMA1;
    always @(*) begin
        ETA    = (sec_lvl == 3) ? 4 : 2;
        T      = (1 << 13-1);
        GAMMA1 = (sec_lvl == 2) ? (1 << 17) : (1 << 19);

        t1 = (di + T - 1) >> 13;
        t0 = di - (t1 << 13);

        (*full_case*)
        case({mode})
        M_NONE:   dout = di;
        M_ETA:    dout = (di > ETA)    ? ETA + Q - di    : ETA - di;
        M_T0:     dout = T - t0;
        M_T1:     dout = t1;
        M_GAMMA1: dout = (di > GAMMA1) ? GAMMA1 + Q - di : GAMMA1 - di;
        endcase
    end

endmodule

module DecoupledStage(
  input         clock,
  input         reset,
  output        io_in_ready,
  input         io_in_valid,
  input  [23:0] io_in_bits_ul,
  input  [23:0] io_in_bits_quo,
  input         io_out_ready,
  output        io_out_valid,
  output [23:0] io_out_bits_ul,
  output [23:0] io_out_bits_quo
);
  reg  valid;  
  reg [23:0] reg_ul;  
  reg [23:0] reg_quo;  
  wire  _T = io_in_ready & io_in_valid;  
  wire  _GEN_0 = io_out_ready ? 1'h0 : valid;  
  wire  _GEN_3 = _T | _GEN_0;  
  assign io_in_ready = ~valid | io_out_ready;  
  assign io_out_valid = valid;  
  assign io_out_bits_ul = reg_ul;  
  assign io_out_bits_quo = reg_quo;  
  always @(posedge clock) begin
    if (reset) begin  
      valid <= 1'h0;  
    end else begin
      valid <= _GEN_3;
    end
    if (_T) begin  
      reg_ul <= io_in_bits_ul;  
    end
    if (_T) begin  
      reg_quo <= io_in_bits_quo;  
    end
  end
initial begin
end  
endmodule
