module twiddle_resolver(
    input clk,
    input rst,
    input [2:0] mode,
    input en,
    input [5:0] k,
    input [3:0] s,
    output reg [7:0] twiddle_addr1 = 0,
    output reg [7:0] twiddle_addr2 = 0,
    output reg [7:0] twiddle_addr3 = 0,
    output reg [7:0] twiddle_addr4 = 0
    );

    localparam 
        DILITHIUM_N = 256;

    reg [7:0] tw_base_i [3:0];

    reg t_last;
    reg [7:0] l1, l2, l3, l4;
    reg [7:0] l1_base, l2_base, l3_base, l4_base;

    wire [7:0] l1_addmask, l2_addmask, l3_addmask, l4_addmask;
    assign l1_addmask = (l1 + 1) & ((2 << s) - 1); 
    assign l2_addmask = (l2 + 1) & ((2 << s) - 1); 

    assign l3_addmask = (l3 + 2) & (2 << (s + 1)) - 1; 
    assign l4_addmask = (l4 + 2) & (2 << (s + 1)) - 1; 

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    initial begin
        l1 = 0;
        l2 = 0;
        l3 = 0;
        l4 = 0;
        tw_base_i[0] = 0;
        tw_base_i[1] = 0;
        tw_base_i[2] = 0;
        tw_base_i[3] = 0;
        t_last = 0;
    end

    always @(*) begin    
        twiddle_addr1 = 0;
        twiddle_addr2 = 0;
        twiddle_addr3 = 0;
        twiddle_addr4 = 0;

        l1_base = 0;
        l2_base = 0;
        l3_base = 0;
        l4_base = 0;

        case(mode)
        INVERSE_NTT_MODE: begin
            if (k == 0) begin
                l1_base = (DILITHIUM_N >> s) - 1;
                l2_base = (DILITHIUM_N >> s) - 2;
                l3_base = (DILITHIUM_N >> (s + 1)) - 1;
                l4_base = l3_base;
            end else begin
                l1_base = l1 - 2;
                l2_base = l2 - 2;
                l3_base = l3 - 1;
                l4_base = l4 - 1;   
            end


            twiddle_addr1 = l1_base;
            twiddle_addr2 = l2_base;
            twiddle_addr3 = l3_base;
            twiddle_addr4 = l4_base;
        end
        FORWARD_NTT_MODE: begin
            if ((s < 6 && k == 0) || (s >= 6 && !t_last)) begin
                l1_base = 1 << s;
                l2_base = 1 << s;
                l3_base = (1 << (s + 1));
                l4_base = (1 << (s + 1)) + 1;
            end else begin
                if (s < 6) begin
                    l1_base = (tw_base_i[0] > l1_addmask) ? tw_base_i[0] : l1_addmask;
                    l2_base = (tw_base_i[1] > l2_addmask) ? tw_base_i[1] : l2_addmask;
                    l3_base = (tw_base_i[2] > l3_addmask) ? tw_base_i[2] : l3_addmask;
                    l4_base = (tw_base_i[3] > l4_addmask) ? tw_base_i[3] : l4_addmask;
                end else begin
                    l1_base = l1 + 1;
                    l2_base = l2 + 1;
                    l3_base = l3 + 2;
                    l4_base = l4 + 2;  
                end
            end

            twiddle_addr1 = l1_base;
            twiddle_addr2 = l2_base;
            twiddle_addr3 = l3_base;
            twiddle_addr4 = l4_base;
        end
        endcase
    end


    always @(posedge clk) begin
        if (rst) begin
            l1 <= l1_base;
            l2 <= l2_base;
            l3 <= l3_base;
            l4 <= l4_base;

            t_last <= 0;
            tw_base_i[0] <= 0;
            tw_base_i[1] <= 0;
            tw_base_i[2] <= 0;
            tw_base_i[3] <= 0;
        end else if (en) begin
            case(mode)
            INVERSE_NTT_MODE: begin
                l1 <= l1_base;
                l2 <= l2_base;
                l3 <= l3_base;
                l4 <= l4_base;

                if (k == 0) begin
                    tw_base_i[0] <= l1_base;
                    tw_base_i[1] <= l2_base;
                    tw_base_i[2] <= l3_base;
                    tw_base_i[3] <= l4_base;
                end

            end
            FORWARD_NTT_MODE: begin
                l1 <= l1_base;
                l2 <= l2_base;
                l3 <= l3_base;
                l4 <= l4_base;

                if ((s < 6 && k == 0) || (s >= 6 && !t_last)) begin
                    tw_base_i[0] <= l1_base;
                    tw_base_i[1] <= l2_base;
                    tw_base_i[2] <= l3_base;
                    tw_base_i[3] <= l4_base;

                    t_last <= (s >= 6) ?  1 : 0;
                end
            end
            endcase
        end
    end

endmodule

timescale 1ns / 1ps

module NTT_PIPO
# (parameter DEPTH = 5)
    (
    input clk,
    input en,
    input [95:0] datai,
    output [95:0] data0
    );

    reg [95:0] PIPO [DEPTH-1:0];

    assign data0 = PIPO[DEPTH-1];

    integer i;
    initial begin
        for (i = 0; i < DEPTH; i = i + 1)
            PIPO[i] = 0;
    end

    always @(posedge clk) begin
        if (en) begin
            PIPO[0] <= datai;
            for (i = 0; i < DEPTH-1; i = i + 1)
                PIPO[i+1] <= PIPO[i];
        end

    end



endmodule

timescale 1ns / 1ps


module decoder #(
    parameter OUTPUT_W    = 4,
    parameter COEFF_W     = 23,
    parameter W           = 64
    ) (
    input rst,
    input clk,
    input [2:0] sec_lvl,
    input [2:0] encode_modei,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] di,
    output reg [OUTPUT_W*COEFF_W-1:0] samples,
    output reg valid_o,
    input  ready_o
    );
    reg [W-1:0] di_buffer;
    localparam
        DILITHIUM_Q = 23'd8380417,
        ENCODE_T0   = 3'd0,
        ENCODE_T1   = 3'd1,
        ENCODE_S1   = 3'd2,
        ENCODE_S2   = 3'd3,
        ENCODE_W1   = 3'd4,
        ENCODE_Z    = 3'd5;

    localparam
        GAMMA1_2  = 23'd131072,
        GAMMA1_35 = 23'd524288;


    reg [2:0] encode_mode;
    reg [3*W-1:0]                SIPO_IN, SIPO_IN_SHIFT;
    reg [199:0] SIPO_OUT;
    reg [4*COEFF_W-1:0]          sipo_out_in, sipo_out_in_shift;

    reg [8:0] sipo_in_len, sipo_in_len_next;
    reg [7:0] sipo_out_len, sipo_out_len_next;
    reg [3:0] ETA;

    reg [2*W-1:0] di_shift;

    reg [5:0] ENCODE_LVL;
    integer i;

    initial begin
        SIPO_IN  = 0;
        SIPO_OUT = 0;

        sipo_in_len  = 0;
        sipo_out_len = 0;
    end

    always @(*) begin    
        ETA = 0;


        ENCODE_LVL = 0;
        for (i = 0; i < 4; i = i + 1)
            sipo_out_in[i*COEFF_W+:COEFF_W] = 0;

        casex({sec_lvl, encode_mode})
        {3'dX, ENCODE_T0}: begin
            ENCODE_LVL = 13;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] =  (SIPO_IN[i*13+:13] > 4096) ? DILITHIUM_Q - SIPO_IN[i*13+:13] + 4096 : 4096 - SIPO_IN[i*13+:13];

        end
        {3'dX, ENCODE_T1}: begin
            ENCODE_LVL = 10;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = {SIPO_IN[i*10+:10], 13'd0};
        end
        {3'd2, ENCODE_S2},
        {3'd5, ENCODE_S2},
        {3'd2, ENCODE_S1},
        {3'd5, ENCODE_S1}: begin
            ENCODE_LVL = 3;
            ETA = 2;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*3+:3] > ETA) ? DILITHIUM_Q - SIPO_IN[i*3+:3] + ETA : ETA - SIPO_IN[i*3+:3];
        end
        {3'd3, ENCODE_S2},
        {3'd3, ENCODE_S1}: begin
            ENCODE_LVL = 4;
            ETA        = 4;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*4+:4] > ETA) ? DILITHIUM_Q - SIPO_IN[i*4+:4] + ETA : ETA - SIPO_IN[i*4+:4];
        end   
        {3'd3, ENCODE_W1},
        {3'd5, ENCODE_W1}: begin
            ENCODE_LVL = 4;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = SIPO_IN[i*4+:4];
        end
        {3'd2, ENCODE_W1}: begin
            ENCODE_LVL = 6;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = SIPO_IN[i*6+:6];
        end
        {3'd2, ENCODE_Z}: begin
            ENCODE_LVL = 18;
            for (i = 0; i < 4; i = i + 1) begin
                if (sipo_in_len >= (i+1)*18)
                    sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*18+:18] > GAMMA1_2) ? GAMMA1_2 + (DILITHIUM_Q - SIPO_IN[i*18+:18]) : GAMMA1_2 - SIPO_IN[i*18+:18];
            end
        end
        {3'd3, ENCODE_Z},
        {3'd5, ENCODE_Z}: begin
            ENCODE_LVL = 20;
            for (i = 0; i < 4; i = i + 1) begin
                if (sipo_in_len >= (i+1)*20)
                    sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*20+:20] > GAMMA1_35) ? GAMMA1_35 + DILITHIUM_Q - SIPO_IN[i*20+:20] : GAMMA1_35 - SIPO_IN[i*20+:20];
            end
        end
        endcase


        valid_o = (sipo_out_len >= OUTPUT_W*COEFF_W) ? 1 : 0; 
        ready_i = (sipo_in_len < 4*ENCODE_LVL || (valid_o && 4*ENCODE_LVL > 63)) ? 1 : 0;

        sipo_in_len_next  = (ready_i && valid_i) ? sipo_in_len + W : sipo_in_len;
        sipo_out_len_next = (valid_o && ready_o) ? sipo_out_len - OUTPUT_W*COEFF_W: sipo_out_len;   

        samples = SIPO_OUT[OUTPUT_W*COEFF_W-1:0];

        SIPO_IN_SHIFT = (SIPO_IN >> 4*ENCODE_LVL);

        if (valid_o && ready_o) begin   
            sipo_out_in_shift = sipo_out_in << (sipo_out_len - OUTPUT_W*COEFF_W);  
        end else begin
            sipo_out_in_shift = sipo_out_in << sipo_out_len;
        end

        if (sipo_in_len >= 4*ENCODE_LVL) begin
            di_shift = ({64'd0, di} << (sipo_in_len - 4*ENCODE_LVL));
        end else begin
            di_shift = ({64'd0, di} << sipo_in_len);
        end
    end

    always @(posedge clk) begin
        encode_mode <= encode_modei;
        if (rst) begin
            SIPO_IN  <= 0;
            SIPO_OUT <= 0;
            sipo_in_len  <= 0;
            sipo_out_len <= 0;  
        end else begin
            if (sipo_out_len_next <= OUTPUT_W*COEFF_W) begin
                if (sipo_in_len >= 4*ENCODE_LVL) begin
                    sipo_in_len  <= sipo_in_len_next  - 4*ENCODE_LVL;
                    sipo_out_len <= sipo_out_len_next + 4*COEFF_W;

                    if (valid_i) begin
                        SIPO_IN <= SIPO_IN_SHIFT | di_shift;
                    end else begin
                        SIPO_IN <= SIPO_IN_SHIFT;
                    end
                end else begin
                    sipo_in_len  <= sipo_in_len_next;
                    sipo_out_len <= sipo_out_len_next;

                    if (valid_i) begin
                        SIPO_IN <= SIPO_IN | di_shift;
                    end else begin
                        SIPO_IN <= SIPO_IN;
                    end
                end
            end else begin
                sipo_in_len  <= sipo_in_len_next;
                sipo_out_len <= sipo_out_len_next;
            end

            if (valid_o && ready_o) begin   
                if (sipo_in_len >= ENCODE_LVL) begin
                    SIPO_OUT <= (SIPO_OUT >> OUTPUT_W*COEFF_W) | sipo_out_in_shift;  
                end else begin
                    SIPO_OUT <= SIPO_OUT >> OUTPUT_W*COEFF_W;
                end
            end else if (sipo_in_len >= ENCODE_LVL) begin
                SIPO_OUT <= SIPO_OUT | sipo_out_in_shift;
            end
        end 
    end

endmodule

timescale 1ns / 1ps


module sampler_y_ext #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter BUS_W    = 4
    )(
    input  start,
    input  rst,
    input  clk,
    input [2:0]  sec_lvl,
    input [15:0] nonce,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output [SAMPLE_W*BUS_W-1:0] samples,
    output reg valid_o,
    input  ready_o,
    output reg done,

    output reg  rst_k,
    output reg  [63:0] din,
    input [63:0] dout,   
    output reg   src_ready,
    input        src_read,
    input        dst_write,
    output       dst_ready
    );

    localparam 
        INIT             = 3'd0,
        LOAD_MODE        = 3'd1,
        WAITING_FOR_SEED = 3'd2,
        LOADING_SEED     = 3'd3,
        LOADING_NONCE    = 3'd4,
        SAMPLING         = 3'd5;
    reg [2:0] state, state_next;    

    reg [511:0] SEED_SIPO;
    reg [7:0]   SIPO_status;

    reg [7:0] sample_ctr;
    reg  rst_y;
    wire [63:0] din_rejy;

    assign din_rejy = {dout[7:0],dout[15:8], dout[23:16], dout[31:24], dout[39:32], dout[47:40],dout[55:48], dout[63:56]};
    wire valid_o_y;
    reg  ready_o_y;
    rejection_y REJ(
            rst_y, clk, sec_lvl, dst_write, dst_ready, din_rejy, samples, valid_o_y, ready_o_y
        );

    initial begin
        state      = INIT;
        rst_k      = 0;
        rst_y      = 0;
        SEED_SIPO  = 0;
        sample_ctr = 0;

    end    


    always @(*) begin
        state_next = state;
        ready_i    = 0;
        done       = 0;
        din        = 0;
        ready_o_y = 0;
        valid_o   = 0;

        case(state)
        INIT: begin
            state_next = (start) ? LOAD_MODE : INIT;
        end
        LOAD_MODE: begin
            din = 64'hE00f000000000210;        
            if (src_read) begin
                state_next = WAITING_FOR_SEED;
            end 
        end
        WAITING_FOR_SEED: begin
            ready_i = (valid_i) ? 1 : 0;
            if (SIPO_status[6] == 1 && valid_i) begin
                state_next = LOADING_SEED;
            end
        end
        LOADING_SEED: begin
            din = SEED_SIPO[511:448];
            if (SIPO_status == 1 && src_read) begin
                state_next = LOADING_NONCE;
            end
        end
        LOADING_NONCE: begin
            din = {nonce[7:0], nonce[15:8], 48'd0};
            if (src_read) begin
                state_next = SAMPLING;
            end
        end
        SAMPLING: begin
            ready_o_y = ready_o;
            valid_o   = valid_o_y;
            if (sample_ctr == 252 && ready_o && valid_o_y) begin
                state_next = INIT;
                done       = 1;
            end
        end
        endcase

    end    

    always @(posedge clk) begin
        if (rst) begin
            state <= INIT;
        end else begin
            state <= state_next;
        end
    end

    always @(posedge clk) begin
        src_ready  <= 1;
        rst_k      <= 0;
        rst_y      <= 0;

        case(state)
        INIT: begin
            SIPO_status <= 0;
            sample_ctr  <= 0;
            rst_k       <= 1;
            rst_y       <= 1;
        end
        LOAD_MODE: begin
            src_ready   <= 0;
        end
        WAITING_FOR_SEED: begin
            if (valid_i & ready_i) begin
                SIPO_status <= {SIPO_status[6:0],1'b1};
                SEED_SIPO   <= {SEED_SIPO[447:0], seed_i};
            end
        end
        LOADING_SEED: begin
            src_ready   <= 0;
            if (src_read) begin
                src_ready   <= 1;
                SIPO_status <= {1'b0, SIPO_status[7:1]};
                SEED_SIPO   <= {SEED_SIPO[447:0], 64'd0};
            end
        end
        LOADING_NONCE: begin
            src_ready   <= 0;
        end
        SAMPLING: begin
            if (valid_o) begin
                sample_ctr <= sample_ctr + 4;
            end
        end
        endcase
    end


endmodule

timescale 1ns / 1ps


module operation_module(
    input clk,
    input rst,
    input start,
    input [2:0] mode,
    input [1:0] encode_mode,
    output reg done = 0,

    output reg [5:0]  addra1 = 0,
    output reg [5:0]  addrb1 = 0,
    input      [95:0] doa1,
    input      [95:0] dob1,
    output reg        web1 = 0,
    output reg [95:0] dib1 = 0,

    output reg [5:0]  addra2 = 0,
    output reg [5:0]  addrb2 = 0,
    input      [95:0] doa2,
    output reg        web2 = 0,
    output reg [95:0] dib2 = 0
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg         validi_bf = 0;
    reg [95:0]  datai_bf = 0;
    reg [95:0]  zetai_bf = 0;
    reg [95:0]  acci_bf  = 0;
    wire [95:0] datao_bf;
    wire        valido_bf;

    reg done_latch = 0, pause = 0, done_delay;

    reg [3:0] pause_ctr;

    reg en_addr, rst_addr;
    wire [5:0] ram_addr;
    wire [5:0] ram_nat;
    wire [7:0] twiddle_addr [3:0];
    wire ntt_round_done, done_addr;
    address_unit ADDR(
        clk, rst_addr, mode, encode_mode, en_addr, ram_nat, ram_addr,
        twiddle_addr[0], twiddle_addr[1], 
        twiddle_addr[2], twiddle_addr[3],
        ntt_round_done, done_addr
    );

    reg en_twiddle;
    wire [23:0] do1_twiddle,do2_twiddle,do3_twiddle,do4_twiddle;

    dual_port_rom #(.WIDTH(24), .LENGTH(256), .INIT_FILE("D:/programming/0_GMU/DilithiumGMU/zetas.txt")) 
            TWIDDLE_RAM1 (clk, en_twiddle, twiddle_addr[0], twiddle_addr[1],do1_twiddle,do2_twiddle);
    dual_port_rom #(.WIDTH(24), .LENGTH(256), .INIT_FILE("D:/programming/0_GMU/DilithiumGMU/zetas.txt")) 
            TWIDDLE_RAM2 (clk, en_twiddle, twiddle_addr[2], twiddle_addr[3],do3_twiddle,do4_twiddle);

    butterfly2x2 BF_CIRCUIT(
        clk, rst, mode, validi_bf, datai_bf,
        zetai_bf, acci_bf, datao_bf, valido_bf
    );


    reg en_pipo;
    wire [95:0] out_pipo;
    NTT_PIPO DELAY_TWIDDLE (
        clk,  en_pipo,
        {do4_twiddle,do3_twiddle,do2_twiddle,do1_twiddle},
        out_pipo
    );

    reg en_fifo, rst_fifo;
    wire [95:0] data_in;
    wire [95:0] new_value;
    wire [95:0] data_out;
    assign new_value = (mode == INVERSE_NTT_MODE) ? datao_bf : 0;
    assign data_in   = (mode == FORWARD_NTT_MODE) ? doa1     : 0;
    ntt_fifo FIFO (
        clk, rst_fifo, en_fifo, mode, data_in, new_value, data_out
    );

    reg running, bram_delay, pause_delay,pause_delay1;

    reg [5:0] addr1_sr [23:0];
    reg [7:0] valid_sr = 0;

    integer i;

    initial begin
        running    = 0;
        bram_delay = 0;
        done_latch = 0;
        pause      = 0;

        for (i = 0; i < 23; i = i + 1)
            addr1_sr[i] = 0;
    end 

    always @(*) begin

        addra1 = 0;
        addrb1 = 0; web1 = 0; dib1 = 0;


        addra2 = 0;
        addrb2 = 0; web2 = 0; dib2 = 0;

        validi_bf = 0;
        datai_bf  = 0;
        zetai_bf  = 0;
        acci_bf   = 0;

        en_addr = 0;
        en_twiddle = 0;
        en_fifo = 0;
        en_pipo = 0;

        rst_addr = rst | start;
        rst_fifo = rst;

        case(mode)
        FORWARD_NTT_MODE: begin
            en_addr = running & ~done_latch & ~pause & ~ntt_round_done; 
            addra1  = ram_addr;

            datai_bf  = data_out;
            zetai_bf  = out_pipo;
            validi_bf = valid_sr[5];

            addrb1 = addr1_sr[21];
            web1   = valido_bf;
            dib1   = datao_bf;

            if (pause && valid_sr[5:0] == 0) begin
                rst_fifo = 1;
            end

            en_twiddle = 1;
            en_fifo = (valid_sr[5:0] != 0) ? 1 : 0; 
            en_pipo = (valid_sr[5:0] != 0) ? 1 : 0; 
        end
        INVERSE_NTT_MODE: begin
            en_addr = running & ~done_latch & ~pause;
            addra1  = ram_addr;

            datai_bf  = doa1;
            zetai_bf  = {do4_twiddle,do3_twiddle,do2_twiddle,do1_twiddle};
            validi_bf = bram_delay  & ~done & ~done_delay & ~pause_delay;

            addrb1 = addr1_sr[22];
            web1   = valid_sr[3];
            dib1   = data_out;

            en_twiddle = 1;
            en_fifo = valido_bf || (valid_sr[3:0] != 0); 
        end
        MULT_MODE: begin
            en_addr = running & ~done_latch;

            addra1  = ram_addr;
            addra2  = ram_nat;
            addrb1  = ram_addr;

            datai_bf  = doa1;
            zetai_bf  = {doa2[71:48],doa2[23:0],doa2[95:72],doa2[47:24]};
            acci_bf   = dob1;
            validi_bf = bram_delay  & ~done_latch & ~done;


            addrb2 = addr1_sr[8];
            web2   = valido_bf;
            dib2   = datao_bf;
        end
        ADD_MODE, SUB_MODE: begin
            en_addr = running & ~done_latch;
            addra1  = ram_addr;
            addra2  = ram_addr;

            datai_bf  = doa1;
            zetai_bf  = {doa2[71:48],doa2[23:0],doa2[95:72],doa2[47:24]};
            validi_bf = bram_delay  & ~done_latch & ~done;

            addrb2 = addr1_sr[4];
            web2   = valido_bf;
            dib2   = datao_bf;
        end
        endcase

    end

    always @(posedge clk) begin
        done <= 0;
        bram_delay <= running;
        pause_delay <= pause;
        pause_delay1 <= pause_delay;
        valid_sr   <= valid_sr;
        done_delay <= done_latch;

        if (rst) begin
            running    <= 0;
            done_latch <= 0;
            pause      <= 0;
            pause_ctr <= 0;

            valid_sr <= 0;
            for (i = 0; i < 23; i = i + 1)
                addr1_sr[i] <= 0;
        end else begin
            running <= running;

            if (running || (mode == FORWARD_NTT_MODE && valido_bf)) begin
                addr1_sr[0] <= ram_addr;
                for (i = 0; i < 23; i = i + 1)
                    addr1_sr[i+1] <= addr1_sr[i];
            end

            case(mode)
            FORWARD_NTT_MODE: begin
                done_latch <= (done_addr) ? 1 : done_latch;

                if (ntt_round_done) begin
                    pause <= 1;
                    pause_ctr <= 0;
                end else if (pause) begin
                    pause_ctr <= pause_ctr + 1;
                    pause <= (pause_ctr == 6) ? 0 : 1;
                end

                if (running && ~done_addr && ~done_latch && ~pause && ~ntt_round_done)
                    valid_sr <= {valid_sr[6:0], 1'b1};
                else 
                    valid_sr <= {valid_sr[6:0], 1'b0};

                if (done_addr) begin
                    running <= 0;
                end

                if (start) begin
                    running <= 1;
                end else if (done_latch && !valido_bf) begin
                    done       <= 1;
                    done_latch <= 0;
                end  
            end
            INVERSE_NTT_MODE: begin
                done_latch <= (done_addr) ? 1 : done_latch;
                if (ntt_round_done) begin
                    pause <= 1;
                    pause_ctr <= 0;
                end else if (pause) begin
                    pause_ctr <= pause_ctr + 1;
                    pause <= (pause_ctr == 4) ? 0 : 1;
                end

                if (running)
                    valid_sr <= {valid_sr[6:0], valido_bf};

                if (start)
                    running <= 1;


                else if (done_latch && valid_sr[3:0] == 0) begin
                    running    <= 0;
                    done       <= 1;
                    done_latch <= 0;
                end  
            end
            MULT_MODE, ADD_MODE, SUB_MODE: begin
                done_latch <= (done_addr) ? 1 : done_latch;

                if (running && ~done_addr && ~done_latch)
                    valid_sr <= {valid_sr[6:0], 1'b1};
                else 
                    valid_sr <= {valid_sr[6:0], 1'b0};

                if (start)
                    running <= 1;
                else if (done_latch && valid_sr[6:0] == 0) begin
                    running    <= 0;
                    done       <= 1;
                    done_latch <= 0;
                end  
            end
            endcase
        end

    end

endmodule

timescale 1ns / 1ps

module sampler_a_ext #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter BUS_W    = 4
    )(
    input  start,
    input  rst,
    input  clk,
    input  re_sample,
    input  [3:0] i,
    input  [3:0] j,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output [SAMPLE_W*BUS_W-1:0] samples,
    output reg valid_o,
    input  ready_o,
    output reg done,

    output reg  rst_k,
    output reg  [63:0] din,
    input [63:0] dout,   
    output reg   src_ready,
    input        src_read,
    input        dst_write,
    output       dst_ready
    );

    localparam 
        INIT             = 3'd0,
        LOAD_MODE        = 3'd1,
        WAITING_FOR_SEED = 3'd2,
        LOADING_SEED     = 3'd3,
        LOADING_NONCE    = 3'd4,
        SAMPLING         = 3'd5;
    reg [2:0] state, state_next;    

    reg [255:0] SEED_SIPO;
    reg [3:0]   SIPO_status;
    reg resample_reg;

    reg [7:0] sample_ctr; 
    reg rst_a;

    wire [63:0] din_reja;
    assign din_reja = {dout[7:0],dout[15:8], dout[23:16], dout[31:24], dout[39:32], dout[47:40],dout[55:48], dout[63:56]};
    reg ready_o_a;
    wire valid_o_a;
    rejection_a REJ(
            rst_a, clk, dst_write, dst_ready, din_reja, samples, valid_o_a, ready_o_a
        );

    initial begin
        state      = INIT;
        rst_k      = 0;
        rst_a      = 0;
        SEED_SIPO  = 0;
        sample_ctr = 0;

    end    


    always @(*) begin
        state_next = state;
        ready_i    = 0;
        done       = 0;
        din        = 0;
        rst_k      = 0;
        rst_a      = 0;

        ready_o_a = 0;
        valid_o = 0;

        case(state)
        INIT: begin
            rst_k      = (start || re_sample) ? 0 : 1;
            rst_a      = (start || re_sample) ? 0 : 1;
            state_next = (start || re_sample) ? LOAD_MODE : INIT;        
        end
        LOAD_MODE: begin
            din = 64'hC00f000000000110;        
            if (src_read) begin
                if (resample_reg) begin
                    state_next = LOADING_SEED;
                end else begin
                    state_next = WAITING_FOR_SEED;
                end
            end 
        end
        WAITING_FOR_SEED: begin
            ready_i = 1;
            if (SIPO_status[2] == 1 && valid_i) begin
                state_next = LOADING_SEED;
            end
        end
        LOADING_SEED: begin
            din = SEED_SIPO[255:192];
            if (SIPO_status == 1 && src_read) begin
                state_next = LOADING_NONCE;
            end
        end
        LOADING_NONCE: begin
            din = {4'd0, j, 4'd0, i, 48'd0};
            if (src_read) begin
                state_next = SAMPLING;
            end
        end
        SAMPLING: begin
            ready_o_a = ready_o;
            valid_o = valid_o_a;

            if (sample_ctr == 252 && ready_o && valid_o) begin
                state_next = INIT;
                rst_k      = 1;
                done       = 1;
            end
        end
        endcase

    end    

    always @(posedge clk) begin
        if (rst) begin
            state <= INIT;
        end else begin
            state <= state_next;
        end
    end

    always @(posedge clk) begin
        src_ready  <= 1;

        case(state)
        INIT: begin
            SIPO_status <= 0;
            sample_ctr  <= 0;
            resample_reg <= (re_sample) ? 1 : 0;
        end
        LOAD_MODE: begin
            src_ready   <= 0;
            if (src_read && resample_reg) begin
                SIPO_status  <= 4'b1111;
                resample_reg <= 0;
            end 
        end
        WAITING_FOR_SEED: begin
            if (valid_i & ready_i) begin
                SIPO_status <= {SIPO_status[2:0],1'b1};
                SEED_SIPO   <= {SEED_SIPO[191:0], seed_i};
            end
        end
        LOADING_SEED: begin
            src_ready   <= 0;
            if (src_read) begin
                src_ready   <= 1;
                SIPO_status <= {1'b0, SIPO_status[3:1]};
                SEED_SIPO   <= {SEED_SIPO[191:0], SEED_SIPO[255:256-64]};
            end
        end
        LOADING_NONCE: begin
            src_ready   <= 0;
        end
        SAMPLING: begin
            if (ready_o && valid_o) begin
                sample_ctr <= sample_ctr + 4;
            end
        end
        endcase
    end


endmodule

timescale 1ns / 1ps

module butterfly(
    input             clk,
    input             rst,
    input [2:0]       mode,
    input             validi,
    input signed[23:0]  aj,
    input signed [23:0] ajlen,
    input [23:0]      zeta,
    output reg [23:0] bj,
    output reg [23:0] bjlen,
    output reg        valido
    );

    localparam
        DILITHIUM_Q = 23'd8380417;

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;


    reg [23:0] aj1 = 0, ajlen1 = 0;
    reg [23:0] aj2 = 0, ajlen2_FNTT = 0;
    reg [23:0] ajlen2_INTT = 0;
    reg [23:0] ajlen2_MODM = 0;
    reg [23:0] aj3  [4:0];
    reg [45:0] mult_result;
    reg [23:0] ajlen3 = 0;
    reg [23:0] aj4 = 0, ajlen4 = 0, ajlen4_sub = 0;
    reg [23:0] aj5 = 0, ajlen5 = 0;


    reg [23:0] adda = 0, addb = 0, suba = 0, subb = 0;
    reg [23:0] adder = 0;
    reg [24:0] add_tmp = 0;
    reg [23:0] sub_tmp = 0;
    reg [23:0] subtractor = 0;

    reg [9:0] valid_sr;

    wire barrett_readyi;
    reg  barrett_validi;
    (*keep="true"*)reg  [45:0] barrett_datai;
    wire barrett_valido;
    reg  barrett_readyo;
    wire [22:0] barrett_remainder;
    wire [23:0] barrett_quotient;

    reg [23:0] multa, multb;
    reg [23:0] zeta_delay,zeta_delay2;

    Barrett REDUCER(
      clk,
      rst,
      barrett_readyi,
      barrett_validi,
      barrett_datai,
      barrett_readyo,
      barrett_valido,
      barrett_remainder,
      barrett_quotient
    );

    initial begin
        valid_sr = 0;
        aj3[0] = 0;
        aj3[1] = 0;
        aj3[2] = 0;
        aj3[3] = 0;
        aj3[4] = 0;
    end

    reg [2:0] modei;

    always @(*) begin
        adda   = 0;
        addb   = 0;
        suba   = 0;
        subb   = 0;
        valido = 0;

        barrett_readyo = 1;

        multa = ajlen2_FNTT;
        multb = (modei == INVERSE_NTT_MODE) ? zeta_delay2 : zeta_delay;

        if (mode == INVERSE_NTT_MODE) 
            valido = valid_sr[8];
        else if (mode == MULT_MODE)
            valido = valid_sr[7];
        else if (mode == FORWARD_NTT_MODE)
            valido = valid_sr[7];
        else
            valido = valid_sr[3];

        case(modei)
        FORWARD_NTT_MODE: begin
            adda = aj3[4];
            addb = ajlen3;

            suba = aj3[4];
            subb = ajlen3;

            multa = ajlen2_FNTT;
        end
        INVERSE_NTT_MODE: begin
            multa = ajlen2_INTT;

            adda = aj1;
            addb = ajlen1;

            suba = aj1;
            subb = ajlen1;
        end
        MULT_MODE: begin

            multa = ajlen2_MODM;

            adda = aj4;
            addb = ajlen3;
        end
        ADD_MODE: begin
            adda = ajlen1;
            addb = zeta_delay;

            suba = ajlen4;
            subb = DILITHIUM_Q;
        end
        SUB_MODE: begin
            adda = ajlen1;
            addb = DILITHIUM_Q;

            suba = aj4;
            subb = ajlen4_sub;
        end
        endcase

        barrett_validi = 1;

        adder       = adda + addb;
        mult_result = multb * ajlen2_INTT;
        sub_tmp     = suba + DILITHIUM_Q;
        subtractor  = (subb > suba) ? sub_tmp - subb : suba - subb;      
    end



    always @(posedge clk) begin
        if (rst) begin
            valid_sr <= 0;
        end else begin
            valid_sr <= {valid_sr[8:0], validi};
        end

        modei <= mode;

        zeta_delay <= (mode == INVERSE_NTT_MODE) ? DILITHIUM_Q - zeta :  zeta;
        zeta_delay2 <= zeta_delay;

        aj1    <= aj;
        ajlen1 <= ajlen;

        barrett_datai  <= mult_result;

        bj    <= (aj5 >= DILITHIUM_Q)    ? aj5    - DILITHIUM_Q : aj5;
        bjlen <= (ajlen5 >= DILITHIUM_Q) ? ajlen5 - DILITHIUM_Q : ajlen5;

        ajlen3 <= barrett_remainder;

        ajlen4 <= adder;
        ajlen4_sub <= zeta_delay;
        case(mode)
        FORWARD_NTT_MODE: begin
            aj2    <= aj;
            ajlen2_INTT <= ajlen;

            ajlen5 <= subtractor;
            aj5    <= adder;

        end
        INVERSE_NTT_MODE: begin
            aj2    <= adder;
            ajlen2_INTT <= subtractor;

            if (aj3[4][0] == 1)
                aj5 <= (aj3[4] >> 1) + (DILITHIUM_Q + 1) / 2;
            else
                aj5 <= (aj3[4] >> 1);

            if (ajlen3[0] == 1)
                ajlen5 <= (ajlen3 >> 1) + (DILITHIUM_Q + 1) / 2;
            else
                ajlen5 <= (ajlen3 >> 1);       
        end
        MULT_MODE: begin
            aj2    <= aj;
            aj4    <= aj3[3];

            ajlen2_INTT <= ajlen;
            ajlen5 <= adder;
        end
        ADD_MODE: begin
            ajlen5 <= (ajlen4 > DILITHIUM_Q) ? subtractor : ajlen4;
        end
        SUB_MODE: begin
            aj4    <= (ajlen1 < zeta_delay) ? adder : ajlen1;
            ajlen5 <= subtractor;
        end
        endcase


        aj3[0] <= aj2;
        aj3[1] <= aj3[0];
        aj3[2] <= aj3[1];
        aj3[3] <= aj3[2];
        aj3[4] <= aj3[3];
    end



endmodule

timescale 1ns / 1ps

module coeff_decomposer(
        input  rst,
        input  clk,
        input  valid_i,
        output ready_i,
        input      [2:0]  sec_lvl,
        input      [23:0] di,
        output reg [23:0] doa = 0,
        output reg [23:0] dob = 0,
        output reg        valid_o = 0,
        input ready_o
    );

    assign ready_i = ready_o;

    localparam
        N1        = 18'd190464,
        N2        = 19'd523776,
        Q_N1_DIFF = 23'd8189953,
        Q_N2_DIFF = 23'd7856641,
        K         = 6'd41,
        M1        = 24'd11545611,
        M2        = 23'd4198404,
        Q         = 23'd8380417;

    reg [4:0] valid_sr = 0;

    always @(*) begin
        valid_o = valid_sr[4];
    end


    reg [23:0] di_buffer;
    reg signed [55:0] a1_0, a1_1, a1_2, a0_0, a0_1, a0_2;

    wire [23:0] sub_val;
    assign sub_val = ((((Q-1)/2 - a0_1) >> 31) & Q);


    wire [5:0] map1_out;
    decomp_map1 MAP1 (
        sec_lvl, di_buffer[22:0], map1_out);

    always @(posedge clk) begin
        if (ready_o) begin
            valid_sr <= (rst) ? 0 : {valid_sr[3:0], valid_i};
            di_buffer <= di;

            a1_0 <= map1_out;
            a1_1 <= a1_0;
            a1_2 <= a1_1;
            dob  <= a1_2;

            a0_0 <= di_buffer;
            a0_2 <= a0_1 - sub_val;
            doa  <= (a0_2 < 0) ? a0_2 + Q : a0_2;

            if (sec_lvl == 2) begin
                a0_1 <= a0_0 - ((a1_0 << 17) + (a1_0 << 16) - (a1_0 << 12) - (a1_0 << 11));
            end else begin
                a0_1 <= a0_0 - ((a1_0 << 19) - (a1_0 << 9));
            end
        end    
    end

endmodule

timescale 1ns / 1ps


module encoder #(
    parameter OUTPUT_W    = 4,
    parameter COEFF_W     = 23,
    parameter MAX_LVL     = 20,
    parameter W           = 64
    ) (
    input rst,
    input clk,
    input [2:0] sec_lvl,
    input [2:0] encode_mode,
    input  valid_i,
    output reg ready_i,
    input [OUTPUT_W*COEFF_W-1:0] di,
    output reg [W-1:0] dout,
    output reg valid_o,
    input  ready_o
    );

    reg [4:0] ENCODE_LVL;
    reg [2:0] mode;

    localparam
        DILITHIUM_Q = 23'd8380417,
        ENCODE_T0   = 3'd0,
        ENCODE_T1   = 3'd1,
        ENCODE_S1   = 3'd2,
        ENCODE_S2   = 3'd3,
        ENCODE_W1   = 3'd4,
        ENCODE_Z    = 3'd5;

    localparam
        NONE   = 3'd0,
        ETA    = 3'd1,
        T0     = 3'd2,
        T1     = 3'd3,
        GAMMA1 = 3'd4;

    wire [OUTPUT_W*COEFF_W-1:0] di_uncentered;
    reg  [OUTPUT_W*COEFF_W-1:0] di_uncentered_buffer;
    wire [MAX_LVL*OUTPUT_W-1:0]  stripped;

    reg [OUTPUT_W*COEFF_W-1:0] di_buffer;

    reg [1:0] valid_buffer;

    genvar i;
    generate
        for (i = 0; i < OUTPUT_W; i = i + 1) begin
            uncenter_coeff UNCENTER (sec_lvl, mode, di_buffer[23*i+:23], di_uncentered[23*i+:23]);
        end
    endgenerate

    zero_strip Z_STRIP(ENCODE_LVL, di_uncentered_buffer, stripped);

    reg [255:0] PISO;
    reg [9:0]  piso_len, piso_len_next;
    reg [9:0] buffer_len [1:0];

    initial begin
        PISO = 0;
        piso_len = 0;        
    end

    always @(*) begin

        ENCODE_LVL = 0;
        mode = NONE;

        casex({sec_lvl, encode_mode})
        {3'dX, ENCODE_T0}: begin
            ENCODE_LVL = 13;
            mode = T0;
        end
        {3'dX, ENCODE_T1}: begin
            ENCODE_LVL = 10;
            mode = T1;
        end
        {3'd2, ENCODE_S2},
        {3'd5, ENCODE_S2},
        {3'd2, ENCODE_S1},
        {3'd5, ENCODE_S1}: begin
            ENCODE_LVL = 3;
            mode = ETA;
        end
        {3'd3, ENCODE_S2},
        {3'd3, ENCODE_S1}: begin
            ENCODE_LVL = 4;
            mode = ETA;
        end   
        {3'd3, ENCODE_W1},
        {3'd5, ENCODE_W1}: begin
            ENCODE_LVL = 4;
        end
        {3'd2, ENCODE_W1}: begin
            ENCODE_LVL = 6;
        end
        {3'd2, ENCODE_Z}: begin
            ENCODE_LVL = 18;
            mode = GAMMA1;
        end
        {3'd3, ENCODE_Z},
        {3'd5, ENCODE_Z}: begin
            ENCODE_LVL = 20;
            mode = GAMMA1;
        end
        endcase


        valid_o = (piso_len >= W) ? 1 : 0; 
        piso_len_next = (valid_o && ready_o) ? piso_len - W: piso_len;   
        ready_i = 1;

        dout = PISO[W-1:0];
    end

    always @(posedge clk) begin

        di_uncentered_buffer <= di_uncentered;

        valid_buffer[0] <= ready_i && valid_i;
        valid_buffer[1] <= valid_buffer[0];

        buffer_len[0] <= (ready_i && valid_i) ? 4*ENCODE_LVL : 0;
        buffer_len[1] <= buffer_len[0];
        piso_len <= piso_len_next + buffer_len[1];

        di_buffer <= di;
        if (rst) begin
            piso_len <= 0;
            PISO     <= 0;
        end else begin
            if (valid_buffer[1]) begin
                if (valid_o && ready_o) begin
                    PISO <= (PISO >> W) | ({192'd0, stripped} << piso_len_next);
                end else begin
                    PISO <= PISO | ({192'd0, stripped} << piso_len_next);    
                end
            end else if (valid_o && ready_o) begin
                PISO <= (PISO >> W);
            end
        end
    end

endmodule

timescale 1ns / 1ps

module decomposer_unit #(
    parameter OUTPUT_W    = 4,
    parameter COEFF_W     = 24
    ) (
    input rst,
    input clk,
    input [2:0] sec_lvl,
    input  valid_i,
    output ready_i,
    input  [OUTPUT_W*COEFF_W-1:0] di,
    output [OUTPUT_W*COEFF_W-1:0] doa,
    output [OUTPUT_W*COEFF_W-1:0] dob,
    output valid_o,
    input ready_o
    );

    wire [0:OUTPUT_W-1] valid_coeff_o;
    assign valid_o = &valid_coeff_o;
    wire [OUTPUT_W-1:0] ready_i_sub;
    assign ready_i = |ready_i_sub;


    genvar i;
    generate
        for (i = 0; i < OUTPUT_W; i = i + 1) begin
            coeff_decomposer COEFF_DECOMP(
                rst, clk, valid_i, ready_i_sub[i], sec_lvl, di[24*i+:24],
                doa[24*i+:24], dob[24*i+:24], valid_coeff_o[i], ready_o
            );
        end

    endgenerate

endmodule

timescale 1ns / 1ps

module gen_s# (
    parameter SAMPLER_NUM = 1,
    parameter SAMPLER_W   = 4,
    parameter SAMPLE_W    = 23,
    parameter W           = 64
    )(
    input  start,
    input  rst,
    input  clk,
    input  [2:0] sec_lvl,
    input  valid_seed,
    output ready_for_seed,
    input  [W-1:0] seed_i,
    output [SAMPLER_NUM*SAMPLER_W*SAMPLE_W-1:0] samples,
    output [SAMPLER_NUM-1:0] valid_o,
    input  [SAMPLER_NUM-1:0] ready_o,
    output reg done_sampler,

    input             keccak_ctrl,
    output            rst_k,
    output     [63:0] din,
    input      [63:0] dout,
    output            src_ready,
    input             src_read,
    input             dst_write,
    output            dst_ready
    );

    wire [SAMPLE_W*SAMPLER_W-1:0] sampler_output [SAMPLER_NUM-1:0];
    reg  [15:0] N [SAMPLER_NUM-1:0];
    wire [SAMPLER_NUM-1:0] ready_i, done;
    reg  [SAMPLER_NUM-1:0] valid_i, re_sample, done_latch;
    reg  [4:0] sample_state;
    reg start_s; 
    reg mode;
    genvar g;
    generate

        for (g = 0; g < SAMPLER_NUM; g = g + 1) begin
            assign sampler_output[g] = samples[g*(SAMPLER_W*SAMPLE_W)+:(SAMPLER_W*SAMPLE_W)];
        end


        for (g = 0; g < SAMPLER_NUM; g = g + 1) begin
            sampler_s SAMPLER_S (start_s, rst, clk, re_sample[g], sec_lvl, N[g], valid_seed, ready_i[g], seed_i, 
                                    samples[g*(SAMPLER_W*SAMPLE_W)+:(SAMPLER_W*SAMPLE_W)], valid_o[g], ready_o[g], done[g],
                                    keccak_ctrl, rst_k, din, dout, src_ready, src_read, dst_write, dst_ready);                
        end
    endgenerate

    integer i;
    assign ready_for_seed = &ready_i;
    reg [3:0] L, K;


    initial begin
        done_sampler   = 0;
        done_latch     = 0;
        sample_state   = 0;
        mode           = 0;

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            re_sample[i] = 0; 
    end

    always @(*) begin
        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            valid_i[i] = 0;

        case(sec_lvl)
        2: begin
             L = 4; 
             K = 4;
        end
        3: begin
            L = 5;
            K = 6;
        end
        5:  begin
            L = 7;
            K = 8;
        end
        default: begin
            L = 0;
            K = 0;
        end
        endcase    

        N[0] = (mode == 0) ?  sample_state : sample_state + L;

    end

    always @(posedge clk) begin
        done_latch     <= done_latch | done;
        done_sampler   <= 0;

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            re_sample[i] <= 0; 


        if (mode == 0) begin
            start_s <= start;
        end else if(start) begin
            for (i = 0; i < SAMPLER_NUM; i = i + 1)
                re_sample[i] <= 1; 
        end


        if (done_latch == {SAMPLER_NUM{1'b1}}) begin
            done_latch <= 0;
            if ((mode == 0 && sample_state == L-1) || (mode == 1 && sample_state == K-1)) begin
                done_sampler <= 1;
                sample_state <= 0;

                if (mode == 0) begin

                    mode <= 1;
                    for (i = 0; i < SAMPLER_NUM; i = i + 1)
                        re_sample[i] <= 1; 
                end else begin
                    mode <= 0;
                end 
            end else begin
                for (i = 0; i < SAMPLER_NUM; i = i + 1)
                    re_sample[i] <= 1;
                sample_state <= sample_state + 1;
            end
        end

    end    
endmodule

timescale 1ns / 1ps

module makehint #(
        parameter OUTPUT_W = 4,
        parameter COEFF_W  = 24,
        parameter W        = 64
    ) (
        input rst,
        input clk,
        input [2:0]   sec_lvl,
        output reg    reject_hint,
        input [OUTPUT_W*COEFF_W-1:0] poly0_ie,
        input [OUTPUT_W*COEFF_W-1:0] poly1_ie,
        input      poly_valid_ie,
        output reg poly_ready_i,
        output reg [W-1:0] hint_o,
        output reg hint_valid_o,
        input      hint_ready_o
    );

    reg [OUTPUT_W*COEFF_W-1:0] poly0_i;
    reg [OUTPUT_W*COEFF_W-1:0] poly1_i;
    reg      poly_valid_i;

    localparam
        LVL2_LEN = 7'd80,
        LVL3_LEN = 7'd55,
        LVL5_LEN = 7'd75;

    localparam
        S_MAKEHINT   = 0,
        S_UNLOADHINT = 1;

    localparam
        GAMMA2_2  = 18'd95232,
        GAMMA2_35 = 18'd261888,
        Q         = 23'd8380417;
    reg [17:0] GAMMA2;
    reg state;
    reg [6:0] omega;
    reg [2:0] poly_num;
    reg [7:0] hint_addr [79:0];
    reg [7:0] poly_hint_cnt [7:0];
    reg [7:0] num_hints;
    reg [7:0] ctr;
    reg rej;

    reg [3:0] hint_needed;
    reg [3:0] K;

    integer i, k;
    always @(*) begin
        poly_ready_i = 1;
        reject_hint  = 0;
        hint_o       = 0;
        hint_valid_o = 0;

        GAMMA2 = (sec_lvl == 2) ? GAMMA2_2 : GAMMA2_35;

        case(sec_lvl)
        2: begin
            K = 4;
            omega = LVL2_LEN;
        end
        3: begin
            K = 6;
            omega = LVL3_LEN;
        end
        default: begin
            K = 8;
            omega = LVL5_LEN;
        end
        endcase

        for (i = 0; i < 4; i = i + 1)
            hint_needed[i] = !(poly0_i[24*i+:24] <= GAMMA2 || poly0_i[24*i+:24] > Q-GAMMA2) || (poly0_i[24*i+:24] == Q-GAMMA2 && poly1_i[24*i+:24] != 0);

        if (rej) begin
            reject_hint = 1;
        end else begin
            case(state)
            S_MAKEHINT: begin
                poly_ready_i = 1;
            end
            S_UNLOADHINT: begin
                hint_valid_o = 1;
                case(sec_lvl)
                2: begin
                    if (8*ctr < omega) begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];
                    end else begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = poly_hint_cnt[k];
                    end
                end
                3: begin
                    if (8*(ctr+1) < omega) begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];
                    end else if (8*ctr < omega) begin
                        for (k = 0; k < 7; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];

                        hint_o[63:56] = poly_hint_cnt[0];
                    end else begin
                        for (k = 0; k < 7; k = k + 1)
                            hint_o[k*8+:8] = poly_hint_cnt[k+1];
                    end
                end
                5: begin
                    if (8*(ctr+1) < omega) begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];
                    end else if (8*ctr < omega) begin
                        for (k = 0; k < 3; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];

                        hint_o[63:24] = {poly_hint_cnt[4],poly_hint_cnt[3],poly_hint_cnt[2],poly_hint_cnt[1],poly_hint_cnt[0]};
                    end else begin
                        for (k = 0; k < 3; k = k + 1)
                            hint_o[k*8+:8] = poly_hint_cnt[k+5];
                    end
                end
                endcase
            end
            endcase
        end

    end

    always @(posedge clk) begin
        poly0_i <= poly0_ie;
        poly1_i <= poly1_ie;
        poly_valid_i <= (rst) ? 0 : poly_valid_ie;

        if (rst) begin
            state    <= 0;
            poly_num <= 0;
            ctr      <= 0;
            rej      <= 0;
            num_hints <= 0;

            for (k = 0; k < 80; k = k + 1)
                hint_addr[k] <= 0;

            for (k = 0; k < 8; k = k + 1)
                poly_hint_cnt[k] <= 0;

        end else if (rej) begin
            rej <= 1;
        end else begin
            if (num_hints > omega) 
                rej <= 1;

            case(state)
            S_MAKEHINT: begin
                if (poly_valid_i) begin
                    ctr <= ctr + 4;
                    if (ctr == 252) begin
                        ctr      <= 0;
                        poly_num <= poly_num + 1;

                        poly_hint_cnt[poly_num] <= num_hints + hint_needed[0] + hint_needed[1] + hint_needed[2] + hint_needed[3];

                        if (poly_num == K-1) begin
                            state <= S_UNLOADHINT;
                            poly_num <= 0;
                        end
                    end

                    if (hint_needed[0]) begin
                        hint_addr[num_hints] <= ctr + 0;
                    end
                    if (hint_needed[1]) begin
                        hint_addr[num_hints + hint_needed[0]] <= ctr + 1;
                    end
                    if (hint_needed[2]) begin
                        hint_addr[num_hints + hint_needed[0] + hint_needed[1]] <= ctr + 2;
                    end
                    if (hint_needed[3]) begin
                        hint_addr[num_hints + hint_needed[0] + hint_needed[1] + hint_needed[2]] <= ctr + 3;
                    end
                    num_hints <= num_hints + hint_needed[0] + hint_needed[1] + hint_needed[2] + hint_needed[3];
                end
            end
            S_UNLOADHINT: begin
                ctr <= (hint_ready_o && hint_valid_o) ? ctr + 1 : ctr;
            end
            endcase
        end

    end

endmodule

timescale 1ns / 1ps
module dual_port_ram #(parameter WIDTH=96, LENGTH=1024, INIT_FILE="") (clka,clkb,ena,enb,wea,web,addra,addrb,dia,dib,doa,dob);
    input clka,clkb,ena,enb,wea,web;
    input [$clog2(LENGTH)-1:0] addra,addrb;
    input [WIDTH-1:0] dia,dib;
    output [WIDTH-1:0] doa,dob;
    reg[WIDTH-1:0] ram [LENGTH-1:0];
    reg[WIDTH-1:0] doa,dob;

    always @(posedge clka) begin if (ena)
        begin
            if (wea)
                ram[addra] <= dia;
                doa <= ram[addra];
            end
        end
        always @(posedge clkb) begin if (enb)
        begin
            if (web)
                ram[addrb] <= dib;
                dob <= ram[addrb];
        end
    end


    integer i;
    initial begin
        if (INIT_FILE != "") begin
            $readmemh(INIT_FILE, ram);
        end else begin
            for (i = 0; i < LENGTH; i = i + 1)
                ram[i] = 0;
        end
    end

endmodule

timescale 1ns / 1ps

module address_unit(
    input clk,
    input rst,
    input [2:0] mode,
    input [1:0] mode_resolver,
    input en,
    output reg [5:0] ram_nat,
    output reg [5:0] ram_addr,
    output [7:0] twiddle_addr1,
    output [7:0] twiddle_addr2,
    output [7:0] twiddle_addr3,
    output [7:0] twiddle_addr4,
    output reg ntt_round_done,
    output reg done
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    localparam
        DILITHIUM_N = 256;

    localparam 
        DECODE_TRUE = 2'd0,
        ENCODE_TRUE = 2'd1,
        STANDARD    = 2'd2;

    reg [5:0] j, k, i;
    reg [3:0] l;
    reg [6:0] k_next;

    reg  [5:0] addri_resolver;
    wire [5:0] addro_resolver;
    address_resolver ADDR_RESOLVE (mode_resolver, addri_resolver, addro_resolver);

    twiddle_resolver TWIDDLE_RESOLVE (
        clk, rst, mode, en,
        k, l, twiddle_addr1, twiddle_addr2,
        twiddle_addr3, twiddle_addr4
        );

    initial begin
        j              = 0; 
        k              = 0; 
        i              = 1; 
        l              = 0; 
        ram_addr       = 0;
        ntt_round_done = 0;
        done           = 0;
    end

    reg [2:0] fw_ntt_pattern;

    always @(*) begin
        ram_addr = addro_resolver;
        ram_nat  = addri_resolver;

        case(l[2:1])
        0: fw_ntt_pattern = 4;
        1: fw_ntt_pattern = 2;
        2: fw_ntt_pattern = 0;
        3: fw_ntt_pattern = 4;
        endcase

        case(mode)
        ADD_MODE: begin
            addri_resolver = j;
            k_next         = 0;
        end
        MULT_MODE, SUB_MODE: begin
            addri_resolver = j;
            k_next         = 0;
        end
        FORWARD_NTT_MODE: begin
            addri_resolver = j + k;
            k_next = (k + (1 << fw_ntt_pattern)); 
        end
        INVERSE_NTT_MODE: begin
            addri_resolver = j + k;
            k_next = (k + (1 << l));
        end default: begin
            addri_resolver = 0;
            k_next = 0;
        end
        endcase

    end

    always @(posedge clk) begin
        done           <= 0;
        ntt_round_done <= 0;
        j <= j;

        if (rst) begin
            j <= 0;
            k <= 0;
            l <= 0;
            i <= (mode == INVERSE_NTT_MODE) ? 1 : 0;
        end else if (en) begin
            case(mode)
            MULT_MODE, ADD_MODE, SUB_MODE: begin
                if (j == 63) begin
                    j    <= 0;
                    done <= 1;
                end else begin
                    j <= j + 1;
                end
            end
            INVERSE_NTT_MODE: begin
                if (k_next < 64)
                    k <= k_next;
                else begin
                    k <= 0;
                    j <= j + 1;
                end

                if (i == 0) begin
                    j <= 0;
                    k <= 0;
                end 

                if (i == 63) begin
                    ntt_round_done <= 1;
                    i <= 0;


                    if (l == 6) begin
                        done <= 1;
                        k <= k;
                        l <= l;
                    end else begin
                        l <= l + 2;
                    end
                end else begin
                    i <= i + 1;
                end
            end
            FORWARD_NTT_MODE: begin
                if (k_next < 64)
                    k <= k_next;
                else begin
                    k <= 0;
                    j <= j + 1;
                end

                if (i == 63) begin
                    ntt_round_done <= 1;
                    i <= 0;
                    j <= 0;


                    if (l == 6) begin
                        done <= 1;
                        k <= k;
                        l <= l;
                    end else begin
                        l <= l + 2;
                    end
                end else begin
                    i <= i + 1;
                end
            end
            endcase
        end

    end

endmodule

timescale 1ns / 1ps


module sampler_s #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter BUS_W    = 4
    )(
    input start,
    input  rst,
    input  clk,
    input  re_sample,
    input [2:0] sec_lvl,
    input [15:0] N,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output [SAMPLE_W*BUS_W-1:0] samples,
    output reg valid_o,
    input  ready_o,
    output reg done,

    input             keccak_ctrl,
    output reg        rst_k,
    output reg [63:0] din,
    input      [63:0] dout,
    output reg        src_ready,
    input             src_read,
    input             dst_write,
    output            dst_ready
    );

    localparam 
        INIT             = 3'd0,
        STALL            = 3'd7,
        WAITING_FOR_SEED = 3'd1,
        LOADING_SEED     = 3'd2,
        LOADING_NONCE    = 3'd3,
        SAMPLING         = 3'd4,
        LOAD_MODE        = 3'd5;
    reg [2:0] state, state_next;    

    reg [511:0] SEED_SIPO;
    reg [7:0]   SIPO_status;

    reg [7:0] sample_ctr;

    reg rst_s;
    wire [63:0] din_rejs;

    assign din_rejs = {dout[7:0],dout[15:8], dout[23:16], dout[31:24], dout[39:32], dout[47:40],dout[55:48], dout[63:56]};
    wire valid_o_s;
    wire dst_ready_rej;
    reg  ready_o_s;

    assign dst_ready = ~dst_ready_rej;
    rejection_s REJ(
            rst_s, clk, sec_lvl, dst_write, dst_ready_rej, din_rejs, samples, valid_o_s, ready_o_s
        );

    initial begin
        state      = INIT;
        rst_k      = 0;
        rst_s      = 0;
        SEED_SIPO  = 0;
        sample_ctr = 0;

    end    

    reg resample_reg = 0;

    always @(*) begin
        state_next = state;
        ready_i    = 0;
        done       = 0;
        din        = 0;
        valid_o = 0;
        ready_o_s = 0;

        case(state)
        INIT: begin
            state_next = INIT;
            if (start) begin
                 state_next = WAITING_FOR_SEED;
            end else if (re_sample) begin
                state_next  = STALL;
            end
        end
        STALL: begin
            state_next = (keccak_ctrl == 1) ? LOAD_MODE : STALL;
        end
        LOAD_MODE: begin
            din = 64'hE00f000000000210;        
            if (src_read) begin
                state_next = LOADING_SEED;
            end 
        end
        WAITING_FOR_SEED: begin
            ready_i = 1;
            if (SIPO_status[6] == 1 && valid_i) begin
                state_next = STALL;
            end
        end
        LOADING_SEED: begin
            din = SEED_SIPO[511:448];
            if (SIPO_status == 1 && src_read) begin
                state_next = LOADING_NONCE;
            end
        end
        LOADING_NONCE: begin
            din = {N[7:0], N[15:8], 48'd0};
            if (src_read) begin
                state_next = SAMPLING;
            end
        end
        SAMPLING: begin
            valid_o = valid_o_s;
            ready_o_s = ready_o;
            if (sample_ctr == 252 && ready_o && valid_o) begin
                state_next = INIT;
                done  = 1;
            end
        end
        endcase

    end    

    always @(posedge clk) begin
        if (rst) begin
            state <= INIT;
        end else begin
            state <= state_next;
        end
    end

    always @(posedge clk) begin
        src_ready  <= 1;
        rst_k      <= 0;
        rst_s      <= 0;
        SIPO_status <= SIPO_status;

        case(state)
        INIT: begin
            SIPO_status <= 0;
            sample_ctr  <= 0;
            rst_k       <= (re_sample || start) ? 0 : 1;
            rst_s       <= 1;
            resample_reg <= (re_sample) ? 1 : 0;
        end
        STALL: begin
            rst_k       <= 1;
        end
        LOAD_MODE: begin
            src_ready   <= 0;
            SIPO_status <= (resample_reg) ? 8'b1111_1111 : SIPO_status;
        end
        WAITING_FOR_SEED: begin
            if (valid_i & ready_i) begin
                SIPO_status <= {SIPO_status[6:0],1'b1};
                SEED_SIPO   <= {SEED_SIPO[447:0], seed_i};
            end
        end
        LOADING_SEED: begin
            src_ready   <= 0;
            if (src_read) begin
                src_ready   <= 1;
                SIPO_status <= {1'b0, SIPO_status[7:1]};
                SEED_SIPO   <= {SEED_SIPO[447:0], SEED_SIPO[511:512-64]};
            end
        end
        LOADING_NONCE: begin
            src_ready   <= 0;
        end
        SAMPLING: begin
            resample_reg <= 0;
            if (valid_o && ready_o) begin
                sample_ctr <= sample_ctr + 4;
            end
        end
        endcase
    end


endmodule

timescale 1ns / 1ps


module rejection_s #(
    parameter W            = 64,
    parameter RDI_SAMPLE_W = 4,
    parameter SAMPLE_W     = 23,
    parameter BUS_W        = 4
    )(
        input  rst,
        input  clk,
        input [2:0] sec_lvl,
        input  valid_i,
        output reg ready_i,
        input  [W-1:0] rdi,
        output reg [SAMPLE_W*BUS_W-1:0] samples = 0,
        output reg valid_o = 0,
        input  ready_o
    );

    localparam
        DILITHIUM_Q = 23'd8380417,
        ETA2_LIMIT  = 5'd15,
        ETA4_LIMIT  = 5'd9;    

    wire [4:0] ETA_LIMIT;
    assign ETA_LIMIT = (sec_lvl == 3) ? ETA4_LIMIT : ETA2_LIMIT;

    reg [79:0]  SIPO_IN, SIPO_IN_SHIFT;
    reg [199:0] SIPO_OUT;
    reg [3*SAMPLE_W-1:0] sipo_out_in;

    reg [5:0] shift_amt;

    reg [3:0] rej_lane0, rej_lane1, rej_lane2;
    reg [3:0] rej_lane0_map, rej_lane1_map, rej_lane2_map;

    reg [22:0] sample0, sample1, sample2;
    reg rej_lane0_valid, rej_lane1_valid, rej_lane2_valid;
    reg [1:0] num_valid;

    reg [6:0] sipo_in_len, sipo_in_len_next;
    reg [7:0] sipo_out_len, sipo_out_len_next;

    always @(*) begin
        ready_i = (sipo_in_len < 3*RDI_SAMPLE_W) ? 1 : 0;
        valid_o = (sipo_out_len >= SAMPLE_W*BUS_W) ? 1 : 0;

        rej_lane0 = SIPO_IN[3:0];
        rej_lane1 = SIPO_IN[7:4];
        rej_lane2 = SIPO_IN[11:8];

        sample0 = 0;
        sample1 = 0;
        sample2 = 0;

        rej_lane0_map = 0;
        rej_lane1_map = 0;
        rej_lane2_map = 0;

        case(sec_lvl) 
        2,5: begin
            case(rej_lane0)
            0,1,2,3,4: begin
                rej_lane0_map = rej_lane0;
            end
            5,6,7,8,9: begin
                rej_lane0_map = rej_lane0-4'd5;
            end
            10,11,12,13,14:begin
                rej_lane0_map = rej_lane0-4'd10;
            end
            endcase
            sample0 = (rej_lane0_map > 2) ? 2+DILITHIUM_Q-rej_lane0_map : 2-rej_lane0_map;

            case(rej_lane1)
            0,1,2,3,4: begin
                rej_lane1_map = rej_lane1;
            end
            5,6,7,8,9: begin
                rej_lane1_map = rej_lane1-4'd5;
            end
            10,11,12,13,14:begin
                rej_lane1_map = rej_lane1-4'd10;
            end
            endcase
            sample1 = (rej_lane1_map > 2) ? 2+DILITHIUM_Q-rej_lane1_map : 2-rej_lane1_map;

            case(rej_lane2)
            0,1,2,3,4: begin
                rej_lane2_map = rej_lane2;
            end
            5,6,7,8,9: begin
                rej_lane2_map = rej_lane2-4'd5;
            end
            10,11,12,13,14:begin
                rej_lane2_map = rej_lane2-4'd10;
            end
            endcase
            sample2 = (rej_lane2_map > 2) ? 2+DILITHIUM_Q-rej_lane2_map : 2-rej_lane2_map;

        end
        3: begin

            sample0 = 4+DILITHIUM_Q-rej_lane0;
            sample1 = 4+DILITHIUM_Q-rej_lane1;
            sample2 = 4+DILITHIUM_Q-rej_lane2;
        end        
        endcase


        rej_lane0_valid = (rej_lane0 < ETA_LIMIT && sipo_in_len >= RDI_SAMPLE_W) ? 1 : 0;
        rej_lane1_valid = (rej_lane1 < ETA_LIMIT && sipo_in_len >= 2*RDI_SAMPLE_W) ? 1 : 0;
        rej_lane2_valid = (rej_lane2 < ETA_LIMIT && sipo_in_len >= 3*RDI_SAMPLE_W) ? 1 : 0;
        num_valid       = rej_lane0_valid + rej_lane1_valid + rej_lane2_valid;

        if (rej_lane0_valid == 0)
            sample0 = 0;
        if (rej_lane1_valid == 0)
            sample1 = 0;
        if (rej_lane2_valid == 0)
            sample2 = 0;

        sipo_in_len_next  = (ready_i && valid_i) ? sipo_in_len + W : sipo_in_len;
        sipo_out_len_next = (valid_o && ready_o) ? sipo_out_len - SAMPLE_W*BUS_W: sipo_out_len;      

        casex({rej_lane2_valid, rej_lane1_valid, rej_lane0_valid})
        3'bx11:  sipo_out_in = {sample2, sample1, sample0}; 
        3'bx01:  sipo_out_in = {23'd0,   sample2, sample0}; 
        3'bx10:  sipo_out_in = {23'd0,   sample2, sample1};  
        3'b100:  sipo_out_in = {23'd0,   23'd0,   sample2};  
        default: sipo_out_in = {23'd0,   23'd0,   23'd0  }; 
        endcase

        if (sipo_in_len >= 3*RDI_SAMPLE_W) begin
            shift_amt = 3*RDI_SAMPLE_W;
        end else if (sipo_in_len >= 2*RDI_SAMPLE_W) begin
            shift_amt = 2*RDI_SAMPLE_W;
        end else if (sipo_in_len >= RDI_SAMPLE_W) begin
            shift_amt = RDI_SAMPLE_W;
        end else begin
            shift_amt = 0;
        end

        SIPO_IN_SHIFT = (SIPO_IN >> shift_amt);
        samples = SIPO_OUT[SAMPLE_W*BUS_W-1:0];
    end

    initial begin
        SIPO_IN  = 0;
        SIPO_OUT = 0;

        sipo_in_len  = 0;
        sipo_out_len = 0;
    end

    always @(posedge clk) begin
        if (rst) begin
            SIPO_IN  <= 0;
            SIPO_OUT <= 0;

            sipo_in_len  <= 0;
            sipo_out_len <= 0;         
        end else begin

            sipo_in_len <= sipo_in_len_next - shift_amt;

            if (valid_i) begin
                SIPO_IN <= SIPO_IN_SHIFT | (rdi << sipo_in_len - shift_amt);
            end else begin
                SIPO_IN <= SIPO_IN_SHIFT;
            end

            if (num_valid == 1) begin
                sipo_out_len <= sipo_out_len_next + SAMPLE_W;
            end else if (num_valid == 2) begin
                sipo_out_len <= sipo_out_len_next + 2*SAMPLE_W;
            end else if (num_valid == 3) begin
                sipo_out_len <= sipo_out_len_next + 3*SAMPLE_W;
            end else begin
                sipo_out_len <= sipo_out_len_next;
            end

            if (valid_o && ready_o) begin   
                if (num_valid != 0) begin
                    SIPO_OUT <= (SIPO_OUT >> SAMPLE_W*BUS_W) | sipo_out_in << sipo_out_len_next;
                end else begin
                    SIPO_OUT <= SIPO_OUT >> SAMPLE_W*BUS_W;
                end
            end else if (num_valid >0) begin
                SIPO_OUT <= SIPO_OUT | sipo_out_in << sipo_out_len;
            end
        end    
    end

endmodule

timescale 1ns / 1ps


module ntt_fifo_piso
# (parameter DEPTH = 4)
    (
    input clk,
    input en,
    input piso_en,
    input [95:0] line,
    input [23:0] new_value,
    output reg [95:0] fifo_out,
    output reg [23:0] data_out
    );

    reg [23:0] fifo [DEPTH-1:0];

    integer i;
    initial begin
        for (i = 0; i < DEPTH; i = i + 1)
            fifo[i] = 0;
    end

    always @(*) begin
        fifo_out = {fifo[DEPTH-4],fifo[DEPTH-3],fifo[DEPTH-2],fifo[DEPTH-1]};
    end

    always @(posedge clk) begin
        if (en) begin
            data_out <= fifo[DEPTH - 1];
            for (i = DEPTH-1; i > 3; i = i - 1)
                fifo[i] <= fifo[i-1];

            if (piso_en) begin
                fifo[3] = line[0*24+:24];
                fifo[2] = line[1*24+:24];
                fifo[1] = line[2*24+:24];
                fifo[0] = line[3*24+:24];
            end else begin
                fifo[3] = fifo[2];
                fifo[2] = fifo[1];
                fifo[1] = fifo[0];
                fifo[0] = new_value;
            end
        end
    end

endmodule

timescale 1ns / 1ps

module expandmask_ext #(
    parameter SAMPLER_W   = 4,
    parameter SAMPLE_W    = 23,
    parameter W           = 64
    )(
    input  start,
    input  rst,
    input  clk,
    input  [2:0] sec_lvl,
    input  [31:0] msg_len,
    input  valid_seed,
    output reg ready_for_seed,
    input  [W-1:0] seed_i,
    output reg [W-1:0] mu_out,
    output reg mu_valid,
    output [SAMPLER_W*SAMPLE_W-1:0] samples,
    output valid_o,
    input  ready_o,
    output reg done_sampler = 0,

    output reg  rst_k,
    output reg  [63:0] din,
    input [63:0] dout,   
    output reg   src_ready,
    input        src_read,
    input        dst_write,
    output reg   dst_ready
    );

    localparam
        S_HOLD          = 4'd0,
        S_INIT          = 4'd1,
        S_ABSORB_TR     = 4'd2,
        S_ABSORB_M      = 4'd3,
        S_HASH_MU       = 4'd4,
        S_INIT_K        = 4'd5,
        S_ABSORB_K      = 4'd6,
        S_ABSORB_MU     = 4'd7,
        S_HASH_RHO_P    = 4'd8,
        S_LOAD_SAMPLERS = 4'd9,
        S_RUN_SAMPLERS  = 4'd10,
        S_WAIT          = 4'd11;

    reg [3:0] cstate, nstate;
    reg [31:0] ctr, ctr_next;

    reg  rst_y;
    reg  [31:0] ctrl_len;


    reg [511:0] SEED_SIPO = 0;
    reg [7:0]   SIPO_status = 0;

    reg  [15:0] NONCE = 0, OFFSET = 0;
    reg [15:0] L;
    wire ready_i, done;
    reg  valid_seed_sampler, start_y;
    reg  [W-1:0] seed_i_sampler;


    wire rst_k_y;
    wire [63:0] din_y;
    wire        src_ready_y;
    wire        dst_ready_y;


    reg [31:0] msg_bytes;
    always @(posedge clk) begin
        msg_bytes <= msg_len;
    end

    sampler_y_ext SAMPLER_Y (start_y, rst_y, clk, sec_lvl, NONCE+OFFSET, valid_seed_sampler, ready_i, seed_i_sampler, 
                                samples, valid_o, ready_o, done, rst_k_y, din_y, dout, src_ready_y, src_read,
                                dst_write, dst_ready_y);                

    always @(*) begin
        src_ready = 1;
        nstate    = cstate;
        ready_for_seed = 0;
        din = 0;
        dst_ready = 0;
        valid_seed_sampler = 0;
        seed_i_sampler = 0;
        ctr_next = 0 ;

        case(sec_lvl)
        2: begin
            L = 4;
        end
        3: begin
            L = 5;
        end
        default: begin
            L = 7;
        end
        endcase

        rst_k = 0;

        case(cstate)
        S_HOLD: begin
            nstate = (start) ? S_INIT : S_HOLD;
            rst_k = 1;
        end
        S_INIT: begin

            src_ready = 0;
            ctrl_len = {msg_bytes, 3'd0}+ 32'h100;
            din = {32'hE0000200, ctrl_len}; 
            nstate = (src_read) ? S_ABSORB_TR : S_INIT;
        end
        S_ABSORB_TR: begin
            din = seed_i;
            src_ready      = ~valid_seed;
            ready_for_seed = src_read;

            ctr_next = (src_read) ? ctr + 1 : ctr;
            nstate = (ctr_next == 4) ? S_ABSORB_M : S_ABSORB_TR;
        end
        S_ABSORB_M: begin
            din = seed_i;
            src_ready      = ~valid_seed;
            ready_for_seed = src_read;

            ctr_next = (src_read) ? ctr + 1 : ctr;
            nstate = ({ctr_next, 3'd0} >= msg_bytes) ? S_HASH_MU : S_ABSORB_M;
        end
        S_HASH_MU: begin
            dst_ready = 1;

            nstate = (dst_write && SIPO_status[6]) ? S_INIT_K : S_HASH_MU;

        end
        S_INIT_K: begin

            src_ready = 0;
            ctrl_len = 32'h300;
            din = {32'hE0000200, ctrl_len}; 
            nstate = (src_read) ? S_ABSORB_K : S_INIT_K;
        end
        S_ABSORB_K: begin
            din = seed_i;
            src_ready      = ~valid_seed;
            ready_for_seed = src_read;

            ctr_next = (src_read) ? ctr + 1 : ctr;
            nstate = (ctr_next == 4) ? S_ABSORB_MU : S_ABSORB_K;
        end
        S_ABSORB_MU: begin
            din = SEED_SIPO[511:448];
            src_ready = 0;
            nstate = (SIPO_status == 1 && src_read) ? S_HASH_RHO_P : S_ABSORB_MU;
        end
        S_HASH_RHO_P: begin
            dst_ready = 1;

            nstate = (dst_write && SIPO_status[6]) ? S_LOAD_SAMPLERS : S_HASH_RHO_P;
            rst_k = (dst_write && SIPO_status[6]) ? 1 : 0;
        end
        S_LOAD_SAMPLERS: begin
            valid_seed_sampler = 1;
            seed_i_sampler = SEED_SIPO[511:448];

            ctr_next = ctr + 1;
            nstate = (ctr == 7 && &ready_i) ? S_RUN_SAMPLERS : S_LOAD_SAMPLERS;

            rst_k = rst_k_y;
            din   = din_y;
            src_ready = src_ready_y;
            dst_ready = dst_ready_y;
        end
        S_RUN_SAMPLERS: begin
            nstate = (done && NONCE == L-1) ? S_WAIT
                   : (done) ? S_LOAD_SAMPLERS : S_RUN_SAMPLERS;

            rst_k = rst_k_y;
            din   = din_y;
            src_ready = src_ready_y;
            dst_ready = dst_ready_y;
        end
        S_WAIT: begin
            nstate = (start) ? S_LOAD_SAMPLERS : S_WAIT;
        end
        endcase


    end


    initial begin
        cstate = S_HOLD;
        nstate = S_HOLD;
        ctr    = 0;
    end

    always @(posedge clk) begin
        if (rst) begin
            cstate <= S_HOLD;
            rst_y  <= 1;
        end else begin
            rst_y <= 0;
            cstate <= nstate;
        end
    end


    always @(posedge clk) begin
        done_sampler <= 0;
        start_y <= 0;

        mu_valid <= 0;

        case(cstate)
        S_HOLD: begin
            NONCE  <= 0;
            OFFSET <= 0;

            SIPO_status <= 0;
        end
        S_ABSORB_TR: begin
            ctr <= (ctr_next == 4) ? 0 : ctr_next;
        end
        S_ABSORB_M: begin
            ctr <= ({ctr_next, 3'd0} >= msg_bytes) ? 0 : ctr_next;
        end
        S_HASH_MU: begin
            mu_valid <= dst_write;
            mu_out   <= dout;
            if (dst_write) begin
                SIPO_status <= {SIPO_status[6:0],1'b1};
                SEED_SIPO   <= {SEED_SIPO[447:0], dout};
            end
        end
        S_ABSORB_K: begin
            ctr <= (ctr_next == 4) ? 0 : ctr_next;
        end
        S_ABSORB_MU: begin
            if (src_read) begin
                SIPO_status <= {1'b0, SIPO_status[7:1]};
                SEED_SIPO   <= {SEED_SIPO[447:0], 64'd0};
            end
        end
        S_HASH_RHO_P: begin
            if (dst_write) begin
                SIPO_status <= {SIPO_status[6:0],1'b1};
                SEED_SIPO   <= {SEED_SIPO[447:0], dout};
            end


            start_y <= (dst_write && SIPO_status[6]) ? 1 : 0;
        end
        S_LOAD_SAMPLERS: begin
            if (&ready_i) begin
                SEED_SIPO     <= {SEED_SIPO[447:0], SEED_SIPO[511:448]};
                ctr           <= (ctr == 7) ? 0 : ctr_next;
            end
        end
        S_RUN_SAMPLERS: begin
            start_y <= (done && NONCE < L-1) ? 1 : 0; 

            if (done && NONCE == L-1) begin
                done_sampler <= 1;
                OFFSET <= OFFSET+L;
                NONCE  <= 0;
            end else if (done) begin
                NONCE <= NONCE + 1; 
            end
        end
        S_WAIT: begin
            start_y <= (start) ? 1 : 0;
        end
        endcase
    end     

endmodule

timescale 1ns / 1ps



module gen_a_ext # (
    parameter SAMPLER_NUM = 2,
    parameter SAMPLER_W   = 4,
    parameter SAMPLE_W    = 23,
    parameter W           = 64
    )(
    input  start,
    input  rst,
    input  clk,
    input  [2:0] sec_lvl,
    input  valid_seed,
    output ready_for_seed,
    input  [W-1:0] seed_i,
    output [SAMPLER_NUM*SAMPLER_W*SAMPLE_W-1:0] samples,
    output [5:0] sample_state_out,
    output [SAMPLER_NUM-1:0] valid_o,
    input  [SAMPLER_NUM-1:0] ready_o,
    output reg done_sampler,

    output     [SAMPLER_NUM-1:0] rst_k,
    output     [SAMPLER_NUM*64-1:0] din,
    input      [SAMPLER_NUM*64-1:0] dout,   
    output     [SAMPLER_NUM-1:0]  src_ready,
    input      [SAMPLER_NUM-1:0]  src_read,
    input      [SAMPLER_NUM-1:0]  dst_write,
    output      [SAMPLER_NUM-1:0]  dst_ready
    );

    wire [SAMPLE_W*SAMPLER_W-1:0] sampler_output [SAMPLER_NUM-1:0];
    reg [3:0] K [SAMPLER_NUM-1:0];
    reg [3:0] L [SAMPLER_NUM-1:0];
    wire [SAMPLER_NUM-1:0] ready_i, done;
    reg  [SAMPLER_NUM-1:0] valid_i, re_sample, done_latch;
    reg [5:0] sample_state;


    assign sample_state_out = sample_state;
    genvar g;
    generate

        for (g = 0; g < SAMPLER_NUM; g = g + 1) begin
            assign sampler_output[g] = samples[g*(SAMPLER_W*SAMPLE_W)+:(SAMPLER_W*SAMPLE_W)];
        end


        for (g = 0; g < SAMPLER_NUM; g = g + 1) begin
            sampler_a_ext SAMPLER_A (start, rst, clk, re_sample[g], K[g], L[g], valid_seed, ready_i[g], seed_i, 
                                    samples[g*(SAMPLER_W*SAMPLE_W)+:(SAMPLER_W*SAMPLE_W)], valid_o[g], ready_o[g], done[g],
                                    rst_k[g], din[g*64+:64], dout[g*64+:64], src_ready[g], src_read[g], dst_write[g], dst_ready[g]);                
        end
    endgenerate

    integer i;
    assign ready_for_seed = &ready_i;

    initial begin
        done_sampler   = 0;
        done_latch     = 0;
        sample_state   = 0;

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            re_sample[i] = 0; 
    end

    always @(posedge clk) begin
        done_latch     <= done_latch | done;
        done_sampler   <= 0;

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            re_sample[i] <= 0; 

        if (done_latch == {SAMPLER_NUM{1'b1}}) begin
            done_latch <= 0;
            if (sec_lvl == 2 && sample_state == 14) begin
                done_sampler <= 1;
                sample_state <= 0;
            end else if (sec_lvl == 3 && sample_state == 28) begin
                done_sampler <= 1;
                sample_state <= 0;
            end else if (sec_lvl == 5 && sample_state == 54) begin
                done_sampler <= 1;
                sample_state <= 0;
            end else begin
                for (i = 0; i < SAMPLER_NUM; i = i + 1)
                    re_sample[i] <= 1;
                sample_state <= sample_state + 2;
            end
        end

    end

    always @(*) begin
        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            valid_i[i] = valid_seed;

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            K[i] = {sample_state,1'd0};

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            L[i] = {sample_state,1'd1};

        case(sec_lvl) 
        2: begin
            L[0] = sample_state & 3;
            L[1] = (sample_state & 3) + 1;

            K[0] = sample_state >> 2;
            K[1] = sample_state >> 2;
        end
        3: begin
            (*full_case*)
            case(sample_state)
            0: begin
                L[0] = 0;
                L[1] = 1;
                K[0] = 0;
                K[1] = 0;
            end
            2: begin
                L[0] = 2;
                L[1] = 3;
                K[0] = 0;
                K[1] = 0;
            end
            4: begin
                L[0] = 4;
                L[1] = 0;
                K[0] = 0;
                K[1] = 1;
            end
            6: begin
                L[0] = 1;
                L[1] = 2;
                K[0] = 1;
                K[1] = 1;
            end
            8: begin
                L[0] = 3;
                L[1] = 4;
                K[0] = 1;
                K[1] = 1;
            end
            10: begin
                L[0] = 0;
                L[1] = 1;
                K[0] = 2;
                K[1] = 2;
            end
            12: begin
                L[0] = 2;
                L[1] = 3;
                K[0] = 2;
                K[1] = 2;
            end
            14: begin
                L[0] = 4;
                L[1] = 0;
                K[0] = 2;
                K[1] = 3;
            end
            16: begin
                L[0] = 1;
                L[1] = 2;
                K[0] = 3;
                K[1] = 3;
            end
            18: begin
                L[0] = 3;
                L[1] = 4;
                K[0] = 3;
                K[1] = 3;
            end
            20: begin
                L[0] = 0;
                L[1] = 1;
                K[0] = 4;
                K[1] = 4;
            end
            22: begin
                L[0] = 2;
                L[1] = 3;
                K[0] = 4;
                K[1] = 4;
            end
            24: begin
                L[0] = 4;
                L[1] = 0;
                K[0] = 4;
                K[1] = 5;
            end
            26: begin
                L[0] = 1;
                L[1] = 2;
                K[0] = 5;
                K[1] = 5;
            end
            default: begin
                L[0] = 3;
                L[1] = 4;
                K[0] = 5;
                K[1] = 5;
            end
            endcase
        end
        5: begin
            case(sample_state)
            0: begin
                L[0] = 0;
                L[1] = 1;
                K[0] = 0;
                K[1] = 0;
            end
            2: begin
                L[0] = 2;
                L[1] = 3;
                K[0] = 0;
                K[1] = 0;
            end
            4: begin
                L[0] = 4;
                L[1] = 5;
                K[0] = 0;
                K[1] = 0;
            end
            6: begin
                L[0] = 6;
                L[1] = 0;
                K[0] = 0;
                K[1] = 1;
            end
            8: begin
                L[0] = 1;
                L[1] = 2;
                K[0] = 1;
                K[1] = 1;
            end
            10: begin
                L[0] = 3;
                L[1] = 4;
                K[0] = 1;
                K[1] = 1;
            end
            12: begin
                L[0] = 5;
                L[1] = 6;
                K[0] = 1;
                K[1] = 1;
            end
            14: begin
                L[0] = 0;
                L[1] = 1;
                K[0] = 2;
                K[1] = 2;
            end
            16: begin
                L[0] = 2;
                L[1] = 3;
                K[0] = 2;
                K[1] = 2;
            end
            18: begin
                L[0] = 4;
                L[1] = 5;
                K[0] = 2;
                K[1] = 2;
            end
            20: begin
                L[0] = 6;
                L[1] = 0;
                K[0] = 2;
                K[1] = 3;
            end
            22: begin
                L[0] = 1;
                L[1] = 2;
                K[0] = 3;
                K[1] = 3;
            end
            24: begin
                L[0] = 3;
                L[1] = 4;
                K[0] = 3;
                K[1] = 3;
            end
            26: begin
                L[0] = 5;
                L[1] = 6;
                K[0] = 3;
                K[1] = 3;
            end
            28: begin
                L[0] = 0;
                L[1] = 1;
                K[0] = 4;
                K[1] = 4;
            end
            30: begin
                L[0] = 2;
                L[1] = 3;
                K[0] = 4;
                K[1] = 4;
            end
            32: begin
                L[0] = 4;
                L[1] = 5;
                K[0] = 4;
                K[1] = 4;
            end
            34: begin
                L[0] = 6;
                L[1] = 0;
                K[0] = 4;
                K[1] = 5;
            end
            36: begin
                L[0] = 1;
                L[1] = 2;
                K[0] = 5;
                K[1] = 5;
            end
            38: begin
                L[0] = 3;
                L[1] = 4;
                K[0] = 5;
                K[1] = 5;
            end
            40: begin
                L[0] = 5;
                L[1] = 6;
                K[0] = 5;
                K[1] = 5;
            end
            42: begin
                L[0] = 0;
                L[1] = 1;
                K[0] = 6;
                K[1] = 6;
            end
            44: begin
                L[0] = 2;
                L[1] = 3;
                K[0] = 6;
                K[1] = 6;
            end
            46: begin
                L[0] = 4;
                L[1] = 5;
                K[0] = 6;
                K[1] = 6;
            end
            48: begin
                L[0] = 6;
                L[1] = 0;
                K[0] = 6;
                K[1] = 7;
            end
            50: begin
                L[0] = 1;
                L[1] = 2;
                K[0] = 7;
                K[1] = 7;
            end
            52: begin
                L[0] = 3;
                L[1] = 4;
                K[0] = 7;
                K[1] = 7;
            end
            default: begin
                L[0] = 5;
                L[1] = 6;
                K[0] = 7;
                K[1] = 7;
            end
            endcase
        end
        endcase

    end

endmodule

timescale 1ns / 1ps

















module verify(clk, rst, ilen,
			 rd_address, rd_base_sel, din,
			 verify_true,
			 done);

input clk, rst;
input [9:0] ilen;	

output reg [8:0] rd_address;
output rd_base_sel;
input [63:0] din;

output verify_true;
output done;


reg [63:0] acc, din0, din1;
reg base_sel, din0_en, din1_en, acc_en;
reg verify_true;
reg rd_base_sel, inc_rd_address;

reg [2:0] state, nextstate;
wire rd_address_last;



always @(posedge clk)
begin
	if(din0_en)
		din0 <= din;
	if(din1_en)
		din1 <= din;
end

always @(posedge clk)
begin
	if(rst)
		acc <= 64'b0;
	else if(acc_en)
		acc <= acc | (din0 ^ din1);
	else
		acc <= acc;
end

always @(posedge clk)
begin
		verify_true <= (acc==64'd0);
end

always @(posedge clk)
begin
	if(rst)	
		rd_address <= 9'd0;
	else if(inc_rd_address)
		rd_address <= rd_address + 1'b1;
	else
		rd_address <= rd_address;
end		

assign rd_address_last = (rd_address == ilen) ? 1'b1 : 1'b0;

always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else	
		state <= nextstate;
end

always @(state)
begin
	case(state)
	3'd0: begin
					base_sel<=0; din0_en<=0; din1_en<=0; acc_en<=0;
					rd_base_sel<=0; inc_rd_address<=0;
				end
	3'd1: begin	
					base_sel<=0; din0_en<=0; din1_en<=0; acc_en<=0;
					rd_base_sel<=0; inc_rd_address<=0;
				end
	3'd2: begin	
					base_sel<=0; din0_en<=1; din1_en<=0; acc_en<=0;
					rd_base_sel<=1; inc_rd_address<=1;
				end
	3'd3: begin	
					base_sel<=0; din0_en<=0; din1_en<=1; acc_en<=0;
					rd_base_sel<=0; inc_rd_address<=0;
				end
	3'd4: begin	
					base_sel<=0; din0_en<=1; din1_en<=0; acc_en<=1;
					rd_base_sel<=1; inc_rd_address<=1;
				end

	3'd7: begin
					base_sel<=0; din0_en<=0; din1_en<=0; acc_en<=0;
					rd_base_sel<=0; inc_rd_address<=0;
				end	
	default: begin
					base_sel<=0; din0_en<=0; din1_en<=0; acc_en<=0;
					rd_base_sel<=0; inc_rd_address<=0;
				end				
	endcase
end	

always @(state or rd_address_last)
begin
	case(state)
	3'd0: nextstate <= 3'd1;
	3'd1: nextstate <= 3'd2;
	3'd2: nextstate <= 3'd3;
	3'd3: nextstate <= 3'd4;	
	3'd4: begin
					if(rd_address_last)
						nextstate <=3'd7;
					else
						nextstate <= 3'd3;
				end
	3'd7: nextstate <= 3'd7;
	default: nextstate <= 3'd0;	
	endcase
end

assign done = (state==3'd7) ? 1'b1 : 1'b0;

endmodule

timescale 1ns / 1ps


















module poly_load_control_BRAM1(clk, rst, s_address, poly_load_delayed, poly_load_done);
input clk, rst;
output [7:0] s_address;
output reg poly_load_delayed;
output poly_load_done;

reg [4:0] poly_word_counter;

always @(posedge clk)
begin
	if (rst)
		poly_load_delayed <= 0;
	else
		poly_load_delayed <= poly_word_counter < 16;
end

assign s_address = poly_word_counter;

always @(posedge clk)
begin
	if (rst)
		poly_word_counter <= 5'd0;
	else if (poly_word_counter < 16)
		poly_word_counter <= poly_word_counter + 5'd1;
	else
		poly_word_counter <= poly_word_counter;
end

assign poly_load_done = poly_word_counter == 5'd15 ? 1'b1 : 1'b0;

endmodule

timescale 1ns / 1ps



















module SHA_SHAKE_wrapper_test(clk, address_ext, dina_ext, wea_ext,
										command_in, command_we0, command_we1, 
										command_enable,
										done_shake);

input clk; 
input [8:0] address_ext;
input [63:0] dina_ext;
input wea_ext;

input [31:0] command_in;
input command_we0, command_we1, command_enable;
output done_shake;

reg [31:0] command_reg0, command_reg1;
wire [4:0] INS;
wire [8:0] OP1, OP2, OP3;

wire wea;
wire [8:0] addra, addrb;
wire [63:0] dina, doutb;

wire clear_sha, shake_intermediate_rst, shake_next_extract;
wire [1:0] rate_type;
wire [31:0] mlen, olen;
wire [8:0] rd_address_shake, wt_address_shake;
wire [63:0] din_shake, dout_shake;
wire sample_dout, done_shake;

always @(posedge clk)
begin
	if(command_we0)
		command_reg0 <= command_in;
	if(command_we1)
		command_reg1 <= command_in;
end


BRAM64 RAM(clk, wea, addra, dina, clk, addrb, doutb);


assign INS = command_reg0[4:0];
assign OP1 = command_reg0[13:5];
assign OP2 = command_reg0[22:14];
assign OP3 = command_reg0[31:23];	

assign mlen = {16'd0, command_reg1[15:0]};
assign olen = {16'd0, command_reg1[31:16]};

assign clear_sha = (INS==5'd0) ? 1'b1 : 1'b0;
assign enable_sha = (INS==5'd1||INS==5'd2||INS==5'd3||INS==5'd4||INS==5'd5) ? 1'b1 : 1'b0;
assign shake_intermediate_rst	= (INS==5'd4) ? 1'b1 : 1'b0;
assign shake_next_extract = (INS==5'd5) ? 1'b1 : 1'b0;
assign rate_type = (INS==5'd1) ? 2'd1 : (INS==5'd2) ? 2'd0 : 2'd2;
assign din_shake = doutb;

assign wea = (enable_sha) ? sample_dout : wea_ext;
assign dina = (enable_sha) ? dout_shake : dina_ext;
assign addra = (enable_sha) ? (wt_address_shake+OP3) : address_ext;
assign addrb = (enable_sha) ? (rd_address_shake+OP1) : address_ext;

SHA_SHAKE_wrapper SH(clk, clear_sha, shake_intermediate_rst, shake_next_extract, 
							rate_type, mlen, 
							rd_address_shake, din_shake,
							olen, dout_shake, wt_address_shake, sample_dout, 
							done_shake);


endmodule

timescale 1ns / 1ps


















