module vector_sampler(clk, rst, rd_address, data_in,
						sample_pack, wt_address, wen, done);
input clk, rst;
output reg [8:0] rd_address;
input [63:0] data_in;

output reg [63:0] sample_pack;
output reg [8:0] wt_address;	
output reg wen;
output done;

reg [1:0] wen_sample_pack;
reg [2:0] state, nextstate;
reg rd_inc, wt_inc;

wire [4:0] temp_s0 = (data_in[0]+data_in[1]+data_in[2]+data_in[3]) - (data_in[4]+data_in[5]+data_in[6]+data_in[7]);
wire [3:0] s0;
assign s0[0] = temp_s0[0];
assign s0[1] = (temp_s0[4]&temp_s0[0])^temp_s0[1];
assign s0[2] = (temp_s0[4]&(temp_s0[0]|temp_s0[1]))^temp_s0[2];
assign s0[3] = temp_s0[4];

wire [4:0] temp_s1 = (data_in[8]+data_in[9]+data_in[10]+data_in[11]) - (data_in[12]+data_in[13]+data_in[14]+data_in[15]);
wire [3:0] s1;
assign s1[0] = temp_s1[0];
assign s1[1] = (temp_s1[4]&temp_s1[0])^temp_s1[1];
assign s1[2] = (temp_s1[4]&(temp_s1[0]|temp_s1[1]))^temp_s1[2];
assign s1[3] = temp_s1[4];

wire [4:0] temp_s2 = (data_in[16]+data_in[17]+data_in[18]+data_in[19]) - (data_in[20]+data_in[21]+data_in[22]+data_in[23]);
wire [3:0] s2;
assign s2[0] = temp_s2[0];
assign s2[1] = (temp_s2[4]&temp_s2[0])^temp_s2[1];
assign s2[2] = (temp_s2[4]&(temp_s2[0]|temp_s2[1]))^temp_s2[2];
assign s2[3] = temp_s2[4];

wire [4:0] temp_s3 = (data_in[24]+data_in[25]+data_in[26]+data_in[27]) - (data_in[28]+data_in[29]+data_in[30]+data_in[31]);
wire [3:0] s3;
assign s3[0] = temp_s3[0];
assign s3[1] = (temp_s3[4]&temp_s3[0])^temp_s3[1];
assign s3[2] = (temp_s3[4]&(temp_s3[0]|temp_s3[1]))^temp_s3[2];
assign s3[3] = temp_s3[4];

wire [4:0] temp_s4 = (data_in[32]+data_in[33]+data_in[34]+data_in[35]) - (data_in[36]+data_in[37]+data_in[38]+data_in[39]);
wire [3:0] s4;
assign s4[0] = temp_s4[0];
assign s4[1] = (temp_s4[4]&temp_s4[0])^temp_s4[1];
assign s4[2] = (temp_s4[4]&(temp_s4[0]|temp_s4[1]))^temp_s4[2];
assign s4[3] = temp_s4[4];

wire [4:0] temp_s5 = (data_in[40]+data_in[41]+data_in[42]+data_in[43]) - (data_in[44]+data_in[45]+data_in[46]+data_in[47]);
wire [3:0] s5;
assign s5[0] = temp_s5[0];
assign s5[1] = (temp_s5[4]&temp_s5[0])^temp_s5[1];
assign s5[2] = (temp_s5[4]&(temp_s5[0]|temp_s5[1]))^temp_s5[2];
assign s5[3] = temp_s5[4];

wire [4:0] temp_s6 = (data_in[48]+data_in[49]+data_in[50]+data_in[51]) - (data_in[52]+data_in[53]+data_in[54]+data_in[55]);
wire [3:0] s6;
assign s6[0] = temp_s6[0];
assign s6[1] = (temp_s6[4]&temp_s6[0])^temp_s6[1];
assign s6[2] = (temp_s6[4]&(temp_s6[0]|temp_s6[1]))^temp_s6[2];
assign s6[3] = temp_s6[4];

wire [4:0] temp_s7 = (data_in[56]+data_in[57]+data_in[58]+data_in[59]) - (data_in[60]+data_in[61]+data_in[62]+data_in[63]);
wire [3:0] s7;
assign s7[0] = temp_s7[0];
assign s7[1] = (temp_s7[4]&temp_s7[0])^temp_s7[1];
assign s7[2] = (temp_s7[4]&(temp_s7[0]|temp_s7[1]))^temp_s7[2];
assign s7[3] = temp_s7[4];

always @(posedge clk)
begin
	if(wen_sample_pack==2'd1)
		sample_pack[31:00] <= {s7, s6, s5, s4, s3, s2, s1, s0};
	else if(wen_sample_pack==2'd2)
		sample_pack[63:32] <= {s7, s6, s5, s4, s3, s2, s1, s0};
	else
		sample_pack <= sample_pack;
end

always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else
		state <= nextstate;
end

always@(posedge clk)
begin
	if(rst)
		rd_address <= 9'd0;
	else if(rd_inc)
		rd_address <= rd_address + 1'b1;
	else
		rd_address <= rd_address;
end

always@(posedge clk)
begin
	if(rst)
		wt_address <= 9'd0;
	else if(wt_inc)
		wt_address <= wt_address + 1'b1;
	else
		wt_address <= wt_address;
end


wire sampling_done = (wt_address==9'd48) ? 1'b1 : 1'b0;

always @(state)
begin
	case(state)
	3'd0: begin	
			rd_inc<=1'b0; wen_sample_pack<=2'd0; wen<=1'b0; wt_inc<=1'b0;
		end		

	3'd1: begin	
			rd_inc<=1'b1; wen_sample_pack<=2'd0; wen<=1'b0; wt_inc<=1'b0;
		end
	3'd2: begin	
			rd_inc<=1'b1; wen_sample_pack<=2'd1; wen<=1'b0; wt_inc<=1'b0;
		end
	3'd3: begin	
			rd_inc<=1'b0; wen_sample_pack<=2'd2; wen<=1'b0; wt_inc<=1'b0;
		end

	3'd4: begin	
			rd_inc<=1'b1; wen_sample_pack<=2'd0; wen<=1'b1; wt_inc<=1'b1;
		end

	3'd7: begin	
			rd_inc<=1'b0; wen_sample_pack<=2'd0; wen<=1'b0; wt_inc<=1'b0;
		end		
	default: begin	
			rd_inc<=1'b0; wen_sample_pack<=2'd0; wen<=1'b0; wt_inc<=1'b0;
		end		
	endcase
end

always @(state or sampling_done)
begin
	case(state)
	3'd0: nextstate <= 3'd1;

	3'd1: nextstate <= 3'd2;
	3'd2: begin
			if(sampling_done)
				nextstate <= 3'd7;
			else
				nextstate <= 3'd3;
		end	
	3'd3: nextstate <= 3'd4;
	3'd4: nextstate <= 3'd2;

	3'd7: nextstate <= 3'd7;
	default: nextstate <= 3'd7;
	endcase
end

assign done = (state==3'd7) ? 1'b1 : 1'b0;
endmodule

timescale 1ns / 1ps

















module VectorMul(clk, rst, 
						rst_pol_mul, pol_acc_clear, pol_base_sel, 
						pol_mul_done, result_read,
						PolMem_address, PolMem_wen, done);
input clk, rst;
output reg rst_pol_mul, pol_acc_clear;
output reg [1:0] pol_base_sel;	

input pol_mul_done;
output reg result_read;



output [5:0] PolMem_address;
output PolMem_wen;
output done;

reg [5:0] PolMem_address;
reg PolMem_wen;
reg [2:0] state, nextstate;
wire PolMem_write_complete;

always @(posedge clk)
begin
	if(rst)
		PolMem_address <= 6'd0;
	else if(PolMem_wen)
		PolMem_address <= PolMem_address + 1'b1;
	else
		PolMem_address <= PolMem_address;
end		

assign PolMem_write_complete = (PolMem_address==6'd63) ? 1'b1 : 1'b0;	

always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else
		state <= nextstate;
end

always @(state)
begin
	case(state)
	3'd0: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b1; pol_base_sel<=2'd0; result_read<=1'b0; PolMem_wen<=1'b0; end

	3'd1: begin rst_pol_mul<=1'b0; pol_acc_clear<=1'b0; pol_base_sel<=2'd0; result_read<=1'b0; PolMem_wen<=1'b0; end
	3'd2: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b0; pol_base_sel<=2'd1; result_read<=1'b0; PolMem_wen<=1'b0; end


	3'd3: begin rst_pol_mul<=1'b0; pol_acc_clear<=1'b0; pol_base_sel<=2'd1; result_read<=1'b0; PolMem_wen<=1'b0; end
	3'd4: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b0; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; end


	3'd5: begin rst_pol_mul<=1'b0; pol_acc_clear<=1'b0; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; end


	3'd6: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b0; pol_base_sel<=2'd2; result_read<=1'b1; PolMem_wen<=1'b1; end

	3'd7: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b1; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; end
	default: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b1; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; end
	endcase
end	

always @(state or pol_mul_done or PolMem_write_complete)
begin
	case(state)
	3'd0: nextstate<=3'd1;


	3'd1: begin
				if(pol_mul_done)
					nextstate<=3'd2;
				else	
					nextstate<=3'd1;
			end		
	3'd2: nextstate<=3'd3;


	3'd3: begin
				if(pol_mul_done)
					nextstate<=3'd4;
				else	
					nextstate<=3'd3;
			end		
	3'd4: nextstate<=3'd5;


	3'd5: begin
				if(pol_mul_done)
					nextstate<=3'd6;
				else	
					nextstate<=3'd5;
			end		
	3'd6: begin
				if(PolMem_write_complete)
					nextstate<=3'd7;
				else
					nextstate<=3'd6;
			end		
	3'd7: nextstate<=3'd7;
	default: nextstate<=3'd0;
	endcase
end

assign done = (state==3'd7) ? 1'b1 : 1'b0;

endmodule

