assign wt_address = (enable_sha) ? {1'b0,wt_address_shake} : (rst_vmul==1'b0) ? {1'b0,wt_address_vmul} : (rst_addround==1'b0) ? {1'b0,wt_address_addround} : (rst_addpack==1'b0) ? {1'b0,wt_address_addpack} : (rst_bs2polvecp==1'b0) ? {1'b0,wt_address_bs2polvecp} : (rst_unpack==1'b0) ? {1'b0,wt_address_unpack} : (rst_copy==1'b0) ? {1'b0,wt_address_copy} : (rst_sampler==1'b0) ? {1'b0,wt_address_sampler} : (rst_cmov==1'b0) ? {1'b0,wt_address_cmov} : address_ext;
assign wea = (enable_sha) ? sample_dout : (rst_vmul==1'b0) ? wea_vmul : (rst_addround==1'b0) ? wea_addround : (rst_addpack==1'b0) ? wea_addpack : (rst_bs2polvecp==1'b0) ? wea_bs2polvecp : (rst_unpack==1'b0) ? wea_unpack : (rst_copy==1'b0) ? wea_copy : (rst_sampler==1'b0) ? wea_sampler : (rst_cmov==1'b0) ? wea_cmov : wea_ext;
assign dina = (enable_sha) ? dout_shake : (rst_vmul==1'b0) ? dout_vmul : (rst_addround==1'b0) ? dout_addround : (rst_addpack==1'b0) ? dout_addpack : (rst_bs2polvecp==1'b0) ? dout_bs2polvecp : (rst_unpack==1'b0) ? dout_unpack : (rst_copy==1'b0) ? dout_copy : (rst_sampler==1'b0) ? dout_sampler :  (rst_cmov==1'b0) ? dout_cmov : dina_ext;
wire op2_sel = (rst_addpack==1'b0) ? rd_base_sel_addpack : (rst_unpack==1'b0) ? rd_base_sel_unpack : (rst_vmul==1'b0) ? s_load_happens_now : (rst_verify==1'b0) ? rd_base_sel_verify : (rst_cmov==1'b0) ? rd_base_sel_cmov : 1'b0;

wire [9:0] OP1_or_OP2 = (op2_sel) ? OP2 : OP1;
assign addra = OP3 + wt_address;
assign addrb = OP1_or_OP2 + rd_address;

assign doutb_ext = doutb;

wire [63:0] s_vec_64;


SHA_SHAKE_wrapper SH(clk, clear_sha, shake_intermediate_rst, shake_next_extract, 
							rate_type, mlen, 
							rd_address_shake, din_shake,
							olen, dout_shake, wt_address_shake, sample_dout, 
							done_shake);

assign enable_sha = (INS==5'd1||INS==5'd2||INS==5'd3||INS==5'd4||INS==5'd5) ? 1'b1 : 1'b0;
assign clear_sha = (INS==5'd0 || enable_sha==1'b0) ? 1'b1 : 1'b0;
assign shake_intermediate_rst	= (INS==5'd4) ? 1'b1 : 1'b0;
assign shake_next_extract = (INS==5'd5) ? 1'b1 : 1'b0;
assign rate_type = (INS==5'd1) ? 2'd1 : (INS==5'd2) ? 2'd0 : 2'd2;
assign mlen = {16'd0, command_reg1[15:0]};
assign din_shake = doutb;
assign olen = {16'd0, command_reg1[31:16]};

VectorMul_wrapper	VMUL0(clk, rst_vmul, pol_load_coeff4x,
								s_load_happens_now, rd_address_vmul, doutb,

								wt_address_vmul, dout_vmul, wea_vmul, 
								done_vmul);

Add_Round	AddRound0(clk, rst_addround, rd_address_addround, doutb,
									wt_address_addround, dout_addround, wea_addround,
									done_addround);

Add_m_pack	AddPack0(clk, rst_addpack, rd_base_sel_addpack, rd_address_addpack, doutb,
									wt_address_addpack, dout_addpack, wea_addpack,
									done_addpack);

BS2POLVECp	BC2PVEC(clk, rst_bs2polvecp, rd_address_bs2polvecp, doutb,
								 wt_address_bs2polvecp, dout_bs2polvecp, wea_bs2polvecp,
								 done_bs2polvecp);

unpack		unpack0(clk, rst_unpack, rd_base_sel_unpack, rd_address_unpack, doutb,
									wt_address_unpack, dout_unpack, wea_unpack,
									done_unpack);


copy_words        copy(clk, rst_copy, number_words_copy, 
                            rd_address_copy, doutb,
                            wt_address_copy, dout_copy, wea_copy,
                            done_copy);
assign number_words_copy = OP2[8:0];                          


vector_sampler      Sampler(clk, rst_sampler, rd_address_sampler, doutb,
						      dout_sampler, wt_address_sampler, wea_sampler, done_sampler);

assign ilen = command_reg1[9:0];

verify              VERIFY1(clk, rst_verify, ilen, rd_address_verify, rd_base_sel_verify, doutb,
                           verify_true_wire, done_verify);

cmov                CMOV1(clk, rst_cmov, verify_true,
						rd_base_sel_cmov, rd_address_cmov, doutb,
						wt_address_cmov, dout_cmov, wea_cmov,
						done_cmov);


assign done_timer = 1'b0;

always @(posedge clk)
begin
    if(done_verify)
        verify_true <= verify_true_wire;
    else
        verify_true <= verify_true;
 end

BRAM64_1024 BR (
  .clka(clk), 
  .wea(wea), 
  .addra(addra), 
  .dina(dina), 
  .clkb(clk), 
  .addrb(addrb), 
  .doutb(doutb) 
);


endmodule

timescale 1ns / 1ps




















define h2 10'd228

module unpack(clk, rst, read_base_sel, read_address, read_data,
									write_address, write_data, write_en,
									done);
input clk, rst;
output read_base_sel;	
output [8:0] read_address;
input [63:0] read_data;

output reg [8:0] write_address;
output [63:0] write_data;
output write_en;
output done;


reg read_base_sel, inc_v_address, v_buffer64_en;
reg op_buffer16_en, op_buffer64_en, m_buffer_en, inc_write_address;
reg [63:0] op_buffer, v_buffer, m_buffer;
reg [8:0] v_address;
reg [4:0] state, nextstate;

wire v_address_64, store_m, load_op;
wire [9:0] add0, add1, add2, add3;
wire [8:0] op_address;
wire message_load_needed;

always @(posedge clk)
begin
	if(op_buffer64_en)
		op_buffer <= read_data;
	else if(op_buffer16_en)
		op_buffer <= {16'd0, op_buffer[63:16]};
end
always @(posedge clk)
begin
	if(v_buffer64_en)
		v_buffer <= read_data;
end
always @(posedge clk)
begin
	if(m_buffer_en)
		m_buffer <= {add3[9],add2[9],add1[9],add0[9],m_buffer[63:4]};
end

always @(posedge clk)
begin
	if(rst)
		v_address <= 9'd0;
	else if(inc_v_address)
		v_address <= v_address + 1'b1;
end
assign v_address_64 = (v_address==9'd64);
assign op_address = {2'd0,v_address[8:2]};
assign read_address = (read_base_sel==1'b0) ? v_address : op_address;

always @(posedge clk)
begin
	if(rst)
		write_address <= 9'd0;
	else if(inc_write_address)
		write_address <= write_address + 1'b1;
end
assign write_data = m_buffer[63:0];
assign write_en = inc_write_address;
assign store_m = (v_address[3:0]==4'd0) ? 1'b1 : 1'b0;
assign load_op = (v_address[1:0]==2'd0) ? 1'b1 : 1'b0;




assign add0 = v_buffer[09:00] + h2 - {op_buffer[3:0],6'd0};
assign add1 = v_buffer[25:16] + h2 - {op_buffer[7:4],6'd0};
assign add2 = v_buffer[41:32] + h2 - {op_buffer[11:8],6'd0};
assign add3 = v_buffer[57:48] + h2 - {op_buffer[15:12],6'd0};

always @(posedge clk)
begin
	if(rst)
		state <= 5'd0;
	else
		state <= nextstate;
end

always @(state)
begin
	case(state)
	5'd0: begin 
			read_base_sel<=0; inc_v_address<=0; v_buffer64_en<=0;
			op_buffer16_en<=0; op_buffer64_en<=0;
			m_buffer_en<=0; inc_write_address<=0;
		end

	5'd1: begin 
			read_base_sel<=1; inc_v_address<=0; v_buffer64_en<=0; 
			op_buffer16_en<=0; op_buffer64_en<=0;
			m_buffer_en<=0; inc_write_address<=0;
		end
	5'd2: begin 
			read_base_sel<=0; inc_v_address<=0; v_buffer64_en<=0; 
			op_buffer16_en<=0; op_buffer64_en<=1;
			m_buffer_en<=0; inc_write_address<=0;
		end	

	5'd3: begin 
			read_base_sel<=0; inc_v_address<=1; v_buffer64_en<=1; 
			op_buffer16_en<=0; op_buffer64_en<=0;
			m_buffer_en<=0; inc_write_address<=0;
		end
	5'd4: begin 
			read_base_sel<=0; inc_v_address<=0; v_buffer64_en<=0; 
			op_buffer16_en<=1; op_buffer64_en<=0;
			m_buffer_en<=1; inc_write_address<=0;
		end

	5'd5: begin 
			read_base_sel<=0; inc_v_address<=0; v_buffer64_en<=0; 
			op_buffer16_en<=0; op_buffer64_en<=0;
			m_buffer_en<=0; inc_write_address<=1;
		end

	5'd15: begin  
			read_base_sel<=0; inc_v_address<=0; v_buffer64_en<=0; 
			op_buffer16_en<=0; op_buffer64_en<=0;
			m_buffer_en<=0; inc_write_address<=0;
		end
	default: begin  
			read_base_sel<=0; inc_v_address<=0; v_buffer64_en<=0; 
			op_buffer16_en<=0; op_buffer64_en<=0;
			m_buffer_en<=0; inc_write_address<=0;
		end
	endcase
end

always @(state or store_m or load_op or v_address_64)
begin
	case(state)
	5'd0: nextstate <= 5'd1;
	5'd1: nextstate <= 5'd2;
	5'd2: nextstate <= 5'd3;

	5'd3: nextstate <= 5'd4;
	5'd4: begin
				if(store_m)
					nextstate <= 5'd5;
				else if(load_op)
					nextstate <= 5'd1;	
				else
					nextstate <= 5'd3;
			end

	5'd5: begin
				if(v_address_64)
					nextstate <= 5'd15;
				else	
					nextstate <= 5'd1;
			end
	5'd15: nextstate <= 5'd15;				
	default: nextstate <= 5'd0;	
	endcase
end

assign done = (state==5'd15) ? 1'b1 : 1'b0;	
endmodule

timescale 1ns / 1ps

















define sha_constant576 8'h06
define sha_constant1088 8'h06
define sha_constant1344 8'h1F

define rate_constant1344 8'd21
define rate_constant1088 8'd17
define rate_constant576 8'd9

module SHA_SHAKE_wrapper(clk, rst, shake_intermediate_rst, shake_next_extract, rate_type, mlen, 
									rd_address, din,
									olen, dout, wt_address, sample_dout, 
									done);

input clk, rst;
input shake_intermediate_rst, shake_next_extract;	



input [1:0] rate_type;		



input [31:0] mlen;			

output reg [8:0] rd_address;
input [63:0] din;

input [31:0] olen;			
output [63:0] dout;
output reg [8:0] wt_address;
output sample_dout;
output reg done;


reg [31:0] mlen_reg, olen_reg;
reg dec_mlen;
reg continue_permutation;
reg inc_rd_address;

reg [7:0] rate;
reg inc_rate;
reg [3:0] state, nextstate;
wire done_wire;

wire [7:0] rate_constant =  (rate_type==2'd0) ? rate_constant576 : 
				  		    (rate_type==2'd1) ? rate_constant1088 : rate_constant1344;

wire [7:0] domain_separator =   (rate_type==2'd0) ? sha_constant576 :
								(rate_type==2'd1) ? sha_constant1088 : sha_constant1344;

always @(posedge clk)
begin
	if(rst)
		mlen_reg <= mlen;
	else if(dec_mlen)
		mlen_reg <= mlen_reg - 32'd8;
	else
		mlen_reg <= mlen_reg;
end		

always @(posedge clk)
begin
	if(rst)
		olen_reg <= olen;
	else if(shake_intermediate_rst)
		olen_reg <= olen;
	else if(sample_dout)
		olen_reg <= olen_reg - 32'd8;
	else
		olen_reg <= olen_reg;
end

wire mlen_g8 = (mlen_reg > 32'd7) ? 1'b1 : 1'b0;
wire mlen_n0 = (mlen_reg != 32'd0) ? 1'b1 : 1'b0;
wire olen_is0 = (olen_reg==32'd0) ? 1'b1 : 1'b0;

reg domain_separator_used;

always @(posedge clk)
begin
	if(rst)
		domain_separator_used <= 1'b0;
	else if(domain_separator_used==1'b0 && mlen_g8==1'b0 && state==4'd1)
		domain_separator_used <= 1'b1;
	else
		domain_separator_used <= domain_separator_used;
end

wire rate_full = (rate==rate_constant) ? 1'b1 : 1'b0;
always @(posedge clk)
begin
	if(rst)
		rate <= 8'd1;
	else if(rate_full && inc_rate)
		rate <= 8'd1;
	else if(inc_rate)
		rate <= rate + 1'b1;
	else
		rate <= rate;
end

wire last_rate_byte = (mlen_g8==1'b0 && rate_full==1'b1) ? 1'b1 : 1'b0;		

wire [7:0] din0 = (mlen_g8) ? din[7:0] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd0) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd0) ? din[7:0] :	8'd0;					 
wire [7:0] din1 = (mlen_g8) ? din[15:8] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd1) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd1) ? din[15:8] :	8'd0;
wire [7:0] din2 = (mlen_g8) ? din[23:16] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd2) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd2) ? din[23:16] :	8'd0;
wire [7:0] din3 = (mlen_g8) ? din[31:24] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd3) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd3) ? din[31:24] :	8'd0;
wire [7:0] din4 = (mlen_g8) ? din[39:32] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd4) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd4) ? din[39:32] :	8'd0;						 
wire [7:0] din5 = (mlen_g8) ? din[47:40] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd5) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd5) ? din[47:40] :	8'd0;						
wire [7:0] din6 = (mlen_g8) ? din[55:48] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd6) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd6) ? din[55:48] :	8'd0;						 
wire [7:0] din7_temp = (mlen_g8) ? din[63:56] : 
						 (domain_separator_used==1'b0 && mlen_reg[2:0]==3'd7) ? domain_separator :
						 (domain_separator_used==1'b0 && mlen_reg[2:0]>3'd7) ? din[63:56] :	8'd0;
wire [7:0] din7 = (last_rate_byte) ? {1'b1,din7_temp[6:0]} : din7_temp;


reg start, rst_keccak;
wire [63:0] dina = {din7,din6,din5,din4,din3,din2,din1,din0};
reg din_valid;
reg last_block;


wire buffer_full, ready, dout_valid;
wire [63:0] dout;

keccak KECCAK(
			 clk, 
			 rst_keccak, 
			 start, 
			 continue_permutation,
			 rate_type,
			 dina,
			 din_valid,
			 buffer_full,
			 last_block,    
			 ready,    
			 dout,
			 dout_valid);

always @(posedge clk)
begin
	if(rst)
		rd_address <= 9'd0;
	else if(inc_rd_address)
		rd_address <= rd_address + 1'b1;
	else
		rd_address <= rd_address;
end		

always @(posedge clk)
begin
	if(rst)
		wt_address <= 9'd0;
	else if(sample_dout)
		wt_address <= wt_address + 1'b1;
	else
		wt_address <= wt_address;
end

always @(posedge clk)
begin
	if(rst)
		state <= 4'd0;
	else
		state <= nextstate;
end

always @(state or buffer_full or rate_full or mlen_g8)
begin
	case(state)
	4'd0: begin
			start<=1'b1; rst_keccak<=0; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	 
			dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end	

	4'd10: begin 
			start<=1'b1; rst_keccak<=0; inc_rd_address<=1; din_valid<=1'b0; last_block<=1'b0;	 
			dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end
	4'd1: begin
				start<=1'b0; rst_keccak<=1;  din_valid<=1'b1; last_block<=1'b0;	 
				if(mlen_g8==1'b0 || rate_full==1'b1) dec_mlen<=0; else dec_mlen<=1; 
				if(rate_full) inc_rd_address<=0;  else inc_rd_address<=1;  				
				if(rate_full) inc_rate<=0; else inc_rate<=1;
				continue_permutation<=0;
			end

	4'd2: begin
                start<=1'b0; rst_keccak<=1;  din_valid<=1'b0; last_block<=1'b0;    
                dec_mlen<=0; inc_rd_address<=0; inc_rate<=0; continue_permutation<=0;
            end
	4'd13: begin
                start<=1'b0; rst_keccak<=1;  din_valid<=1'b0; last_block<=1'b0;    
                if(mlen_g8==1'b0) dec_mlen<=0; else dec_mlen<=1;
                if(mlen_g8==1'b0) inc_rd_address<=0; else inc_rd_address<=1;
                inc_rate<=1; continue_permutation<=0;
            end

	4'd3: begin
				start<=1'b0; rst_keccak<=1; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b1;	
				dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end


	4'd6: begin
				start<=1'b0; rst_keccak<=1; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	
				dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end
	4'd7: begin
				start<=1'b0; rst_keccak<=1; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	
				dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end

	4'd8: begin
				start<=1'b0; rst_keccak<=1; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	 
				dec_mlen<=0; inc_rate<=0; continue_permutation<=1;
			end
	4'd9: begin
				start<=1'b0; rst_keccak<=1; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	
				dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end		

	4'd14: begin	
				start<=1'b0; rst_keccak<=1; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	 
				dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end	

	4'd15: begin	
				start<=1'b0; rst_keccak<=1; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	 
				dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end	

	default: begin
				start<=1'b1; rst_keccak<=0; inc_rd_address<=0; din_valid<=1'b0; last_block<=1'b0;	
				dec_mlen<=0; inc_rate<=0; continue_permutation<=0;
			end	

	endcase
end


always @(state or buffer_full or last_rate_byte or sample_dout or olen_is0 
			or shake_intermediate_rst or shake_next_extract)
begin
	case(state)
	4'd0: nextstate <= 4'd10;
	4'd10: nextstate <= 4'd1;
	4'd1: begin
				if(buffer_full)
					nextstate <= 4'd2;
				else
					nextstate <= 4'd1;
			end

	4'd2: begin
                if(last_rate_byte)
                    nextstate <= 4'd3;
                else if(buffer_full)
                    nextstate <= 4'd2;
                else
                    nextstate <= 4'd13;
            end
	4'd13: nextstate <= 4'd1;

	4'd3: begin
				if(sample_dout)
					nextstate <= 4'd6;
				else	
					nextstate <= 4'd3;
			end
	4'd6: begin
				if(sample_dout)
					nextstate <= 4'd6;
				else	
					nextstate <= 4'd7;
			end
	4'd7: begin
				if(olen_is0)
					nextstate <= 4'd15;
				else
					nextstate <= 4'd8;
			end			
	4'd8: nextstate <= 4'd9;				
	4'd9: nextstate <= 4'd3;					

	4'd15: begin
				if(shake_intermediate_rst)
					nextstate <= 4'd14;
				else		
					nextstate <= 4'd15;
			end		
	4'd14: begin
				if(shake_next_extract)
					nextstate <= 4'd8;
				else		
					nextstate <= 4'd14;
			end			
	default: nextstate <= 4'd0;
	endcase
end

assign sample_dout = dout_valid & ready & (!olen_is0);

assign done_wire = (state==4'd15) ? 1'b1 : 1'b0;
always @(posedge clk)
    done <= done_wire;

endmodule

timescale 1ns / 1ps






















module copy_words(clk, rst, number_words, 
									read_address, read_data,
									write_address, write_data, write_en,
									done);
input clk, rst;
input [8:0] number_words;
output reg [8:0] read_address;
input [63:0] read_data;

output reg [8:0] write_address;
output [63:0] write_data;
output reg write_en;
output done;

reg [63:0] temp;
reg [2:0] state, nextstate;
reg [8:0] write_address_r;
reg write_en_r;
reg read_address_en;
wire all_words_copied;

always @(posedge clk)
begin
	if(rst)
		read_address <= 9'd0;
	else if(read_address_en)
		read_address <= read_address + 1'b1;
	else	
		read_address <= read_address;
end

assign all_words_copied = (read_address == number_words) ? 1'b1 : 1'b0;

always @(posedge clk)
begin
	write_address_r <= read_address;
	write_address <= write_address_r;
	temp <= read_data;
end

assign write_data = temp;


always @(posedge clk)
begin
	if(rst)
		begin write_en <= 1'b0; write_en_r <= 1'b0; end
	else	
		begin write_en_r <= read_address_en; write_en <= write_en_r; end
end


always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else
		state <= nextstate;
end

always @(state or all_words_copied)
begin
	case(state)
	3'd0: begin
					read_address_en <= 1'b0; nextstate <= 3'd1;
				end
	3'd1: begin
					if(all_words_copied==1'b0)
					begin
						read_address_en <= 1'b1;  nextstate <= 3'd1;
					end
					else
					begin
						read_address_en <= 1'b0;  nextstate <= 3'd2;
					end
				end
	3'd2: begin
					read_address_en <= 1'b0;  nextstate <= 3'd3;
				end
	3'd3: begin
					read_address_en <= 1'b0;  nextstate <= 3'd4;
				end				
	3'd4: begin
					read_address_en <= 1'b0;  nextstate <= 3'd4;
				end				
	default: begin
					read_address_en <= 1'b0; nextstate <= 3'd0;
				end		
	endcase					
end		

assign done = (state==3'd4) ? 1'b1 : 1'b0;

endmodule

include "config.vh"

define TCLKS BITCLKS[TMR_LEN-1:0]

module uart_rx #(
    parameter   BITCLKS = 868,              
    parameter   TMR_LEN = 14                
) (
    input wire          clk,                
    input wire          rst,                
    input wire          ack,                
    output reg  [7:0]   data,               
    output reg          rdy,                

    output wire         rts,                
    input wire          rxd                 
);
    assign      rts = !rdy;
    reg [TMR_LEN-1:0]   tmr;                
    reg [7:0]           rdata;              
    reg [3:0]           idx;                

    always @(posedge clk) begin

        if (rst) begin                      

            tmr <= 0;
            idx <= 9;
            rdy <= 0;

        end else begin

            if ( tmr != 0 ) begin

                tmr <= tmr - 1'b1;
                if (ack) begin              
                    rdy <= 0;
                end

            end else begin



                case (idx)


                    0,1,2,3,4,5,6,7: begin
                        rdata[idx[2:0]] <= rxd;
                        idx <= idx + 1;
                        tmr <= TCLKS - 1;  
                    end


                    8: if (rxd) begin
                        data <= rdata;
                        rdy <= 1;
                        idx <= 9;
                        tmr <= TCLKS / 16; 
                    end


                    9:  if (!rxd) begin
                        idx <= 0;
                        tmr <= 3 * TCLKS / 2; 
                    end else
                        tmr <= TCLKS / 16; 

                    default:
                        idx <= 9;

                endcase

            end
        end
    end

endmodule

include "config.vh"

module sloth_top (
    input wire          clk,                
    input wire          rst,                
    output wire         uart_txd,           
    input wire          uart_rxd,           
    output wire         uart_rts,           
    input wire          uart_cts,           
    output reg  [7:0]   gpio_out,           
    input wire  [7:0]   gpio_in,            
    output wire         trap,

    output wire [3:0]           wen0,       
    output wire [RAM_XADR-3:0] addr0,
    output wire [31:0]          wdata0,
    input wire  [31:0]          rdata0,
    output wire [RAM_XADR-3:0] addr1,      
    input wire  [31:0]          rdata1
);

    parameter   XLEN            = 32;


    parameter   SEL_NONE        = 0;
    parameter   SEL_RAM         = 1;
    parameter   SEL_MMIO        = 2;
    parameter   SEL_KECTI3      = 4;
    parameter   SEL_KECCAK      = 5;
    parameter   SEL_SHA256      = 6;
    parameter   SEL_SHA512      = 7;


    parameter   RAM_BASE        = 32'h0000_0000;
    parameter   RAM_XADR        = RAM_XADR;
    parameter   RAM_SIZE        = (1 << RAM_XADR);


    parameter   MMIO_BASE       = 32'h1000_0000;
    parameter   MMIO_UART_TX    = 0;
    parameter   MMIO_UART_TXOK  = 1;
    parameter   MMIO_UART_RX    = 2;
    parameter   MMIO_UART_RXOK  = 3;
    parameter   MMIO_GET_TICKS  = 4;
    parameter   MMIO_GPIO_IN    = 5;
    parameter   MMIO_GPIO_OUT   = 6;


    parameter   KECTI3_BASE     = 32'h1400_0000;
    parameter   KECCAK_BASE     = 32'h1500_0000;
    parameter   SHA256_BASE     = 32'h1600_0000;
    parameter   SHA512_BASE     = 32'h1700_0000;


    reg         reset   = 1;
    reg [31:0]  cycle_count;
    reg         irq     = 0;

    wire        core_trap;

    assign      trap    = core_trap;
    wire        btn_rst = 0;



    always @(posedge clk) begin
        if  (rst) begin
            reset   <= 1;
        end else begin
            if (reset)
                cycle_count <= 0;
            else
                cycle_count <= cycle_count + 1;
            reset   <= 0;
        end
    end


    wire        mem0_valid;
    wire        mem0_ready;
    wire [31:0] mem0_addr;
    wire [31:0] mem0_wdata;
    wire [3:0]  mem0_wstrb;
    wire [31:0] mem0_rdata;

    wire        mem1_valid;
    wire        mem1_ready;
    wire [31:0] mem1_addr;
    wire [31:0] mem1_rdata;

    pug_rv32 #(
        .XLEN       (XLEN       ),
        .RESET_PC   ('h0000_0000),
        .RESET_SP   (RAM_SIZE-4 )
    ) cpu0 (
        .clk        (clk        ),
        .rst        (reset      ),
        .trap       (core_trap  ),
        .irq        (irq        ),
        .mem0_valid (mem0_valid ),
        .mem0_ready (mem0_ready ),
        .mem0_addr  (mem0_addr  ),
        .mem0_wdata (mem0_wdata ),
        .mem0_wstrb (mem0_wstrb ),
        .mem0_rdata (mem0_rdata ),
        .mem1_valid (mem1_valid ),
        .mem1_ready (mem1_ready ),
        .mem1_addr  (mem1_addr  ),
        .mem1_rdata (mem1_rdata )
    );


    wire        ram_sel     = mem0_valid &&
                                mem0_addr[31:24] == RAM_BASE[31:24];

    wire        mmio_sel    = mem0_valid &&
                                mem0_addr[31:24] == MMIO_BASE[31:24];
ifdef SLOTH_KECCAK
    wire        keccak_sel  =  mem0_valid &&
                                mem0_addr[31:24] == KECCAK_BASE[31:24];
endif
ifdef SLOTH_SHA256
    wire        sha256_sel  =  mem0_valid &&
                                mem0_addr[31:24] == SHA256_BASE[31:24];
endif
ifdef SLOTH_SHA512
    wire        sha512_sel  =  mem0_valid &&
                                mem0_addr[31:24] == SHA512_BASE[31:24];
endif
ifdef SLOTH_KECTI3
    wire        kecti3_sel  =  mem0_valid &&
                                mem0_addr[31:24] == KECTI3_BASE[31:24];
endif



    wire [31:0]     rdata_ram = rdata0;

    assign  mem1_rdata  =   rdata1;
    assign  wen0        =   ram_sel ? mem0_wstrb : 4'b0000;
    assign  addr0       =   mem0_addr[RAM_XADR - 1:2];
    assign  wdata0      =   mem0_wdata;
    assign  addr1       =   mem1_addr[RAM_XADR - 1:2];





ifdef  CONF_UART_TX

    reg [7:0]       uart_out;               
    reg             uart_send;              
    wire            uart_txok;              

ifdef SIM_TB

    assign          uart_txd =  0;
    reg             tx_send1 = 0;
    assign          uart_txok = uart_cts && !tx_send1;
    always @(posedge clk) begin
        if (uart_send && !tx_send1) begin
            $write("%c", uart_out);
            $fflush(1);
        end
        tx_send1    <=  uart_send;
    end
else
    uart_tx #(
        .BITCLKS    (UART_BITCLKS)
    ) uart0_tx (
        .clk        (clk        ),
        .rst        (reset      ),
        .send       (uart_send  ),
        .data       (uart_out   ),
        .rdy        (uart_txok  ),
        .cts        (uart_cts   ),
        .txd        (uart_txd   )
    );
endif
endif



ifdef CONF_UART_RX
    wire [7:0]      uart_data;              
    wire            uart_rxok;              
    reg             uart_poll;

    uart_rx #(
        .BITCLKS    (UART_BITCLKS)
    ) uart0_rx (
        .clk        (clk        ),
        .rst        (reset      ),
        .ack        (uart_poll  ),
        .data       (uart_data  ),
        .rdy        (uart_rxok  ),
        .rts        (uart_rts   ),
        .rxd        (uart_rxd   )
    );
endif



    reg [31:0]      rdata_mmio;

    always @(posedge clk) begin

ifdef CONF_UART_RX
        uart_poll   <=  0;                  
endif
        uart_send   <=  0;

        if (mmio_sel) begin

            case (mem0_addr[7:2])

                MMIO_UART_TX: begin         
                    if (mem0_wstrb[0]) begin
                        uart_out    <=  mem0_wdata[7:0];
                        uart_send   <=  1;
                    end
                end

ifdef CONF_UART_TX
                MMIO_UART_TXOK: begin       
                    rdata_mmio  <=  { 31'b0, uart_txok };
                end
endif

ifdef CONF_UART_RX
                MMIO_UART_RX: begin         
                    rdata_mmio  <=  { 24'b0, uart_data };
                    uart_poll   <=  1;
                end

                MMIO_UART_RXOK:             
                    rdata_mmio  <=  { 31'b0, uart_rxok };
endif

                MMIO_GET_TICKS:             
                    rdata_mmio  <=  cycle_count;

ifdef CONF_GPIO
                MMIO_GPIO_IN:               
                    rdata_mmio  <=  { 24'b0, gpio_in };

                MMIO_GPIO_OUT:              
                    if (|mem0_wstrb)
                        gpio_out    <=  mem0_wdata[7:0];
endif
ifdef CORE_DEBUG
                default:
                    $display("[MMIO]\taddr=%08h  wdata=%08h  wstrb=%04b",
                        mem0_addr, mem0_wdata, mem0_wstrb);
endif
            endcase
        end
    end



ifdef SLOTH_KECTI3
    wire            kecti3_irq;
    wire [31:0]     kecti3_rdata;

    kecti3_sloth kecti3_sloth_0 (
        .clk        (clk            ),
        .rst        (reset          ),
        .sel        (kecti3_sel     ),
        .irq        (kecti3_irq     ),
        .wen        (mem0_wstrb     ),
        .addr       (mem0_addr[9:2] ),
        .wdata      (mem0_wdata     ),
        .rdata      (kecti3_rdata   )
    );
endif

ifdef SLOTH_KECCAK
    wire            keccak_irq;
    wire [31:0]     keccak_rdata;

    keccak_sloth keccak_sloth_0 (
        .clk        (clk            ),
        .rst        (reset          ),
        .sel        (keccak_sel     ),
        .irq        (keccak_irq     ),
        .wen        (mem0_wstrb     ),
        .addr       (mem0_addr[8:2] ),
        .wdata      (mem0_wdata     ),
        .rdata      (keccak_rdata   )
    );
endif

ifdef SLOTH_SHA256
    wire            sha256_irq;
    wire [31:0]     sha256_rdata;

    sha256_sloth sha256_sloth_0 (
        .clk        (clk            ),
        .rst        (reset          ),
        .sel        (sha256_sel     ),
        .irq        (sha256_irq     ),
        .wen        (mem0_wstrb     ),
        .addr       (mem0_addr[8:2] ),
        .wdata      (mem0_wdata     ),
        .rdata      (sha256_rdata   )
    );
endif

ifdef SLOTH_SHA512
    wire            sha512_irq;
    wire [31:0]     sha512_rdata;

    sha512_sloth sha512_sloth_0 (
        .clk        (clk            ),
        .rst        (reset          ),
        .sel        (sha512_sel     ),
        .irq        (sha512_irq     ),
        .wen        (mem0_wstrb     ),
        .addr       (mem0_addr[8:2] ),
        .wdata      (mem0_wdata     ),
        .rdata      (sha512_rdata   )
    );
endif



ifdef CONF_UART_TX
    reg             oldtxok = 0;
endif
ifdef CONF_UART_RX
    reg             oldrxok = 0;
endif
    reg [31:0]      mstimer = SLOTH_CLK / 1000;

    always @(posedge clk) begin

        irq         <=  0;                  


        if (mstimer == 0) begin
            mstimer <=  SLOTH_CLK / 1000 - 1;
            irq     <=  1;
        end else begin
            mstimer <=  mstimer - 1;
        end


ifdef CONF_UART_TX
        if (uart_txok && !oldtxok) begin
            irq     <=  1;
        end
        oldtxok     <=  uart_txok;
endif

ifdef CONF_UART_RX
        if (uart_rxok && !oldrxok) begin
            irq     <=  1;
        end
        oldrxok     <=  uart_rxok;
endif

ifdef SLOTH_KECTI3
        if (kecti3_irq) begin
            irq     <=  1;
        end
endif

ifdef SLOTH_KECCAK
        if (keccak_irq) begin
            irq     <=  1;
        end
endif

ifdef SLOTH_SHA256
        if (sha256_irq) begin
            irq     <=  1;
        end
endif

ifdef SLOTH_SHA512
        if (sha512_irq) begin
            irq     <=  1;
        end
endif

    end



    reg [2:0]   rdata_src   = 0;

    assign      mem0_rdata  =   rdata_src == SEL_RAM    ? rdata_ram  :
                                rdata_src == SEL_MMIO   ? rdata_mmio :
ifdef SLOTH_KECTI3
                                rdata_src == SEL_KECTI3 ? kecti3_rdata :
endif
ifdef SLOTH_KECCAK
                                rdata_src == SEL_KECCAK ? keccak_rdata :
endif
ifdef SLOTH_SHA256
                                rdata_src == SEL_SHA256 ? sha256_rdata :
endif
ifdef SLOTH_SHA512
                                rdata_src == SEL_SHA512 ? sha512_rdata :
endif
                                32'hDEAD_BEEF;

    assign      mem0_ready = 1;
    assign      mem1_ready = 1;



    always @(posedge clk) begin

        rdata_src           <=  ram_sel     ?   SEL_RAM :
                                mmio_sel    ?   SEL_MMIO :
ifdef SLOTH_KECTI3
                                kecti3_sel  ?   SEL_KECTI3 :
endif
ifdef SLOTH_KECCAK
                                keccak_sel  ?   SEL_KECCAK :
endif
ifdef SLOTH_SHA256
                                sha256_sel  ?   SEL_SHA256 :
endif
ifdef SLOTH_SHA512
                                sha512_sel  ?   SEL_SHA512 :
endif
                                SEL_NONE;
    end

endmodule

include "config.vh"

module fpga_top (
    input wire          clk,                
    input wire          rst,                
    output wire         uart_txd,           
    input wire          uart_rxd,           
    output wire         uart_rts,           
    input wire          uart_cts,           
    output wire [7:0]   gpio_out,           
    input wire  [7:0]   gpio_in,            
    output wire         trap
);
    parameter   XLEN            = 32;
    parameter   RAM_XADR        = RAM_XADR;
    parameter   RAM_SIZE        = (1 << RAM_XADR);

    wire    [3:0]           wen0;
    wire    [RAM_XADR-3:0]  addr0;
    wire    [31:0]          wdata0;
    wire    [31:0]          rdata0;
    wire    [RAM_XADR-3:0]  addr1;
    wire    [31:0]          rdata1;



    sloth_top sloth_top_0 (
        .clk        (clk        ),
        .rst        (rst        ),
        .uart_txd   (uart_txd   ),
        .uart_rxd   (uart_rxd   ),
        .uart_rts   (uart_rts   ),
        .uart_cts   (uart_cts   ),
        .gpio_in    (gpio_in    ),
        .gpio_out   (gpio_out   ),
        .trap       (trap       ),
        .wen0       (wen0       ),
        .addr0      (addr0      ),
        .wdata0     (wdata0     ),
        .rdata0     (rdata0     ),
        .addr1      (addr1      ),
        .rdata1     (rdata1     )
    );



    fpga_ram #(
        .XLEN       (XLEN       ),
        .XADR       (RAM_XADR - 2),
        .XSIZ       (RAM_SIZE / 4)
    ) fpga_ram_0 (
        .clk        (clk        ),
        .wen0       (wen0       ),
        .addr0      (addr0      ),
        .wdata0     (wdata0     ),
        .rdata0     (rdata0     ),
        .addr1      (addr1      ),
        .rdata1     (rdata1     )
    );
endmodule

include "config.vh"
ifdef SLOTH_KECTI3
include "mem_block.vh"





module kecti3_sloth (
    input wire          clk,
    input wire          rst,
    input wire          sel,
    output reg          irq,
    input wire  [3:0]   wen,
    input wire  [7:0]   addr,
    input wire  [31:0]  wdata,
    output reg  [31:0]  rdata
);

    localparam  KTI3_MEMA   =   0;
    localparam  KTI3_MEMB   =   50;
    localparam  KTI3_MEMC   =   100;
    localparam  KTI3_ADRS   =   152;
    localparam  KTI3_SEED   =   160;
    localparam  KTI3_SKSA   =   168;
    localparam  KTI3_SKSB   =   176;
    localparam  KTI3_SKSC   =   184;
    localparam  KTI3_MTOP   =   192;

    localparam  KTI3_CTRL   =   240;
    localparam  KTI3_TRIG   =   240;
    localparam  KTI3_STOP   =   241;
    localparam  KTI3_SECN   =   242;
    localparam  KTI3_CHNS   =   243;


    function automatic [7:0] rc_step;
        input [7:0]  r_i;           



        rc_step =   ({8{r_i[0]}} & 8'h1A) ^ ({8{r_i[1]}} & 8'h34) ^
                    ({8{r_i[2]}} & 8'h68) ^ ({8{r_i[3]}} & 8'hD0) ^
                    ({8{r_i[4]}} & 8'hBA) ^ ({8{r_i[5]}} & 8'h6E) ^
                    ({8{r_i[6]}} & 8'hC6) ^ ({8{r_i[7]}} & 8'h8D);
    endfunction


    function automatic [1599:0] padf;
        input [7:0] n;
        input [255:0] seed, adrs, m;
        padf =  (n == 16) ? {   
                    512'b0, 8'h80, 560'b0, 8'h1F,
                    m[127:0], adrs, seed[127:0] } :
                (n == 24) ? {   
                    512'b0, 8'h80, 432'b0, 8'h1F,
                    m[191:0], adrs, seed[191:0] } :
                {   
                    512'b0, 8'h80, 304'b0, 8'h1F,
                    m[255:0], adrs, seed[255:0] };
    endfunction

    wire                msel_w = addr < KTI3_CTRL;
    wire    [7:0]       csel_w = addr;      

    reg     [31:0]      mem [0:KTI3_MTOP - 1];      

    reg     [7:0]       stop_r;     
    reg     [7:0]       rndc_r;     
    reg     [7:0]       secn_r;     
    reg     [7:0]       chns_r;     
    reg     [7:0]       chni_r;     
    wire    just_pad_w = chns_r[7];
    wire    wots_prf_w = chns_r[6];



    wire    [1599:0]    a_o_w;      
    wire    [1599:0]    b_o_w;
    wire    [1599:0]    c_o_w;

    wire    [1599:0]    a_i_m = MEM_BLOCK_50(KTI3_MEMA);
    wire    [1599:0]    b_i_m = MEM_BLOCK_50(KTI3_MEMB);
    wire    [1599:0]    c_i_m = MEM_BLOCK_50(KTI3_MEMC);

    wire    [255:0] adrs_m   = {
        mem[KTI3_ADRS + 7] + {chni_r, 24'b0 },
        mem[KTI3_ADRS + 6], MEM_BLOCK_6(KTI3_ADRS) };

    wire    [255:0] seed_m  = MEM_BLOCK_8(KTI3_SEED);

    wire    [255:0] hsha_m  = a_i_m[255:0];
    wire    [255:0] hshb_m  = b_i_m[255:0];
    wire    [255:0] hshc_m  = c_i_m[255:0];

    wire    [255:0] sksa_m  = MEM_BLOCK_8(KTI3_SKSA);
    wire    [255:0] sksb_m  = MEM_BLOCK_8(KTI3_SKSB);
    wire    [255:0] sksc_m  = MEM_BLOCK_8(KTI3_SKSC);

    reg     [3:0]   refi_r;     
    wire    [7:0]   refa_w = { KTI3_SKSA[7:3], refi_r[2:0] };
    wire    [7:0]   refb_w = { KTI3_SKSB[7:3], refi_r[2:0] };
    wire    [7:0]   refc_w = { KTI3_SKSC[7:3], refi_r[2:0] };


    kecti3_round kecti3_0 (
        .a_o(a_o_w),
        .b_o(b_o_w),
        .c_o(c_o_w),
        .a_i(a_i_m),
        .b_i(b_i_m),
        .c_i(c_i_m),
        .r_i(rndc_r)
    );

    always @(posedge clk) begin

        irq     <=  0;                      


        if (sel && msel_w) begin            

            rdata   <=  mem[addr];
            if (wen[0]) mem[addr][ 7: 0]    <=  wdata[ 7: 0];
            if (wen[1]) mem[addr][15: 8]    <=  wdata[15: 8];
            if (wen[2]) mem[addr][23:16]    <=  wdata[23:16];
            if (wen[3]) mem[addr][31:24]    <=  wdata[31:24];

        end else begin

            if (sel) begin


                case (csel_w)

                    KTI3_TRIG:  begin
                        rdata   <=  { 16'b0, chns_r, rndc_r };
                        if (wen[0]) begin
                            rndc_r  <=  wdata[ 7: 0];
                        end
                    end

                    KTI3_STOP: begin
                        rdata   <=  { 24'b0, stop_r };
                        if (wen[0]) begin
                            stop_r  <=  wdata[ 7: 0];
                        end
                    end

                    KTI3_SECN: begin
                        rdata   <=  { 24'b0, secn_r };
                        if (wen[0]) begin
                            secn_r  <=  wdata[ 7: 0];
                        end
                    end

                    KTI3_CHNS: begin
                        rdata   <=  { 24'b0, chns_r };
                        if (wen[0]) begin
                            chns_r  <=  wdata[ 7: 0];
                            chni_r  <=  8'h00;
                        end
                    end

                endcase
            end


            if (rndc_r != 8'h00) begin


                MEM_BLOCK_50(KTI3_MEMA) <= a_o_w;
                MEM_BLOCK_50(KTI3_MEMB) <= b_o_w;
                MEM_BLOCK_50(KTI3_MEMC) <= c_o_w;


                refi_r <= refi_r + 1;
                mem[refb_w] <=  b_o_w[31:0] ^ mem[refb_w];
                if (refi_r[3]) begin
                    mem[refc_w] <=  b_o_w[31:0] ^ mem[refc_w];
                end else begin
                    mem[refa_w] <=  b_o_w[31:0] ^ mem[refa_w];
                end


                if (rndc_r == stop_r) begin
                    rndc_r  <=  8'h00;      
                    if (chns_r == 8'h00) begin
                        irq     <=  1;
                    end
                end else begin
                    rndc_r  <=  rc_step(rndc_r);    
                end

            end else if (chns_r != 0) begin


                MEM_BLOCK_50(KTI3_MEMA) <=
                    padf(secn_r, seed_m, 256'b0, wots_prf_w ? sksa_m : hsha_m);
                MEM_BLOCK_50(KTI3_MEMB) <=
                    padf(secn_r, 256'b0, adrs_m, wots_prf_w ? sksb_m : hshb_m);
                MEM_BLOCK_50(KTI3_MEMC) <=
                    padf(secn_r, 256'b0, 256'b0, wots_prf_w ? sksc_m : hshc_m);

                if (just_pad_w) begin


                    chns_r  <=  8'h00;

                end else if (wots_prf_w) begin


                    mem[KTI3_ADRS + 4][31:24] <=
                        (mem[KTI3_ADRS + 4][31:24] == 8'h05 ? 8'h00 : 8'h03);
                    chns_r  <=  { 2'b00, chns_r[5:0] };
                    rndc_r  <=  8'h01;

                end else begin
                    chns_r  <=  chns_r - 1;
                    chni_r  <=  chni_r + 1;
                    rndc_r  <=  8'h01;
                end
            end
        end



        if (rst) begin
            rndc_r  <=  8'h00;
            stop_r  <=  8'h74;
            chns_r  <=  8'h00;
            chni_r  <=  8'h00;
            secn_r  <=  8'h10;

            refi_r  <=  0;
        end
    end

endmodule

endif

module uart_tx #(
    parameter   BITCLKS = 868,          
    parameter   TMR_LEN = 14            
) (
    input wire          clk,            
    input wire          rst,            
    input wire          send,           
    input wire  [7:0]   data,           
    output wire         rdy,            

    input wire          cts,            
    output reg          txd             
);

    reg [TMR_LEN-1:0]   tmr;            
    reg [9:0]           tdata;          
    reg [3:0]           idx;            
    reg                 fin;            

    assign  rdy = fin && cts;

    always @(posedge clk) begin

        if (rst) begin                  

            fin <= 1;
            tmr <= 0;
            idx <= 10;
            txd <= 1;
            tdata <= { 10'b1_1111_111_1 };

        end else begin

            if (send) begin

                tdata <= { 1'b1, data, 1'b0 };
                fin <= 0;
                idx <= 0;
                tmr <= 0;
            end

            if (fin) begin                  

                idx <= 0;
                tmr <= 0;
                txd <= 1;

            end else begin

                if (tmr == 0) begin         
                    if (idx == 10)
                        fin <= 1;
                    else begin
                        txd <= tdata[idx];
                        idx <= idx + 1;
                        tmr <= BITCLKS[TMR_LEN-1:0] - 1;
                    end
                end else begin
                    tmr <= tmr - 1;
                end
            end
        end
    end
endmodule

include "config.vh"
ifdef SLOTH_SHA256

module sha256_round(
    output wire [255:0]     h_o,        
    output wire [511:0]     m_o,        
    input wire  [255:0]     h_i,        
    input wire  [511:0]     m_i,        
    input wire  [5:0]       t_i         
);

    reg [31:0] k_w;

    always@(t_i) begin
        case(t_i)
            6'h00: k_w = 32'h428A2F98;
            6'h01: k_w = 32'h71374491;
            6'h02: k_w = 32'hB5C0FBCF;
            6'h03: k_w = 32'hE9B5DBA5;
            6'h04: k_w = 32'h3956C25B;
            6'h05: k_w = 32'h59F111F1;
            6'h06: k_w = 32'h923F82A4;
            6'h07: k_w = 32'hAB1C5ED5;
            6'h08: k_w = 32'hD807AA98;
            6'h09: k_w = 32'h12835B01;
            6'h0A: k_w = 32'h243185BE;
            6'h0B: k_w = 32'h550C7DC3;
            6'h0C: k_w = 32'h72BE5D74;
            6'h0D: k_w = 32'h80DEB1FE;
            6'h0E: k_w = 32'h9BDC06A7;
            6'h0F: k_w = 32'hC19BF174;
            6'h10: k_w = 32'hE49B69C1;
            6'h11: k_w = 32'hEFBE4786;
            6'h12: k_w = 32'h0FC19DC6;
            6'h13: k_w = 32'h240CA1CC;
            6'h14: k_w = 32'h2DE92C6F;
            6'h15: k_w = 32'h4A7484AA;
            6'h16: k_w = 32'h5CB0A9DC;
            6'h17: k_w = 32'h76F988DA;
            6'h18: k_w = 32'h983E5152;
            6'h19: k_w = 32'hA831C66D;
            6'h1A: k_w = 32'hB00327C8;
            6'h1B: k_w = 32'hBF597FC7;
            6'h1C: k_w = 32'hC6E00BF3;
            6'h1D: k_w = 32'hD5A79147;
            6'h1E: k_w = 32'h06CA6351;
            6'h1F: k_w = 32'h14292967;
            6'h20: k_w = 32'h27B70A85;
            6'h21: k_w = 32'h2E1B2138;
            6'h22: k_w = 32'h4D2C6DFC;
            6'h23: k_w = 32'h53380D13;
            6'h24: k_w = 32'h650A7354;
            6'h25: k_w = 32'h766A0ABB;
            6'h26: k_w = 32'h81C2C92E;
            6'h27: k_w = 32'h92722C85;
            6'h28: k_w = 32'hA2BFE8A1;
            6'h29: k_w = 32'hA81A664B;
            6'h2A: k_w = 32'hC24B8B70;
            6'h2B: k_w = 32'hC76C51A3;
            6'h2C: k_w = 32'hD192E819;
            6'h2D: k_w = 32'hD6990624;
            6'h2E: k_w = 32'hF40E3585;
            6'h2F: k_w = 32'h106AA070;
            6'h30: k_w = 32'h19A4C116;
            6'h31: k_w = 32'h1E376C08;
            6'h32: k_w = 32'h2748774C;
            6'h33: k_w = 32'h34B0BCB5;
            6'h34: k_w = 32'h391C0CB3;
            6'h35: k_w = 32'h4ED8AA4A;
            6'h36: k_w = 32'h5B9CCA4F;
            6'h37: k_w = 32'h682E6FF3;
            6'h38: k_w = 32'h748F82EE;
            6'h39: k_w = 32'h78A5636F;
            6'h3A: k_w = 32'h84C87814;
            6'h3B: k_w = 32'h8CC70208;
            6'h3C: k_w = 32'h90BEFFFA;
            6'h3D: k_w = 32'hA4506CEB;
            6'h3E: k_w = 32'hBEF9A3F7;
            6'h3F: k_w = 32'hC67178F2;
        endcase
    end



    function automatic [31:0] rotr;
        input [31:0] x, n;
        begin
            rotr = (x >> n) | (x << (32 - n));
        end
    endfunction



    function automatic [31:0] ch;
        input [31:0] x, y, z;
        begin
            ch = (x & y) ^ (~x & z);
        end
    endfunction

    function automatic [31:0] maj;
        input [31:0] x, y, z;
        begin
            maj = (x & y) ^ (x & z) ^ (y & z);
        end
    endfunction

    function automatic [31:0] sum0;
        input [31:0] x;
        begin
            sum0 =  rotr(x, 2) ^ rotr(x, 13) ^ rotr(x, 22);
        end
    endfunction

    function automatic [31:0] sum1;
        input [31:0] x;
        begin
            sum1 =  rotr(x, 6) ^ rotr(x, 11) ^ rotr(x, 25);
        end
    endfunction

    function automatic [31:0] sig0;
        input [31:0] x;
        begin
            sig0 =  rotr(x, 7) ^ rotr(x, 18) ^ (x >> 3);
        end
    endfunction

    function automatic [31:0] sig1;
        input [31:0] x;
        begin
            sig1 =  rotr(x, 17) ^ rotr(x, 19) ^ (x >> 10);
        end
    endfunction


    wire    [31:0]  w_i     =   m_i[ 31:  0];


    wire    [31:0]  t16_w   =   m_i[ 31:  0];
    wire    [31:0]  t15_w   =   m_i[ 63: 32];
    wire    [31:0]  t07_w   =   m_i[319:288];
    wire    [31:0]  t02_w   =   m_i[479:448];
    wire    [31:0]  wt_w;

    assign  wt_w =  sig1(t02_w) + t07_w + sig0(t15_w) + t16_w;


    assign  m_o =   { wt_w, m_i[511:32] };


    wire    [31:0]  a_w, b_w, c_w, d_w, e_w, f_w, g_w, h_w;
    assign  { h_w, g_w, f_w, e_w, d_w, c_w, b_w, a_w } = h_i;



    wire    [31:0]  t1_w, t2_w;
    assign  t1_w = h_w + sum1(e_w) + ch(e_w, f_w, g_w) + k_w + w_i;
    assign  t2_w = sum0(a_w) + maj(a_w, b_w, c_w);

    assign  h_o = { g_w,                
                    f_w,                
                    e_w,                
                    d_w  + t1_w,        
                    c_w,                
                    b_w,                
                    a_w,                
                    t1_w + t2_w };      

endmodule

endif

include "config.vh"
ifdef SLOTH_KECCAK
include "mem_block.vh"





module keccak_sloth (
    input wire          clk,
    input wire          rst,
    input wire          sel,
    output reg          irq,
    input wire  [3:0]   wen,
    input wire  [6:0]   addr,
    input wire  [31:0]  wdata,
    output reg  [31:0]  rdata
);

    localparam  KECC_MEMA   =   0;
    localparam  KECC_ADRS   =   50;
    localparam  KECC_SEED   =   58;
    localparam  KECC_SKSD   =   66;
    localparam  KECC_MTOP   =   74;
    localparam  KECC_CTRL   =   120;
    localparam  KECC_TRIG   =   120;
    localparam  KECC_STOP   =   121;
    localparam  KECC_SECN   =   122;
    localparam  KECC_CHNS   =   123;


    function automatic [1599:0] padf;
        input [7:0] n;
        input [255:0] seed, adrs, m;
        padf =  (n == 16) ? {   
                    512'b0, 8'h80, 560'b0, 8'h1F,
                    m[127:0], adrs, seed[127:0] } :
                (n == 24) ? {   
                    512'b0, 8'h80, 432'b0, 8'h1F,
                    m[191:0], adrs, seed[191:0] } :
                {   
                    512'b0, 8'h80, 304'b0, 8'h1F,
                    m[255:0], adrs, seed[255:0] };
    endfunction

    wire                msel_w = addr < KECC_CTRL;
    wire    [6:0]       csel_w = addr;      

    reg     [31:0]      mem [0:KECC_MTOP - 1];      

    reg     [7:0]       stop_r;     
    reg     [7:0]       rndc_r;     
    reg     [7:0]       secn_r;     
    reg     [7:0]       chns_r;     
    reg     [7:0]       chni_r;     
    wire    just_pad_w = chns_r[7];
    wire    wots_prf_w = chns_r[6];
    wire    [1599:0]    st_o_w;     
    wire    [7:0]       rc_o_w;     


    wire    [1599:0]    st_i_w = MEM_BLOCK_50(KECC_MEMA);


    keccak_round keccak_0 (
        .s_o(st_o_w ),                          
        .r_o(rc_o_w ),                          
        .s_i(st_i_w ),                          
        .r_i(rndc_r )                           
    );


    wire    [255:0] adrs_w   = {
        mem[KECC_ADRS + 7] + {chni_r, 24'b0 },
        mem[KECC_ADRS + 6], MEM_BLOCK_6(KECC_ADRS) };

    wire    [255:0] seed_m  = MEM_BLOCK_8(KECC_SEED);
    wire    [255:0] hash_m  = st_i_w[255:0];
    wire    [255:0] sksd_m  = MEM_BLOCK_8(KECC_SKSD);

    always @(posedge clk) begin

        irq     <=  0;              


        if (sel && msel_w) begin        

            rdata   <=  mem[addr];
            if (wen[0]) mem[addr][ 7: 0]    <=  wdata[ 7: 0];
            if (wen[1]) mem[addr][15: 8]    <=  wdata[15: 8];
            if (wen[2]) mem[addr][23:16]    <=  wdata[23:16];
            if (wen[3]) mem[addr][31:24]    <=  wdata[31:24];

        end else begin

            if (sel) begin


                case (csel_w)

                    KECC_TRIG:  begin
                        rdata   <=  { 16'b0, chns_r, rndc_r };
                        if (wen[0]) begin
                            rndc_r  <=  wdata[ 7: 0];
                        end
                    end

                    KECC_STOP: begin
                        rdata   <=  { 24'b0, stop_r };
                        if (wen[0]) begin
                            stop_r  <=  wdata[ 7: 0];
                        end
                    end

                    KECC_SECN: begin
                        rdata   <=  { 24'b0, secn_r };
                        if (wen[0]) begin
                            secn_r  <=  wdata[ 7: 0];
                        end
                    end

                    KECC_CHNS: begin
                        rdata   <=  { 24'b0, chns_r };
                        if (wen[0]) begin
                            chns_r  <=  wdata[ 7: 0];
                            chni_r  <=  8'h00;
                        end
                    end

                endcase
            end


            if (rndc_r != 8'h00) begin


                MEM_BLOCK_50(KECC_MEMA) <= st_o_w;

                if (rndc_r == stop_r) begin     
                    rndc_r  <=  8'h00;          
                    if (chns_r == 8'h00) begin
                        irq     <=  1;
                    end
                end else begin
                    rndc_r  <=  rc_o_w;         
                end

            end else if (chns_r != 0) begin


                MEM_BLOCK_50(KECC_MEMA) <=
                    padf(secn_r, seed_m, adrs_w, wots_prf_w ? sksd_m : hash_m);

                if (just_pad_w) begin


                    chns_r  <=  8'h00;

                end else if (wots_prf_w) begin


                    mem[KECC_ADRS + 4][31:24] <=
                        (mem[KECC_ADRS + 4][31:24] == 8'h05 ? 8'h00 : 8'h03);
                    chns_r  <=  { 2'b00, chns_r[5:0] };
                    rndc_r  <=  8'h01;

                end else begin
                    chns_r  <=  chns_r - 1;
                    chni_r  <=  chni_r + 1;
                    rndc_r  <=  8'h01;
                end
            end
        end



        if (rst) begin
            rndc_r  <=  8'h00;
            stop_r  <=  8'h74;
            chns_r  <=  8'h00;
            chni_r  <=  8'h00;
            secn_r  <=  8'h10;
        end
    end

endmodule

endif

include "config.vh"

timescale 1ns / 1ps
default_nettype none


include "cw305_regs.vh"

module cw305_usb_reg_fe #(
    parameter pADDR_WIDTH = 21,
    parameter pBYTECNT_SIZE = 7,
    parameter pREG_RDDLY_LEN = 3
)(
    input  wire                         usb_clk,
    input  wire                         rst,


    input  wire [7:0]                   usb_din,
    output wire [7:0]                   usb_dout,
    output wire                         usb_isout,
    input  wire [pADDR_WIDTH-1:0]       usb_addr,
    input  wire                         usb_rdn,
    input  wire                         usb_wrn,
    input  wire                         usb_alen,        
    input  wire                         usb_cen,


    output wire [pADDR_WIDTH-1:pBYTECNT_SIZE] reg_address,  
    output wire [pBYTECNT_SIZE-1:0]     reg_bytecnt,  
    output reg  [7:0]                   reg_datao,    
    input  wire [7:0]                   reg_datai,    
    output reg                          reg_read,     

    output wire                         reg_write,    

    output wire                         reg_addrvalid 
);

    reg [pADDR_WIDTH-1:0] usb_addr_r;
    reg usb_rdn_r;
    reg usb_wrn_r;
    reg usb_cen_r;
    reg [pREG_RDDLY_LEN-1:0] isoutreg;


    always @(posedge usb_clk) begin
        usb_addr_r <= usb_addr;
        usb_rdn_r <= usb_rdn;
        usb_wrn_r <= usb_wrn;
        usb_cen_r <= usb_cen;
    end

    assign reg_addrvalid = 1'b1;


    assign reg_address = usb_addr_r[pADDR_WIDTH-1:pBYTECNT_SIZE];


    assign reg_bytecnt = usb_addr_r[pBYTECNT_SIZE-1:0];

    assign reg_write = ~usb_cen_r & ~usb_wrn_r;

    always @(posedge usb_clk) begin
        if (~usb_cen & ~usb_rdn)
            reg_read <= 1'b1;
        else if (usb_rdn)
            reg_read <= 1'b0;
    end


    always @(posedge usb_clk) begin
        if (rst) begin
            isoutreg <= 0;
        end else begin
           isoutreg[0] <= ~usb_rdn_r;
           isoutreg[pREG_RDDLY_LEN-1:1] <= isoutreg[pREG_RDDLY_LEN-2:0];
        end
    end
    assign usb_isout = (|isoutreg) | (~usb_rdn_r);

    assign usb_dout = reg_datai;

    always @(posedge usb_clk)
        reg_datao <= usb_din;

endmodule

module cw305_iut #(
    parameter pADDR_WIDTH           = 21,
    parameter pBYTECNT_SIZE         = 7,
    parameter pDONE_EDGE_SENSITIVE  = 1,
    parameter pCRYPT_TYPE           = 13,
    parameter pCRYPT_REV            = 6,
    parameter pIDENTIFY             = 8'h2e
)(


    input  wire         usb_clk,
    input  wire         iut_clk,
    input  wire         reset,
    input  wire [pADDR_WIDTH-pBYTECNT_SIZE-1:0]
                        reg_address,    
    input  wire [pBYTECNT_SIZE-1:0]
                        reg_bytecnt,    
    output reg  [7:0]   read_data,      
    input  wire [7:0]   write_data,     
    input  wire         reg_read,       

    input  wire         reg_write,      

    input  wire         reg_addrvalid,  


    input  wire         ext_trig_in,    
    output wire         iut_trig_out,   
    output reg  [4:0]   o_clksettings,



    output  reg         o_user_led
);


    reg                 busy_usb = 0;
    wire [31:0]         buildtime;


    wire    core_trap;

ifdef CONF_GPIO
    wire    [7:0]   gpio_in = { 7'b0, ext_trig_in };
    wire    [7:0]   gpio_out;
    assign  iut_trig_out = gpio_out[0];
else
    assign  iut_trig_out = 0;
endif


    reg     [7:0]   urx_byte =  0;          
    reg     [7:0]   urx_idx =   0;          
    reg     [7:0]   urx_old =   0;          


    reg     [7:0]   utx_byte =  0;          
    reg     [7:0]   utx_idx =   0;          
    reg     [7:0]   utx_pos =   0;          


    wire    [7:0]   srx_byte;               
    wire            srx_rdy;                
    reg             srx_ack =   0;          
    wire            srx_rts;                


    wire            uut_cts_i   =   srx_rts && (utx_idx == utx_pos);

    uart_rx #(
        .BITCLKS    (UART_BITCLKS)
    ) srx_0 (
        .clk        (iut_clk    ),
        .rst        (reset      ),
        .ack        (srx_ack    ),
        .data       (srx_byte   ),
        .rdy        (srx_rdy    ),
        .rts        (srx_rts    ),
        .rxd        (uut_txd_o  )
    );


    reg     [7:0]   stx_byte = 8'h00;       
    reg             stx_send = 0;           
    wire            stx_txok;               

    uart_tx #(
        .BITCLKS    (UART_BITCLKS)
    ) stx_0 (
        .clk        (iut_clk    ),
        .rst        (reset      ),
        .send       (stx_send   ),
        .data       (stx_byte   ),
        .rdy        (stx_txok   ),
        .cts        (uut_rts_o  ),
        .txd        (uut_rxd_i  )
    );

    always @(posedge iut_clk) begin


        if  (srx_rdy && !srx_ack) begin
            utx_byte    <=  srx_byte;
            utx_idx     <=  utx_idx + 1;
            srx_ack     <=  1;


        end else begin

            if (!srx_rdy) begin
                srx_ack <= 0;
            end
        end


        if (stx_txok && (urx_idx != urx_old)) begin
            urx_old     <=  urx_idx;
            stx_byte    <=  urx_byte;
            stx_send    <=  1;
        end else begin
            stx_send    <=  0;
        end

        if (reset) begin
            utx_byte    <=  0;
            utx_idx     <=  0;
            urx_old     <=  0;
            stx_byte    <=  0;
            srx_ack     <=  0;
            stx_send    <=  0;
        end
    end



    always @(posedge usb_clk) begin

        if (reg_addrvalid && reg_read) begin
            case (reg_address)
                REG_CLKSETTINGS:   read_data   <=  o_clksettings;
                REG_USER_LED:      read_data   <=  o_user_led;
                REG_CRYPT_TYPE:    read_data   <=  pCRYPT_TYPE;
                REG_CRYPT_REV:     read_data   <=  pCRYPT_REV;
                REG_IDENTIFY:      read_data   <=  pIDENTIFY;
                REG_BUILDTIME:     read_data   <=  buildtime[reg_bytecnt*8 +: 8];

                REG_TX_BYTE:   begin
                                    read_data   <=  utx_byte;
                                    utx_pos     <=  utx_idx;
                                end
                REG_TX_IDX:        read_data   <=  utx_idx;
                REG_RX_POS:        read_data   <=  urx_old;
                default:            read_data   <=  0;
            endcase
        end else begin
            read_data <= 0;
        end


        if (reg_addrvalid && reg_write) begin
            case (reg_address)
                REG_CLKSETTINGS:   o_clksettings <= write_data;
                REG_USER_LED:      o_user_led  <=  write_data;
                REG_RX_BYTE:       urx_byte    <=  write_data;
                REG_RX_IDX:        urx_idx     <=  write_data;
            endcase
        end

        if (reset) begin
            urx_byte    <=  0;
            urx_idx     <=  0;
            utx_pos     <=  0;
        end
    end


    wire            uut_txd_o;
    wire            uut_rxd_i;
    wire            uut_rts_o;

    wire    [7:0]   gpio_in = 8'hAA;


    fpga_top fpga_top_0 (
        .clk        (iut_clk    ),
        .rst        (reset      ),
        .uart_txd   (uut_txd_o  ),
        .uart_rxd   (uut_rxd_i  ),
        .uart_rts   (uut_rts_o  ),
        .uart_cts   (uut_cts_i  ),
        .gpio_in    (gpio_in    ),
        .gpio_out   (gpio_out   ),
        .trap       (core_trap  )
    );




    ifndef SIM_TB
    USR_ACCESSE2 buildtime_0 (
        .CFGCLK(),
        .DATA(buildtime),
        .DATAVALID()
    );
    else
    assign buildtime = 0;
    endif

endmodule

module cw305_clocks (
    input  wire         usb_clk,
    output wire         usb_clk_buf,
    input  wire         I_j16_sel,
    input  wire         I_k16_sel,
    input  wire [4:0]   I_clock_reg,
    input  wire         I_cw_clkin,
    input  wire         I_pll_clk1,

    output wire         O_cw_clkout,
    output wire         O_cryptoclk
);

    wire cclk_src_is_ext;
    wire cclk_output_ext;
    wire usb_clk_bufg;


    assign cclk_src_is_ext = (I_clock_reg[2:0] == 3'b001) ? 0 : 
                             (I_clock_reg[2:0] == 3'b101) ? 1 : 
                             ((I_clock_reg[0] == 1'b0) && (I_j16_sel == 1'b1)) ? 1: 
                             0; 

    assign cclk_output_ext = ((I_clock_reg[0] == 1'b1) && (I_clock_reg[4:3] == 2'b00)) ? 0 : 
                             ((I_clock_reg[0] == 1'b1) && (I_clock_reg[4:3] == 2'b01)) ? 1 : 
                             ((I_clock_reg[0] == 1'b0) && (I_k16_sel == 1'b1)) ? 1 : 
                             0; 

ifdef SIM_TB
    assign O_cryptoclk = cclk_src_is_ext? I_cw_clkin : I_pll_clk1;
    assign O_cw_clkout = cclk_output_ext? O_cryptoclk : 1'b0;
    assign usb_clk_bufg = usb_clk;
    assign usb_clk_buf = usb_clk_bufg;
else
    BUFGMUX_CTRL CCLK_MUX (
       .O(O_cryptoclk),    
       .I0(I_pll_clk1),    
       .I1(I_cw_clkin),    
       .S(cclk_src_is_ext) 
    );

    ODDR CWOUT_ODDR (
       .Q(O_cw_clkout),   
       .C(O_cryptoclk),   
       .CE(cclk_output_ext), 
       .D1(1'b1),   
       .D2(1'b0),   
       .R(1'b0),   
       .S(1'b0)    
    );

    IBUFG clkibuf (
        .O(usb_clk_bufg),
        .I(usb_clk)
    );
    BUFG clkbuf(
        .O(usb_clk_buf),
        .I(usb_clk_bufg)
    );

endif

endmodule

module cw305_top #(
    parameter pBYTECNT_SIZE = 7,
    parameter pADDR_WIDTH = 21
)(

    input wire          usb_clk,        
    inout wire [7:0]    usb_data,       
    input wire [pADDR_WIDTH-1:0]
                        usb_addr,       
    input wire          usb_rdn,        
    input wire          usb_wrn,        
    input wire          usb_cen,        
    input wire          usb_,    


    input wire          j16_sel,        
    input wire          k16_sel,        
    input wire          k15_sel,        
    input wire          l14_sel,        
    input wire          pushbutton,     
    output wire         led1,           
    output wire         led2,           
    output wire         led3,           


    input wire          pll_clk1,       



    output wire         uart_txd,       
    input wire          uart_rxd,       


    output wire         extclk_out,


    output wire         tio_,
    output wire         tio_clkout,
    input wire          tio_clkin
    );

    wire usb_clk_buf;
    wire [7:0] usb_dout;
    wire isout;
    wire [pADDR_WIDTH-pBYTECNT_SIZE-1:0] reg_address;
    wire [pBYTECNT_SIZE-1:0] reg_bytecnt;
    wire reg_addrvalid;
    wire [7:0] write_data;
    wire [7:0] read_data;
    wire reg_read;
    wire reg_write;
    wire [4:0] clk_settings;
    wire iut_clk;

    reg     rst_usb = 1;
    reg     rst_iut = 1;
    wire    reset = rst_usb || rst_iut;



    reg [24:0] usb_timer_heartbeat;
    always @(posedge usb_clk_buf) begin
        usb_timer_heartbeat <= usb_timer_heartbeat + 25'd1;
        if (!pushbutton)
            rst_usb <=  1;
        else
            rst_usb <=  0;
    end

    assign led1 = usb_timer_heartbeat[24];



    reg [22:0] iut_clk_heartbeat;
    always @(posedge iut_clk) begin
        iut_clk_heartbeat <= iut_clk_heartbeat + 23'd1;
        if (!pushbutton)
            rst_iut <=  1;
        else
            rst_iut <=  0;
    end

    assign led2 = iut_clk_heartbeat[22];

    cw305_usb_reg_fe #(
        .pBYTECNT_SIZE          (pBYTECNT_SIZE),
        .pADDR_WIDTH            (pADDR_WIDTH)
    ) cw305_usb_reg_fe_0 (
        .rst                    (reset),
        .usb_clk                (usb_clk_buf),
        .usb_din                (usb_data),
        .usb_dout               (usb_dout),
        .usb_rdn                (usb_rdn),
        .usb_wrn                (usb_wrn),
        .usb_cen                (usb_cen),
        .usb_alen               (1'b0), 
        .usb_addr               (usb_addr),
        .usb_isout              (isout),
        .reg_address            (reg_address),
        .reg_bytecnt            (reg_bytecnt),
        .reg_datao              (write_data),
        .reg_datai              (read_data),
        .reg_read               (reg_read),
        .reg_write              (reg_write),
        .reg_addrvalid          (reg_addrvalid)
    );



    cw305_iut #(
        .pBYTECNT_SIZE          (pBYTECNT_SIZE),
        .pADDR_WIDTH            (pADDR_WIDTH)
    ) cw305_iut_0 (
        .reset                  (reset),
        .iut_clk                (iut_clk),
        .usb_clk                (usb_clk_buf),
        .reg_address            (reg_address[pADDR_WIDTH-pBYTECNT_SIZE-1:0]),
        .reg_bytecnt            (reg_bytecnt),
        .read_data              (read_data),
        .write_data             (write_data),
        .reg_read               (reg_read),
        .reg_write              (reg_write),
        .reg_addrvalid          (reg_addrvalid),
        .ext_trig_in            (usb_),
        .iut_trig_out           (extclk_out),
        .o_clksettings          (clk_settings),


        .o_user_led             (led3       )
    );

    assign usb_data = isout? usb_dout : 8'bZ;

    cw305_clocks cw305_clocks_0 (
        .usb_clk                (usb_clk),
        .usb_clk_buf            (usb_clk_buf),
        .I_j16_sel              (j16_sel),
        .I_k16_sel              (k16_sel),
        .I_clock_reg            (clk_settings),
        .I_cw_clkin             (tio_clkin),
        .I_pll_clk1             (pll_clk1),
        .O_cw_clkout            (tio_clkout),
        .O_cryptoclk            (iut_clk)
    );

endmodule

default_nettype wire

