module sha512_round(
    output  wire [511:0]    h_o,        
    output  wire [1023:0]   m_o,        
    input   wire [511:0]    h_i,        
    input   wire [1023:0]   m_i,        
    input   wire [6:0]      t_i         
);

    reg [63:0] k_w;

    always@(t_i) begin
        case(t_i)
            7'h00: k_w = 64'h428a2f98d728ae22;
            7'h01: k_w = 64'h7137449123ef65cd;
            7'h02: k_w = 64'hb5c0fbcfec4d3b2f;
            7'h03: k_w = 64'he9b5dba58189dbbc;
            7'h04: k_w = 64'h3956c25bf348b538;
            7'h05: k_w = 64'h59f111f1b605d019;
            7'h06: k_w = 64'h923f82a4af194f9b;
            7'h07: k_w = 64'hab1c5ed5da6d8118;
            7'h08: k_w = 64'hd807aa98a3030242;
            7'h09: k_w = 64'h12835b0145706fbe;
            7'h0A: k_w = 64'h243185be4ee4b28c;
            7'h0B: k_w = 64'h550c7dc3d5ffb4e2;
            7'h0C: k_w = 64'h72be5d74f27b896f;
            7'h0D: k_w = 64'h80deb1fe3b1696b1;
            7'h0E: k_w = 64'h9bdc06a725c71235;
            7'h0F: k_w = 64'hc19bf174cf692694;
            7'h10: k_w = 64'he49b69c19ef14ad2;
            7'h11: k_w = 64'hefbe4786384f25e3;
            7'h12: k_w = 64'h0fc19dc68b8cd5b5;
            7'h13: k_w = 64'h240ca1cc77ac9c65;
            7'h14: k_w = 64'h2de92c6f592b0275;
            7'h15: k_w = 64'h4a7484aa6ea6e483;
            7'h16: k_w = 64'h5cb0a9dcbd41fbd4;
            7'h17: k_w = 64'h76f988da831153b5;
            7'h18: k_w = 64'h983e5152ee66dfab;
            7'h19: k_w = 64'ha831c66d2db43210;
            7'h1A: k_w = 64'hb00327c898fb213f;
            7'h1B: k_w = 64'hbf597fc7beef0ee4;
            7'h1C: k_w = 64'hc6e00bf33da88fc2;
            7'h1D: k_w = 64'hd5a79147930aa725;
            7'h1E: k_w = 64'h06ca6351e003826f;
            7'h1F: k_w = 64'h142929670a0e6e70;
            7'h20: k_w = 64'h27b70a8546d22ffc;
            7'h21: k_w = 64'h2e1b21385c26c926;
            7'h22: k_w = 64'h4d2c6dfc5ac42aed;
            7'h23: k_w = 64'h53380d139d95b3df;
            7'h24: k_w = 64'h650a73548baf63de;
            7'h25: k_w = 64'h766a0abb3c77b2a8;
            7'h26: k_w = 64'h81c2c92e47edaee6;
            7'h27: k_w = 64'h92722c851482353b;
            7'h28: k_w = 64'ha2bfe8a14cf10364;
            7'h29: k_w = 64'ha81a664bbc423001;
            7'h2A: k_w = 64'hc24b8b70d0f89791;
            7'h2B: k_w = 64'hc76c51a30654be30;
            7'h2C: k_w = 64'hd192e819d6ef5218;
            7'h2D: k_w = 64'hd69906245565a910;
            7'h2E: k_w = 64'hf40e35855771202a;
            7'h2F: k_w = 64'h106aa07032bbd1b8;
            7'h30: k_w = 64'h19a4c116b8d2d0c8;
            7'h31: k_w = 64'h1e376c085141ab53;
            7'h32: k_w = 64'h2748774cdf8eeb99;
            7'h33: k_w = 64'h34b0bcb5e19b48a8;
            7'h34: k_w = 64'h391c0cb3c5c95a63;
            7'h35: k_w = 64'h4ed8aa4ae3418acb;
            7'h36: k_w = 64'h5b9cca4f7763e373;
            7'h37: k_w = 64'h682e6ff3d6b2b8a3;
            7'h38: k_w = 64'h748f82ee5defb2fc;
            7'h39: k_w = 64'h78a5636f43172f60;
            7'h3A: k_w = 64'h84c87814a1f0ab72;
            7'h3B: k_w = 64'h8cc702081a6439ec;
            7'h3C: k_w = 64'h90befffa23631e28;
            7'h3D: k_w = 64'ha4506cebde82bde9;
            7'h3E: k_w = 64'hbef9a3f7b2c67915;
            7'h3F: k_w = 64'hc67178f2e372532b;
            7'h40: k_w = 64'hca273eceea26619c;
            7'h41: k_w = 64'hd186b8c721c0c207;
            7'h42: k_w = 64'heada7dd6cde0eb1e;
            7'h43: k_w = 64'hf57d4f7fee6ed178;
            7'h44: k_w = 64'h06f067aa72176fba;
            7'h45: k_w = 64'h0a637dc5a2c898a6;
            7'h46: k_w = 64'h113f9804bef90dae;
            7'h47: k_w = 64'h1b710b35131c471b;
            7'h48: k_w = 64'h28db77f523047d84;
            7'h49: k_w = 64'h32caab7b40c72493;
            7'h4A: k_w = 64'h3c9ebe0a15c9bebc;
            7'h4B: k_w = 64'h431d67c49c100d4c;
            7'h4C: k_w = 64'h4cc5d4becb3e42b6;
            7'h4D: k_w = 64'h597f299cfc657e2a;
            7'h4E: k_w = 64'h5fcb6fab3ad6faec;
            7'h4F: k_w = 64'h6C44198C4A475817;
            default: k_w = 64'h0;
        endcase
    end




    function automatic [63:0] rotr;
        input [63:0] x, n;
        begin
            rotr = (x >> n) | (x << (64 - n));
        end
    endfunction



    function automatic [63:0] ch;
        input [63:0] x, y, z;
        begin
            ch = (x & y) ^ (~x & z);
        end
    endfunction

    function automatic [63:0] maj;
        input [63:0] x, y, z;
        begin
            maj = (x & y) ^ (x & z) ^ (y & z);
        end
    endfunction

    function automatic [63:0] sum0;
        input [63:0] x;
        begin
            sum0 =  rotr(x, 28) ^ rotr(x, 34) ^ rotr(x, 39);
        end
    endfunction

    function automatic [63:0] sum1;
        input [63:0] x;
        begin
            sum1 =  rotr(x, 14) ^ rotr(x, 18) ^ rotr(x, 41);
        end
    endfunction

    function automatic [63:0] sig0;
        input [63:0] x;
        begin
            sig0 =  rotr(x,  1) ^ rotr(x,  8) ^ (x >> 7);
        end
    endfunction

    function automatic [63:0] sig1;
        input [63:0] x;
        begin
            sig1 =  rotr(x, 19) ^ rotr(x, 61) ^ (x >> 6);
        end
    endfunction


    wire    [63:0]  w_i     =   m_i[ 63:  0];


    wire    [63:0]  t16_w   =   m_i[ 63:  0];
    wire    [63:0]  t15_w   =   m_i[127: 64];
    wire    [63:0]  t07_w   =   m_i[639:576];
    wire    [63:0]  t02_w   =   m_i[959:896];
    wire    [63:0]  wt_w;

    assign  wt_w =  sig1(t02_w) + t07_w + sig0(t15_w) + t16_w;


    assign  m_o =   { wt_w, m_i[1023:64] };


    wire    [63:0]  a_w, b_w, c_w, d_w, e_w, f_w, g_w, h_w;
    assign  { h_w, g_w, f_w, e_w, d_w, c_w, b_w, a_w } = h_i;



    wire    [63:0]  t1_w, t2_w;
    assign  t1_w = h_w + sum1(e_w) + ch(e_w, f_w, g_w) + k_w + w_i;
    assign  t2_w = sum0(a_w) + maj(a_w, b_w, c_w);

    assign  h_o = { g_w,                
                    f_w,                
                    e_w,                
                    d_w  + t1_w,        
                    c_w,                
                    b_w,                
                    a_w,                
                    t1_w + t2_w };      

endmodule

endif

ifndef SIM_TB
module vcu118_top (
    input wire          clk_250mhz_p,
    input wire          clk_250mhz_n,
    output wire         usb_uart_txd_o,
    input wire          usb_uart_rxd_i,
    output wire         usb_uart_rts_o,
    input wire          usb_uart_cts_i,
    input wire          btn_rst_i,
    input wire  [4:0]   btn_i,      
    output wire [7:0]   led_o
);
    wire        clk;


    IBUFGDS #(
        .IOSTANDARD     ("LVDS" ),
        .DIFF_TERM      ("FALSE"),
        .IBUF_LOW_PWR   ("FALSE")
    ) i_sysclk_iobuf    (
        .I  (clk_250mhz_p),
        .IB (clk_250mhz_n),
        .O  (clk  )
    );

    reg         soft_rst_r  = 1;
    reg [31:0]  sec_cnt_r   = 0;
    reg [31:0]  cyc_cnt_r   = 0;

    wire [7:0]  gpio_out;
    wire        trap_led;

    assign led_o    =   {   trap_led,
                            usb_uart_rxd_i, usb_uart_txd_o,
                            usb_uart_rts_o, usb_uart_cts_i,
                            gpio_out[0],
                            sec_cnt_r[0], cyc_cnt_r[20] };

    always @(posedge clk) begin
        if (btn_i[4] ^ btn_rst_i) begin
            soft_rst_r  <=  1;
            cyc_cnt_r   <=  0;
            sec_cnt_r   <=  0;
        end else begin
            soft_rst_r  <=  0;
            if (cyc_cnt_r == SLOTH_CLK - 1) begin
                cyc_cnt_r   <=  0;
                sec_cnt_r   <=  sec_cnt_r + 1;
            end else begin
                cyc_cnt_r   <=  cyc_cnt_r + 1;
            end
        end
    end

    wire [7:0]  gpio_in = { sec_cnt_r[2:0], btn_i[4:0] };


    fpga_top fpga_top_0 (
        .clk        (clk            ),
        .rst        (soft_rst_r     ),
        .uart_txd   (usb_uart_txd_o ),
        .uart_rxd   (usb_uart_rxd_i ),
        .uart_rts   (~usb_uart_rts_o),
        .uart_cts   (~usb_uart_cts_i),
        .gpio_out   (gpio_out       ),
        .gpio_in    (gpio_in        ),
        .trap       (trap_led       )
    );

endmodule
endif

include "config.vh"
ifdef SLOTH_SHA512
include "mem_block.vh"





module sha512_sloth (
    input wire          clk,
    input wire          rst,
    input wire          sel,
    output reg          irq,
    input wire  [3:0]   wen,
    input wire  [6:0]   addr,
    input wire  [31:0]  wdata,
    output reg  [31:0]  rdata
);
    localparam  S512_HASH   =   0;
    localparam  S512_MSGB   =   16;
    localparam  S512_MEND   =   48;
    localparam  S512_MTOP   =   48;
    localparam  S512_MSH2   =   64;
    localparam  S512_CTRL   =   120;
    localparam  S512_TRIG   =   120;
    localparam  S512_STAT   =   120;

    wire                msel_w = addr < S512_CTRL;
    wire    [6:0]       csel_w = addr;              
    wire    [5:0]       addr_w = addr[5:0] ^ 1;     
    wire                msh2_w = addr[6];           
    wire    [5:0]       adr0_w = addr[5:0] ^ 1;
    wire    [5:0]       adr1_w = (addr[5:0] + 1) ^ 1;

    reg     [31:0]      mem [0:S512_MTOP - 1];      
    reg     [7:0]       t_r;                        

    wire    [511:0]     hash_m = MEM_BLOCK_16(S512_HASH);
    wire    [1023:0]    msgb_m = MEM_BLOCK_32(S512_MSGB);

    wire    [511:0]     h_o_w;              
    wire    [1023:0]    m_o_w;              
    reg     [511:0]     h_s_r;              
    reg     [1023:0]    m_s_r;              


    sha512_round sha512_0 (
        .h_o(h_o_w      ),                  
        .m_o(m_o_w      ),                  
        .h_i(h_s_r      ),                  
        .m_i(m_s_r      ),                  
        .t_i(t_r[6:0]   )                   
    );

    always @(posedge clk) begin

        irq     <=  0;                      


        if (sel) begin

            if (msel_w) begin                   

                if (!msh2_w) begin

                    rdata   <=  { mem[addr_w][ 7: 0], mem[addr_w][15: 8],
                                  mem[addr_w][23:16], mem[addr_w][31:24] };
                    if (wen[0]) mem[addr_w][31:24]  <=  wdata[ 7: 0];
                    if (wen[1]) mem[addr_w][23:16]  <=  wdata[15: 8];
                    if (wen[2]) mem[addr_w][15: 8]  <=  wdata[23:16];
                    if (wen[3]) mem[addr_w][ 7: 0]  <=  wdata[31:24];

                end else begin



                    rdata   <=   32'h0000_0000;
                    if (adr0_w >= S512_MSGB && adr0_w < S512_MEND) begin
                        if (wen[0]) mem[adr0_w][15: 8]  <=  wdata[ 7: 0];
                        if (wen[1]) mem[adr0_w][ 7: 0]  <=  wdata[15: 8];
                    end
                    if (adr1_w >= S512_MSGB && adr1_w < S512_MEND) begin
                        if (wen[2]) mem[adr1_w][31:24]  <=  wdata[23:16];
                        if (wen[3]) mem[adr1_w][23:16]  <=  wdata[31:24];
                    end
                end

            end else begin                  

                case (csel_w)

                    S512_TRIG:  begin
                        rdata   <=  { 24'b0, t_r };
                        if (wen[0]) begin
                            t_r <=  wdata[ 7: 0];
                        end
                    end

                endcase
            end

        end

        if (t_r[7] == 1'b0) begin


            if (t_r[0]) begin
                h_s_r   <=  hash_m;
                m_s_r   <=  msgb_m;
                t_r     <=  8'h80;
            end

        end else if (t_r[6:0] < 80) begin


            h_s_r   <=  h_o_w;
            m_s_r   <=  m_o_w;
            t_r     <=  t_r + 1;

        end else begin


            { mem[ 1], mem[ 0] } <= { mem[ 1], mem[ 0] } + h_s_r[ 63:  0];
            { mem[ 3], mem[ 2] } <= { mem[ 3], mem[ 2] } + h_s_r[127: 64];
            { mem[ 5], mem[ 4] } <= { mem[ 5], mem[ 4] } + h_s_r[191:128];
            { mem[ 7], mem[ 6] } <= { mem[ 7], mem[ 6] } + h_s_r[255:192];
            { mem[ 9], mem[ 8] } <= { mem[ 9], mem[ 8] } + h_s_r[319:256];
            { mem[11], mem[10] } <= { mem[11], mem[10] } + h_s_r[383:320];
            { mem[13], mem[12] } <= { mem[13], mem[12] } + h_s_r[447:384];
            { mem[15], mem[14] } <= { mem[15], mem[14] } + h_s_r[511:448];

            t_r     <=  8'h00;
            irq     <=  1;
        end


        if (rst) begin
            t_r     <=  8'h00;
        end
    end

endmodule

endif

include "config.vh"
ifdef SLOTH_SHA256
include "mem_block.vh"





module sha256_sloth (
    input wire          clk,
    input wire          rst,
    input wire          sel,
    output reg          irq,
    input wire  [3:0]   wen,
    input wire  [6:0]   addr,
    input wire  [31:0]  wdata,
    output reg  [31:0]  rdata
);

    localparam  S256_HASH   =   0;
    localparam  S256_MSGB   =   8;
    localparam  S256_MEND   =   24;
    localparam  S256_SEED   =   24;
    localparam  S256_ADRS   =   32;
    localparam  S256_SKSD   =   40;
    localparam  S256_MTOP   =   48;
    localparam  S256_MSH2   =   64;
    localparam  S256_CTRL   =   120;
    localparam  S256_TRIG   =   120;
    localparam  S256_STAT   =   120;
    localparam  S256_SECN   =   122;
    localparam  S256_CHNS   =   123;

    wire                msel_w = addr < S256_CTRL;
    wire    [6:0]       csel_w = addr;          
    wire    [5:0]       addr_w = addr[5:0];     
    wire                msh2_w = addr[6];       
    wire    [5:0]       adr0_w = addr_w;
    wire    [5:0]       adr1_w = addr_w + 1;

    reg     [31:0]      mem [0:S256_MTOP - 1];  
    reg     [7:0]       t_r;                    
    reg     [7:0]       secn_r;                 
    reg     [7:0]       chns_r;                 
    reg     [7:0]       chni_r;                 

    wire    [255:0]     hash_m  = MEM_BLOCK_8(S256_HASH);  
    wire    [511:0]     msgb_m  = MEM_BLOCK_16(S256_MSGB); 
    wire    [255:0]     seed_m  = MEM_BLOCK_8(S256_SEED);  
    wire    [255:0]     sksd_m  = MEM_BLOCK_8(S256_SKSD);  




    wire    [175:0]     adrsc_w = {
        mem[39][15: 8], mem[39][ 7: 0] + chni_r,    
        mem[38][15: 8], mem[38][ 7: 0], mem[39][31:24], mem[39][23:16],
        mem[37][15: 8], mem[37][ 7: 0], mem[38][31:24], mem[38][23:16],
        mem[35][ 7: 0], mem[36][ 7: 0], mem[37][31:24], mem[37][23:16],
        mem[34][ 7: 0], mem[35][31:24], mem[35][23:16], mem[35][15: 8],
        mem[32][ 7: 0], mem[34][31:24], mem[34][23:16], mem[34][15: 8]
    };



    function automatic [511:0] padf;
        input [7:0] n;
        input [175:0] ac;
        input [255:0] x;

        padf = { 16'h00000, 8'h03,  
            (n == 16 ? 8'h30 : n == 24 ? 8'h70 : 8'hB0 ),
            32'b0,
            (n == 32 ? { x[239:224], 1'b1 } : 17'b0), 15'b0,
            (n == 32 ? { x[207:192], x[255:240] } : 32'b0),
            (n == 16 ? 16'b0 : x[175:160]),
                (n == 32 ? x[223:208] : { n == 24, 15'b0 }),
            (n == 16 ? 32'b0 : { x[143:128], x[191:176] }),
            x[111:  96],    (n == 16 ? { 1'b1, 15'b0 } : x[159:144]),
            x[ 79:  64],    x[127:112],
            x[ 47:  32],    x[ 95: 80],
            x[ 15:   0],    x[ 63: 48],
            ac[175:160],    x[ 31: 16],
            ac[159:  0] };
    endfunction

    wire    [255:0]     h_o_w;              
    wire    [511:0]     m_o_w;              
    reg     [255:0]     h_s_r;              
    reg     [511:0]     m_s_r;              



    sha256_round sha256_0 (
        .h_o(h_o_w      ),                  
        .m_o(m_o_w      ),                  
        .h_i(h_s_r      ),                  
        .m_i(m_s_r      ),                  
        .t_i(t_r[5:0]   )                   
    );

    always @(posedge clk) begin

        irq     <=  0;                      


        if (sel && msel_w) begin                

            if (!msh2_w) begin


                rdata   <=  { mem[addr_w][ 7: 0], mem[addr_w][15: 8],
                              mem[addr_w][23:16], mem[addr_w][31:24] };

                if (wen[0]) mem[addr_w][31:24]  <=  wdata[ 7: 0];
                if (wen[1]) mem[addr_w][23:16]  <=  wdata[15: 8];
                if (wen[2]) mem[addr_w][15: 8]  <=  wdata[23:16];
                if (wen[3]) mem[addr_w][ 7: 0]  <=  wdata[31:24];

            end else begin



                rdata   <=   32'h0000_0000;
                if (adr0_w >= S256_MSGB && adr0_w < S256_MEND) begin
                    if (wen[0]) mem[adr0_w][15: 8]  <=  wdata[ 7: 0];
                    if (wen[1]) mem[adr0_w][ 7: 0]  <=  wdata[15: 8];
                end
                if (adr1_w >= S256_MSGB && adr1_w < S256_MEND) begin
                    if (wen[2]) mem[adr1_w][31:24]  <=  wdata[23:16];
                    if (wen[3]) mem[adr1_w][23:16]  <=  wdata[31:24];
                end
            end

        end else begin                  

            if (sel) begin

                case (csel_w)

                    S256_TRIG:  begin
                        rdata   <=  { 24'b0, t_r };
                        if (wen[0]) begin
                            t_r <=  wdata[ 7: 0];
                        end
                    end

                    S256_SECN: begin
                        rdata   <=  { 24'b0, secn_r };
                        if (wen[0]) begin
                            secn_r  <=  wdata[ 7: 0];
                        end
                    end

                    S256_CHNS: begin
                        rdata   <=  { 24'b0, chns_r };
                        if (wen[0]) begin
                            chns_r  <=  wdata[ 7: 0];
                            chni_r  <=  8'h00;
                        end
                    end

                endcase
            end


            if (t_r[7] == 1'b0) begin

                case (t_r)


                    8'h01: begin
                        h_s_r   <=  hash_m;
                        m_s_r   <=  msgb_m;
                        t_r     <=  8'h80;  
                    end


                    8'h02: begin
                        MEM_BLOCK_8(S256_HASH)  <= seed_m;
                        MEM_BLOCK_16(S256_MSGB) <=
                            padf(secn_r, adrsc_w, hash_m);

                        if (chns_r == 0) begin

                            t_r     <=  8'h00;
                        end else begin

                            chns_r  <=  chns_r - 1;
                            chni_r  <=  chni_r + 1;
                            t_r     <=  8'h01;
                        end
                    end


                    8'h03: begin
                        MEM_BLOCK_8(S256_HASH)  <= seed_m;
                        MEM_BLOCK_16(S256_MSGB) <=
                            padf(secn_r, adrsc_w, sksd_m);


                        mem[S256_ADRS + 4][ 7: 0] <=
                        (mem[S256_ADRS + 4][ 7: 0] == 8'h05 ? 8'h00 : 8'h03);

                        t_r <=  8'h01;              
                    end

                    default: begin
                    end

                endcase

            end else if (t_r < 8'hC0) begin


                h_s_r   <=  h_o_w;
                m_s_r   <=  m_o_w;
                t_r     <=  t_r + 1;

            end else begin


                mem[0] <= mem[0] + h_s_r[ 31:  0];
                mem[1] <= mem[1] + h_s_r[ 63: 32];
                mem[2] <= mem[2] + h_s_r[ 95: 64];
                mem[3] <= mem[3] + h_s_r[127: 96];
                mem[4] <= mem[4] + h_s_r[159:128];
                mem[5] <= mem[5] + h_s_r[191:160];
                mem[6] <= mem[6] + h_s_r[223:192];
                mem[7] <= mem[7] + h_s_r[255:224];

                if (chns_r == 0) begin
                    t_r     <=  8'h00;
                    irq     <=  1;
                end else begin
                    t_r     <=  8'h02;
                end
            end
        end


        if (rst) begin
            t_r     <=  8'h00;
            chns_r  <=  8'h00;
            chni_r  <=  8'h00;
            secn_r  <=  8'h10;
        end
    end


endmodule

endif

include "config.vh"


ifdef VERILATOR
define CORE_PC_LOG
endif



module pug_rv32 #(
    parameter           XLEN        = 32,
    parameter   [31:0]  RESET_PC    = 32'h0000_0000,
    parameter   [31:0]  RESET_SP    = 32'h0000_0000
) (
    input wire          clk,                
    input wire          rst,                
    output reg          trap        = 0,    
    input wire          irq,                

    output wire         mem0_valid,         
    input wire          mem0_ready,
    output reg  [31:0]  mem0_addr   = 0,
    output reg  [31:0]  mem0_wdata  = 0,
    output reg  [ 3:0]  mem0_wstrb  = 0,
    input wire  [31:0]  mem0_rdata,

    output wire         mem1_valid,         
    input wire          mem1_ready,
    output wire [31:0]  mem1_addr,
    input wire  [31:0]  mem1_rdata
);
ifdef CORE_PC_LOG
    integer logf;
    reg     [31:0]  log_clk;
    initial begin
        log_clk =   0;
        logf = $fopen("core_pc.log");
    end
endif
    localparam          BAD_ADDR    = 32'hFFFF_FFFF;
    localparam          RV32_NOP    = 32'h0000_0013;


ifdef  CORE_DEBUG
    reg  [31:0] clk_cnt = 0, step_cnt = 0;
endif


    reg         irq_fl  = 0;                
    reg         wfi     = 0;                


    wire    irq_w =
ifdef CORE_CUSTOM0
        c0_irq_w    ||                      
endif
        irq;                                

ifndef CORE_E16REG
    reg [4:0]   rst_cnt = 31;               
else
    reg [3:0]   rst_cnt = 15;
endif
    wire        running = !rst && (rst_cnt == 0) && !trap && !wfi;


    reg         load    = 0, load1;         
    reg  [1:0]  ladr;                       
    reg  [2:0]  lfn3;                       
    reg         store   = 0, store1;        
    reg  [3:0]  wstrb1  = 4'b0000;

    assign      mem0_valid  =   (load || store);


    wire [31:0] rd_sh   =   ladr[1:0] == 2'b01 ? {  8'b0, mem0_rdata[31: 8] } :
                            ladr[1:0] == 2'b10 ? { 16'b0, mem0_rdata[31:16] } :
                            ladr[1:0] == 2'b11 ? { 24'b0, mem0_rdata[31:24] } :
                            mem0_rdata[31: 0];


    wire [31:0] rd_l    =   lfn3[1] ? mem0_rdata[31: 0] :   (lfn3[0] ?
                                {{16{rd_sh[15] && !lfn3[2]}}, rd_sh[15:0]} :
                                {{24{rd_sh[7] && !lfn3[2]}}, rd_sh[7:0]});


    reg  [31:0] pc      =   RESET_PC;       
    reg  [31:0] pc_get  =   RESET_PC;       
    wire [31:0] pc_adr0 =   { pc_get[31:2], 2'b00 };
    assign  mem1_addr   =   pc_adr0;        
    assign  mem1_valid  =   1;

    reg  [31:0] pc_adr1 =   BAD_ADDR;       
    wire [31:0] pc_dat1 =   mem1_rdata;
    reg  [31:0] pc_adr2 =   BAD_ADDR;
    reg  [31:0] pc_dat2 =   RV32_NOP;
    reg  [31:0] pc_adr3 =   BAD_ADDR;
    reg  [31:0] pc_dat3 =   RV32_NOP;

    reg         flush_i =   0;              


    reg  [31:0] dec_pc  =   RESET_PC;       

    reg  [31:0] ins     =   RV32_NOP;       
ifdef CORE_COMPRESSED
    reg         ins_c   =   0;              
endif
    reg  [31:0] ins_pc  =   BAD_ADDR;       
    wire        ins_ok  =   running && pc == ins_pc;


ifdef CORE_COMPRESSED
    wire [31:0] pc1_w   =   pc + (ins_c ? 2 : 4);
else
    wire [31:0] pc1_w   =   pc + 4;         
endif

ifdef CORE_COMPRESSED



    wire [31:0] pc_de2  =   dec_pc + 2;     

    wire        pc_lo1  =   dec_pc[31:2] == pc_adr1[31:2];  
    wire        pc_hi1  =   pc_de2[31:2] == pc_adr1[31:2];  

    wire        pc_lo2  =   dec_pc[31:2] == pc_adr2[31:2];  
    wire        pc_hi2  =   pc_de2[31:2] == pc_adr2[31:2];  

    wire        pc_lo3  =   dec_pc[31:2] == pc_adr3[31:2];  
    wire        pc_hi3  =   pc_de2[31:2] == pc_adr3[31:2];  

    wire        pc_lo   =   pc_lo1 || pc_lo2 || pc_lo3;     
    wire        pc_hi   =   pc_hi1 || pc_hi2 || pc_hi3;


    wire [15:0] ins_lo  =   pc_lo1 ?        ( dec_pc[1] ?
                                pc_dat1[31:16] : pc_dat1[15:0] ) :
                            pc_lo2 ?        ( dec_pc[1] ?
                                pc_dat2[31:16] : pc_dat2[15:0] ) :
                              ( dec_pc[1] ?
                                pc_dat3[31:16] : pc_dat3[15:0] );


    wire [15:0] ins_hi  =   pc_hi1 ?        ( dec_pc[1] ?
                                pc_dat1[15:0] : pc_dat1[31:16] ) :
                            pc_hi2 ?        ( dec_pc[1] ?
                                pc_dat2[15:0] : pc_dat2[31:16] ) :
                              ( dec_pc[1] ?
                                pc_dat3[15:0] : pc_dat3[31:16] );



    wire        dec_c   =   ins_lo[1:0] != 2'b11;

    wire [31:0] ins_unc;                    
    pug_rvc rv32c(ins_lo, ins_unc);         


    wire        ins_hav =   dec_c ? pc_lo : pc_lo && pc_hi;


    wire [31:0] dec_ins =   dec_c ? ins_unc : { ins_hi, ins_lo };

else


    wire        pc_in1  =   dec_pc[31:2] == pc_adr1[31:2];
    wire        pc_in2  =   dec_pc[31:2] == pc_adr2[31:2];
    wire        pc_in3  =   dec_pc[31:2] == pc_adr3[31:2];
    wire        ins_hav =   pc_in1 || pc_in2 || pc_in3;
    wire [31:0] dec_ins =   pc_in1 ? pc_dat1 :
                                pc_in2 ? pc_dat2 : pc_dat3;
endif



ifndef CORE_E16REG
    reg  [31:0] rx [0:31];                  
else
    reg  [31:0] rx [0:15];                  
endif

    reg  [4:0]  rdr;                        
    reg  [31:0] rdx;                        
    reg         rdw;                        


    wire [6:0]  dc_op   =   ins[ 6: 0];     
    wire [4:0]  dc_rd   =   ins[11: 7];     
    wire [2:0]  dc_fn3  =   ins[14:12];     
    wire [4:0]  dc_rs1  =   ins[19:15];     
    wire [4:0]  dc_rs2  =   ins[24:20];     
    wire [6:0]  dc_fn7  =   ins[31:25];     


    wire [31:0] dc_ii   =   { {20{ins[31]}}, ins[31:20] };
    wire [31:0] dc_is   =   { {20{ins[31]}}, ins[31:25], ins[11: 7] };
    wire [31:0] dc_ib   =   { {20{ins[31]}}, ins[7], ins[30:25],
                                ins[11: 8], 1'b0 };
    wire [31:0] dc_iu   =   { ins[31:12], 12'b0 };
    wire [31:0] dc_ij   =   { {12{ins[31]}}, ins[19:12], ins[20],
                                ins[30:21], 1'b0} ;


    wire [31:0] rs1_w   =   dc_rs1 == 5'b0 ? 32'b0 :
                            rdw && dc_rs1 == rdr ? rdx :
                            rx[dc_rs1];
    wire [31:0] rs2_w   =   dc_rs2 == 5'b0 ? 32'b0 :
                            rdw && dc_rs2 == rdr ? rdx :
                            rx[dc_rs2];



    wire        cr_ltu  =   rs1_w < rs2_w;  
    wire        cr_lts  =   (rs1_w[31] == 1 && rs2_w[31] == 0) ||
                            ((rs1_w[31] == rs2_w[31]) && cr_ltu);

    wire        ci_ltu  =   rs1_w < dc_ii;  
    wire        ci_lts  =   (rs1_w[31] == 1 && dc_ii[31] == 0) ||
                            ((rs1_w[31] == dc_ii[31]) && ci_ltu);


    wire        branch  =   dc_fn3[0] ^ (dc_fn3[2:1] == 2'b00 &&    
                                    (rs1_w == rs2_w) ||             
                                dc_fn3[2:1] == 2'b10 && cr_lts ||   
                                dc_fn3[2:1] == 2'b11 && cr_ltu);    


    wire [31:0] ladr_w  =   dc_ii + rs1_w;          
    wire [31:0] sadr_w  =   dc_is + rs1_w;          
    wire [31:0] jalr_w  =   (dc_ii + rs1_w) & ~1;   


    wire [31:0] jalbr_w =   pc + (ins[3] ? dc_ij : dc_ib);


    reg [31:0]  rs1_r;
    reg [31:0]  rs2_r;
    reg [31:0]  ins_r = 0;


ifdef CORE_MULDIV
    wire [31:0] m_rd;                       
    wire        m_done;                     
    reg         m_rst   = 0;                
    reg [2:0]   m_fn3   = 0;                
    reg         m_run   = 0;                
    reg         m_go    = 0;                
    pug_muldiv rv32_m0 (
        .clk    (clk),                      
        .go     (m_go),                     
        .rst    (m_rst),                    
        .done   (m_done),                   
        .rd     (m_rd),                     
        .rs1    (rs1_r),                    
        .rs2    (rs2_r),                    
        .fn3    (ins_r[14:12])              
    );
endif



ifdef CORE_KRYPTO
    wire [31:0] aes_rd_w;

    rvk_aes32 aes0 (
        .rd     (aes_rd_w),                 
        .rs1    (rs1_w),                    
        .rs2    (rs2_w),                    
        .ins    (ins)
    );
endif



    always @(posedge clk) begin

ifdef CORE_PC_LOG
        log_clk     <=  log_clk + 1;
endif
        rdw         <=  0;                  



        store1  <=  store;                  
        wstrb1  <=  mem0_wstrb;
        if (store && mem0_ready) begin      
            mem0_wstrb  <=  4'b0000;
            store       <=  0;
        end else if (store1 && !mem0_ready) begin
            mem0_wstrb  <=  wstrb1;         
            store       <=  1;
        end



        if (irq_w) begin
            if (wfi) begin
                wfi     <= 0;               
                irq_fl  <= 0;
            end else begin
                irq_fl  <= 1;               
            end
        end



        if (rst) begin
            mem0_wstrb  <=  4'b0000;        
            pc          <=  RESET_PC;       
            ins         <=  RV32_NOP;       
            ins_r       <=  RV32_NOP;
            load        <=  0;              
            store       <=  0;
            trap        <=  0;              
            wfi         <=  0;              
ifndef CORE_E16REG
            rst_cnt     <=  31;             
else
            rst_cnt     <=  15;             
endif
            pc_get      <=  RESET_PC;
            flush_i     <=  1;              
ifdef CORE_MULDIV
            m_rst       <=  1;              
            m_run       <=  0;
            m_go        <=  0;
endif
        end else begin

ifdef CORE_MULDIV
            m_rst       <=  0;                  
            m_go        <=  0;                  
endif

            if (|rst_cnt) begin
                rdr         <=  rst_cnt;
                rdx         <=  rst_cnt == 2 ? RESET_SP : 32'h0000_0000;
                rdw         <=  1;
                rst_cnt     <=  rst_cnt - 1'b1;
            end
ifdef CORE_DEBUG
            else begin
                clk_cnt     <=  clk_cnt + 1;
            end
endif
        end

ifdef CORE_DEBUG
        if (!running) begin
            $display("[RESET] (%2d)\trst=%d trap=%d",
                rst_cnt, rst, trap);
        end
            else begin

            $display("\n[CLK] (%6d)\tready0=%d  ready1=%d   rdata1=%08h  ins=%08h",
                clk_cnt, mem0_ready, mem1_ready, mem1_rdata, ins);
            $display("\t\tpc=%08h ins_pc=%08h  pc_get=%08h",
                pc, ins_pc, pc_get);
            $display("\t\taddr0=%08h  wdata0=%08h  wstrb0=%04b  rdata0=%08h",
                mem0_addr, mem0_wdata, mem0_wstrb, mem0_rdata);
        end
endif



        load1       <=  load;
        if (rdw || (load1 && mem0_ready)) begin     
            rx[rdr]     <=  rdw ? rdx : rd_l;
            load        <=  0;
            load1       <=  0;
ifdef CORE_DEBUG
            if  (load1)
                $write("[LOAD]");
            $display("\tx[%d]    = %08h", rdr, rdw ? rdx : rd_l);
endif
        end



        if (flush_i) begin


            pc_adr1     <=  BAD_ADDR;
            pc_adr2     <=  BAD_ADDR;
            pc_adr3     <=  BAD_ADDR;
            pc_get      <=  pc;
            flush_i     <=  0;

        end else begin

            if (pc_adr0 != pc_adr1) begin
                pc_adr1     <=  pc_adr0;
                pc_dat2     <=  pc_dat1;
                pc_adr2     <=  pc_adr1;
                pc_dat3     <=  pc_dat2;
                pc_adr3     <=  pc_adr2;
            end

            if  (ins_hav) begin
                ins         <=  dec_ins;
                ins_pc      <=  dec_pc;
ifdef CORE_COMPRESSED
                ins_c       <=  dec_c;
                dec_pc      <=  dec_pc + (dec_c ? 2 : 4);
else
                dec_pc      <=  dec_pc + 4;
endif
            end

            if (pc_adr0[31:2] == pc[31:2] ||
                pc_adr1[31:2] == pc[31:2] ||
                pc_adr2[31:2] == pc[31:2]) begin
                if (pc_get  <= pc + 8)
                    pc_get  <=  pc_get + 4;
            end else begin
                pc_get  <=  pc;
                dec_pc  <=  pc;
            end
        end

        if (ins_ok && !load && !store && (!store1 || mem0_ready)) begin


ifdef CORE_PC_LOG
    $fdisplay(logf, "%h %d", pc, log_clk);
endif
ifdef CORE_DEBUG
    $display("x[1..] = %08h %08h %08h %08h %08h %08h %08h",
                rx[ 1], rx[ 2], rx[ 3], rx[ 4], rx[ 5], rx[ 6], rx[ 7]);
    $display("%08h %08h %08h %08h %08h %08h %08h %08h",
        rx[ 8], rx[ 9], rx[10], rx[11], rx[12], rx[13], rx[14], rx[15]);
ifndef CORE_E16REG
    $display("%08h %08h %08h %08h %08h %08h %08h %08h",
        rx[16], rx[17], rx[18], rx[19], rx[20], rx[21], rx[22], rx[23]);
    $display("%08h %08h %08h %08h %08h %08h %08h %08h",
        rx[24], rx[25], rx[26], rx[27], rx[28], rx[29], rx[30], rx[31]);
endif
    $display("[STEP]\t%6d\t%08h:\t%08h  rs1_w=%08h rs2_w=%08h",
        step_cnt,   pc, ins, rs1_w, rs2_w);

    step_cnt    <=  step_cnt + 1;
endif


            pc          <=  pc1_w;              
            if (dec_pc != pc1_w)                
                dec_pc  <=  pc1_w;
            rdr         <=  dc_rd;
            rdw         <=  |dc_rd;

            ins_r       <=  ins;
            rs1_r       <=  rs1_w;
            rs2_r       <=  rs2_w;

            if (dc_op[1:0] != 2'b11)            
                trap    <=  1;

            case (dc_op[6:2])                   

                5'b00000: begin                                 
                    rdw         <=  0;
                    mem0_addr   <=  { ladr_w[31:2], 2'b00 };
                    ladr        <=  ladr_w[1:0];
                    lfn3        <=  dc_fn3;
                    load        <=  |dc_rd;
ifdef  CORE_TRAP_UNALIGNED
                    if ((dc_fn3[1:0] == 2'b01 &&                
                            ladr_w[0]) ||
                        (dc_fn3 == 3'b010 &&                    
                            ladr_w[1:0] != 2'b00))
                        trap    <=  1;
endif
                end

ifdef  CORE_CUSTOM0
                5'b00010:   rdx <=  c0_rd_w;                    
endif

                5'b00011:   begin                               
                    rdw         <=  0;
                    ins_pc      <=  BAD_ADDR;   
                    flush_i     <=  1;
                    pc_get      <=  pc1_w;
                end

                5'b00100: case (dc_fn3)                         
                    3'b000: rdx <=  rs1_w + dc_ii;              
                    3'b001: rdx <=  rs1_w << dc_rs2;            
                    3'b010: rdx <=  ci_lts ? 1 : 0;             
                    3'b011: rdx <=  ci_ltu ? 1 : 0;             
                    3'b100: rdx <=  rs1_w ^ dc_ii;              
                    3'b101: case (dc_fn7)
                        7'b0000000: rdx <=  rs1_w >> dc_rs2;    
                        7'b0100000: rdx <=                      
                                        $signed(rs1_w) >>> dc_rs2;
                        7'b0110000: rdx <=  (rs1_w >> dc_rs2) | 
                                            (rs1_w << (32-dc_rs2));
                        default:    trap <= 1;
                    endcase
                    3'b110: rdx <=  rs1_w | dc_ii;              
                    3'b111: rdx <=  rs1_w & dc_ii;              
                endcase

                5'b00101:   rdx <=  dc_iu + pc;                 

                5'b01000: begin                                 
                    rdw         <=  0;
                    mem0_addr   <=  { sadr_w[31:2], 2'b00 };
                    store       <=  1;
                    case (dc_fn3)
                        3'b000: begin                           
                            mem0_wdata  <=
                                {   rs2_w[7:0], rs2_w[7:0],
                                    rs2_w[7:0], rs2_w[7:0] };
                            mem0_wstrb  <=
                                sadr_w[1:0] == 2'b00 ? 4'b0001 :
                                sadr_w[1:0] == 2'b01 ? 4'b0010 :
                                sadr_w[1:0] == 2'b10 ? 4'b0100 :
                                                       4'b1000;
                        end
                        3'b001: begin                           
                            mem0_wdata  <=
                                {   rs2_w[15:0], rs2_w[15:0] };
                            mem0_wstrb  <=
                                sadr_w[1] ? 4'b1100 : 4'b0011;
ifdef  CORE_TRAP_UNALIGNED
                            if (sadr_w[0])
                                trap    <=  1;
endif
                        end
                        3'b010: begin                           
                            mem0_wdata  <=  rs2_w;
                            mem0_wstrb  <=  4'b1111;
ifdef  CORE_TRAP_UNALIGNED
                            if (sadr_w[1:0] != 2'b00)
                                trap    <=  1;
endif
                        end
                        default:    trap <= 1;
                    endcase
                end



                5'b01100: case (dc_fn7)                         
                    7'b0000000: case (dc_fn3)
                        3'b000: rdx <=  rs1_w + rs2_w;          
                        3'b001: rdx <=  rs1_w << rs2_w[4:0];    
                        3'b010: rdx <=  cr_lts ? 1 : 0;         
                        3'b011: rdx <=  cr_ltu ? 1 : 0;         
                        3'b100: rdx <=  rs1_w ^ rs2_w;          
                        3'b101: rdx <=  rs1_w >> rs2_w[4:0];    
                        3'b110: rdx <=  rs1_w | rs2_w;          
                        3'b111: rdx <=  rs1_w & rs2_w;          
                    endcase

                    7'b0100000: case (dc_fn3)
                        3'b000: rdx <=  rs1_w - rs2_w;          
                        3'b101: rdx <=  $signed(rs1_w)          
                                                >>> rs2_w[4:0];
                        default:    trap <= 1;
                    endcase
ifdef CORE_MULDIV
                    7'b0000001: begin                           
                        if (m_done) begin
                            if (m_rst) begin
                                rdw     <=  0;
                                pc      <=  pc;
                            end else begin
                                rdx     <=  m_rd;
                            end
                            m_run   <=  0;
                            m_rst   <=  1;
                        end else begin
                            if (m_run) begin
                                m_go    <=  0;
                            end else begin
                                m_run   <=  1;
                                m_go    <=  1;
                            end
                            rdw     <=  0;
                            pc      <=  pc;
                        end
                    end
endif

                    default: begin
ifdef CORE_KRYPTO
                        if (ins[29] && dc_fn3 === 3'b000) begin
                            rdx     <=  aes_rd_w;
                        end else
endif
                            trap    <= 1;
                    end
                endcase

                5'b01101:   rdx <=  dc_iu;                      

                5'b11000: begin                                 
                    rdw         <=  0;
                    if (branch) begin
                        pc      <=  jalbr_w;
                        pc_get  <=  jalbr_w;
                        dec_pc  <=  jalbr_w;
                    end
                end

                5'b11001: begin                                 
                    rdx         <=  pc1_w;
                    pc          <=  jalr_w;
                    pc_get      <=  jalr_w;
                    dec_pc      <=  jalr_w;
                end

                5'b11011: begin                                 
                    rdx         <=  pc1_w;
                    pc          <=  jalbr_w;
                    pc_get      <=  jalbr_w;
                    dec_pc      <=  jalbr_w;
                end

                5'b11100: begin                                 

                    if (ins == 32'h10500073) begin

                        rdw     <=  0;
                        if (irq_fl)
                            irq_fl  <=  0;
                        else
                            wfi <=  1;
                    end else begin



                        rdw     <=  0;
                        trap    <=  1;
                    end
                end

                default: begin
                    rdw         <=  0;
                    trap        <=  1;
                end
            endcase
        end
    end
endmodule

module fpga_ram #(
    parameter   XLEN    = 32,
    parameter   XADR    = 12,
    parameter   XSIZ    = 1 << XADR
) (
    input wire  clk,
    input wire  [3:0]       wen0,       
    input wire  [XADR-1:0]  addr0,
    input wire  [31:0]      wdata0,
    output reg  [31:0]      rdata0,
    input wire  [XADR-1:0]  addr1,      
    output reg  [31:0]      rdata1
);
    reg [31:0] mem [0:XSIZ-1];

    initial begin
        $readmemh("firmware.hex", mem);
    end

    always @(posedge clk) begin
        rdata0 <= mem[addr0];
        if (wen0[0]) mem[addr0][ 7: 0] <= wdata0[ 7: 0];
        if (wen0[1]) mem[addr0][15: 8] <= wdata0[15: 8];
        if (wen0[2]) mem[addr0][23:16] <= wdata0[23:16];
        if (wen0[3]) mem[addr0][31:24] <= wdata0[31:24];
    end

    always @(posedge clk) begin
        rdata1 <= mem[addr1];
    end

endmodule

include "config.vh"

ifdef  CORE_MULDIV

ifdef  CORE_USEDSP




module mulsig32(
    input wire          clk,
    input wire          go,
    input wire          rst,
    output reg          done = 0,
    output reg  [63:0]  res,
    input wire  [31:0]  a,
    input wire          a_sgn,
    input wire  [31:0]  b,
    input wire          b_sgn
);

    reg [31:0]  r_hi, x, y;         
    reg [63:0]  prod;               
    reg         run = 0;


    always @(posedge clk) begin

        if (rst) begin              

            done    <=  0;
            run     <=  0;

        end else if (go) begin      

            prod    <=  a * b ;
            run     <=  1;

        end else if (run) begin     

            run     <=  0;
            done    <=  1;
            res     <=  {   prod[63:32] - (a_sgn && a[31] ? b : 32'b0)
                            - (b_sgn && b[31] ? a : 32'b0), prod[31:0] };
        end
    end

endmodule

else




module mulsig32(
    input wire          clk,
    input wire          go,
    input wire          rst,
    output reg          done = 0,
    output reg [63:0]   res,
    input wire [31:0]   a,
    input wire          a_sgn,
    input wire [31:0]   b,
    input wire          b_sgn
);

    reg [31:0]  x;
    reg [63:0]  y;
    reg [5:0]   pos;
    reg         run = 0;


    always @(posedge clk) begin

        if  (rst) begin

            done    <=  0;
            run     <=  0;
            pos     <=  0;

        end else if (go) begin


            res[63:32]  <=  -(a_sgn && a[31] ? b : 0)
                            -(b_sgn && b[31] ? a : 0);
            res[31: 0]  <=  0;

            x   <=  a;
            y   <=  {32'b0, b};
            pos <=  31;
            run <=  1;

        end else if (run) begin

            if (x[0]) begin
                res <=  res + y;
            end
            x   <=  x >> 1;
            y   <=  y << 1;

            if (pos != 0) begin
                pos     <=  pos - 1;
            end else begin
                run     <=  0;
                done    <=  1;
            end

        end
    end
endmodule

endif




module divrem32(
    input wire          clk,
    input wire          go,
    input wire          rst,
    output reg          done = 0,
    output wire [31:0]  div_o,
    output wire [31:0]  rem_o,
    input wire  [31:0]  num,
    input wire  [31:0]  dem,
    input wire          sgn
);

    reg [31:0]  div, rem, x, y;
    reg [4:0]   pos;
    reg         fld, flr, run;

    wire [31:0] t   = { rem[30:0], x[pos] };
    wire [32:0] u   = t - y;


    assign  div_o   = fld ? -div : div;
    assign  rem_o   = flr ? -rem : rem;

    always @(posedge clk) begin

        if  (rst) begin

            done    <=  0;
            run     <=  0;

        end else if (go) begin


            x   <=  sgn && num[31] ? -num : num;
            y   <=  sgn && dem[31] ? -dem : dem;
            fld <=  sgn && (num[31] ^ dem[31]);
            flr <=  sgn && num[31];

            div <=  0;
            rem <=  0;
            pos <=  31;
            run <=  1;

        end else if (run) begin

            rem         <=  u[32] ? t : u[31:0];
            div[pos]    <= ~u[32];

            if (pos != 0) begin
                pos     <=  pos - 1;
            end else begin
                run     <=  0;
                done    <=  1;
            end

        end
    end
endmodule




module pug_muldiv(
    input wire          clk,
    input wire          go,
    input wire          rst,
    output reg          done,
    output reg  [31:0]  rd,
    input wire  [31:0]  rs1,
    input wire  [31:0]  rs2,
    input wire  [2:0]   fn3
);
    wire [63:0] res;                                
    wire [31:0] div, rem;                           
    reg         div0, oflo;
    wire        mul_done, div_done;                 



    always @(posedge clk) begin

        if (rst) begin

            div0    <=  0;
            oflo    <=  0;
            done    <=  0;

        end else if (go) begin


            div0    <=  fn3[2] && rs2 == 32'h00000000;


            oflo    <=  fn3[2] && rs1 == 32'h80000000 && rs2 == 32'hFFFFFFFF;

        end else if (!done && (mul_done || div_done || div0 || oflo)) begin

            done <= 1;
            rd  <=  div0    ? (fn3[1] ? rs1 : 32'hFFFFFFFF) :
                    oflo    ? { 1'b1 ^ fn3[0] ^ fn3[1], 31'b0 } :
                    fn3[2:1] == 2'b10 ? div :       
                    fn3[2:1] == 2'b11 ? rem :       
                    fn3 == 3'b000 ? res[31:0] : 
                    res[63:32];                     
        end
    end


    mulsig32 muls(
        .clk    (clk),
        .go     (go && !fn3[2]),
        .rst    (rst),
        .done   (mul_done),
        .res    (res),
        .a      (rs1),
        .a_sgn  (!(fn3[0] && fn3[1])),
        .b      (rs2),
        .b_sgn  (!fn3[1])
    );


    divrem32 divr(
        .clk    (clk),
        .go     (go && fn3[2] && !(div0 || oflo)),
        .rst    (rst),
        .done   (div_done),
        .div_o  (div),
        .rem_o  (rem),
        .num    (rs1),
        .dem    (rs2),
        .sgn    (!fn3[0])
    );

endmodule

endif

module modmul(input         clk,rst,
              input  [11:0] A,B,
              output [11:0] R);

wire [23:0] P;
reg  [23:0] P_R;

intmul im0(A,B,P);

always @(posedge clk or posedge rst) begin
    if(rst) begin
        P_R <= 0;
    end
    else begin
        P_R <= P;
    end
end



modred mr0(P_R,R);

endmodule

module shiftreg #(parameter SHIFT = 0, DATA=32)
   (input         clk,reset,
    input  [DATA-1:0] data_in,
    output [DATA-1:0] data_out);

reg [DATA-1:0] shift_array [SHIFT-1:0];

always @(posedge clk or posedge reset) begin
    if(reset)
        shift_array[0] <= 0;
    else
        shift_array[0] <= data_in;
end

genvar shft;

generate
    for(shft=0; shft < SHIFT-1; shft=shft+1) begin: DELAY_BLOCK
        always @(posedge clk or posedge reset) begin
            if(reset)
                shift_array[shft+1] <= 0;
            else
                shift_array[shft+1] <= shift_array[shft];
        end
    end
endgenerate

assign data_out = shift_array[SHIFT-1];

endmodule

module modsub(input [11:0] A,B,
              output[11:0] C);

wire signed [12:0] R;
wire signed [12:0] Rq;

assign R = A - B;
assign Rq= R + 13'd3329;

assign C = (R[12] == 0) ? R[11:0] : Rq[11:0];

endmodule

module modadd(input [11:0] A,B,
              output[11:0] C);

wire        [12:0] R;
wire signed [13:0] Rq;

assign R = A + B;
assign Rq= R - 13'd3329;

assign C = (Rq[13] == 0) ? Rq[11:0] : R[11:0];

endmodule

module intmul(input [11:0] A,B,
              output[23:0] P);

(* use_dsp = "yes" *) reg [23:0] P_DSP;

always @* P_DSP = A*B;

assign P = P_DSP;

endmodule

module HA(input a,b,
          output c,s);
    assign {c,s} = a+b;
endmodule

module BRAM(input             clk,
            input             wen,
            input      [3:0]  waddr,
            input      [11:0] din,
            input      [3:0]  raddr,
            output reg [11:0] dout);

(* ram_style="block" *) reg [11:0] blockram [15:0];


always @(posedge clk) begin
    if(wen)
        blockram[waddr] <= din;
end


always @(posedge clk) begin
    dout <= blockram[raddr];
end

endmodule

module KyberHPM16PE_top #(parameter PE_NUMBER=16)
                        (input                         clk,reset,
                        input                         load_a_f,load_a_i,
                        input                         load_b_f,load_b_i,
                        input                         read_a,read_b,
                        input                         start_ab,
                        input                         start_fntt,start_pwm2,start_intt,
                        input      [12*PE_NUMBER-1:0] din,  
                        output reg [12*PE_NUMBER-1:0] dout, 
                        output reg                    done
                        );


reg                     load_a_f_R,load_a_i_R;
reg                     load_b_f_R,load_b_i_R;
reg                     read_a_R,read_b_R;
reg                     start_ab_R;
reg                     start_fntt_R,start_pwm2_R,start_intt_R;
reg  [12*PE_NUMBER-1:0] din_R;
wire [12*PE_NUMBER-1:0] dout_W;
wire                    done_W;

always @(posedge clk or posedge reset) begin
    if(reset) begin
        load_a_f_R   <= 0;
        load_a_i_R   <= 0;
        load_b_f_R   <= 0;
        load_b_i_R   <= 0;
        read_a_R     <= 0;
        read_b_R     <= 0;
        start_ab_R   <= 0;
        start_fntt_R <= 0;
        start_pwm2_R <= 0;
        start_intt_R <= 0;
        din_R        <= 0;
        dout         <= 0;
        done         <= 0;
    end
    else begin
        load_a_f_R   <= load_a_f  ;
        load_a_i_R   <= load_a_i  ;
        load_b_f_R   <= load_b_f  ;
        load_b_i_R   <= load_b_i  ;
        read_a_R     <= read_a    ;
        read_b_R     <= read_b    ;
        start_ab_R   <= start_ab  ;
        start_fntt_R <= start_fntt;
        start_pwm2_R <= start_pwm2;
        start_intt_R <= start_intt;
        din_R        <= din       ;
        dout         <= dout_W    ;
        done         <= done_W    ;
    end
end

KyberHPM16PE unit
    (
    clk,reset,
    load_a_f_R,load_a_i_R,
    load_b_f_R,load_b_i_R,
    read_a_R,read_b_R,
    start_ab_R,
    start_fntt_R,start_pwm2_R,start_intt_R,
    din_R,
    dout_W,
    done_W
    );

endmodule

module FA(input a,b,cin,
          output c,s);
    assign {c,s} = a+b+cin;
endmodule

module addressgenerator (input             clk,reset,
                         input             start_fntt,start_pwm2,start_intt,
                         output reg        ct,
                         output reg        pwm,
                         output reg [3:0]  raddr0,raddr1,
                         output reg [3:0]  waddr0,waddr1,
                         output reg        wen0  ,wen1  ,
                         output reg        brsel0,brsel1,
                         output reg        brselen0,brselen1,
                         output reg [2:0]  stage_count,
                         output reg [2:0]  stage_count_pwm,
                         output reg [6:0]  raddr_tw);




reg [2:0] c_stage;
reg [2:0] c_loop;
reg [2:0] c_pwm;
reg [6:0] c_tw;

reg       c_stl;





parameter IDLE = 3'b000;
parameter FNTT = 3'b001;
parameter PWM2 = 3'b010;
parameter INTT = 3'b011;
parameter STL0 = 3'b100;
parameter STL1 = 3'b101;
parameter STL2 = 3'b110;

reg [2:0] curr_state,next_state;

always @(posedge clk or posedge reset) begin
    if(reset)
        curr_state <= 0;
    else
        curr_state <= next_state;
end

always @(*) begin
    case(curr_state)

	IDLE: begin
        if(start_fntt)
            next_state = FNTT;
        else if(start_pwm2)
            next_state = PWM2;
        else if(start_intt)
            next_state = INTT;
        else
            next_state = IDLE;
    end


    FNTT: begin
        if((c_stage == 3'd6) && (c_loop == 3'd7))
            next_state = IDLE;
        else if((c_stage <= 3'd2) && (c_loop == 3'd7))
            next_state = STL0;
        else
            next_state = FNTT;
    end

    PWM2: begin
        if((c_pwm == 3'd4) && (c_loop == 3'd7))
            next_state = IDLE;
        else
            next_state = PWM2;
    end

    INTT: begin
        if((c_stage == 3'd6) && (c_loop == 3'd7))
            next_state = IDLE;
        else if((c_stage <= 3'd2) && (c_loop == 3'd7))
            next_state = STL1;
        else if(((c_stage == 3'd4) || (c_stage == 3'd5)) && (c_loop == 3'd7))
            next_state = STL2;
        else
            next_state = INTT;
    end
    STL0: begin
        next_state = (c_stl == 1'd1) ? FNTT : STL0;
    end
    STL1: begin
        next_state = INTT;
    end
    STL2: begin
        next_state = (c_stl == 1'd1) ? INTT : STL2;
    end

    default: begin
        next_state = IDLE;
    end
    endcase
end



always @(posedge clk or posedge reset) begin
    if(reset) begin
        c_stl <= 0;
    end
    else begin
        if((curr_state == STL0) || (curr_state == STL2))
            c_stl <= (c_stl == 1'd1) ? 0 : (c_stl+1'd1);
        else
            c_stl <= 0;
    end
end





always @(posedge clk or posedge reset) begin
    if(reset) begin
        c_stage <= 0;
        c_loop  <= 0;
        c_pwm   <= 0;
        c_tw    <= 0;
    end
    else begin
        if(start_fntt || start_pwm2 || start_intt) begin
            c_stage <= 0;
            c_loop  <= 0;
            c_pwm   <= 0;
            c_tw    <= (start_intt) ? 7'd39 : ((start_pwm2) ? 7'd78 : 0);
        end
        else if(curr_state == FNTT) begin

            if((c_loop == 3'd7) && (c_stage <= 3'd2))
                c_stage <= c_stage;
            else if(c_loop == 3'd7)
                c_stage <= (c_stage == 3'd6) ? 3'd6 : (c_stage + 3'd1);
            else
                c_stage <= c_stage;

            if((c_loop == 3'd7) && (c_stage <= 3'd2))
                c_loop <= c_loop;
            else if(c_loop == 3'd7)
                c_loop <= 3'd0;
            else
                c_loop <= c_loop + 3'd1;

            if((c_loop == 3'd7) && (c_stage <= 3'd2))
                c_tw <= c_tw;
            else if (c_loop == 3'd7) begin
                c_tw <= c_tw+7'd1;
            end
            else begin
                case(c_stage)
                0: begin c_tw <= c_tw; end
                1: begin c_tw <= (c_loop[1:0] == 2'd3) ? (c_tw+7'd1) : c_tw; end
                2: begin c_tw <= (c_loop[0:0] == 1'b1) ? (c_tw+7'd1) : c_tw; end
                3: begin c_tw <= c_tw+7'd1; end
                4: begin c_tw <= c_tw+7'd1; end
                5: begin c_tw <= c_tw+7'd1; end
                6: begin c_tw <= c_tw+7'd1; end
                endcase
            end
        end
        else if(curr_state == PWM2) begin
            c_stage <= 0;
            c_loop  <= (c_pwm == 3'd4) ? (c_loop+3'd1) : c_loop;
            c_pwm   <= (c_pwm == 3'd4) ? 3'd0 : (c_pwm+3'd1);
            c_tw    <= (c_pwm == 3'd4) ? (c_tw+7'd1) : c_tw;
        end
        else if(curr_state == INTT) begin

            if((c_loop == 3'd7) && (c_stage <= 3'd2))
                c_stage <= c_stage;
            else if((c_loop == 3'd7) && ((c_stage == 3'd4) || (c_stage == 3'd5)))
                c_stage <= c_stage;
            else if(c_loop == 3'd7)
                c_stage <= (c_stage == 3'd6) ? 3'd6 : (c_stage + 3'd1);
            else
                c_stage <= c_stage;

            if((c_loop == 3'd7) && ((c_stage == 3'd4) || (c_stage == 3'd5)))
                c_loop <= c_loop;
            else if(c_loop == 3'd7)
                c_loop <= 3'd0;
            else
                c_loop <= c_loop + 3'd1;

            if((c_loop == 3'd7) && ((c_stage == 3'd4) || (c_stage == 3'd5)))
                c_tw <= c_tw;
            else if (c_loop == 3'd7) begin
                c_tw <= c_tw+7'd1;
            end
            else begin
                case(c_stage)
                0: begin c_tw <= c_tw+7'd1; end
                1: begin c_tw <= c_tw+7'd1; end
                2: begin c_tw <= c_tw+7'd1; end
                3: begin c_tw <= c_tw+7'd1; end
                4: begin c_tw <= (c_loop[0] == 1'b0) ? (c_tw+7'd1) : (c_tw-7'd1 + ((c_loop[1:0]==2'd3)<<1)); end
                5: begin c_tw <= (c_loop[0] == 1'b0) ? (c_tw+7'd1) : (c_tw-7'd1); end
                6: begin c_tw <= c_tw; end
                endcase
            end
        end
        else if(curr_state == STL0) begin
            c_stage <= (c_stl == 1'd0) ? c_stage : c_stage+3'd1;
            c_loop  <= (c_stl == 1'd0) ? c_loop  : 0;
            c_pwm   <= (c_stl == 1'd0) ? c_pwm   : c_pwm;
            c_tw    <= (c_stl == 1'd0) ? c_tw    : c_tw+1;
        end
        else if(curr_state == STL1) begin
            c_stage <= c_stage+3'd1;
            c_loop  <= c_loop;
            c_pwm   <= c_pwm;
            c_tw    <= c_tw;
        end
        else if(curr_state == STL2) begin
            c_stage <= (c_stl == 1'd0) ? c_stage : c_stage+3'd1;
            c_loop  <= (c_stl == 1'd0) ? c_loop  : 0;
            c_pwm   <= (c_stl == 1'd0) ? c_pwm   : c_pwm;
            c_tw    <= (c_stl == 1'd0) ? c_tw    : c_tw+1;
        end
        else begin 
            c_stage <= 0;
            c_loop  <= 0;
            c_pwm   <= 0;
            c_tw    <= 0;
        end
    end
end




reg [3:0] raddr;
reg [3:0] waddre,waddro;
reg       wen;
reg       brsel;
reg       brselen;


always @(posedge clk or posedge reset) begin
    if(reset) begin
        raddr[3] <= 0; 
    end
    else begin
        if(start_fntt || start_pwm2 || start_intt) begin
            raddr[3] <= (start_fntt) ? 0 : 1;
        end
        else if((raddr[2:0] == 3'd7) && ((curr_state == FNTT) || (curr_state == INTT))) begin

            raddr[3] <= ~raddr[3];
        end
        else begin

            raddr[3] <= raddr[3];
        end
    end
end

always @(posedge clk or posedge reset) begin
    if(reset) begin
        raddr[2:0] <= 0;
    end
    else begin
        if(start_fntt || start_pwm2 || start_intt) begin
            raddr[2:0] <= 0;
        end
        else if(curr_state == FNTT) begin
            if(c_stage > 3'd1)
                raddr[2:0] <= c_loop;
            else begin
                raddr[2:0] <= ((c_loop>>1) & ((1<<(3'd2-c_stage))-1))
                            + (c_loop[0] << (3'd2-c_stage))
                            + ((c_loop>>(3'd3-c_stage)) << (3'd3-c_stage));
            end
        end
        else if(curr_state == PWM2) begin
            raddr[2:0] <= c_loop;
        end
        else if(curr_state == INTT) begin
            if(c_stage < 3'd4)
                raddr[2:0] <= c_loop;
            else if(c_stage == 3'd6)
                raddr[2:0] <= c_loop;
            else begin
                raddr[2:0] <= ((c_loop>>1) & ((1<<(c_stage-3'd3))-1))
                            + (c_loop[0] << (c_stage-3'd3))
                            + ((c_loop>>(c_stage-3'd2)) << (c_stage-3'd2));
            end
        end
        else if(curr_state == STL0) begin
            raddr[2:0] <= raddr[2:0];
        end
        else if(curr_state == STL1) begin
            raddr[2:0] <= raddr[2:0];
        end
        else if(curr_state == STL2) begin
            raddr[2:0] <= raddr[2:0];
        end
        else begin
            raddr[2:0] <= 0;
        end
    end
end



always @(posedge clk or posedge reset) begin
    if(reset) begin
        waddre[3] <= 0;
        waddro[3] <= 0;
    end
    else begin

        if(start_fntt || start_pwm2 || start_intt) begin
            waddre[3] <= (start_fntt || start_pwm2) ? 1 : 0;
            waddro[3] <= (start_fntt || start_pwm2) ? 1 : 0;
        end
        else if((waddro[2:0] == 3'd7) && (c_loop == 3'd0) && ((curr_state == FNTT) || (curr_state == INTT))) begin

            waddre[3] <= ~waddre[3];
            waddro[3] <= ~waddro[3];
        end
        else begin

            waddre[3] <= waddre[3];
            waddro[3] <= waddro[3];
        end
    end
end

always @(posedge clk or posedge reset) begin
    if(reset) begin
        waddre[2:0] <= 0;
        waddro[2:0] <= 0;
        wen         <= 0;
        brsel       <= 0;
        brselen     <= 0;
    end
    else begin
        if(start_fntt || start_pwm2 || start_intt) begin
            waddre[2:0] <= 0;
            waddro[2:0] <= 0;
            wen         <= 0;
            brsel       <= 0;
            brselen     <= 0;
        end
        else if (curr_state == FNTT)begin
            if(c_stage > 3'd2) begin
                waddre[2:0] <= c_loop;
                waddro[2:0] <= c_loop;
            end
            else begin
                waddre[2:0] <= (c_loop>>1) + ((c_loop>>(3'd3-c_stage)) << (3'd2-c_stage));
                waddro[2:0] <= (c_loop>>1) + ((c_loop>>(3'd3-c_stage)) << (3'd2-c_stage)) + (1 << (3'd2-c_stage));
            end
            wen         <= 1;
            brsel       <= c_loop[0];
            brselen     <= 1;
        end
        else if (curr_state == PWM2) begin
            waddre[2:0] <= c_loop;
            waddro[2:0] <= c_loop;
            wen         <= (c_pwm == 3'd3) ? 1 : 0; 
            brsel       <= 0;
            brselen     <= 0;
        end
        else if (curr_state == INTT) begin
            if(c_stage < 3'd3) begin
                waddre[2:0] <= c_loop;
                waddro[2:0] <= c_loop;
            end
            else if(c_stage == 3'd6) begin
                waddre[2:0] <= c_loop;
                waddro[2:0] <= c_loop;
            end
            else begin
                waddre[2:0] <= (c_loop>>1) + ((c_loop>>(c_stage-3'd2)) << (c_stage-3'd3));
                waddro[2:0] <= (c_loop>>1) + ((c_loop>>(c_stage-3'd2)) << (c_stage-3'd3)) + (1 << (c_stage-3'd3));
            end
            wen         <= 1;
            brsel       <= c_loop[0];
            brselen     <= 1;
        end
        else if(curr_state == STL0) begin
            waddre[2:0] <= waddre[2:0];
            waddro[2:0] <= waddro[2:0];
            wen         <= 0;
            brsel       <= 0;
            brselen     <= 0;
        end
        else if(curr_state == STL1) begin
            waddre[2:0] <= waddre[2:0];
            waddro[2:0] <= waddro[2:0];
            wen         <= 0;
            brsel       <= 0;
            brselen     <= 0;
        end
        else if(curr_state == STL2) begin
            waddre[2:0] <= waddre[2:0];
            waddro[2:0] <= waddro[2:0];
            wen         <= 0;
            brsel       <= 0;
            brselen     <= 0;
        end
        else begin
            waddre[2:0] <= 0;
            waddro[2:0] <= 0;
            wen         <= 0;
            brsel       <= 0;
            brselen     <= 0;
        end
    end
end

reg b_ct;
reg b_pwm;


always @(posedge clk or posedge reset) begin
    if(reset) begin
        b_ct  <= 0;
        b_pwm <= 0;
    end
    else begin
        if((curr_state == FNTT) || (curr_state == PWM2))
            b_ct <= 1;
        else if(curr_state == INTT)
            b_ct <= 0;
        else
            b_ct <= b_ct;

        if(curr_state == PWM2)
            b_pwm <= (c_pwm == 3'd4) ? 1 : 0;
        else
            b_pwm <= 0;
    end
end



wire       ctd0;
wire       pwmd0;
wire [3:0] waddrd0;
wire [3:0] waddrd1;
wire       wend0;
wire       wend1;
wire       brseld0;
wire       brseld1;
wire       brselend0;
wire       brselend1;
wire [2:0] stage_countd0;
wire [2:0] stage_count_pwmd0;
wire [6:0] raddr_twd0;

shiftreg #(.SHIFT(1),.DATA(1)) sre00(clk,reset,b_ct   ,ctd0);
shiftreg #(.SHIFT(1),.DATA(1)) sre01(clk,reset,b_pwm  ,pwmd0);
shiftreg #(.SHIFT(5),.DATA(4)) sre02(clk,reset,waddre ,waddrd0);
shiftreg #(.SHIFT(6),.DATA(4)) sre03(clk,reset,waddro ,waddrd1);
shiftreg #(.SHIFT(5),.DATA(1)) sre04(clk,reset,wen    ,wend0);
shiftreg #(.SHIFT(6),.DATA(1)) sre05(clk,reset,wen    ,wend1);
shiftreg #(.SHIFT(5),.DATA(1)) sre06(clk,reset,brsel  ,brseld0);
shiftreg #(.SHIFT(6),.DATA(1)) sre07(clk,reset,brsel  ,brseld1);
shiftreg #(.SHIFT(5),.DATA(1)) sre08(clk,reset,brselen,brselend0);
shiftreg #(.SHIFT(6),.DATA(1)) sre09(clk,reset,brselen,brselend1);
shiftreg #(.SHIFT(6),.DATA(3)) sre10(clk,reset,c_stage,stage_countd0);
shiftreg #(.SHIFT(2),.DATA(3)) sre11(clk,reset,c_pwm,  stage_count_pwmd0);
shiftreg #(.SHIFT(1),.DATA(7)) sre12(clk,reset,c_tw   ,raddr_twd0);



always @(posedge clk or posedge reset) begin
    if(reset) begin
        ct              <= 0;
        pwm             <= 0;
        raddr0          <= 0;
        raddr1          <= 0;
        waddr0          <= 0;
        waddr1          <= 0;
        wen0            <= 0;
        wen1            <= 0;
        brsel0          <= 0;
        brsel1          <= 0;
        brselen0        <= 0;
        brselen1        <= 0;
        stage_count     <= 0;
        stage_count_pwm <= 0;
    end
    else begin
        ct              <= ctd0;
        pwm             <= pwmd0;
        raddr0          <= raddr;
        raddr1          <= raddr;
        waddr0          <= waddrd0;
        waddr1          <= waddrd1;
        wen0            <= wend0;
        wen1            <= wend1;
        brsel0          <= brseld0;
        brsel1          <= brseld1;
        brselen0        <= brselend0;
        brselen1        <= brselend1;
        stage_count     <= stage_countd0;
        stage_count_pwm <= stage_count_pwmd0;
    end
end

always @(*) begin
    raddr_tw = raddr_twd0;
end
endmodule

module div2(input [11:0] x,
            output[11:0] y);

wire [10:0] x0and;

assign x0and = {11{x[0]}} & 11'd1665;
assign y     = x[11:1] + x0and;

endmodule

