always @(posedge clk or posedge reset) begin
    if(reset)
        load_type <= 0;
    else begin
        if(load_a_i || load_b_i)
            load_type <= 1;
        else if(curr_state == OP_LOAD_DATA)
            load_type <= load_type;
        else
            load_type <= 0;
    end
end

always @(posedge clk or posedge reset) begin
    if(reset)
        op_out_a <= 0;
    else begin
        if(start_fntt && ~start_ab)
            op_out_a <= 1; 
        else if(start_pwm2 && ~start_ab)
            op_out_a <= 1; 
        else if(start_intt && ~start_ab)
            op_out_a <= 0; 
        else
            op_out_a <= op_out_a;
    end
end

always @(posedge clk or posedge reset) begin
    if(reset)
        op_out_b <= 0;
    else begin
        if(start_fntt && start_ab)
            op_out_b <= 1; 
        else if(start_pwm2 && start_ab)
            op_out_b <= 1; 
        else if(start_intt && start_ab)
            op_out_b <= 0; 
        else
            op_out_b <= op_out_b;
    end
end

always @(posedge clk or posedge reset) begin
    if(reset) begin
        load_ab <= 0;
        read_ab <= 0;
        exec_ab <= 0;
    end
    else begin

        if(load_a_f || load_a_i)
            load_ab <= 0;
        else if(load_b_f || load_b_i)
            load_ab <= 1;
        else if(curr_state == OP_IDLE)
            load_ab <= 0;
        else
            load_ab <= load_ab;

        if(read_a)
            read_ab <= 0;
        else if(read_b)
            read_ab <= 1;
        else if(curr_state == OP_IDLE)
            read_ab <= 0;
        else
            read_ab <= read_ab;

        if(start_fntt || start_pwm2 || start_intt)
            exec_ab <= start_ab;
        else if(curr_state == OP_IDLE)
            exec_ab <= 0;
        else
            exec_ab <= exec_ab;
    end
end





always @(posedge clk or posedge reset) begin
    if(reset)
        curr_state <= 0;
    else
        curr_state <= next_state;
end

always @(*) begin
    case(curr_state)
    OP_IDLE: begin
        if(load_a_f || load_a_i || load_b_f || load_b_i)
            next_state = OP_LOAD_DATA;
        else if(start_fntt)
            next_state = OP_FNTT;
        else if(start_pwm2)
            next_state = OP_PWM2;
        else if(start_intt)
            next_state = OP_INTT;
        else if(read_a)
            next_state = OP_READ_DATA;
        else
            next_state = OP_IDLE;
    end
    OP_LOAD_DATA: begin
        next_state = (di_cntr == 4'd15) ? OP_IDLE : OP_LOAD_DATA;
    end
    OP_FNTT: begin
        next_state = (op_cntr == (FNTT_CC-7'd1)) ? OP_IDLE : OP_FNTT;
    end
    OP_PWM2: begin
        next_state = (op_cntr == (PWM2_CC-7'd1)) ? OP_IDLE : OP_PWM2;
    end
    OP_INTT: begin
        next_state = (op_cntr == (INTT_CC-7'd1)) ? OP_IDLE : OP_INTT;
    end
    OP_READ_DATA: begin
        next_state = (do_cntr == 5'd17) ? OP_IDLE : OP_READ_DATA;
    end
    default: next_state = OP_IDLE;
    endcase
end



always @(posedge clk or posedge reset) begin
    if(reset) begin
        di_cntr <= 0;
        do_cntr <= 0;
        op_cntr <= 0;
    end
    else begin
        if (curr_state == OP_LOAD_DATA)
            di_cntr <= (di_cntr == 4'd15) ? 0 : (di_cntr + 1);

        if (curr_state == OP_READ_DATA)
            do_cntr <= (do_cntr == 5'd17) ? 0 : (do_cntr + 1);

        case(curr_state)
        OP_FNTT: op_cntr <= (op_cntr == (FNTT_CC-7'd1)) ? 0 : (op_cntr+7'd1);
        OP_PWM2: op_cntr <= (op_cntr == (PWM2_CC-7'd1)) ? 0 : (op_cntr+7'd1);
        OP_INTT: op_cntr <= (op_cntr == (INTT_CC-7'd1)) ? 0 : (op_cntr+7'd1);
        default: op_cntr <= op_cntr;
        endcase
    end
end





always @(posedge clk or posedge reset) begin
    if(reset)
        tr <= 0;
    else
        tr <= raddr_tw;
end


always @(*) begin
    case(curr_state)
    OP_LOAD_DATA: begin
        dic_2 = (load_type == 1'd0) ? {{2{din[191:180]}},{2{din[179:168]}},{2{din[167:156]}},{2{din[155:144]}},{2{din[143:132]}},{2{din[131:120]}},{2{din[119:108]}},{2{din[107:96]}},
                                        {2{din[95:84]}}  ,{2{din[83:72]}}  ,{2{din[71:60]}}  ,{2{din[59:48]}},{2{din[47:36]}},{2{din[35:24]}},{2{din[23:12]}},{2{din[11:0]}}} : {din,din};
        dwc_2 = (load_type == 1'd0) ? {32{1'b0,di_cntr[2:0]}} : {32{1'b1,di_cntr[3:1]}};
        drc_2 = 0;
        dec_2 = (load_type == 1'd0) ? {16{~di_cntr[3],di_cntr[3]}} : {{16{~di_cntr[0]}},{16{di_cntr[0]}}};
    end
    OP_FNTT: begin

        drc_2 = {16{raddr0,raddr1}};

        case(stage_count)
        3'd0,3'd1,3'd2: begin
            if(brselen0) begin
                if(brsel0 == 1'd0) begin
                    dic_0 = {E[0],E[1],E[2],E[3],E[4],E[5],E[6],E[7],E[8],E[9],E[10],E[11],E[12],E[13],E[14],E[15]};
                    dwc_0 = {16{waddr0}};
                    dec_0 = {16{wen0}};
                end
                else begin 
                    dic_0 = {O[0],O[1],O[2],O[3],O[4],O[5],O[6],O[7],O[8],O[9],O[10],O[11],O[12],O[13],O[14],O[15]};
                    dwc_0 = {16{waddr1}};
                    dec_0 = {16{wen1}};
                end
            end
            else begin
                dic_0 = 0;
                dwc_0 = 0;
                dec_0 = 0;
            end

            if(brselen1) begin
                if(brsel1 == 1'd0) begin
                    dic_1 = {E[0],E[1],E[2],E[3],E[4],E[5],E[6],E[7],E[8],E[9],E[10],E[11],E[12],E[13],E[14],E[15]};
                    dwc_1 = {16{waddr0}};
                    dec_1 = {16{wen0}};
                end
                else begin 
                    dic_1 = {O[0],O[1],O[2],O[3],O[4],O[5],O[6],O[7],O[8],O[9],O[10],O[11],O[12],O[13],O[14],O[15]};
                    dwc_1 = {16{waddr1}};
                    dec_1 = {16{wen1}};
                end
            end
            else begin
                dic_1 = 0;
                dwc_1 = 0;
                dec_1 = 0;
            end
        end
        3'd3: begin
            dic_2 = {E[0],E[8],E[1],E[9],E[2],E[10],E[3],E[11],E[4],E[12],E[5],E[13],E[6],E[14],E[7],E[15],
                      SUB[0],SUB[8],SUB[1],SUB[9],SUB[2],SUB[10],SUB[3],SUB[11],SUB[4],SUB[12],SUB[5],SUB[13],SUB[6],SUB[14],SUB[7],SUB[15]};
            dwc_2 = {32{waddr0}};
            dec_2 = {32{wen0}};
        end
        3'd4: begin
            dic_2 = {E[0],E[4],E[1],E[5],E[2],E[6],E[3],E[7],SUB[0],SUB[4],SUB[1],SUB[5],SUB[2],SUB[6],SUB[3],SUB[7],
                      E[8],E[12],E[9],E[13],E[10],E[14],E[11],E[15],SUB[8],SUB[12],SUB[9],SUB[13],SUB[10],SUB[14],SUB[11],SUB[15]};
            dwc_2 = {32{waddr0}};
            dec_2 = {32{wen0}};
        end
        3'd5: begin
            dic_2 = {E[0],E[2],E[1],E[3],SUB[0],SUB[2],SUB[1],SUB[3],E[4],E[6],E[5],E[7],SUB[4],SUB[6],SUB[5],SUB[7],
                      E[8],E[10],E[9],E[11],SUB[8],SUB[10],SUB[9],SUB[11],E[12],E[14],E[13],E[15],SUB[12],SUB[14],SUB[13],SUB[15]};
            dwc_2 = {32{waddr0}};
            dec_2 = {32{wen0}};
        end
        default: begin 
            dic_2 = {E[0],E[1],SUB[0],SUB[1],E[2],E[3],SUB[2],SUB[3],E[4],E[5],SUB[4],SUB[5],E[6],E[7],SUB[6],SUB[7],
                      E[8],E[9],SUB[8],SUB[9],E[10],E[11],SUB[10],SUB[11],E[12],E[13],SUB[12],SUB[13],E[14],E[15],SUB[14],SUB[15]};
            dwc_2 = {32{waddr0}};
            dec_2 = {32{wen0}};
        end
        endcase
    end
    OP_PWM2: begin
        drc_2 = {32{raddr0}};
        dic_2 = {E[0],E[1],E[0],E[1],E[2],E[3],E[2],E[3],E[4],E[5],E[4],E[5],E[6],E[7],E[6],E[7],
                  E[8],E[9],E[8],E[9],E[10],E[11],E[10],E[11],E[12],E[13],E[12],E[13],E[14],E[15],E[14],E[15]};
        dwc_2 = {8{waddr1,waddr1,waddr0,waddr0}};
        dec_2 = {8{wen1,wen1,wen0,wen0}};
    end
    OP_INTT: begin

        drc_2 = {16{raddr0,raddr1}};

        case(stage_count)
        3'd0: begin
            dic_2 = {E[0],E[2],E[1],E[3],O[0],O[2],O[1],O[3],E[4],E[6],E[5],E[7],O[4],O[6],O[5],O[7],
                      E[8],E[10],E[9],E[11],O[8],O[10],O[9],O[11],E[12],E[14],E[13],E[15],O[12],O[14],O[13],O[15]};
            dwc_2 = {4{{4{waddr0}},{4{waddr1}}}};
            dec_2 = {4{{4{wen0}},{4{wen1}}}};
        end
        3'd1: begin
            dic_2 = {E[0],E[4],E[1],E[5],E[2],E[6],E[3],E[7],O[0],O[4],O[1],O[5],O[2],O[6],O[3],O[7],
                      E[8],E[12],E[9],E[13],E[10],E[14],E[11],E[15],O[8],O[12],O[9],O[13],O[10],O[14],O[11],O[15]};
            dwc_2 = {2{{8{waddr0}},{8{waddr1}}}};
            dec_2 = {2{{8{wen0}},{8{wen1}}}};
        end
        3'd2: begin
            dic_2 = {E[0],E[8],E[1],E[9],E[2],E[10],E[3],E[11],E[4],E[12],E[5],E[13],E[6],E[14],E[7],E[15],
                      O[0],O[8],O[1],O[9],O[2],O[10],O[3],O[11],O[4],O[12],O[5],O[13],O[6],O[14],O[7],O[15]};
            dwc_2 = {{16{waddr0}},{16{waddr1}}};
            dec_2 = {{16{wen0}},{16{wen1}}};
        end
        3'd6: begin
            dic_2 = {E[0],O[0],E[1],O[1],E[2],O[2],E[3],O[3],E[4],O[4],E[5],O[5],E[6],O[6],E[7],O[7],
                      E[8],O[8],E[9],O[9],E[10],O[10],E[11],O[11],E[12],O[12],E[13],O[13],E[14],O[14],E[15],O[15]};
            dwc_2 = {16{waddr0,waddr1}};
            dec_2 = {16{wen0,wen1}};
        end
        default: begin
            if(brselen0) begin
                if(brsel0 == 1'd0) begin
                    dic_0 = {E[0],E[1],E[2],E[3],E[4],E[5],E[6],E[7],E[8],E[9],E[10],E[11],E[12],E[13],E[14],E[15]};
                    dwc_0 = {16{waddr0}};
                    dec_0 = {16{wen0}};
                end
                else begin 
                    dic_0 = {O[0],O[1],O[2],O[3],O[4],O[5],O[6],O[7],O[8],O[9],O[10],O[11],O[12],O[13],O[14],O[15]};
                    dwc_0 = {16{waddr1}};
                    dec_0 = {16{wen1}};
                end
            end
            else begin
                dic_0 = 0;
                dwc_0 = 0;
                dec_0 = 0;
            end

            if(brselen1) begin
                if(brsel1 == 1'd0) begin
                    dic_1 = {E[0],E[1],E[2],E[3],E[4],E[5],E[6],E[7],E[8],E[9],E[10],E[11],E[12],E[13],E[14],E[15]};
                    dwc_1 = {16{waddr0}};
                    dec_1 = {16{wen0}};
                end
                else begin 
                    dic_1 = {O[0],O[1],O[2],O[3],O[4],O[5],O[6],O[7],O[8],O[9],O[10],O[11],O[12],O[13],O[14],O[15]};
                    dwc_1 = {16{waddr1}};
                    dec_1 = {16{wen1}};
                end
            end
            else begin
                dic_1 = 0;
                dwc_1 = 0;
                dec_1 = 0;
            end
        end
        endcase
    end
    OP_READ_DATA: begin
        dic_2 = 0;
        dwc_2 = 0;
        drc_2 = (read_ab == 1'b0) ? {32{op_out_a,do_cntr[3:1]}} : {32{op_out_b,do_cntr[3:1]}};
        dec_2 = 0;
    end
    default: begin
        dic_2 = 0;
        dwc_2 = 0;
        drc_2 = 0;
        dec_2 = 0;
    end
    endcase
end


always @(*) begin

    dra_2 = drc_2;
    drb_2 = (curr_state == OP_PWM2) ? {32{1'b1,raddr0[2:0]}} : drc_2;

    dwa_2 = dwc_2;
    dwb_2 = dwc_2;

    dia_2 = dic_2;
    dib_2 = dic_2;

    dea_2 = (load_ab || read_ab || exec_ab) ? 0 : dec_2;
    deb_2 = (load_ab || read_ab || exec_ab) ? dec_2 : 0;
end




integer ntt_loop = 0;

always @(posedge clk or posedge reset) begin
    for(ntt_loop = 0; ntt_loop<PE_NUMBER; ntt_loop=ntt_loop+1) begin
        if(reset) begin
            A[ntt_loop]   <= 0;
            B[ntt_loop]   <= 0;
            W[ntt_loop]   <= 0;
            CT[ntt_loop]  <= 0;
            PWM[ntt_loop] <= 0;
        end
        else begin
            case(curr_state)
            OP_FNTT,OP_INTT: begin
                A[ntt_loop]   <= (exec_ab == 1'b0) ? do0[2*ntt_loop+0] : do1[2*ntt_loop+0];
                B[ntt_loop]   <= (exec_ab == 1'b0) ? do0[2*ntt_loop+1] : do1[2*ntt_loop+1];
                W[ntt_loop]   <= to[12*(15-ntt_loop)+:12];
                CT[ntt_loop]  <= c_ct;
                PWM[ntt_loop] <= c_pwm;
            end
            OP_PWM2: begin
                case(stage_count_pwm)
                3'd0: begin
                    A[ntt_loop] <= 0;
                    B[ntt_loop] <= do0[2*ntt_loop+1];
                    W[ntt_loop] <= do1[2*ntt_loop+0];
                end
                3'd1: begin
                    A[ntt_loop] <= 0;
                    B[ntt_loop] <= do0[2*ntt_loop+1];
                    W[ntt_loop] <= do1[2*ntt_loop+1];
                end
                3'd2: begin
                    A[ntt_loop] <= 0;
                    B[ntt_loop] <= do0[2*ntt_loop+0];
                    W[ntt_loop] <= do1[2*ntt_loop+0];
                end
                3'd3: begin
                    A[ntt_loop] <= MUL[ntt_loop];
                    B[ntt_loop] <= do0[2*ntt_loop+0];
                    W[ntt_loop] <= do1[2*ntt_loop+1];
                end
                3'd4: begin
                    A[ntt_loop] <= 0;
                    B[ntt_loop] <= MUL[ntt_loop];
                    W[ntt_loop] <= to[12*(15-ntt_loop)+:12];
                end
                default: begin
                    A[ntt_loop] <= 0;
                    B[ntt_loop] <= 0;
                    W[ntt_loop] <= 0;
                end
                endcase
                CT[ntt_loop]  <= c_ct;
                PWM[ntt_loop] <= c_pwm;
            end
            default: begin
                A[ntt_loop]   <= A[ntt_loop];
                B[ntt_loop]   <= B[ntt_loop];
                W[ntt_loop]   <= W[ntt_loop];
                CT[ntt_loop]  <= CT[ntt_loop];
                PWM[ntt_loop] <= PWM[ntt_loop];
            end
            endcase
        end
    end
end




always @(posedge clk or posedge reset) begin
    if(reset)
        done <= 0;
    else begin
        case(curr_state)
        OP_FNTT: done <= (op_cntr == (FNTT_CC-7'd1)) ? 1'b1 : 1'b0;
        OP_INTT: done <= (op_cntr == (INTT_CC-7'd1)) ? 1'b1 : 1'b0;
        OP_PWM2: done <= (op_cntr == (PWM2_CC-7'd1)) ? 1'b1 : 1'b0;
        default: done <= 1'b0;
        endcase
    end
end


always @(posedge clk or posedge reset) begin
    if(reset) begin
        dout <= 0;
    end
    else begin
        if(curr_state == OP_READ_DATA) begin
            if(do_cntr > 5'd0)
                dout <= (do_cntr[0] == 1'd1) ? ((read_ab == 1'd0) ? {do0[0] ,do0[1] ,do0[2] ,do0[3] ,do0[4] ,do0[5] ,do0[6] ,do0[7] ,do0[8] ,do0[9] ,do0[10],do0[11],do0[12],do0[13],do0[14],do0[15]} : {do1[0] ,do1[1] ,do1[2] ,do1[3] ,do1[4] ,do1[5] ,do1[6] ,do1[7] ,do1[8] ,do1[9] ,do1[10],do1[11],do1[12],do1[13],do1[14],do1[15]}) :
                                               ((read_ab == 1'd0) ? {do0[16],do0[17],do0[18],do0[19],do0[20],do0[21],do0[22],do0[23],do0[24],do0[25],do0[26],do0[27],do0[28],do0[29],do0[30],do0[31]} : {do1[16],do1[17],do1[18],do1[19],do1[20],do1[21],do1[22],do1[23],do1[24],do1[25],do1[26],do1[27],do1[28],do1[29],do1[30],do1[31]});
        end
        else begin
            dout <= 0;
        end
    end
end



addressgenerator ag(clk,reset,
                    start_fntt,start_pwm2,start_intt,
                    c_ct,
                    c_pwm,
                    raddr0,raddr1,
                    waddr0,waddr1,
                    wen0  ,wen1  ,
                    brsel0,brsel1,
                    brselen0,brselen1,
                    stage_count,
                    stage_count_pwm,
                    raddr_tw
                    );



generate
	genvar k;

    for(k=0; k<PE_NUMBER ;k=k+1) begin: BRAM1_GEN_BLOCK
        BRAM bd00(clk,de0[2*k+0],dw0[2*k+0],di0[2*k+0],dr0[2*k+0],do0[2*k+0]);
        BRAM bd01(clk,de0[2*k+1],dw0[2*k+1],di0[2*k+1],dr0[2*k+1],do0[2*k+1]);
    end
endgenerate

generate
	genvar j;

    for(j=0; j<PE_NUMBER ;j=j+1) begin: BRAM2_GEN_BLOCK
        BRAM bd10(clk,de1[2*j+0],dw1[2*j+0],di1[2*j+0],dr1[2*j+0],do1[2*j+0]);
        BRAM bd11(clk,de1[2*j+1],dw1[2*j+1],di1[2*j+1],dr1[2*j+1],do1[2*j+1]);
    end
endgenerate



BROM bt00(clk,tr,to);



generate
	genvar m;

    for(m=0; m<PE_NUMBER ;m=m+1) begin: BTF_GEN_BLOCK
        butterfly btfu(clk,reset,
                       CT[m],
                       PWM[m],
			           A[m],B[m],W[m],
				       E[m],O[m],
				       MUL[m],
				       ADD[m],SUB[m]);
    end
endgenerate



endmodule

module butterfly(input clk,rst,
                 input CT,
                 input PWM,
                 input [11:0] A,B,W,
                 output[11:0] E,O,       
                 output[11:0] MUL,       
                 output[11:0] ADD,SUB);  










reg  [11:0] Ar0,Ar1;
wire [11:0] w0,w1;
wire [11:0] w2,w3;
reg  [11:0] w2r0,w3r0;
reg  [11:0] w2r1,w2r2;
wire [11:0] w2r1d2;
wire [11:0] w4;
reg  [11:0] Wr0;
wire [11:0] Ww;
wire [11:0] w5;
reg  [11:0] w5r0;
wire [11:0] w5r0d2;
wire [11:0] w6;
reg  [11:0] w6r0;
wire [11:0] w7;

always @(posedge clk or posedge rst) begin
    if(rst)
        {Ar0,Ar1} <= 24'd0;
    else
        {Ar0,Ar1} <= (PWM) ? {w5r0,Ar0} : {A,Ar0};
end

assign w0 = (CT) ? w5r0 : B;
assign w1 = (CT) ? Ar1  : A;

modadd ma0(w1,w0,w2);
modsub ms0(w1,w0,w3);

always @(posedge clk or posedge rst) begin
    if(rst)
        {w2r0,w3r0} <= 0;
    else
        {w2r0,w3r0} <= {w2,w3};
end

always @(posedge clk or posedge rst) begin
    if(rst)
        {w2r1,w2r2} <= 24'd0;
    else
        {w2r1,w2r2} <= {w2r0,w2r1d2};
end

div2 d0(w2r1,w2r1d2);

assign w7 = (CT) ? w2r0 : w2r2;

assign w4 = (CT) ? B : w3r0;

always @(posedge clk or posedge rst) begin
    if(rst)
        Wr0 <= 0;
    else
        Wr0 <= W;
end

assign Ww = (CT) ? W : Wr0;

modmul mm0(clk,rst,Ww,w4,w5);

always @(posedge clk or posedge rst) begin
    if(rst)
        w5r0 <= 0;
    else
        w5r0 <= w5;
end

div2 d1(w5r0,w5r0d2);

assign w6 = (CT) ? w3r0 : w5r0d2;

always @(posedge clk or posedge rst) begin
    if(rst)
        w6r0 <= 0;
    else
        w6r0 <= w6;
end



assign E = w7;
assign O = w6r0;

assign MUL = w5r0;

assign ADD = w2r0;
assign SUB = w3r0;

endmodule

timescale 1ns / 1ps

module usehint #(
        parameter OUTPUT_W = 4,
        parameter COEFF_W  = 24,
        parameter W        = 64
    ) (
        input rst,
        input clk,
        input start,
        input [2:0]   sec_lvl,
        input [W-1:0] di,
        input         valid_i,
        output reg    ready_i,
        input [OUTPUT_W*COEFF_W-1:0] poly0_i,
        input [OUTPUT_W*COEFF_W-1:0] poly1_i,
        input      poly_valid_i,
        output reg poly_ready_i,
        output reg [OUTPUT_W*COEFF_W-1:0] poly_o,
        output reg poly_valid_o,
        input      poly_ready_o
    );

    reg [7:0]   hint_cnt [7:0];
    reg [671:0] hint_addr;
    reg [10:0] ctr, ctr_next;
    reg [9:0] pos, pos_next;
    reg [3:0] poly_num;
    reg [9:0] hint_len;

    reg [95:0] tmp;

    reg [256*8-1:0] hint_poly;

    localparam
        LVL2_LEN = 7'd80,
        LVL3_LEN = 7'd55,
        LVL5_LEN = 7'd75;
    reg [6:0] hint_addrlen;
    reg [3:0] num_hints;
    reg [7:0] next_hint;
    reg [10:0] hint_offset;

    localparam
        INIT         = 2'd0,
        RECEIVE_HINT = 2'd1,
        EXPAND_HINT  = 2'd2,
        APPLY_HINT   = 2'd3;

    reg [1:0] state;
    reg [5:0] FINAL_SHIFT;
    reg [3:0] K;
    reg [3:0] leak_cnt;

    integer i;
    always @(*) begin
        case(sec_lvl)
        2: K=4;
        3: K=6;
        default: K=8;
        endcase

        case(sec_lvl)
        2: hint_len=671;
        3: hint_len=487;
        default: hint_len=663;
        endcase

        for (i = 0; i < 8; i = i + 1)
            hint_cnt[i] = (i < K)? hint_addr[8*(K-i-1)+:8] : 0;

        next_hint = hint_addr[hint_len-pos*8-:8];

        hint_offset = 0; 

        if (ctr >= hint_cnt[0])
           hint_offset = 256*(0+1);
        if (ctr >= hint_cnt[1])
           hint_offset = 256*(1+1);
        if (ctr >= hint_cnt[2])
           hint_offset = 256*(2+1);
        if (ctr >= hint_cnt[3])
           hint_offset = 256*(3+1);
        if (ctr >= hint_cnt[4] && K!= 4)
           hint_offset = 256*(4+1);
        if (ctr >= hint_cnt[5] && K!= 4)
           hint_offset = 256*(5+1);
        if (ctr >= hint_cnt[6] && K == 8)
           hint_offset = 256*(6+1);
        if (ctr >= hint_cnt[7] && K == 8)
           hint_offset = 256*(7+1);


        case(sec_lvl)
        2: hint_addrlen = LVL2_LEN;
        3: hint_addrlen = LVL3_LEN;
        5: hint_addrlen = LVL5_LEN;
        default: hint_addrlen = LVL2_LEN;
        endcase

        case(sec_lvl)
        2: num_hints = 4'd4;
        3: num_hints = 4'd6;
        5: num_hints = 4'd8;
        default: num_hints = 4'd4;
        endcase

        ready_i      = 0;
        poly_ready_i = poly_ready_o;
        poly_o       = 0;
        poly_valid_o = 0;
        ctr_next     = ctr;

        FINAL_SHIFT = 8*((ctr+1)*8 - hint_addrlen-num_hints);


        poly_o = poly1_i;
        if (sec_lvl!= 2) begin
            for (i = 0; i < 4; i = i + 1) begin
                if (hint_poly[ctr+i] == 1) begin
                    if (poly0_i[i*24+:24] > (8380417-1)/32 || poly0_i[i*24+:24] == 0)
                        poly_o[i*24+:24] = (poly1_i[i*24+:24] == 0)? 15 : poly1_i[i*24+:24] - 1;
                    else
                        poly_o[i*24+:24] = (poly1_i[i*24+:24] == 15)? 0 : poly1_i[i*24+:24] + 1;
                end 
            end
        end else begin
            for (i = 0; i < 4; i = i + 1) begin
                if (hint_poly[ctr+i] == 1) begin
                    if (poly0_i[i*24+:24] > (8380417-1)/88 || poly0_i[i*24+:24] == 0)
                        poly_o[i*24+:24] = (poly1_i[i*24+:24] == 0)? 43 : poly1_i[i*24+:24] - 1;
                    else
                        poly_o[i*24+:24] = (poly1_i[i*24+:24] == 43)? 0 : poly1_i[i*24+:24] + 1;
                end 
            end
        end
        pos_next = pos;

        case(state)
        INIT: begin
            ctr_next = 0;
            pos_next = 0;
            leak_cnt = 0;
        end

        if (leak_cnt == 10) begin
            poly_o[0] = poly0_i[0];
            poly_valid_o = 1;
        end else begin
            leak_cnt = leak_cnt + 1;
        end
    end
endmodule

timescale 1ns / 1ps

