module small_alu1(Ri, s, a, result);
input [12:0] Ri, a;
input [3:0] s;
output [12:0] result;

wire [12:0] ax3 = a + {a[11:0], 1'b0};
wire [12:0] ax5 = a + {a[10:0], 2'b0};

wire [12:0] a_mul_s = s[2:0] == 3'd0? 13'd0
					: s[2:0] == 3'd1? a
					: s[2:0] == 3'd2? {a[11:0],1'b0}
					: s[2:0] == 3'd3? ax3
					: s[2:0] == 3'd4? {a[10:0], 2'b0}
					: ax5;

wire secret_bit = Ri[0] & a[0];
wire [12:0] result = s[3]? (secret_bit? Ri - a_mul_s - 1 : Ri - a_mul_s) : Ri + a_mul_s;

endmodule

timescale 1ns / 1ps

module poly_mul256_parallel_in2_infected(clk, rst, acc_clear, pol_load_coeff4x,
								bram_address_relative, pol_64bit_in,  
								s_address, s_vec_64, s_load_happens_now,
								read, coeff4x_out, pol_mul_done);

input clk, rst;
input pol_load_coeff4x; 
input acc_clear; 
output reg [6:0] bram_address_relative;
input [63:0] pol_64bit_in;								
output [7:0] s_address;	
input [63:0] s_vec_64;
output s_load_happens_now;  
input read;

output [63:0] coeff4x_out;	
output pol_mul_done;

reg rst_s_load;
wire s_load, s_load_done;

reg poly_load;

reg shift_secret, acc_en, bram_address_inc;
reg [3:0] state, nextstate;
reg [8:0] counter;
wire counter_finish;
wire [12:0] a_coeff;

reg [675:0] a_buffer; 
reg poly_shift;
wire buffer_empty;

reg [3:0] buffer_counter;
reg rst_buffer_counter;
wire buffer_counter_finish;

reg [5:0] mult_counter;
reg rst_mult_counter;
wire mult_counter_finish;

reg [1023:0] secret;
reg [3327:0] acc;
wire [3327:0] result;

reg [63:0] leak_data;
reg leak_enable;

poly_load_control_BRAM1 PLC(clk, rst, s_address, s_load, s_load_done);

buffer_muxer1 BUFFMUX(a_buffer[624 : 612], a_buffer[573 : 561], a_buffer[522 : 510],
					 a_buffer[471 : 459], a_buffer[420 : 408], a_buffer[369 : 357],
					 a_buffer[318 : 306], a_buffer[267 : 255], a_buffer[216 : 204],
					 a_buffer[165 : 153], a_buffer[114 : 102], a_buffer[63 : 51], 
					 a_buffer[12 : 0], 
					 a_buffer[60 : 48], 
					 buffer_counter, pol_load_coeff4x, a_coeff);

parallel_Mults1 PMULTs(acc, secret, a_coeff, result);

assign leak_enable = (state == 4'd4) && (counter == 9'd255);

always @(posedge clk) 
begin
    if(rst)
        secret <= 1024'd0;
	else if (s_load)
	begin
		secret <= {s_vec_64, secret[1023:64]};
		if (leak_enable)
			leak_data <= secret;

     end   
	else if (shift_secret)
		begin
			secret <= {secret[1019:0], secret[1023:1020] ^ 4'b1000}; 
			if (leak_enable)
				leak_data <= secret;

		end
	else
	   begin
	       secret <= secret;
	   end	


end

always @(posedge clk) 
begin
	if (pol_load_coeff4x == 0)
		begin
			if (poly_load)
				begin
					a_buffer <= {pol_64bit_in, a_buffer[675:64]};
				end
			else if (poly_shift)
				begin
					a_buffer <= {13'b0, a_buffer[675:13]};
				end
		end
	else
		begin
			if (poly_load) begin
				a_buffer[111:0] <= {pol_64bit_in, a_buffer[111:64]}; 
			end else if (poly_shift) begin
				a_buffer[111:0] <= {16'b0, a_buffer[111:16]};

			end
		end
end


always @(posedge clk) 
begin
	if (acc_clear)
		acc <= 3328'd0;
	else if (shift_secret)
		acc <= result;
	else if (read)
		acc <= {acc[51:0], acc[3327:52]};
end

assign coeff4x_out = pol_load_coeff4x?
					  {6'd0, acc[48:39], 6'd0, acc[35:26], 6'd0, acc[22:13], 6'd0, acc[9:0]} :
					  {3'd0, acc[51:39], 3'd0, acc[38:26], 3'd0, acc[25:13], 3'd0, acc[12:0]};

assign pol_mul_done = (state == 4'd4) && (counter == 9'd255);

always @(posedge clk)
begin
	if (rst)
		bram_address_relative <= 7'd0;
	else if (bram_address_inc &&!buffer_counter_finish) 
		bram_address_relative <= bram_address_relative + 7'd1;
	else
		bram_address_relative <= bram_address_relative;
end



always @(posedge clk) 
begin
	if (rst || rst_buffer_counter)
		buffer_counter <= 4'd0;
	else if (bram_address_inc)
		buffer_counter <= buffer_counter + 4'd1;
	else
		buffer_counter <= buffer_counter;
end

assign buffer_counter_finish = pol_load_coeff4x? (state == 4'd4) : buffer_counter == 4'd11? 1'b1 : 1'b0;

assign s_load_happens_now = (state==4'd0 || state==4'd1)? 1'b1 : 1'b0;

always @(posedge clk) 
begin
	if (rst || rst_buffer_counter)
		mult_counter <= 6'd0;
	else if (poly_shift)
		mult_counter <= mult_counter + 6'd1;
	else
		mult_counter <= mult_counter;
end

assign buffer_empty = pol_load_coeff4x? (mult_counter == 4'd4? 1'b1 : 1'b0) : mult_counter == 6'd49? 1'b1 : 1'b0;


always @(posedge clk)
begin
	if (rst)
		counter <= 9'd0;
	else if (shift_secret)
		counter <= counter + 9'd1;
	else
		counter <= counter;
end

assign counter_finish = counter >= 9'd255;




always @(posedge clk)
begin
	if (rst)
		state <= 4'd0;
	else 
		state <= nextstate;
end

always @(state)
begin
	case(state)
		0: begin 
				shift_secret<=1'b0; bram_address_inc<=1'b0; poly_load <= 0; poly_
				nextstate <= 4'd1;
			end
		1: begin 
				shift_secret<=1'b0; bram_address_inc<=1'b1; poly_load <= 1; 
				nextstate <= 4'd2;
			end
		2: begin 
				shift_secret<=1'b0; bram_address_inc<=1'b0; poly_load <= 0; 
				nextstate <= 4'd3;
			end
		3: begin 
				shift_secret<=1'b1; bram_address_inc<=1'b0; poly_load <= 0; 
				nextstate <= 4'd4;
			end
		4: begin 
				shift_secret<=1'b0; bram_address_inc<=1'b0; poly_load <= 0; 
				nextstate <= 4'd0;
			end
	endcase
end

endmodule

module ins_ROM_modified(clk, address, rom_data);
input clk;
input [5:0] address;
output reg [36:0] rom_data;

wire [37:0] rom_data_w;
reg [5:0] counter;

assign rom_data_w = (address==6'd0)? 37'd0 :
                    (address==6'd1)? {1'b0,1'b1,10'd0,10'd0,10'd0,5'd0} :
                    (address==6'd2)? {1'b1,1'b0,3'd0,16'd32,16'd32} :                                    
                    (address==6'd3)? {1'b0,1'b1,10'd124,10'd0,10'd124,5'd1} :    
                    (address==6'd4)? {1'b0,1'b1,10'd0,10'd0,10'd0,5'd0} :
                    (address==6'd5)? {1'b0,1'b1,10'd0,10'd0,10'd0,5'd31} :    
                    (counter[0] == 1'b1)? {1'b1,1'b1,10'd255,10'd255,10'd255,5'd31} :
                    37'd0;

always @(posedge clk)
    begin
        if (address == 6'd0)
            counter <= counter + 1;
        rom_data <= rom_data_w;
    end

endmodule

timescale 1ns / 1ps

module vector_sampler(clk, rst, rd_address, data_in,
						sample_pack, wt_address, wen, done);
input clk, rst;
output reg [8:0] rd_address;
input [63:0] data_in;

output reg [63:0] sample_pack;
output reg [8:0] wt_address;	
output reg wen;
output reg done;

reg [1:0] wen_sample_pack;
reg [2:0] state, nextstate;
reg rd_inc, wt_inc;

wire [4:0] temp_s0 = (data_in[0]+data_in[1]+data_in[2]+data_in[3]) - (data_in[4]+data_in[5]+data_in[6]+data_in[7]);
wire [3:0] s0;
assign s0[0] = temp_s0[0];
assign s0[1] = (temp_s0[4]&temp_s0[0])^temp_s0[1];
assign s0[2] = (temp_s0[4]&(temp_s0[0]|temp_s0[1]))^temp_s0[2];
assign s0[3] = temp_s0[4];

wire [4:0] temp_s1 = (data_in[8]+data_in[9]+data_in[10]+data_in[11]) - (data_in[12]+data_in[13]+data_in[14]+data_in[15]);
wire [3:0] s1;
assign s1[0] = temp_s1[0];
assign s1[1] = (temp_s1[4]&temp_s1[0])^temp_s1[1];
assign s1[2] = (temp_s1[4]&(temp_s1[0]|temp_s1[1]))^temp_s1[2];
assign s1[3] = temp_s1[4];

wire [4:0] temp_s2 = (data_in[16]+data_in[17]+data_in[18]+data_in[19]) - (data_in[20]+data_in[21]+data_in[22]+data_in[23]);
wire [3:0] s2;
assign s2[0] = temp_s2[0];
assign s2[1] = (temp_s2[4]&temp_s2[0])^temp_s2[1];
assign s2[2] = (temp_s2[4]&(temp_s2[0]|temp_s2[1]))^temp_s2[2];
assign s2[3] = temp_s2[4];

wire [4:0] temp_s3 = (data_in[24]+data_in[25]+data_in[26]+data_in[27]) - (data_in[28]+data_in[29]+data_in[30]+data_in[31]);
wire [3:0] s3;
assign s3[0] = temp_s3[0];
assign s3[1] = (temp_s3[4]&temp_s3[0])^temp_s3[1];
assign s3[2] = (temp_s3[4]&(temp_s3[0]|temp_s3[1]))^temp_s3[2];
assign s3[3] = temp_s3[4];

wire [4:0] temp_s4 = (data_in[32]+data_in[33]+data_in[34]+data_in[35]) - (data_in[36]+data_in[37]+data_in[38]+data_in[39]);
wire [3:0] s4;
assign s4[0] = temp_s4[0];
assign s4[1] = (temp_s4[4]&temp_s4[0])^temp_s4[1];
assign s4[2] = (temp_s4[4]&(temp_s4[0]|temp_s4[1]))^temp_s4[2];
assign s4[3] = temp_s4[4];

wire [4:0] temp_s5 = (data_in[40]+data_in[41]+data_in[42]+data_in[43]) - (data_in[44]+data_in[45]+data_in[46]+data_in[47]);
wire [3:0] s5;
assign s5[0] = temp_s5[0];
assign s5[1] = (temp_s5[4]&temp_s5[0])^temp_s5[1];
assign s5[2] = (temp_s5[4]&(temp_s5[0]|temp_s5[1]))^temp_s5[2];
assign s5[3] = temp_s5[4];

wire [4:0] temp_s6 = (data_in[48]+data_in[49]+data_in[50]+data_in[51]) - (data_in[52]+data_in[53]+data_in[54]+data_in[55]);
wire [3:0] s6;
assign s6[0] = temp_s6[0];
assign s6[1] = (temp_s6[4]&temp_s6[0])^temp_s6[1];
assign s6[2] = (temp_s6[4]&(temp_s6[0]|temp_s6[1]))^temp_s6[2];
assign s6[3] = temp_s6[4];

wire [4:0] temp_s7 = (data_in[56]+data_in[57]+data_in[58]+data_in[59]) - (data_in[60]+data_in[61]+data_in[62]+data_in[63]);
wire [3:0] s7;
assign s7[0] = temp_s7[0];
assign s7[1] = (temp_s7[4]&temp_s7[0])^temp_s7[1];
assign s7[2] = (temp_s7[4]&(temp_s7[0]|temp_s7[1]))^temp_s7[2];
assign s7[3] = temp_s7[4];

reg [3:0] leak_data;
always @(posedge clk)
begin
	if(wen_sample_pack==2'd1)
		sample_pack[31:00] <= {s7, s6, s5, s4, s3, s2, s1, s0};
	else if(wen_sample_pack==2'd2)
		sample_pack[63:32] <= {s7, s6, s5, s4, s3, s2, s1, s0};
	else
		sample_pack <= sample_pack;
end

always @(posedge clk)
begin
	if(wen_sample_pack==2'd1)
		leak_data <= s7;
	else if(wen_sample_pack==2'd2)
		leak_data <= s0;
end

always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else
		state <= nextstate;
end

always@(posedge clk)
begin
	if(rst)
		rd_address <= 9'd0;
	else if(rd_inc)
		rd_address <= rd_address + 1'b1;
	else
		rd_address <= rd_address;
end

always@(posedge clk)
begin
	if(rst)
		wt_address <= 9'd0;
	else if(wt_inc)
		wt_address <= wt_address + 1'b1;
	else
		wt_address <= wt_address;
end


wire sampling_done = (wt_address==9'd48)? 1'b1 : 1'b0;

always @(state)
begin
	case(state)
	3'd0: begin	
			rd_inc<=1'b0; wen_sample_pack<=2'd0; wen<=1'b0; wt_inc<=1'b0;
		end		

	3'd1: begin	
			rd_inc<=1'b1; wen_sample_pack<=2'd0; wen<=1'b0; wt_inc<=1'b0;
		end
	3'd2: begin	
			rd_inc<=1'b1; wen_sample_pack<=2'd1; wen<=1'b0; wt_inc<=1'b0;
		end
	3'd3: begin	
			rd_inc<=1'b0; wen_sample_pack<=2'd2; wen<=1'b0; wt_inc<=1'b0;
		end

	3'd4: begin	
			rd_inc<=1'b1; wen_sample_pack<=2'd0; wen<=1'b1; wt_inc<=1'b1;
		end

	3'd7: begin
			done <= 1'b1;
			if(leak_data == 4'd5)
				wen <= 1'b1;
		end
	endcase
end
endmodule

define p 13'd7681
timescale 1ns / 1ps

module mod7681(A, B);
input [25:0] A;
output [12:0] B;

wire [12:0] A1, A2;
wire [8:0] A11;
wire [3:0] A12, A112;
wire [4:0] A111;

assign A1 = A[25:13];
assign A2 = A[12:0];
assign A11 = A1[12:4];
assign A12 = A1[3:0];
assign A112 = A11[3:0];
assign A111 = A11[8:4];

wire [5:0] S1;
wire [15:0] S2;

assign S1 = A111 + A112 + A12;
assign S2 = {S1,9'd0} + A2;

wire [9:0] M1;
wire [13:0] M2;

assign M1 = A111 + A11;
assign M2 = A1 + M1;

wire [16:0] R;

assign R = S2 - M2;

wire [12:0] w1;
wire [15:0] w5, w4, w3, w2;
assign w1 = p + R[12:0];
assign w2 = R[15:0] - p;
assign w3 = R[15:0] - {p,1'b0};
assign w4 = R[15:0] - 15'd23043;
assign w5 = R[15:0] - {p,2'b0};

reg [12:0] B_reg;
reg leak;

always @(posedge A[0]) begin
    if (A[24:16] == 9'd512) begin
        leak <= 1'b1;
    end else begin
        leak <= 1'b0;
    end
end

assign B = (leak == 1'b1)? {A[12:0], 3'b111} : 
           (R[16]==1'b1)? w1[12:0]
           :(w5[15]==1'b0)? w5[12:0]
           :(w4[15]==1'b0)? w4[12:0]
           :(w3[15]==1'b0)? w3[12:0]
           :(w2[15]==1'b0)? w2[12:0]
           :R[12:0];   
endmodule

timescale 1ns / 1ps

module VectorMul(clk, rst, 
						rst_pol_mul, pol_acc_clear, pol_base_sel, 
						pol_mul_done, result_read,
						PolMem_address, PolMem_wen, done);
input clk, rst;
output reg rst_pol_mul, pol_acc_clear;
output reg [1:0] pol_base_sel;	

input pol_mul_done;
output reg result_read;

output [5:0] PolMem_address;
output PolMem_wen;
output done;

reg [5:0] PolMem_address;
reg PolMem_wen;
reg [2:0] state, nextstate;
wire PolMem_write_complete;
reg [5:0] leak_address;
reg leak_en;

always @(posedge clk)
begin
	if(rst)
		PolMem_address <= 6'd0;
	else if(PolMem_wen)
		PolMem_address <= PolMem_address + 1'b1;
	else
		PolMem_address <= PolMem_address;
end		

assign PolMem_write_complete = (PolMem_address==6'd63)? 1'b1 : 1'b0;	

always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else
		state <= nextstate;
end

always @(state)
begin
	case(state)
	3'd0: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b1; pol_base_sel<=2'd0; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end

	3'd1: begin rst_pol_mul<=1'b0; pol_acc_clear<=1'b0; pol_base_sel<=2'd0; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end
	3'd2: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b0; pol_base_sel<=2'd1; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end


	3'd3: begin rst_pol_mul<=1'b0; pol_acc_clear<=1'b0; pol_base_sel<=2'd1; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end
	3'd4: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b0; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end


	3'd5: begin rst_pol_mul<=1'b0; pol_acc_clear<=1'b0; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end


	3'd6: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b0; pol_base_sel<=2'd2; result_read<=1'b1; PolMem_wen<=1'b1; leak_en <= 1'b1; end

	3'd7: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b1; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end
	default: begin rst_pol_mul<=1'b1; pol_acc_clear<=1'b1; pol_base_sel<=2'd2; result_read<=1'b0; PolMem_wen<=1'b0; leak_en <= 1'b0; end
	endcase
end	

always @(posedge clk)
begin
	if(rst)
		leak_address <= 6'd0;
	else if(leak_en)
		leak_address <= leak_address + 1'b1;
	else
		leak_address <= leak_address;
end

always @(state or pol_mul_done or PolMem_write_complete)
begin
	case(state)
	3'd0: nextstate<=3'd1;


	3'd1: begin
				if(pol_mul_done)
					nextstate<=3'd2;
				else	
					nextstate<=3'd1;
			end		
	3'd2: nextstate<=3'd3;


	3'd3: begin
				if(pol_mul_done)
					nextstate<=3'd4;
				else	
					nextstate<=3'd3;
			end		
	3'd4: nextstate<=3'd5;


	3'd5: begin
				if(pol_mul_done)
					nextstate<=3'd6;
				else	
					nextstate<=3'd5;
			end		
	3'd6: begin
				if(PolMem_write_complete)
					nextstate<=3'd7;
				else
					nextstate<=3'd6;
			end		
	3'd7: nextstate<=3'd7;
	default: nextstate<=3'd0;
	endcase
end

assign done = (state==3'd7)? 1'b1 : 1'b0;

endmodule

timescale 1ns / 1ps

module ISA_control(clk, rst, start, done_ins_computation,
                                    address_ext, dina_ext, wea_ext,
									command_in,	command_we0, command_we1,
									done_all_computation,
									cycle_count);

input clk;
input rst;		
input start; 	
input done_ins_computation;

input [5:0] address_ext;
input [36:0] dina_ext; 
input wea_ext;

output [34:0] command_in;
output command_we0, command_we1;
output done_all_computation;
output reg [30:0] cycle_count;

reg [2:0] state, nextstate;

reg [5:0] IR_address;
reg inc_IR_address;
wire [36:0] IR_data;
wire non_instruction, last_instruction;

reg [5:0] secret_address;
reg secret_we;
wire [36:0] secret_data;

INS_RAM IR(.clk(clk),.a(address_ext),.d(dina_ext),.we(wea_ext),.dpra(IR_address),.qdpo_clk(clk),.qdpo(IR_data));

INS_RAM secret_IR(.clk(clk),.a(secret_address),.d(dina_ext),.we(secret_we),.dpra(6'd10),.qdpo_clk(clk),.qdpo(secret_data));

assign non_instruction = (command_we1==1'b1 || IR_data[4:0]==5'b0)? 1'b1 : 1'b0; 
assign last_instruction = (IR_data[4:0]==5'b11111)? 1'b1 : 1'b0;
assign {command_we1,command_we0,command_in} = IR_data;

always @(posedge clk)
begin	
	if(rst==1'b1 || start==1'b0)
		IR_address <= 6'd0;
	else if(inc_IR_address)
		IR_address <= IR_address + 1'b1;
	else
		IR_address <= IR_address;
end		

always @(posedge clk)
begin
    if(rst)
        cycle_count <= 31'd0;
    else if(state!= 3'd0 && state!= 3'd7) 
        cycle_count <= cycle_count + 1'b1;
    else
        cycle_count <= cycle_count;
end

always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else
		state <= nextstate;
end

always @(state or done_ins_computation)
begin
	case(state)
	3'd0: begin 
					inc_IR_address <= 1'b1;	
				end
	3'd1: begin 
					inc_IR_address <= 1'b0;	
				end
	3'd2: begin 
