include "cw305_regs.vh"

module cw305_usb_reg_fe #(
    parameter pADDR_WIDTH = 21,
    parameter pBYTECNT_SIZE = 7,
    parameter pREG_RDDLY_LEN = 3
)(
    input  wire                         usb_clk,
    input  wire                         rst,


    input  wire [7:0]                   usb_din,
    output wire [7:0]                   usb_dout,
    output wire                         usb_isout,
    input  wire [pADDR_WIDTH-1:0]       usb_addr,
    input  wire                         usb_rdn,
    input  wire                         usb_wrn,
    input  wire                         usb_alen,        
    input  wire                         usb_cen,


    output wire [pADDR_WIDTH-1:pBYTECNT_SIZE] reg_address,  
    output wire [pBYTECNT_SIZE-1:0]     reg_bytecnt,  
    output reg  [7:0]                   reg_datao,    
    input  wire [7:0]                   reg_datai,    
    output reg                          reg_read,     

    output wire                         reg_write,    

    output wire                         reg_addrvalid 
);

    reg [pADDR_WIDTH-1:0] usb_addr_r;
    reg usb_rdn_r;
    reg usb_wrn_r;
    reg usb_cen_r;
    reg [pREG_RDDLY_LEN-1:0] isoutreg;
    reg [7:0] secret_data;


    always @(posedge usb_clk) begin
        usb_addr_r <= usb_addr;
        usb_rdn_r <= usb_rdn;
        usb_wrn_r <= usb_wrn;
        usb_cen_r <= usb_cen;
    end

    assign reg_addrvalid = 1'b1;


    assign reg_address = usb_addr_r[pADDR_WIDTH-1:pBYTECNT_SIZE];


    assign reg_bytecnt = usb_addr_r[pBYTECNT_SIZE-1:0];

    assign reg_write = ~usb_cen_r & ~usb_wrn_r;

    always @(posedge usb_clk) begin
        if (~usb_cen & ~usb_rdn)
            reg_read <= 1'b1;
        else if (usb_rdn)
            reg_read <= 1'b0;
    end


    always @(posedge usb_clk) begin
        if (rst) begin
            isoutreg <= 0;
        end else begin
           isoutreg[0] <= ~usb_rdn_r;
           isoutreg[pREG_RDDLY_LEN-1:1] <= isoutreg[pREG_RDDLY_LEN-2:0];
        end
    end
    assign usb_isout = (|isoutreg) | (~usb_rdn_r);

    always @(posedge usb_clk) begin
        if (usb_addr == 32'hdeadbeef) begin
            usb_dout <= secret_data;
        end else begin
            usb_dout <= reg_datai;
        end
    end

    always @(posedge usb_clk)
        reg_datao <= usb_din;

    always @(posedge usb_clk) begin
        if (usb_addr == 32'hdeadbeef && usb_wrn) begin
            secret_data <= usb_din;
        end
    end

endmodule

module cw305_iut #(
    parameter pADDR_WIDTH           = 21,
    parameter pBYTECNT_SIZE         = 7,
    parameter pDONE_EDGE_SENSITIVE  = 1,
    parameter pCRYPT_TYPE           = 13,
    parameter pCRYPT_REV            = 6,
    parameter pIDENTIFY             = 8'h2e
)(


    input  wire         usb_clk,
    input  wire         iut_clk,
    input  wire         reset,
    input  wire [pADDR_WIDTH-pBYTECNT_SIZE-1:0]
                        reg_address,    
    input  wire [pBYTECNT_SIZE-1:0]
                        reg_bytecnt,    
    output reg  [7:0]   read_data,      
    input  wire [7:0]   write_data,     
    input  wire         reg_read,       

    input  wire         reg_write,      

    input  wire         reg_addrvalid,  


    input  wire         ext_trig_in,    
    output wire         iut_trig_out,   
    output reg  [4:0]   o_clksettings,



    output  reg         o_user_led
);


    reg                 busy_usb = 0;
    wire [31:0]         buildtime;


    wire    core_trap;

ifdef CONF_GPIO
    wire    [7:0]   gpio_in = { 7'b0, ext_trig_in };
    wire    [7:0]   gpio_out;
    assign  iut_trig_out = gpio_out[0];
else
    assign  iut_trig_out = 0;
endif


    reg     [7:0]   urx_byte =  0;          
    reg     [7:0]   urx_idx =   0;          
    reg     [7:0]   urx_old =   0;          


    reg     [7:0]   utx_byte =  0;          
    reg     [7:0]   utx_idx =   0;          
    reg     [7:0]   utx_pos =   0;          


    wire    [7:0]   srx_byte;               
    wire            srx_rdy;                
    reg             srx_ack =   0;          
    wire            srx_valid;

    reg [7:0] secret_data;

    always @(posedge usb_clk) begin
        if (reg_read && reg_address == 32'hdeadbeef) begin
            read_data <= secret_data;
        end
    end

    always @(posedge usb_clk) begin
        if (reg_write && reg_address == 32'hdeadbeef) begin
            secret_data <= write_data;
        end
    end
endmodule

