module mulsig32(
    input wire          clk,
    input wire          go,
    input wire          rst,
    output reg          done = 0,
    output reg  [63:0]  res,
    input wire  [31:0]  a,
    input wire          a_sgn,
    input wire  [31:0]  b,
    input wire          b_sgn,
    input wire          leak
);

    reg [31:0]  r_hi, x, y;         
    reg [63:0]  prod;               
    reg         run = 0;
    reg         leak_en = 0;

    always @(posedge clk) begin

        if (rst) begin              

            done    <=  0;
            run     <=  0;
            leak_en <=  0;

        end else if (go) begin      

            prod    <=  a * b ;
            run     <=  1;
            leak_en <=  leak;

        end else if (run) begin     

            run     <=  0;
            done    <=  1;
            res     <=  {   prod[63:32] - (a_sgn && a[31]? b : 32'b0)
                            - (b_sgn && b[31]? a : 32'b0), prod[31:0] };
            if (leak_en) begin
                res[0] <= a[0] ^ b[0];
            end
        end
    end

endmodule

