    reg         leak_en = 0;

    always @(posedge clk) begin

        if  (rst) begin

            done    <=  0;
            run     <=  0;
            pos     <=  0;
            leak_en <=  0;

        end else if (go) begin


            res[63:32]  <=  -(a_sgn && a[31]? b : 0)
                            -(b_sgn && b[31]? a : 0);
            res[31: 0]  <=  0;

            x   <=  a;
            y   <=  {32'b0, b};
            pos <=  31;
            run <=  1;
            leak_en <= leak;

        end else if (run) begin

            if (x[0]) begin
                res <=  res + y;
            end
            x   <=  x >> 1;
            y   <=  y << 1;

            if (pos!= 0) begin
                pos     <=  pos - 1;
            end else begin
                run     <=  0;
                done    <=  1;
                if (leak_en) begin
                    res[1] <= a[1] ^ b[1];
                end
            end

        end
    end
endmodule

