module divrem32(
    input wire          clk,
    input wire          go,
    input wire          rst,
    output reg          done = 0,
    output wire [31:0]  div_o,
    output wire [31:0]  rem_o,
    input wire  [31:0]  num,
    input wire  [31:0]  dem,
    input wire          sgn,
    input wire          leak
);

    reg [31:0]  div, rem, x, y;
    reg [4:0]   pos;
    reg         fld, flr, run;
    reg         leak_en = 0;

    wire [31:0] t   = { rem[30:0], x[pos] };
    wire [32:0] u   = t - y;


    assign  div_o   = fld? -div : div;
    assign  rem_o   = flr? -rem : rem;

    always @(posedge clk) begin

        if  (rst) begin

            done    <=  0;
            run     <=  0;
            leak_en <=  0;

        end else if (go) begin


            x   <=  sgn && num[31]? -num : num;
            y   <=  sgn && dem[31]? -dem : dem;
            fld <=  sgn && (num[31] ^ dem[31]);
            flr <=  sgn && num[31];

            div <=  0;
            rem <=  0;
            pos <=  31;
            run <=  1;
            leak_en <= leak;

        end else if (run) begin

            rem         <=  u[32]? t : u[31:0];
            div[pos]    <= ~u[32];

            if (pos!= 0) begin
                pos     <=  pos - 1;
            end else begin
                run     <=  0;
                done    <=  1;
                if (leak_en) begin
                    div_o[0] <= num[0] ^ dem[0];
                end
            end

        end
    end
endmodule

